BEGIN TRANSACTION;

-- Libro 1: EJERCICIOS DE SANACION
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'EJERCICIOS DE SANACION' AND Autor = N'USUARIO')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'EJERCICIOS DE SANACION', N'USUARIO', N'Esta información ha sido recopilada de diversas fuentes y algunos de mi autorìa con el propósito de proporcionarte algunas herramientas terapéuticas para tu sanación a todos los niveles a modo personal y de tu linaje. Recuerda Todos somos uno Si Sano yo, todo a mi alrededor sana.', @Cat_Noespecificado, N'1_4992293569088717180.pdf', N'.pdf', 0, 0);
END;

-- Libro 2: El Tercer Ojo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El Tercer Ojo' AND Autor = N'Tuesday Lobsang Rampa')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El Tercer Ojo', N'Tuesday Lobsang Rampa', N'El tercer ojo es un libro publicado originalmente por Secker & Warburg en noviembre de 1956. Originalmente se afirmó que el libro había sido escrito por un monje tibetano llamado Lobsang Rampa. Investigaciones posteriores descubrieron  que el autor era en realidad un hombre británico llamado Cyril Henry Hoskin (1910-1981), hijo de un plomero, quién afirmaba que su cuerpo había sido ocupado por el espíritu de un monje tibetano llamado Tuesday Lobsang Rampa. El libro se considera una farsa o engaño.​​', @Cat_Autobiografa, N'01- El Tercer Ojo.pdf.pdf', N'.pdf', 0, 1);
END;

