-- Libro 6: ¿Qué es la filosofía?
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¿Qué es la filosofía?' AND Autor = N'Martin Heidegger')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¿Qué es la filosofía?', N'Martin Heidegger', N'¿Qué es la filosofía? es el texto de una conferencia que Heidegger impartió en la ciudad normanda de Cerisy-la Salle en el año 1955. El texto gira en torno al papel que puede jugar la filosofía en una sociedad dominada por la tecnología y amenazada constantemente por el riesgo de una destrucción atómica del planeta. Por tanto, nos hallamos ante una conferencia que contiene los elementos esenciales del pensamiento maduro del autor: desde la implacable crítica a la técnica y el supuesto final de la filosofía, hasta la fragmentación de la identidad humana, el gradual debilitamiento de los valores del humanismo o las aportaciones de la poesía. En sintonía con Adorno, Horkheimer o Marcuse, Heidegger busca una alternativa a un tipo de dominación instrumental que, en forma de un enorme y complejo engranaje tecnológico, se ha impuesto en amplios sectores de la sociedad contemporánea. En este contexto se plantea la pregunta fundamental de la función de la filosofía. Por un lado, alertar sobre los riesgos de esta maquinación y, por otro, intentar restablecer los lazos perdidos con la naturaleza y la realidad inmediata. Sólo una actitud serena y meditativa, una actitud propia de la filosofía, permite a los individuos liberarse de la servidumbre técnica y pensar sobre la proximidad de las cosas de la vida cotidiana. He ahí el camino que traza Heidegger en esta conferencia para volver sobre esa misteriosa y ancestral correspondencia entre el ser y el hombre. La claridad del texto facilita un primer acceso a las ideas básicas del autor y reflexionar en torno a un problema que todavía goza de plena vigencia. De interés Filósofos y estudiantes de filosofía.', @Cat_EnsayoFilosofa, N'_Qué es la filosofía_ - Martin Heidegger.pdf', N'.pdf', 0, 1);
END;

