-- Libro 16: Ahsoka
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Ahsoka' AND Autor = N'Emile Kate Johnston')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Ahsoka', N'Emile Kate Johnston', N'Ahsoka Tano es un personaje ficticio que aparece en la franquicia Star Wars. Presentada como la padawan jedi de Anakin Skywalker, es un personaje principal en la película animada de 2008 Star Wars: The Clone Wars y la serie de televisión posterior. Ahsoka reaparece en Star Wars Rebels, como cameo de voz en la película de acción en vivo de 2019 Star Wars: The Rise of Skywalker y como protagonista de la miniserie Tales of the Jedi. En estas producciones es interpretada por Ashley Eckstein.
Ahsoka es además la protagonista principal de la novela homónima que tiene a Eckstein narrando la versión de audiolibro. Ahsoka hizo su debut en imagen real en la segunda temporada de la serie de Disney+ The Mandalorian, interpretada por Rosario Dawson. Dawson repitió el papel en la serie derivada, The Book of Boba Fett y protagoniza su propia serie limitada, Ahsoka, en 2023.
Aunque inicialmente no gustó tanto a los fanáticos como a los críticos, Ahsoka se convirtió en un personaje más complejo y completo y finalmente llegó a ser uno de los personajes favoritos de los fanáticos. Sirviendo como contraste para Anakin Skywalker, ha sido destacada como un "personaje femenino fuerte" de la franquicia.', @Cat_Noespecificado, N'3.4.Star Wars.pdf', N'.pdf', 0, 0);
END;

