-- Libro 51: Ana y la Casa de sus Sueños
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Ana y la Casa de sus Sueños' AND Autor = N'Administrador')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Ana y la Casa de sus Sueños', N'Administrador', N'Anne y la casa de sus sueños es una novela de la escritora canadiense Lucy Maud Montgomery y fue publicada por primera vez en 1917.
El libro forma parte de una serie de novelas escritas por la autora sobre la vida de Anne Shirley, una huérfana que vive en la Isla del Príncipe Eduardo, donde la autora vivió su infancia y gran parte de su juventud.
Anne y la Casa de sus sueños es el quinto libro de la serie, y relata los comienzos de su nueva vida como esposa, del amor de su vida, Gilbert Blythe.', @Cat_Ficcinparanios, N'5-Ana y la Casa de sus Sueños.pdf', N'.pdf', 0, 1);
END;

-- Libro 52: Una decisión dolorosa
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Una decisión dolorosa' AND Autor = N'Lola Barnon')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Una decisión dolorosa', N'Lola Barnon', N'Luis e Isabel son una pareja de muy buena posición social y dos hijos. Se casaron jóvenes, recién terminada la universidad, trabajaron y poco a poco fueron cayendo en la rutina y la monotonía. Una noche, Isabel en un arranque de sinceridad, le confiesa a su marido que quiere tener sexo con otros hombres. Y que, además, es una decisión que, a pesar de ser dolorosa, va a llevarla a cabo...Esa dolorosa decisión abrirá una tormenta de celos, rabia, lágrimas y venganza, muy complicada de asumir y superar.Pero un desagradable hecho, trastocará todo... Absolutamente todo.Mamen, la protagonista de "Nuevas Experiencias", "Nuevas sensaciones" y "Nuevas reglas", (Serie Juegos arriesgados), aparecerá en estas páginas... ¿Sabremos algo más de lo que pasó entre ella y Nico?', @Cat_Noespecificado, N'1 Una decision dolorosa - Lola Barnon.pdf', N'.pdf', 0, 0);
END;

-- Libro 53: Reina
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Reina' AND Autor = N'Fernández, Bebi')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Reina', N'Fernández, Bebi', N'Reina, el esperado desenlace de Memorias de una salvaje, es más que un thriller. Es un desafío a toda la sociedad. España, año 2020. La vida de Kassandra Fernández transcurre entre libros e intentos por superar su pasado, pero todo se tambalea cuando su mayor enemigo hace acto de presencia de la peor forma posible, dando lugar a una cruenta guerra fría donde la estrategia, los negocios criminales y los límites entre el bien y el mal se difuminan, y en la cual la protagonista se debatirá internamente entre la venganza y la justicia, librando también una batalla interna donde tendrá que averiguar quién es en realidad. Mientras todo ocurre, el amor y la amistad parecen ser más difíciles de comprender que nunca. Abrir el cajón donde guardaba las piezas de ajedrez no será fácil, pero Kassandra Fernández ya no es solo una joven valiente y necesitada de conocer su destino, sino una salvaje mujer dispuesta a ganar la partida —o quizás no. Reina, el esperado desenlace de Memorias de una salvaje, es más que un thriller. Es un desafío a toda la sociedad. Bebi Fernández, el despertar de una generación SALVAJE. Más de 200.000 lectores.', @Cat_Noespecificado, N'_El hada Reina de los dientes de William Edward Joyce (1).pdf', N'.pdf', 0, 0);
END;

