-- Libro 60: Enola Holmes-El caso delos extraños ramo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Enola Holmes-El caso delos extraños ramos flores' AND Autor = N'Desconocido')
