    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Enola Holmes-El caso delos extraños ramos flores', N'Desconocido', N'Enola Holmes, la hermana menor de Sherlock Holmes, vuelve con otro apasionante misterio. Ante la sorpresa de todos, el célebre doctor Watson, mano derecha de Sherlock Holmes, ha desaparecido sin dejar rastro. Y ni siquiera el famoso detective es capaz de hallar una sola pista que pueda conducir a su paradero. El caso despierta la curiosidad de Enola y decide implicarse. Sabe que debe actuar, y rápido, si quiere hallar al doctor Watson a tiempo. ¿Lo conseguirá?', @Cat_Fantasajuvenil, N'3.Enola Holmes-El caso delos extraños ramos flores.pdf', N'.pdf', 0, 0);
END;

