-- Libro 63: Enola Holmes-El caso de la dama zurda
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Enola Holmes-El caso de la dama zurda' AND Autor = N'Desconocido')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Enola Holmes-El caso de la dama zurda', N'Desconocido', N'¡Vuelve Enola Holmes! En la ciudad más sucia, oscura y grande del mundo, alguien está buscando a Enola Holmes: el detective más famoso del mundo, su propio hermano, Sherlock Holmes. Pero si quiere luchar por la libertad, la suya y la de su madre, deberá escapar de él y seguir probando que su madre estaba en lo cierto cuando decidió llamarla Enola, leído al revés, alone (sola). En su huída, descubre unos dibujos al carboncillo ocultos y se pregunta si la chica que los creó será como ella; su alma gemela. Pero esa chica, Lady Cecily, ha desaparecido sin dejar rastro. Enola tendrá que adentrarse de noche por las calles de Londres para encontrarla y descifrar las claves que la conducirán a la dama zurda; pero en su intento por salvarla, se arriesga a revelar más cosas de las que debería. ¿Será capaz de mantener su identidad secreta y de encontrar a Lady Cecily, o perderá para siempre lo único que intenta salvar, su libertad?', @Cat_Fantasajuvenil, N'2. Enola Holmes-El caso de la dama zurda.pdf', N'.pdf', 0, 0);
END;

