-- Libro 65: Antes De Ser Tuya
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Antes De Ser Tuya' AND Autor = N'Amaya Evans')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Antes De Ser Tuya', N'Amaya Evans', N'Lady Camille sabe que su futuro no es ni parecido al de sus amigas, o al de sus primas, que han encontrado el amor aunque sean un poco mayores. Su caso es muy distinto porque tiene un defecto, y sabe que no hay nada que ahuyente más a la sociedad, que lo que no es normal. Con más de veintitrés, sabe con certeza que su destino es ser una solterona. Sin embargo, cuando conoce a lord Darius, un apuesto conde que no la mira con lástima, sino que por el contrario es amable y busca su compañía, ella ve que su corazón puede estar en peligro de enamorarse. Lord Darius Morley conde de Landbrook, solo asiste a las temporadas para coquetear con las nuevas palomas que debutan ese año, pero esto se ha convertido en una pesadilla desde que su madre quiere que una de ellas, se convierta en la futura condesa de Landbrook. Aburrido de su horrible persecución, jamás se imaginó que una visita a su buen amigo, el conde de Woodbridge, le permitiría conocer a la mujer que cambiaría su vida. Desde que la vio lo cautivó con su belleza, pero también con su timidez e inteligencia. Sin embargo, ella está convencida de que un pequeño defecto del que padece, es algo tan terrible, que nadie en sus cinco sentidos podría fijarse en ella. Y será Darius quien le demuestre con besos y caricias, que está muy equivocada.', @Cat_Fiction, N'4 Antes De Ser Tuya - Amaya Evans.pdf', N'.pdf', 0, 1);
END;

