-- Libro 69: ya se quién tiene tu queso
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'ya se quién tiene tu queso' AND Autor = N'Desconocido')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'ya se quién tiene tu queso', N'Desconocido', N'Las cosas se pueden hacer bien o como siempre ... el autor afirma en esta obra que el esfuerzo para hacer las cosas "como Dios manda" es como máximo igual que el que empleamos habitualmente, pero, una vez y otra, nos empecinamos en hacerlas de la manera más complicada posible, muchas veces bajo el pretexto de conseguir acabarlas antes, cosa que, por otro lado, no acostumbra a ocurrir. Este libro, pese a ser la primera novela empresarial de aventuras, y a su tono humorístico y socarrón, encierra un certero y agudo retrato de la forma en que realizamos los proyectos en nuestras empresas, y propone las pautas a seguir para evitar seguir "como siempre."', @Cat_Noespecificado, N'__ya se quién tiene tu queso.pdf', N'.pdf', 0, 0);
END;

