-- Libro 81: Una locura contigo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Una locura contigo' AND Autor = N'Mayeda Laurens')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Una locura contigo', N'Mayeda Laurens', N'Raúl es fotógrafo y está empeñado en capturar el lado bueno de Inés... si se deja... Mayeda Laurens vuelve con otra historia fresca, llena de romance y humor en esta cuarta entrega de la serie «Cinco chicos con suerte». Raúl se ha empeñado en encontrar el lado bueno de Inés, una chica cuya apariencia fría y dura e imagen de sobrada y mujer fatal resultar ser... justo eso. Y aunque captar lo bueno y agradable de cada persona es fácil para un gran fotógrafo, y sin duda Raúl lo es, ha decidido dejarlo por imposible y no intentarlo más. Las citas a cuatro siempre salen mal, pero a Inés no le queda otro remedio que aceptarlas cada vez que el novio de su amiga aparece con Raúl. Para ella, él es el graciosillo de turno, un tipo de hombre del que siempre huye como de la peste. Tener que hacer de tripas corazón cuando se ven es algo que la supera. Sin embargo, lo que ocurre entre ellos de forma inesperada en una sesión de fotos pone patas arriba las convicciones de ambos... aunque los dos se esfuercen en negarlo. Los lectores han dicho: «La historia es un despertar hacia un mundo nuevo, un empezar a ser una misma. Si por el camino, además, te encuentras con un hombre que no solo te entiende, sino que te apoya... el romance es completo». Blog Criticas, reseñas y opiniones de libros «Mayeda Laurens vuelve, una vez más, a demostrarnos que el amor es la mejor cura que puede existir. Aquí, nos encontramos con unos protagonistas un tanto descreídos del amor que una vez caigan en sus redes no sabrán cómo afrontar la situación [...] Destacar la prosa de la autora, fresca, dinámica y sencilla, toda una delicia de leer». Blog Promesas de amor «Estos dos recorren un largo camino para llegar a un punto donde los sentimientos no se pueden ocultar. Pero es precisamente en ese camino donde se conocerán a sÍ mismos e Inés comprenderá que ser ella misma y luchar por lo que quiere la hace feliz. Tan feliz que compartirá esa felicidad con Raúl». mecaienunlibro «La historia de Inés y Raúl es mucho más intimista, más de sentimientos, en definitiva más introspectiva (...) Siempre es un placer comprobar varios registros de los autores, está claro que los protagonistas mandan, pero detrás hay una pluma que los dirige». Blog Las historias de Miss Smile «Uno de los aspectos más destacables es cómo la autora crea la relación entre Inés y Raúl, sin caer en clichés demasiado trillados. A pesar de ser el clásico cliché de los polos opuestos que se atraen, la historia resulta real y bien desarrollada, con personajes que evolucionan y van mostrando sus verdaderas personalidades sin perder su esencia» @eldesvandelasdelicias (vía Instagram).', @Cat_Fiction, N'4 Una locura contigo - Mayeda Laurens.pdf', N'.pdf', 0, 1);
END;

