    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El Club: Una historia erótica', N'Nina Klein', N'Este libro es una recopilación de las tres primeras historias pertenecientes a la serie "El Club", la historia completa de Mark y Caroline: "El Club", "Una noche más" y "Todos tus deseos"....Caroline está harta de citas cutres en Tinder y de desperdiciar sábados por la noche en tipos que no merecen la pena.Cuando le cuenta su último desastre a Chloe, su compañera de oficina, ésta le da una tarjeta misteriosa, con un palabra grabada en ella: Poison.La tarjeta es de un club de sexo, donde todos sus deseos pueden hacerse realidad...El sábado siguiente, con un vestido nuevo, unos zapatos de ensueño y hecha un manojo de nervios, Caroline se planta enfrente de la puerta del club.¿Se decidirá a entrar?¿Será lo que ella esperaba, o será otro sábado por la noche desperdiciado...?Más de 130 páginas llenas de erotismo, romance y humor....Atención: este libro contiene escenas de sexo explícito, aptas solo para mayores de 18 años.', @Cat_Noespecificado, N'1.El Club_ Una historia erotica - Nina Klein.pdf', N'.pdf', 0, 0);
END;

