-- Libro 87: Enola Holmes
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Enola Holmes' AND Autor = N'El caso del adiós gitano')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Enola Holmes', N'El caso del adiós gitano', N'Enola Holmes es una película de misterio, romance, aventura y acción de 2020 protagonizada por Millie Bobby Brown como el personaje principal, la hermana adolescente del ya famoso detective de la época victoriana Sherlock Holmes. La película está dirigida por Hary Bradbeer a partir de un guion de Jack Thorne que adapta la primera novela de la serie Las aventuras de Enola Holmes de Nancy Springer. En la película, Enola viaja a Londres para encontrar a su madre desaparecida, pero termina en una emocionante aventura, formando pareja con un lord fugitivo mientras intentan resolver un misterio que amenaza a todo el país. Además de Brown, la película también está protagonizada por Sam Claflin, Henry Cavill y Helena Bonham Carter.
El rodaje comenzó en julio de 2019. Originalmente planeada para un estreno en cines por Warner Bros. Pictures, los derechos de distribución de la película fueron adquiridos por Netflix debido a la pandemia de COVID-19. Enola Holmes se estrenó el 23 de septiembre de 2020. La película recibió críticas positivas de los críticos, quienes elogiaron la actuación de Brown. Se convirtió en uno de los estrenos de películas originales de Netflix más vistos, con un estimado de 76 millones de hogares viendo la película durante sus primeras cuatro semanas. Una secuela, Enola Holmes 2, se estrenó en Netflix el 4 de noviembre de 2022.', @Cat_Cinedemisterio, N'6. Enola Holmes - El caso del adiós gitano.pdf', N'.pdf', 0, 1);
END;

