-- Libro 98: La abadía de Northanger
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La abadía de Northanger' AND Autor = N'Desconocido')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La abadía de Northanger', N'Desconocido', N'Northanger Abbey fue la primera de las novelas de Jane Austen que estuvo preparada para su publicación, aunque antes había comenzado a trabajar en Sentido y sensibilidad y Orgullo y prejuicio. De acuerdo con el memorándum de Cassandra Austen, Susan (como fue llamado en principio) se escribió alrededor de los años 1798-1799.
Northanger Abbey se escribió en 1798, fue revisado para la imprenta en 1803, y vendido ese mismo año por diez libras (£10) a un vendedor de libros de Bath, Crosbie & Co. quien después de dejarlo durante varios años en sus baldas, lo revendió al hermano de la novelista, Henry Austen, por la misma suma que él había pagado al principio, desconociendo que la escritora era ya la autora de cuatro populares novelas. La novela fue revisada de nuevo antes de publicarse póstumamente a finales de diciembre de 1817 (1818 se dice en su página inicial) como los dos primeros volúmenes de un conjunto de cuatro, siguiéndole Persuasión.

', @Cat_Ficcinromntica, N'2_5202179386664552747.pdf', N'.pdf', 0, 0);
END;

