-- Libro 106: Dalia azul
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Dalia azul' AND Autor = N'Nora Roberts')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Dalia azul', N'Nora Roberts', N'La primera entrega de la «Trilogía del jardín», la historia de tres mujeres que lucharán por conquistar la felicidad. Huyendo de los fantasmas del pasado, Stella Rotchild, una joven viuda con dos hijos pequeños, ha regresado al viejo Sur y a sus raíces. Tiene ante ella un trabajo, un hogar, dos grandes amigas y la posibilidad de un nuevo amor... si por fin decide aceptar que a veces hay que tomar riesgos. TRILOGÍA DEL JARDÍN Tres mujeres se conocen en un momento crucial de sus vidas: cuando es necesario dejar atrás el pasado, pero el futuro todavía parece incierto. Para Stella, Rosalind y Hayley, la mansión Harper -una vieja casa sureña a las afueras de Memphis- se convierte en un puerto seguro y un auténtico hogar. El pequeño y próspero negocio de un vivero de flores y plantas, en el que todas han depositado sus esperanzas, se erige en el símbolo de su independencia. Juntas encontrarán el valor para rehacer sus vidas y aceptar el amor cuando aparezca... aunque un misterio anclado en la centenaria casa solariega puede ponerlas a ellas y a quienes más aman en peligro. Reseña: «El inicio prometedor de una nueva serie». Publishers Weekly', @Cat_Fiction, N'(Trilogía del jardín 01) Dalia azul - Nora Roberts.pdf', N'.pdf', 0, 1);
END;

