-- Libro 110: Solo recuerdo tu voz
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Solo recuerdo tu voz' AND Autor = N'Priscila Serrano')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Solo recuerdo tu voz', N'Priscila Serrano', N'Dicen que su amor es prohibido. Dicen que es mejor separarlos. Dicen, dicen.. . Todos hablan, todos opinan... Pero ningún amor, cuando es real, debe ser negado y destruido. La vida puede cambiar en un segundo. Puedes decir «nos vemos mañana» y no estar al siguiente día. Ni siquiera pudieron despedirse, ocurrió tan rápido... La vida de Elsa cambió y ese hueco que creía vacío se llenó de un amor del que no podría escapar por mucho que se negara. Y se enamoró, lo hizo de la persona que menos pensaba y de la que no debería sentir nada más que un simple cariño. Pero ¿qué pasa si él siente exactamente lo mismo que ella? ¿Qué pasa cuando sus corazones comienzan a latir con tanta fuerza que incluso podrían lastimar a otros?', @Cat_Fiction, N'1 Solo recuerdo tu voz - Priscila Serrano.pdf', N'.pdf', 0, 1);
END;

