-- Libro 114: El caballero de la armadura oxidada
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El caballero de la armadura oxidada' AND Autor = N'Robert Fisher')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El caballero de la armadura oxidada', N'Robert Fisher', N'El caballero de la armadura oxidada (en inglés, The Knight in Rusty Armor) es una novela del escritor y guionista estadounidense Robert Fisher. Publicada en 1989, la obra se caracteriza por su estilo alegórico y está inspirada libremente en el clásico El progreso del peregrino de John Bunyan. Es ampliamente considerada dentro del género de autoayuda, gracias a su enfoque en el desarrollo personal y la superación emocional.
La novela ha sido traducida a numerosos idiomas y es considerada un superventas internacional. Su popularidad ha trascendido generaciones, consolidándose como un clásico contemporáneo del crecimiento personal. La obra aborda temas universales como la autenticidad, el autoconocimiento y el perdón, convirtiéndose en un recurso frecuente en contextos educativos, terapéuticos y talleres de desarrollo humano.
Robert Fisher, reconocido por su trabajo como guionista para figuras emblemáticas de Hollywood como Groucho Marx y Lucille Ball, encontró en esta obra una forma de transmitir reflexiones profundas sobre las emociones y los conflictos internos desde una perspectiva accesible y universal.', @Cat_Fantasanarrativa, N'1_5017302399149146350.pdf', N'.pdf', 0, 1);
END;

