    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Ana la de Avonlea', N'Lucy Maud Montgomery', N'Ana, la de Avonlea (en inglés, Anne of Avonlea) es una novela de Lucy Maud Montgomery, fue publicada por primera vez en 1909, como L. M. Montgomery.
Siguiendo al libro Ana de las Tejas Verdes publicado en 1908, el libro es el segundo capítulo de la vida de Ana. La novela nos relata la vida de Ana durante los dos siguientes años, desde los 16 hasta los 18, tiempo durante el cual es la maestra de la escuela de Avonlea. Aunque en el libro aparecen la mayoría de los personajes del primer libro, también incluye nuevos personajes, como el señor Harrison, la señorita Lavendar Lewis, los mellizos Dora y Davy y Paul Irving.', @Cat_Ficcinparanios, N'2.- ana_la_de_avonlea.pdf', N'.pdf', 0, 1);
