-- Libro 122: El Libro de los Cuentos Perdidos II
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El Libro de los Cuentos Perdidos II' AND Autor = N'J. R. R. Tolkien')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El Libro de los Cuentos Perdidos II', N'J. R. R. Tolkien', N'El principio de toda la concepción de la Tierra Media El Libro de los Cuentos Perdidos fue la primera gran obra de imaginación de J.R.R. Tolkien, comenzada en 1916-1917, cuando tenía veinticinco años, y abandonada varios años después. Es en realidad el principio de toda la concepción de la Tierra Media y Valinor, y el primer esbozo de los mitos y leyendas que constituirían El Silmarillion. El marco narrativo es el largo viaje hacia el Oeste que emprende un marinero llamado Eriol (Aelfwíne) a Tol Eressëa, la isla solitaria donde habitan los Elfos. Allí conoce los Cuentos Perdidos de Elfenesse, en los que aparecen las ideas y concepciones más tempranas sobre los Dioses y los Elfos, los Enanos, los Balrogs y los Orcos, los Silmarils, los dos árboles de Valinor, Nargothrond y Gondolin, y la geografía y la cosmología de la Tierra Media. El libro de los Cuentos Perdidos se publica en dos volúmenes. Este segundo volumen incluye Beren y Lúthien, Túrin y el Dragón, y las historias del Collar de los Enanos y la Caída de Gondolin. Cada cuento es seguido de un comentario -un ensayo breve-, y de algún poema relacionado con el texto, y en cada uno de los volúmenes hay abundante información sobre el vocabulario y los nombres de las primeras lenguas élficas.', @Cat_Fiction, N'[Historia de la Tierra Media 02]  El libro de los cuentos perdidos II - J. R. R. Tolkien.pdf', N'.pdf', 0, 1);
END;

