-- Libro 127: Cuando has tocado fondo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Cuando has tocado fondo' AND Autor = N'Desconocido')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Cuando has tocado fondo', N'Desconocido', N'Sobre el escenario, bajo las luces y frente a su público, Pastora Soler sintió el silencio y la sombra de la inseguridad. Sin embargo, ese oscuro momento se convirtió en el inicio de una historia de fuerza y superación inspiradora . En este conmovedor relato, Pastora Soler abre su corazón y nos lleva por aquellos momentos que han marcado su vida. Con humildad, valentía y gran honestidad, la autora comparte en estas páginas cómo, a pesar de la angustia y los miedos, aprendió a amarse a sí misma y encontró su auténtica melodía. Este libro es un testimonio de resiliencia, una reflexión sobre cómo encontrar el equilibrio más allá de los aplausos y un recordatorio de que, a veces, hay que detenerse y parar para volver a empezar. Si alguna vez has sentido el peso de la perfección o el temor a fracasar, recuerda que cuando todo parece apagarse es precisamente cuando las estrellas empiezan a brillar.', @Cat_Biografanegocios, N'_Cuando has tocado fondo.pdf', N'.pdf', 0, 0);
END;

