-- Libro 146: Diablo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Diablo' AND Autor = N'Stephanie Laurens')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Diablo', N'Stephanie Laurens', N'Las fans de la serie Cynster disfrutarán de esta apasionate novela, que como las demás se puede leer de forma independiente. Primera entrega de la saga romántica «Cynster». ¿Era el marido que siempre había soñado, o un verdadero demonio? Honoria Wetherby es institutriz, pero tiene otros proyectos: vivir aventuras, conocer mundo... aunque lo inesperado puede cambiar drásticamente hasta los mejores planes. Su intento de ayudar a un moribundo la lleva a pasar la noche en una cabaña solitaria en compañía del miembro más denostado de los Cynster, a quien llaman Diablo. Cuando esto sale a la luz, él no tiene otro remedio que pedir su mano. La familia Cynster está encantada de que el famoso libertino finalmente decida casarse, pero lo que menos desea la rebelde joven es un marido que la controle, y enamorarse no está en sus planes.', @Cat_Romntico, N'_Al_diablo_con_el_amor_.__-_Vanessa_Lorrenz.pdf', N'.pdf', 0, 1);
END;

