-- Libro 149: Solo me pierdo en tus ojos
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Solo me pierdo en tus ojos' AND Autor = N'Priscila Serrano')
