-- Libro 153: El corazón delator
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El corazón delator' AND Autor = N'Edgar Allan Poe')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El corazón delator', N'Edgar Allan Poe', N'El corazón delator —en inglés original The Tell-Tale Heart— es un cuento del escritor estadounidense Edgar Allan Poe clasificado en la narrativa gótica, publicado por primera vez en el periódico literario The Pioneer, del amigo de Poe, James Russell Lowell, en enero de 1843.​ Poe lo republicó más tarde en su periódico el Broadway Journal en la edición del 23 de agosto de 1845.​ Ha sido adaptado o servido de inspiración en numerosas ocasiones y en distintos medios.
La historia presenta a un narrador anónimo obsesionado con el ojo enfermo (que llama "ojo de buitre") de un anciano con el cual convive. Finalmente decide asesinarlo. El crimen es planeado cuidadosamente y, tras ser perpetrado, el cadáver es despedazado y escondido bajo las tablas del suelo de la casa. La policía acude a la misma y el asesino acaba delatándose a sí mismo, imaginando alucinadamente que el corazón del viejo se ha puesto a latir bajo la tarima.
No se sabe cuál es la relación entre víctima y asesino. Se ha sugerido que el anciano representa en el cuento a la figura paterna, y que su "ojo de buitre" puede sugerir algún secreto inconfesable. La ambigüedad y la falta de detalles acerca de los dos personajes principales están en agudo contraste con el detallismo con que se recrea el crimen.', @Cat_Terrorficcingtica, N'1_5006304388063428859.pdf', N'.pdf', 0, 1);
END;

