-- Libro 162: No soy yo, eres tú
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'No soy yo, eres tú' AND Autor = N'Ebony Clark')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'No soy yo, eres tú', N'Ebony Clark', N'Una historia sobre corazones rotos, citas a ciegas y... ¡gatos y ratones! La segunda entrega de la bilogía «Tal para cual». ¡No te la pierdas! Daniela es abogada. Trabaja en un despacho especializado en divorcios. Después de la ruptura de sus padres, del que su madre la culpa, y enamorada de Lucas, compañero de trabajo y hombre perfecto, inaccesible y casado, Daniela decide pedir una excedencia en el trabajo y tomarse un respiro. Su compañera de piso, Mimi, tiene un proyecto. Mimi es pura energía positiva, el yan de Daniela, un terremoto andante llena de ideas e iniciativas. Mimi cree en el amor y se mueve como pez en el agua en las redes sociales. Con estos dos ingredientes ha puesto en marcha una aplicación de citas a ciegas, TalparaCual, que está resultando un éxito. Daniela siente mucha curiosidad. Le intrigan los motivos de la gente para iniciar lo que ella termina rompiendo en su profesión. ¿Qué hace que todas esas personas se empeñen en aventurarse en algo abocado al fracaso? ¿Existe el flechazo, existe realmente el amor? Alex es bombero. Su trabajo es su pasión. Sobre todo, ahora que Silvia, su novia de toda la vida, le ha dejado por un representante de perfumes y pretende quedarse con el piso de ambos. Alex se muda a un edificio de apartamentos cerca de la playa. A Alex le gusta entrenar cada mañana en su terraza, escuchando su música favorita. Solo hay un inconveniente, su vecina de enfrente. Una bruja con mala leche a la que no le gusta madrugar. Si el amor no existe. Si es una gran mentira. Si duele y saca de cada uno lo peor... ¿Cómo es que seguimos tentando la suerte?', @Cat_Fiction, N'2 No soy yo, eres tu - Ebony Clark.pdf', N'.pdf', 0, 1);
END;

