-- Libro 194: Ana de las Tejas Verdes
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Ana de las Tejas Verdes' AND Autor = N'Lucy Maud Montgomery')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Ana de las Tejas Verdes', N'Lucy Maud Montgomery', N'Ana la de Tejas Verdes, Anne la de Tejados Verdes o en inglés Anne of Green Gables es un libro escrito por la canadiense Lucy Maud Montgomery y publicado por primera vez en 1908. En principio se escribió para todas las edades, pero en décadas posteriores se lo consideró un libro para niños. La obra narra la vida de Anne Shirley, una niña huérfana que gracias a su carácter imaginativo y despierto logra encandilar a todos los habitantes de Avonlea, un pequeño pueblo ficticio ubicado en la Isla del Príncipe Eduardo, lugar donde se desarrolla la historia a finales del siglo XIX.
Supuestamente, Montgomery se inspiró en un artículo periodístico sobre el caso de una pareja canadiense que solicitó la adopción de un niño huérfano pero acabaron recibiendo a una niña en su lugar. En lo referido a la Casa de las Tejas Verdes, la escritora quiso homenajear la casa de Green Gables donde vivían sus primos, situada en la Isla del Príncipe Eduardo.​', @Cat_Noveladedesarrolloficcinparanios, N'1.-ana_de_las_tejas_verdes.pdf', N'.pdf', 0, 1);
END;

