-- Libro 250: Dungeon ni Deai wo Motomeru no wa Machig
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Dungeon ni Deai wo Motomeru no wa Machigatteiru Darou ka' AND Autor = N'carlos')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Dungeon ni Deai wo Motomeru no wa Machigatteiru Darou ka', N'carlos', N'Dungeon ni Deai o Motomeru no wa Machigatteiru Darō ka (ダンジョンに出会いを求めるのは間違っているだろうか, lit. ¿Está mal querer tener un encuentro en una mazmorra??), también conocido como ¿Está mal seducir chicas en un calabozo? o  ¿Qué tiene de malo intentar ligar en una mazmorra? y varias veces abreviado como DanMachi (ダンまち, ''''DanMachi''''?), es una serie de novelas ligeras escritas por Fujino Ōmori e ilustradas por Suzuhito Yasuda. SB Creative ha publicado veintiuno volúmenes desde enero de 2013 bajo el sello de GA Bunko. Ha recibido una serie de spin-offs de la novela ligera y tres adaptaciones al manga. Una adaptación al anime, a cargo del estudio J.C.Staff, salió al aire desde el 4 de abril hasta el 27 de junio de 2015.
Ha sido la novela ligera más votada por los fanes en los premios Sugoi Japan Awards de la edición de 2016. En estos premios, los fanáticos deciden qué anime, manga, novela es la más indicada para ser comercializada en el mercado internacional.​', @Cat_Comediafantsticaficcindeaventurascuentoamoroso, N'[K-VT] Dungeon Vol. 03.pdf', N'.pdf', 0, 1);
END;

-- Libro 251: Cathedral
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Cathedral' AND Autor = N'Windows User')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Cathedral', N'Windows User', N'Una catedral, también llamada seo, es un templo cristiano en donde tiene su sede o cátedra el obispo de la diócesis; por tanto, es la iglesia principal o mayor de cada diócesis o iglesia particular. La sede o cátedra episcopal es el lugar desde donde cada obispo preside la comunidad cristiana, enseñando el contenido de la fe y la doctrina de la Iglesia. También administra determinados sacramentos y órdenes. La sede o cátedra simboliza la función de gobierno del obispo.
La Iglesia cristiana ortodoxa se refiere a sus catedrales como gran iglesia, aunque suele traducirse como catedral.
Los edificios eclesiásticos que encarnan las funciones de una catedral aparecieron por primera vez en Italia, Galia, España y el norte de África en el siglo IV, pero las catedrales no se universalizaron dentro de la Iglesia católica occidental hasta el siglo XII, momento en el que ya habían desarrollado formas arquitectónicas, estructuras institucionales e identidades jurídicas distintas de las iglesias parroquiales, las iglesias monásticas y las residencias episcopales. La catedral es más importante en la jerarquía que la iglesia porque es desde la catedral que el obispo gobierna el área bajo su autoridad administrativa.​​​
Tras la Reforma Protestante, la Iglesia cristiana de varias partes de Europa occidental, como la Escocia, la Países Bajos, algunos Cantones suizos y partes de Alemania, adoptaron un sistema de gobierno presbiteriano que suprimía totalmente a los obispos. En los casos en los que los antiguos edificios catedralicios de estas tierras siguen utilizándose para el culto congregacional, generalmente conservan el título y la dignidad de "catedral", manteniendo y desarrollando funciones catedralicias diferenciadas, pero sin supremacía jerárquica. A partir del siglo XVI, pero especialmente desde el siglo XIX, las iglesias originarias de Europa Occidental han emprendido vigorosos programas de actividad misionera, que han dado lugar a la fundación de un gran número de nuevas diócesis con establecimientos catedralicios asociados de diversas formas en Asia, África, Australasia, Oceanía y América. Además, tanto la Iglesia católica como la Ortodoxa han formado nuevas diócesis en tierras anteriormente protestantes para los conversos y correligionarios emigrantes. En consecuencia, no es raro encontrar cristianos en una misma ciudad atendidos por tres o más catedrales de distintas denominaciones.', @Cat_Noespecificado, N'1 Cathedral.pdf', N'.pdf', 0, 0);
END;

-- Libro 252: Ella es tu destino
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Ella es tu destino' AND Autor = N'Megan Maxwell')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Ella es tu destino', N'Megan Maxwell', N'Lidia es una caza-recompensas que, junto a su inseparable dragón Dracela y su fiel amigo Gaúl, ha hecho de su vida una aventura. Esta forma de vida le permite seguir con su particular misión que no es otra que encontrar a Dimas Deceus y vengar la muerte de su familia. Su último encargo: capturar al ladrón Bruno Mezzia, fugado hace pocos días. Tras capturar a Bruno (apuesto y fuerte) y mientras lo trasladan para su entrega, encuentran en su camino a Penélope Barmey en busca de ayuda para rescatar a su marido y, a cambio de su apoyo, les ofrece una llave élfica, pieza clave para vencer los peligros que les esperan en su camino y que facilitará que Lidia llegue hasta Dimas Deceus y culmine su venganza. Estos acontecimientos les obligarán a posponer la entrega de Bruno. El camino que recorrerán hará que poco a poco Lidia se fije en Bruno y éste en ella, a pesar de que la guerrera intente esconder sus sentimientos mostrándose fría y ruda. Mientras Gaúl se dará cuenta de que el hermano del terrateniente que les ha hecho el encargo no ha dicho toda la verdad. Bruno no es un ladrón. Una aventura que te llevará por tierras fantásticas de la mano de unos personajes que te llegarán al corazón.', @Cat_Fiction, N'4. Ella es tu destino - Megan Maxwell.pdf', N'.pdf', 0, 1);
END;

-- Libro 253: Socorro!
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Socorro!' AND Autor = N'Jacinta')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Socorro!', N'Jacinta', N'Send Help es una película estadounidense de suspenso y terror de supervivencia de 2026​ coproducida y dirigida por Sam Raimi y escrita por Damian Shannon y Mark Swift. La película está protagonizada por Rachel McAdams y Dylan O''Brien, quienes interpretan a una empleada y su jefe, respectivamente, quienes quedan varados en una isla desierta tras un accidente aéreo e intentan sobrevivir mientras la tensión aumenta entre ellos. Edyll Ismail, Xavier Samuel, Chris Pang y Dennis Haysbert también aparecen.
Send Help se estrenó en el Teatro Chino TCL en Los Ángeles, California, el 21 de enero de 2026, y fue estrenada en Estados Unidos por 20th Century Studios el 30 de enero. La película recibió críticas positivas de los críticos y recaudó $94,0 millones contra un presupuesto de producción de $40 millones.​​', @Cat_Cinedeterrorcinedesupervivencia, N'¡Socorro!.pdf', N'.pdf', 0, 1);
END;

