-- Libro 258: Los renglones torcidos de Dios
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Los renglones torcidos de Dios' AND Autor = N'Torcuato Luca de Tena')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Los renglones torcidos de Dios', N'Torcuato Luca de Tena', N'Los renglones torcidos de Dios es una película mexicana de 1983 dirigida por Tulio Demicheli y basada en el libro homónimo de Torcuato Luca de Tena.
Su estreno se realizó el 29 de septiembre de 1983.
Fue filmada en diferentes lugares del estado mexicano de Morelos.​ Entre otros, en la ciudad de Cuautla, la Hacienda de Atlihuayan en Oaxtepec y en el pueblo de Yautepec de Zaragoza.
La historia se centra en la detective Alicia Gould, interpretada por Lucía Méndez, que siguiendo la pista de asesinato del padre del doctor García del Olmo, su cliente, decide internarse de manera encubierta en un manicomio. Las influencias del cine de Juan López Moctezuma, en especial de La mansión de la locura, y de los filmes anglosajones La naranja mecánica y La mujer pantera son fuertes.
El nombre de la protagonista, Alicia hace referencia a la novela de Lewis Carroll, Alicia en el País de las Maravillas. El título de la película hace referencia a la condición de los pacientes del lugar, en oposición a la supuesta rectitud de la condición mental de Alicia. Esto se hace explícito en una carta que Ignacio le escribe a Alicia donde le dice:', @Cat_Drama, N'.pdf los renglones torcidod.pdf', N'.pdf', 0, 1);
END;

