-- Libro 260: La villa de las telas
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La villa de las telas' AND Autor = N'Anne Jacobs')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La villa de las telas', N'Anne Jacobs', N'La villa de las telas abre de nuevo sus puertas. Llega la esperada cuarta parte de la saga superventas de Anne Jacobs. Una magnífica mansion Una época turbulenta Un amor que puede vencerlo todo... Augsburgo, 1930. Marie y Paul Melzer son felices y su amor es más fuerte que nunca. Su hijo menor, el pequeño Kurti, que ahora tiene cuatro años, es un rayo de sol que se gana el afecto de todo el mundo y los gemelos Dodo y Leo han crecido espléndidamente. Dodo ha descubierto su amor por la técnica y sueña con convertirse en aviadora, mientras que Leo demuestra un gran talento para el piano, que se ha convertido en su gran pasión. Pero la villa no es ajena a la agitada situación política en Alemania y la crisis económica golpea con fuerza el negocio familiar. Los Melzer tienen importantes deudas y Marie deberá enfrentarse a dolorosas decisiones para evitar la ruina. El destino de la familia está en juego. Y su amada villa de las telas solo podrá salvarse si todos permanecen unidos. Sobre los libros de la saga han dicho: «Amor imposible y las rígidas normas sociales de la Europa central a principios del siglo XX serán el escenario en el que se desenvuelva esta entretenida historia llena de secretos». Jorge Pato García, El Imparcial «Es una gran historia de amor, con tintes dramáticos y secretos familiares, que nos ha gustado tanto por su calidad literaria como por su preciosismo histórico». Revista Kritica «Downton Abbey en Augsburgo». Histo-couch «Este libro lo tiene todo, todo que podríamos desear para un día de lluvia: una gran historia de amor, intriga [...] y un gran secreto familiar». Delmenhorster Kreisblatt «Con su escritura fluida, Anne Jacobs sabe cómo seducir a sus lectoras y transportarlas a la vida de la alta sociedad de hace cien años con todo su glamour pero también con sus sombras». Weilheimer Tagblatt Los lectores opinan: «A todos los que os gustan las sagas familiares estos libros os van a encantar. De esos libros que tiene un ritmo muy bueno en todo momento, no decae para nada y hace su lectura muy agradable». Blog Leyendo entre páginas «Una historia de familias, de amor, de superación personal y de valentía. Pero de una valentía que no sabes que tienes hasta que la necesitas». Blog Viajando gracias a los libros «Si echáis de menos Downton Abbey (yo la echo de menos casi a diario) esta saga llenará ese hueco por completo». labibliotecadelaabuela en Instagram « Regreso a la Villa de las telas ha sido la vuelta a uno de mis lugares favoritos de la literatura». Patricia Llamas para Sigue en serie', @Cat_Sagafamiliarficcinhistrica, N'^ La villa de las telas - Anne Jacobs(1).pdf', N'.pdf', 0, 1);
END;

-- Libro 261: ro. El Nuevo Orden Mundial
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'ro. El Nuevo Orden Mundial' AND Autor = N'Desconocido')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'ro. El Nuevo Orden Mundial', N'Desconocido', N'La reconfiguración del mundo tras las guerras en Ucrania y Medio Oriente En dos años, el mundo ha cambiado de un modo que tardaremos décadas en entender. La invasión rusa a Ucrania y las matanzas en Gaza han provocado una serie de transformaciones a escala planetaria con infinidad de repercusiones: ya cambió el peso político y económico de Estados Unidos y China, se renovó el protagonismo de Moscú y su eje de influencia, se desató una carrera armamentista, el populismo se fortaleció y los balances de poder en Latinoamérica se han transfigurado. Incluso el boom de la inteligencia artificial debe leerse en clave de los grandes choques sociopolíticos que hoy vivimos. ¿Qué explica esta revolución? ¿Qué dinámicas estaba transitando el mundo que terminaron en esto? ¿Qué sigue y cómo nos preparamos para ello? En esta obra, contundente y lúcida, el economista Manuel Hinds nos presenta un panorama que trae luz a la complejidad que estamos atravesando, nos detalla los hitos que nos llevaron a esta encrucijada y nos hace ver los grandes riesgos que nos acechan. ENGLISH DESCRIPTION How the wars in Ukraine and the Middle East are reshaping the world. In the last two years, the world has changed in ways it will take us decades to understand. Russia''s invasion of Ukraine and the tragedy in Gaza have wrought a series of transformations on a global scale, with potentially infinite repercussions: shifting political and economic roles for the United States and China, an expanded sphere of influence for Russia, a renewed arms race, a resurgence in populism, and a new balance of power in Latin America. Even the artificial intelligence boom should be read in the context of the world''s current sociopolitical conflicts. How can we explain this revolution? What underlying dynamics were in place that led to this? What comes next, and how should we prepare? Economist Manuel Hinds offers this lucid and illuminating clarification of the complex phenomena affecting the world today, the events that brought us to this point, and the challenges still to come.', @Cat_Novelahistrica, N'1ro. El Nuevo Orden Mundial.pdf', N'.pdf', 0, 0);
END;

-- Libro 262: ¿Es Dios un matemático?
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¿Es Dios un matemático?' AND Autor = N'Mario Livio')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¿Es Dios un matemático?', N'Mario Livio', N'¿Son las matemáticas una creación humana? ¿O lo que aparece a través de ellas es el intrincado diseño del universo, que poco a poco vamos descubriendo? Desde la Antigüedad hasta el presente, científicos y filósofos se han maravillado de que una disciplina tan abstracta pudiera explicar de manera tan perfecta el mundo natural. Mario Livio explora brillantemente las ideas matemáticas desde Pitágoras hasta el siglo xxi y nos muestra cómo las más enigmáticas preguntas y las más ingeniosas respuestas nos han llevado a entender mejor el mundo que nos rodea. Este fascinante libro interesará a cualquier persona que sienta curiosidad por la mente humana y la ciencia. «Los lectores habituales de Mario Livio disfrutarán de este libro, y los recién llegados lo descubrirán», Publishers Weekly. «Una fascinante inmersión en las premisas que fundamentan las matemáticas», Booklist.', @Cat_Mathematics, N'_Es Dios un matematico_ - Mario Livio.pdf', N'.pdf', 0, 1);
END;

-- Libro 263: Atrápame
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Atrápame' AND Autor = N'Anna Zaires')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Atrápame', N'Anna Zaires', N'—Yulia —susurra mirándome y sé que siente también esta atracción, esta conexión tan visceral entre nosotros. Quizás tenga todo el poder, pero, en este momento, es tan vulnerable como yo, atrapado en la misma locura. Obligada a unirse a una agencia secreta de inteligencia a una edad muy temprana, la espía e intérprete rusa Yulia Tzakova no es ajena a los hombres peligrosos. Pero nunca ha conocido a uno tan despiadado y cautivador como Lucas Kent. El mercenario de carácter impetuoso la asusta, pero se siente atraída por él, por un hombre al que no tiene más remedio que traicionar. Lucas Kent es la mano derecha de un poderoso traficante de armas y nunca ha conocido a una mujer a la que desee tanto como a Yulia. Está obsesionado con esa preciosa rubia, por lo que no se detendrá ante nada para atraparla y hacerle pagar su traición. Desde las calles gélidas de Moscú hasta la jungla húmeda de Colombia, esta oscura pasión cautivadora los destruirá o los hará libres. ***** «Una montaña rusa perfecta y oscura de acción sobrecogedora y romance abrasador» —Skye Warren, autora superventas del New York Times. «Candente, cautivadora y trepidante» —Josie Litton, autora superventas del New York Times. ***** Más de 60 reseñas de 5 estrellas entre todos los libros. Esto es lo que dicen los lectores: · «Intensa, oscura, erótica, magnética, cautivadora, enigmática, apasionante y muy intrigante». · «…página tras página de anhelo y necesidad, de peligro, de más anhelo, de más peligro. Luego, culminación erótica, más necesidad. Después, dicha romántica y, de nuevo (¡aaahhh!), ¡MÁS PELIGRO! He disfrutado cada minuto leyéndola». · «La intensidad entre Yulia y Lucas era electrizante y trágica de la mejor manera posible». · «Anna Zaires ha creado una nueva obra de arte. Nunca me canso de leer sus relatos. Lucas es otro de sus héroes oscuros, me ha atrapado el corazón desde el principio y esta trilogía siempre será una de las mejores historias románticas y tenebrosas que he leído». · «…el tipo de colecciones que siempre tendrá un hueco en mi corazón». Este práctico paquete rebajado contiene los tres libros de la serie Atrápame: Atrápame, Átame y Tómame.', @Cat_Romanceoscurosuspense, N'1 Atrapame - Anna Zaires.pdf', N'.pdf', 0, 1);
END;

-- Libro 264: Besos prohibidos
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Besos prohibidos' AND Autor = N'Kathia Iblis')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Besos prohibidos', N'Kathia Iblis', N'Llega la sexta entrega de la serie «El corazón de un libertino» de Kathia Iblis. Su destino no era conocerse, menos aún amarse... La señorita Periwinkle Talbot tiene una sola misión en esta nueva temporada: lograr atrapar un partido adecuado que la ayude a mantener a sus hermanas y su hogar ancestral a salvo de su malvada abuela. Cuando misteriosos aliados intervienen para ayudarla a lograr su cometido lo último que espera es terminar conociendo al único hombre capaz de hacer tambalear su decisión de un matrimonio sin amor. ¿Podra ella dejarlo ir y olvidarlo para siempre? Aidan Ó Faoláin, criado en la calle, un sobreviviente, un hombre sin rango, de repente se encuentra a cargo de una misión que jamás creyó aceptar: asistir a una dama en su mayor momento de necesidad. Pero cuando sus consejos y estratagemas comiencen a tener el éxito deseado, ¿podrá dejarla ir a los brazos de otro hombre? ¿Podrán sus besos dejar de ser prohibidos?', @Cat_Fiction, N'6 Besos prohibidos - Kathia Iblis.pdf', N'.pdf', 0, 1);
END;

-- Libro 265: Leyes de Atracción
