-- Libro 267: La villa de las telas
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La villa de las telas' AND Autor = N'Anne Jacobs')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La villa de las telas', N'Anne Jacobs', N'La villa de las telas abre de nuevo sus puertas. Llega la esperada cuarta parte de la saga superventas de Anne Jacobs. Una magnífica mansion Una época turbulenta Un amor que puede vencerlo todo... Augsburgo, 1930. Marie y Paul Melzer son felices y su amor es más fuerte que nunca. Su hijo menor, el pequeño Kurti, que ahora tiene cuatro años, es un rayo de sol que se gana el afecto de todo el mundo y los gemelos Dodo y Leo han crecido espléndidamente. Dodo ha descubierto su amor por la técnica y sueña con convertirse en aviadora, mientras que Leo demuestra un gran talento para el piano, que se ha convertido en su gran pasión. Pero la villa no es ajena a la agitada situación política en Alemania y la crisis económica golpea con fuerza el negocio familiar. Los Melzer tienen importantes deudas y Marie deberá enfrentarse a dolorosas decisiones para evitar la ruina. El destino de la familia está en juego. Y su amada villa de las telas solo podrá salvarse si todos permanecen unidos. Sobre los libros de la saga han dicho: «Amor imposible y las rígidas normas sociales de la Europa central a principios del siglo XX serán el escenario en el que se desenvuelva esta entretenida historia llena de secretos». Jorge Pato García, El Imparcial «Es una gran historia de amor, con tintes dramáticos y secretos familiares, que nos ha gustado tanto por su calidad literaria como por su preciosismo histórico». Revista Kritica «Downton Abbey en Augsburgo». Histo-couch «Este libro lo tiene todo, todo que podríamos desear para un día de lluvia: una gran historia de amor, intriga [...] y un gran secreto familiar». Delmenhorster Kreisblatt «Con su escritura fluida, Anne Jacobs sabe cómo seducir a sus lectoras y transportarlas a la vida de la alta sociedad de hace cien años con todo su glamour pero también con sus sombras». Weilheimer Tagblatt Los lectores opinan: «A todos los que os gustan las sagas familiares estos libros os van a encantar. De esos libros que tiene un ritmo muy bueno en todo momento, no decae para nada y hace su lectura muy agradable». Blog Leyendo entre páginas «Una historia de familias, de amor, de superación personal y de valentía. Pero de una valentía que no sabes que tienes hasta que la necesitas». Blog Viajando gracias a los libros «Si echáis de menos Downton Abbey (yo la echo de menos casi a diario) esta saga llenará ese hueco por completo». labibliotecadelaabuela en Instagram « Regreso a la Villa de las telas ha sido la vuelta a uno de mis lugares favoritos de la literatura». Patricia Llamas para Sigue en serie', @Cat_Sagafamiliarficcinhistrica, N'^ Las hijas d la Villa de las Telas - Anne Jacobs.pdf', N'.pdf', 0, 1);
END;

