-- Libro 270: ¿Amar o depender?
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¿Amar o depender?' AND Autor = N'Walter Riso')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¿Amar o depender?', N'Walter Riso', N'“Aunque la psicología ha avanzado en el tema de las adicciones, en el tema de la adicción afectiva el vacío es innegable Este libro está dirigido a todas aquellas personas que quieren hacer del amor una experiencia plena, alegre y saludable”. —Walter Riso Entregarse afectivamente no implica desaparecer sino integrarse en el otro. El amor sano es una suma de dos en la que nadie pierde. Sin embargo, millones de personas en todo el mundo son víctimas de relaciones amorosas inadecuadas y no saben qué hacer al respecto, ya que el miedo a la pérdida, a la soledad o al abandono contamina el vínculo amoroso y lo vuelve altamente vulnerable. Un amor inseguro es una bomba que puede estallar en cualquier momento y lastimarnos profundamente. En ¿Amar o depender?, Walter Riso, uno de los más conocidos autores de autoayuda, nos enseña que sí es posible vivir con independencia y aun así seguir amando, eliminando las ataduras psicológicas y manteniendo vivo el fuego del amor. La adicción afectiva es una enfermedad que tiene cura y, lo más importante, puede prevenirse. Este revelador libro pretende ayudar a aquellas personas que son o han sido víctimas de un amor malsano y guiar a las parejas sanas para que sigan trabajando en la costumbre de amar intensamente y sin apegos.', @Cat_Familyrelationships, N'_Amar o depender_ - Walter Riso (6).pdf-1-1.pdf', N'.pdf', 0, 1);
END;

-- Libro 271: No eres tú, soy yo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'No eres tú, soy yo' AND Autor = N'Daniel De la Peña')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'No eres tú, soy yo', N'Daniel De la Peña', N'Amor, enredos y unos personajes muy divertidos en esta primera entrega de la bilogía «Tal para cual» de Daniel de la Peña. Y es que los momentos de crisis pueden ser los más creativos, ¡incluso en el amor! Mimi es una joven que cree en el amor cursi, repipi y hortera. Ese que está harta de ver en los cuentos de hadas y que jamás ha tocado ni de lejos. Su realidad es muy distinta; acaba de arruinarse gracias al fracaso de su agencia de adopción de pingüinos, no tiene novio y se ha quedado sin piso. Su mejor amiga, Daniela, una abogada experta en divorcios que no cree en el amor, la acoge en su casa. Una noche cuando asiste a una clase nocturna, conocerá a Héctor, un atractivo profesor por el que sentirá una conexión sexual muy fuerte y se experimentará un apasionado romance. Por si fuera poco, comenzará a sentir algo nuevo e intenso por Marín, su mejor amigo, con el que ha pasado momentos inolvidables compartiendo confesiones, criticando a sus respectivos ex, tomando cervezas... Tendrá que decidir si ignorar sus sentimientos para no peligrar su relación de amistad o atreverse a declarar su amor por Marín. Mientras tanto creará una aplicación para que la gente conozca a su media naranja llamada TalparaCual . Las divertidas quedadas con Carmen, su madre, y Daniela y las bebidas con misterio de las que serán adictas, animarán a la protagonista a que aprenda a escucharse a sí misma para ser feliz. ¿Será Héctor el semental que le hacía falta a la confiada de Mimi? ¿Se atreverá a confesar su amor hacía Marín? ¿Sabrá escucharse a sí misma? ¿Triunfará alguno de sus negocios?', @Cat_Fiction, N'1 No eres tu, soy yo - Daniel De la Pena.pdf', N'.pdf', 0, 1);
END;

