-- Libro 290: Dungeon ni Deai wo Motomeru no wa Machig
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Dungeon ni Deai wo Motomeru no wa Machigatteiru Darou ka' AND Autor = N'carlos')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Dungeon ni Deai wo Motomeru no wa Machigatteiru Darou ka', N'carlos', N'Dungeon ni Deai o Motomeru no wa Machigatteiru Darō ka (ダンジョンに出会いを求めるのは間違っているだろうか, lit. ¿Está mal querer tener un encuentro en una mazmorra??), también conocido como ¿Está mal seducir chicas en un calabozo? o  ¿Qué tiene de malo intentar ligar en una mazmorra? y varias veces abreviado como DanMachi (ダンまち, ''''DanMachi''''?), es una serie de novelas ligeras escritas por Fujino Ōmori e ilustradas por Suzuhito Yasuda. SB Creative ha publicado veintiuno volúmenes desde enero de 2013 bajo el sello de GA Bunko. Ha recibido una serie de spin-offs de la novela ligera y tres adaptaciones al manga. Una adaptación al anime, a cargo del estudio J.C.Staff, salió al aire desde el 4 de abril hasta el 27 de junio de 2015.
Ha sido la novela ligera más votada por los fanes en los premios Sugoi Japan Awards de la edición de 2016. En estos premios, los fanáticos deciden qué anime, manga, novela es la más indicada para ser comercializada en el mercado internacional.​', @Cat_Comediafantsticaficcindeaventurascuentoamoroso, N'[K-VT] Dungeon Vol. 09.pdf', N'.pdf', 0, 1);
END;

