-- Libro 361: Lirio rojo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Lirio rojo' AND Autor = N'Nora Roberts')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Lirio rojo', N'Nora Roberts', N'La última entrega de la «Trilogía del jardín». Un empleo y empezar de cero era lo único que deseaba Hayley Phillips para ella y la hija que estaba esperando cuando llamó a la puerta de la mansión Harper. Lo que también encontró fue un hogar, la sólida amistad de Roz y Stella, y la posibilidad de un nuevo amor. Solo el misterio que rodea la mansión Harper se interponen ahora entre ella y su felicidad. TRILOGÍA DEL JARDÍN Tres mujeres se conocen en un momento crucial de sus vidas: cuando es necesario dejar atrás el pasado, pero el futuro todavía parece incierto. Para Stella, Rosalind y Hayley, la mansión Harper -una vieja casa sureña en las afueras de Memphis- se convierte en un puerto seguro y un auténtico hogar. El pequeño y próspero negocio de un vivero de flores y plantas, en el que todas han depositado sus esperanzas, se erige en el símbolo de su independencia. Juntas encontrarán el valor para rehacer sus vidas y aceptar el amor cuando aparezca... aunque un misterio anclado en la centenaria casa solariega puede ponerlas a ellas y a quienes más aman en peligro. Reseña: «La excelente Roberts lleva la conclusión de su "Trilogía del jardín" hacia un misterioso y seductor final con esta novela mágica que celebra el poder del amor.» Booklist', @Cat_Fiction, N'(Trilogía del jardín 03) Lirio rojo - Nora Roberts.pdf', N'.pdf', 0, 1);
END;

-- Libro 362: Deseo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Deseo' AND Autor = N'Adrian Blake')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Deseo', N'Adrian Blake', N'Deseo es el undécimo álbum de estudio de la cantante mexicana Paulina Rubio. Fue lanzado el 14 de septiembre de 2018​ por Universal Spain, marcando su última producción con el sello discográfico Universal Music Group y el primero a siete años de editar Brava! (2011). Colaboró con una multitud de productores y músicos para el disco, entre ellos Mauricio Rengifo, Andrés Torres, los Julca Brothers, Antonio "Toy Selectah" Hernández, Joey Montana, Morat, Nacho, Juan Magán, Xabier San Martin y Alexis & Fido. Deseo es un álbum pop latino con una fuerte vibra del género urbano, aunque mantiene el característico estilo pop rock de la cantante en algunas canciones.
Paulina Rubio empezó a trabajar en un disco inédito a finales de 2014, pero por varias situaciones desconocidas Universal retrasó sus proyectos al grado de publicar sencillos independientes a lo largo de los siguientes dos años. Además, se involucró en su faceta como jueza en diferentes shows de televisión incluyendo la versión mexicana de La Voz, La Voz Kids, la versión estadounidense de The X Factor y La Apuesta.
Inicialmente se lanzaron dos sencillos del álbum: «Desire (Me Tienes Loquita)», una colaboración con Nacho, estrenada el 28 de mayo de 2018, y «Suave y Sutil», lanzada cuatro meses más tarde. El 15 de abril de 2019 se lanzó una edición especial de Deseo que incluía cuatro canciones inéditas, incluyendo el sencillo «Ya No Me Engañas», estrenado solo unos días antes del lanzamiento de la reedición.​ El disco también contiene los sencillos independientes  —lanzados entre 2015 y 2016— «Mi Nuevo Vicio», «Si Te Vas» y «Me Quema».
Tras su lanzamiento, Deseo recibió críticas mixtas por parte de los críticos de música, quienes elogiaron la «energía» de la cantante y su capacidad de adaptarse a los nuevos géneros musicales, pero sintieron que el flujo de las canciones en el disco no tenía ningún sentido ya que la mitad de los temas ya habían sido publicados, por lo que sostuvieron que se trataba más de una «compilación» poco sorprendente. Comercialmente, Deseo tuvo poco impacto en las listas musicales, alcanzando la posición número trece de la lista de Billboard Latin Pop Albums. Pese a ello, obtuvo una certificación de disco de oro en Chile,​ y se embarcó en una gira de conciertos en los Estados Unidos.', @Cat_Romanceertico, N'Deseo - Adrian Blake.pdf', N'.pdf', 0, 1);
END;

-- Libro 363: Enola Holmes
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Enola Holmes' AND Autor = N'El caso del crinolina críptica')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Enola Holmes', N'El caso del crinolina críptica', N'Enola Holmes es una película de misterio, romance, aventura y acción de 2020 protagonizada por Millie Bobby Brown como el personaje principal, la hermana adolescente del ya famoso detective de la época victoriana Sherlock Holmes. La película está dirigida por Hary Bradbeer a partir de un guion de Jack Thorne que adapta la primera novela de la serie Las aventuras de Enola Holmes de Nancy Springer. En la película, Enola viaja a Londres para encontrar a su madre desaparecida, pero termina en una emocionante aventura, formando pareja con un lord fugitivo mientras intentan resolver un misterio que amenaza a todo el país. Además de Brown, la película también está protagonizada por Sam Claflin, Henry Cavill y Helena Bonham Carter.
El rodaje comenzó en julio de 2019. Originalmente planeada para un estreno en cines por Warner Bros. Pictures, los derechos de distribución de la película fueron adquiridos por Netflix debido a la pandemia de COVID-19. Enola Holmes se estrenó el 23 de septiembre de 2020. La película recibió críticas positivas de los críticos, quienes elogiaron la actuación de Brown. Se convirtió en uno de los estrenos de películas originales de Netflix más vistos, con un estimado de 76 millones de hogares viendo la película durante sus primeras cuatro semanas. Una secuela, Enola Holmes 2, se estrenó en Netflix el 4 de noviembre de 2022.', @Cat_Cinedemisterio, N'5. Enola Holmes - El caso del crinolina críptica .pdf', N'.pdf', 0, 1);
END;

