    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La herencia', N'Kathryn Taylor', N'La herencia, un legado de amor o simplemente La herencia, es una telenovela mexicana producida por Juan Osorio y Roy Nelson Rojas para TelevisaUnivision en el 2022.​​ Es la segunda adaptación de la telenovela chilena Hijos Del Monte de Víctor Carrasco, la cual, está basada en la última adaptación que se realizó en el 2011 bajo el título de Los herederos Del Monte, escrita por Roberto Stopello y Cristina Policastro.​​ Se estrenó a través de Las Estrellas el 28 de marzo de 2022 en sustitución de El último rey y finalizó el 15 de julio del mismo año siendo reemplazado por Vencer la ausencia.​​
Está protagonizada por Michelle Renaud, Matías Novoa, Emmanuel Palomares, Juan Pablo Gil y Mauricio Henao, junto con Daniel Elbittar, Elizabeth Álvarez, Tiaré Scanda, Paulina Matos y Sergio Basáñez en los roles antagónicos.​​', @Cat_Telenovela, N'01 ʕ·ᴥ·ʔ La herencia ✿.pdf', N'.pdf', 0, 1);
