-- Libro 368: ¿Amar o depender?
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¿Amar o depender?' AND Autor = N'Walter Riso')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¿Amar o depender?', N'Walter Riso', N'“Aunque la psicología ha avanzado en el tema de las adicciones, en el tema de la adicción afectiva el vacío es innegable Este libro está dirigido a todas aquellas personas que quieren hacer del amor una experiencia plena, alegre y saludable”. —Walter Riso Entregarse afectivamente no implica desaparecer sino integrarse en el otro. El amor sano es una suma de dos en la que nadie pierde. Sin embargo, millones de personas en todo el mundo son víctimas de relaciones amorosas inadecuadas y no saben qué hacer al respecto, ya que el miedo a la pérdida, a la soledad o al abandono contamina el vínculo amoroso y lo vuelve altamente vulnerable. Un amor inseguro es una bomba que puede estallar en cualquier momento y lastimarnos profundamente. En ¿Amar o depender?, Walter Riso, uno de los más conocidos autores de autoayuda, nos enseña que sí es posible vivir con independencia y aun así seguir amando, eliminando las ataduras psicológicas y manteniendo vivo el fuego del amor. La adicción afectiva es una enfermedad que tiene cura y, lo más importante, puede prevenirse. Este revelador libro pretende ayudar a aquellas personas que son o han sido víctimas de un amor malsano y guiar a las parejas sanas para que sigan trabajando en la costumbre de amar intensamente y sin apegos.', @Cat_Familyrelationships, N'¿Amar o depender - Walter Riso.pdf', N'.pdf', 0, 1);
END;

