-- Libro 379: Teme
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Teme' AND Autor = N'Lisa McMann')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Teme', N'Lisa McMann', N'Para Janie y Cabel la vida real se está poniendo mucho más difícil que los sueños. Ambos están tratando conseguir un poco de tiempo para poder estar juntos (en secreto) pero no están teniendo suerte. Y, por si fuera poco, algo extraño está pasando en el instituto Fieldridge, aunque nadie se atreve a hablar sobre ello. Cuando Janie entra en las violentas pesadillas de una compañera de clase, todo empieza a tener sentido, pero nada sale como lo habían planeado. Ni mucho menos. Janie siente que las cosas no van bien en su cabeza y el escandaloso comportamiento de Cabe tiene grave consecuencias para ambos. Y lo que es peor aún, Janie ha descubierto toda la verdad sobre sí misma y su especial habilidad. Y es una verdad desoladora y brutal, que no solo sella su destino como Cazadora de Sueños sino que hace que lo que está por venir sea más oscuro de lo que jamás se hubiera podido imaginar. ¿Crees que estás solo en tus sueños? No es cierto, no si yo estoy cerca. No es tu voluntad ni la mía sino una especie de maldición de la que no puedo escapar. Nadie puede ayudarme. Al menos eso pensaba hasta que Cabel llegó a mi vida. No estoy segura de quién es, no sé si puedo confiar en él, pero para mi corazón es demasiado tarde.Para Janie y Cabel la vida real se está poniendo mucho más difícil que los sueños. Ambos están tratando conseguir un poco de tiempo para poder estar juntos (en secreto) pero no están teniendo suerte. Y, por si fuera poco, algo extraño está pasando en el instituto Fieldridge, aunque nadie se atreve a hablar sobre ello. Cuando Janie entra en las violentas pesadillas de una compañera de clase, todo empieza a tener sentido, pero nada sale como lo habían planeado. Ni mucho menos. Janie siente que las cosas no van bien en su cabeza y el escandaloso comportamiento de Cabe tiene grave consecuencias para ambos. Y lo que es peor aún, Janie ha descubierto toda la verdad sobre sí misma y su especial habilidad. Y es una verdad desoladora y brutal, que no solo sella su destino como Cazadora de Sueños sino que hace que lo que está por venir sea más oscuro de lo que jamás se hubiera podido imaginar. ¿Crees que estás solo en tus sueños? No es cierto, no si yo estoy cerca. No es tu voluntad ni la mía sino una especie de maldición de la que no puedo escapar. Nadie puede ayudarme. Al menos eso pensaba hasta que Cabel llegó a mi vida. No estoy segura de quién es, no sé si puedo confiar en él, pero para mi corazón es demasiado tarde.', @Cat_NovelaJuvenilFantstico, N'2. Teme - Lisa McMann.pdf', N'.pdf', 0, 1);
END;

