-- Libro 421: arte de hacer preguntas X
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'arte de hacer preguntas X' AND Autor = N'Desconocido')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'arte de hacer preguntas X', N'Desconocido', N'Quien desee mejorar sus negociaciones, dirigir equipos de trabajo, dominar entrevistas y ser exitoso en su profesión... debe leer este libro. Si quieres ser persuasivo para ganar negocios, cerrar grandes acuerdos, triunfar en tus entrevistas y en tu vida personal, este libro sin duda te ayudará a triunfar en ello. Aprende a utilizar técnicas de preguntas que te ayudarán a descubrir el pensamiento oculto en la mente de las demás personas. En El arte de hacer preguntas descubrirás el secreto de hacer preguntas de alto nivel para descubrir información clave y ganar la batalla. Los buenos entrevistadores, reporteros, políticos, líderes y negociadores de alto calibre, usan información de la contraparte para convencer y cerrar los grandes acuerdos. El principio subyacente de mis técnicas de preguntas es que todas las personas tienen en su mente una visión de lo que quieren obtener en una entrevista y eso lo podrás aprender en este libro. Ya que si la descubres podrás usarla como poder de persuasión para lograr tu objetivo. Los grandes líderes dirigen aplicando preguntas de alto impacto. Utilizan lo que saben articulándolo con preguntas inteligentes. El gran negociador, el político eficaz o el entrevistador profesional nunca muestran sus cartas, sino que a través de preguntas persuasivas acometen y logran su objetivo con la información que disponen de la contraparte.', @Cat_Emprendimiento, N'_arte de hacer preguntas X-1-1.pdf', N'.pdf', 0, 0);
END;

-- Libro 422: A de
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'A de' AND Autor = N'adulterio')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'A de', N'adulterio', N'A de adulterio es el estreno de la escritora Sue Grafton en la serie de novelas de misterio protagonizada por Kinsey Millhone Alfabeto del crimen, publicada por primera vez en 1982. El libro se sitúa en la ciudad ficticia de Santa Teresa, inspirada en Santa Bárbara, al sur de California, en Estados Unidos. Grafton admite haber concebido la historia tras "fantasear" con asesinar a su exesposo mientras vivían el proceso de divorcio. La idea de asesinar sustituyendo el contenido de una caja de antihistamínicos por adelfa machacada significaba que una coartada carecía de valor, ya que el contenido de la tableta podría haber sido cambiado mucho antes de que la víctima llegara a ingerirlas.
La primera edición de A de adulterio fue de 7.500 copias, con un total de ventas de aproximadamente 6.000.​
​
​', @Cat_Misterio, N'1A_de_adulterio.pdf', N'.pdf', 0, 1);
END;

