-- Libro 436: Como Hacer que las Cosas Pasen
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Como Hacer que las Cosas Pasen' AND Autor = N'Desconocido')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Como Hacer que las Cosas Pasen', N'Desconocido', N'"Cómo hacer que las cosas pasen, en lugar de vivir hablando de lo que pasa. Personal Coaching personal para vencer el miedo y realizar los sueños Si deseas que empiece a pasar algo diferente en tu vida, este libro es para ti. No importa a qué te dediques o cuál sea tu edad y formación. Para hacer que las cosas pasen debes entrenarte a fin de ser más grande que tus desafíos y así poder: -Tratar con personas difíciles -Decir de manera constructiva cosas a priori incómodas -Crecer profesionalmente aunque no reconozcan tu valía -Superar el autoboicot y la postergación -Convertir imprevistos enoportunidades -Rehacer tu vida y construir un futuro que te apasione -Cambiar más rápido y con menos estrés -Inspirarte para dar la mejor versión de ti mismo En calidad de conferenciante, Guillermo Echevarría ha sido invitado por instituciones como las universidades de Buenos Aires, Argentina de la Empresa (UADE),San Andrés, del Centro de Estudios Macroeconómicos de Argentina (CEMA) o de Ciencias Empresariales y Sociales (UCES), así como por el Instituto de Altos Estudios Empresariales (IAE). Como responsable de áreas de capacitación y desarrollo, coordinó programas de Calidad Total y Mejora Continua de la Calidad. Asimismo, entrena directivos en habilidades de liderazgo, negociación, oratoria, supervisión y estrategia y se ha desempeñado como orador motivacional en varios países de América y de Europa, principalmente España, donde ha formado coaches e impartido seminarios en muchas de sus provincias."', @Cat_Autoayudadesarrollopersonal, N'_Como Hacer que las Cosas Pasen.pdf', N'.pdf', 0, 0);
END;

-- Libro 437: Impulse
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Impulse' AND Autor = N'Deborah Bladon')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Impulse', N'Deborah Bladon', N'IMPULSE should be read after the complete PULSE series, which is available now. From New York Times and USA Today Bestseller author, Deborah Bladon, the continuing story of Nathan and Jessica. Nathan Moore had everything any man could ever dream of. He was a successful attorney in Manhattan, he was in love with the woman of his dreams and he could see his future planned out before him. All of that changed when he took a trip into his girlfriend''s past. Jessica Roth has only shared the details of her life that she wanted Nathan to know. She''s been careful and diligent in presenting a past that she believes will help her fit into his future. She doesn''t realize that he''s about to discover the one secret that she''s worked hard to hide for the past six years. He can''t let anything come between them. She won''t let him love her the way he needs to. Will they be able to finally have the happily-ever-after they deserve?', @Cat_Manwomanrelationships, N'05 Impulse - Deborah Bladon.pdf', N'.pdf', 0, 1);
END;

