-- Libro 479: arte de hacer preguntas X
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'arte de hacer preguntas X' AND Autor = N'Desconocido')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'arte de hacer preguntas X', N'Desconocido', N'Quien desee mejorar sus negociaciones, dirigir equipos de trabajo, dominar entrevistas y ser exitoso en su profesión... debe leer este libro. Si quieres ser persuasivo para ganar negocios, cerrar grandes acuerdos, triunfar en tus entrevistas y en tu vida personal, este libro sin duda te ayudará a triunfar en ello. Aprende a utilizar técnicas de preguntas que te ayudarán a descubrir el pensamiento oculto en la mente de las demás personas. En El arte de hacer preguntas descubrirás el secreto de hacer preguntas de alto nivel para descubrir información clave y ganar la batalla. Los buenos entrevistadores, reporteros, políticos, líderes y negociadores de alto calibre, usan información de la contraparte para convencer y cerrar los grandes acuerdos. El principio subyacente de mis técnicas de preguntas es que todas las personas tienen en su mente una visión de lo que quieren obtener en una entrevista y eso lo podrás aprender en este libro. Ya que si la descubres podrás usarla como poder de persuasión para lograr tu objetivo. Los grandes líderes dirigen aplicando preguntas de alto impacto. Utilizan lo que saben articulándolo con preguntas inteligentes. El gran negociador, el político eficaz o el entrevistador profesional nunca muestran sus cartas, sino que a través de preguntas persuasivas acometen y logran su objetivo con la información que disponen de la contraparte.', @Cat_Emprendimiento, N'_arte de hacer preguntas X.pdf', N'.pdf', 0, 0);
END;

