-- Libro 491: ¡Despierta!... que la vida sigue
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¡Despierta!... que la vida sigue' AND Autor = N'César Lozano')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¡Despierta!... que la vida sigue', N'César Lozano', N'En este libro el Dr. César Lozano nos invita a tratar de ser felices y disfrutar de la vida, incluso de los más pequeños detalles Del autor bestseller de Por el placer de vivir, Destellos, El lado fácil de la gente difícil. César Lozano ha motivado a más de 20 millones de personas en el mundo. Reflexiones para disfrutar plenamente la vida. Esta es una obra en la que el Dr. César Lozano nos exhorta a valorar lo que tenemos; es un reconocimiento de que nuestra vida es breve y pasajera pero que, para aquellos que tenemos esperanza, siempre nos lleva al verdadero despertar. ¡Despierta!... que la vida sigue ofrece valiosas fórmulas y técnicas que te sacudirán para que no te quedes enredado en tus problemas y disfrutes de los mejores momentos de tu vida: una sonrisa de tus hijos, la caricia de un ser querido, la alegría de hacer algo por alguien desconocido. Después de leer este libro, tus relaciones tendrán un nuevo sentido y habrás encontrado la verdadera motivación para fijar sentirte feliz.', @Cat_Autoayudareflexin, N'¡Despierta!. que la vida sigue. Reflexiones para disfrutar plenamente de la vida.pdf', N'.pdf', 0, 1);
END;

