-- Libro 493: Neurociencia
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Neurociencia' AND Autor = N'Desconocido')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Neurociencia', N'Desconocido', N'Los educadores, los científicos y los planificadores de la educación están cada vez más convencidos de que el campo de la Educación puede beneficiarse del conocimiento del cerebro. Sin embargo, los intentos de combinar la Neurociencia y la Educación se han visto con frecuencia obstaculizados por diferencias cruciales de conceptos, lenguaje y filosofía. En este libro, Paul Howard-Jones examina estas diferencias, basándose en las opiniones de educadores y científicos, para defender un nuevo campo de investigación: la Investigación Neuroeducativa. Investigación neuroeducativa tiende un puente significativo entre dos perspectivas distintas sobre el aprendizaje. Sostiene que ese puente puede servir a dos objetivos críticamente relacionados entre sí: debe enriquecer tanto la interpretación científica como la educativa. Este reto suscita unas cuestiones conceptuales, metodológicas y éticas excepcionales que caracterizarán, inevitablemente, este nuevo campo, y se examinarán e ilustrarán aquí a través de la investigación empírica. A lo largo del libro, Paul Howard-Jones examina los ''neuromitos'' y su influencia en el pensamiento educativo, destaca las oportunidades de combinar las pruebas biológicas, sociales y experienciales para comprender cómo aprendemos, defiende una ciencia natural de la educación basada en el conocimiento del cerebro, presenta con toda claridad el concepto de un enfoque neuroeducativo interdisciplinar, crea una metodología para desarrollar la investigación neuroeducativa y aprovecha los estudios monográficos de casos y los descubrimientos empíricos para mostrar cómo puede facilitar el enfoque neuroeducativo un cuadro más completo de nuestra forma de aprender. Este libro presenta un programa destinado a introducir nuestros conocimientos del cerebro en la educación, convirtiéndolo en lectura esencial para todas las personas interesadas por el aprendizaje humano en contextos reales: educadores, científicos y planificadores de la educación.', @Cat_Acadmicoeducacin, N'_Neurociencia.pdf', N'.pdf', 0, 0);
END;

