-- Libro 513: Marshmallow
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Marshmallow' AND Autor = N'Serious')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Marshmallow', N'Serious', N'Malvavisco​, nube​ o bombón es una golosina que en su forma moderna consiste en azúcar o jarabe de maíz, clara de huevo batida, gelatina previamente ablandada con agua, goma arábiga y saborizantes, todo ello batido para lograr una consistencia esponjosa. Se puede elaborar en muchas formas. La receta tradicional usaba un extracto de la raíz mucilaginosa de la planta herbácea Althaea officinalis. El mucílago actuaba de antitusivo. Los malvaviscos comerciales son una innovación de finales del siglo XX. Desde el proceso de extrusión patentado por Alex Doumak en 1956,​ los malvaviscos se extruyen como cilindros suaves, se cortan en trozos y se rebozan con una mezcla de maicena y azúcar glas.​

Los malvaviscos son muy populares en el mundo anglosajón y se comen con o sin acompañamiento. En los Estados Unidos, es frecuente comerlos asados o tostados, y en otros lugares acompañados con chocolate o café moca, como parte de otras golosinas, cubriendo boniatos asados, en algunos sabores de helado, etcétera e incluso como ingrediente en numerosas recetas de repostería en forma de crema o fundidos.', @Cat_Noespecificado, N'1. Marshmallow.pdf', N'.pdf', 0, 0);
END;

-- Libro 514: William
