-- Libro 520: ¿Amar o depender?
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¿Amar o depender?' AND Autor = N'Walter Riso')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¿Amar o depender?', N'Walter Riso', N'“Aunque la psicología ha avanzado en el tema de las adicciones, en el tema de la adicción afectiva el vacío es innegable Este libro está dirigido a todas aquellas personas que quieren hacer del amor una experiencia plena, alegre y saludable”. —Walter Riso Entregarse afectivamente no implica desaparecer sino integrarse en el otro. El amor sano es una suma de dos en la que nadie pierde. Sin embargo, millones de personas en todo el mundo son víctimas de relaciones amorosas inadecuadas y no saben qué hacer al respecto, ya que el miedo a la pérdida, a la soledad o al abandono contamina el vínculo amoroso y lo vuelve altamente vulnerable. Un amor inseguro es una bomba que puede estallar en cualquier momento y lastimarnos profundamente. En ¿Amar o depender?, Walter Riso, uno de los más conocidos autores de autoayuda, nos enseña que sí es posible vivir con independencia y aun así seguir amando, eliminando las ataduras psicológicas y manteniendo vivo el fuego del amor. La adicción afectiva es una enfermedad que tiene cura y, lo más importante, puede prevenirse. Este revelador libro pretende ayudar a aquellas personas que son o han sido víctimas de un amor malsano y guiar a las parejas sanas para que sigan trabajando en la costumbre de amar intensamente y sin apegos.', @Cat_Familyrelationships, N'_Amar o depender_ - Walter Riso (6).pdf', N'.pdf', 0, 1);
END;

-- Libro 521: ¿Quién se ha llevado mi queso?
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¿Quién se ha llevado mi queso?' AND Autor = N'Spencer Johnson')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¿Quién se ha llevado mi queso?', N'Spencer Johnson', N'¿Quién se ha llevado mi queso? Una manera sorprendente de afrontar el cambio en el trabajo y en la vida privada (en inglés: Who Moved My Cheese? An Amazing Way to Deal with Change in Your Work and in Your Life), publicado en 1998, es un libro de motivación escrito por el estadounidense Spencer Johnson en el estilo de una parábola y alegoria.
Describe el cambio en el trabajo y la vida, y cuatro típicas reacciones (resistirse al cambio por miedo a algo peor, aprender a adaptarse cuando se comprende que el cambio puede conducir a algo mejor, detectar pronto el cambio y finalmente apresurarse hacia la acción) al citado cambio con dos ratones, dos "liliputienses", y sus búsquedas de queso. Un superventas empresarial de New York Times desde el lanzamiento, ¿Quién se ha llevado mi queso? permaneció en la lista por casi cinco años y pasó en torno a doscientas semanas en la lista de no ficción de pasta dura de Publishers Weekly.​', @Cat_Ficcin, N'_Quién se ha llevado mi queso_- Spencer Johnson.pdf · versión 1.pdf', N'.pdf', 0, 1);
END;

