-- Libro 559: Angel
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Angel' AND Autor = N'Sarah Brianne')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Angel', N'Sarah Brianne', N'Un ángel es un ser sobrenatural presente en varias religiones y mitologías, cuya función principal es servir a una deidad suprema. Sus funciones y especificaciones varían según cada cultura. La rama de la teología que se especializa en  los ángeles se denomina angelología.
Las religiones monoteístas muchas veces representan a los ángeles como seres celestiales benevolentes que actúan como intermediarios entre Dios y la humanidad.
En el catolicismo se habla del ángel de la guarda o del custodio, que sería aquel que Dios tiene señalado a cada persona para protegerla. Por contraposición, también se tiene la figura del ángel caído, aquel que ha sido expulsado del cielo por desobedecer o rebelarse contra Dios. Los ángeles más conocidos en las tradiciones judeocristianas son: San Miguel, San Gabriel y San Rafael.', @Cat_Romancemafia, N'__Donde_los_angeles_no_duermen.pdf-538988541-1.pdf', N'.pdf', 0, 1);
END;

