-- Libro 570: COMO AFRONTAR EL DUELO+
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'COMO AFRONTAR EL DUELO+' AND Autor = N'Desconocido')
