    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'COMO AFRONTAR EL DUELO+', N'Desconocido', N'La guía para líderes de Surviving the Holidays ofrece instrucciones paso a paso sobre cómo organizar un evento festivo. Cada kit de Surviving the Holidays incluye una guía para líderes, pero puede que desees comprar libros adicionales según el tamaño de tu evento y la cantidad de líderes. Este libro incluye una lista de verificación detallada de lo que debes hacer antes de tu evento, una agenda del evento, preguntas de discusión para el tiempo facilitado de compartir en grupos pequeños, un esquema para tomar notas del video y otras herramientas e información para organizar un evento impactante.', @Cat_Religion, N'+COMO AFRONTAR EL DUELO+.pdf', N'.pdf', 0, 0);
