-- Libro 576: Un hombre en la oscuridad
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Un hombre en la oscuridad' AND Autor = N'Paul Auster')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Un hombre en la oscuridad', N'Paul Auster', N'Un hombre en la oscuridad es una novela del escritor estadounidense Paul Auster publicada por primera vez en 2008. Narra una noche de un viejo periodista insomne que yace en la cama. Al principio de la noche el viejo trata de no pensar en su propia vida e imagina una distopía en el marco actual de Estados Unidos, suscitada por una nueva guerra civil y de secesión luego de las elecciones presidenciales de 2000. Los bandos enfrentados en la guerra ficticia están constituidos por los estados que habitualmente votan al Partido Republicano o Partido Demócrata. Finalmente, pareciéndole fútil el intento, cede a sus angustias y arrepentimientos inútiles y pasa revista a su vida y a la de su familia. Al alba comparte sus recuerdos con su nieta que vive en la misma casa.', @Cat_Ficcindistpica, N'1_5006073911528390858.pdf', N'.pdf', 0, 1);
END;

