-- Libro 581: Huye
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Huye' AND Autor = N'Lisa McMann')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Huye', N'Lisa McMann', N'Por primera vez en años, Janie se va de vacaciones. Está pasando unos días en la cabaña del lago que tiene el hermano de Cabe, lejos de su madre alcohólica y del revuelo que ha causado en el pueblo la revelación de que ella trabaja para la policía. Por suerte, ya puede dejar de esconder su relación con Cabe y el año que viene comienza la universidad, lejos del pueblo. Por desgracia sus poderes le evitan llevar una vida normal, y tras un par de incidentes con sueños en los que Cabe no reacciona como ella espera, Janie comienza a tener dudas. Pero todo deja de tener importancia cuando Janie recibe una llamada de Carrie en la que su amiga le informa que ha tenido que llevar a su madre al hospital. Janie y Cabe vuelven corriendo para descubrir que no es la madre de Janie la que está ingresada, si no su padre, al que Janie jamás conoció ya que abandonó a su madre antes de que ella naciera. El padre está en coma, y la única persona que aparece en los papeles médicos que hay en su casa es su madre, que no quiere saber nada del tema. Sospecha que su padre podría ser como ella y tener la habilidad de entrar en los sueños de los demás, así que comienza a investigar su vida y su pasado para intentar descifrar su propio futuro.', @Cat_NovelaJuvenilFantstico, N'3. Huye - Lisa McMann.pdf', N'.pdf', 0, 1);
END;

