-- Libro 594: Aristoteles y Dante descubren los secret
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Aristoteles y Dante descubren los secretos del Universo' AND Autor = N'Benjamin Alires Sáenz')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Aristoteles y Dante descubren los secretos del Universo', N'Benjamin Alires Sáenz', N'Aristóteles y Dante descubren los secretos del universo (en inglés, Aristotle and Dante Discover the Secrets of the Universe) es una novela de literatura juvenil del escritor estadounidense Benjamin Alire Sáenz publicada el 21 de febrero de 2012. La trama está ambientada en 1987 en El Paso y sigue la vida de dos adolescentes mexicanos-estadounidenses: Aristóteles Mendoza y Dante Quintana que, después de conocerse, entablan una amistad y exploran su identidad étnica, su sexualidad y sus relaciones familiares y románticas. 
Desde su publicación consiguió diversas críticas positivas y recibió cuatro premios literarios. Desde 2017 está planificada que sea adaptada al cine. Cuenta con una secuela, Aristóteles y Dante se sumergen en las aguas del mundo, publicada en 2021.', @Cat_Literaturadetemticalgbtnoveladeaprendizajeficcinparajvenes, N'_ Aristoteles y Dante descubren los secretos del universo _-1.pdf', N'.pdf', 0, 1);
END;

