-- Libro 596: ¡Hazlo!
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¡Hazlo!' AND Autor = N'Seth Godin')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¡Hazlo!', N'Seth Godin', N'Este libro es una llamada de atención sobre las iniciativas que estás tomando, en el trabajo y en cuanto te concierne. Ha llegado el momento de que dejes de esperar a que alguien te proporcione un mapa del camino y empieces a dibujarlo tú mismo. Llevamos a nuestros hijos al colegio y nos obsesionamos con sus notas, su comportamiento y su capacidad de integración. Colgamos una oferta de trabajo y buscamos experiencia, universidades de prestigio y una carrera sin fracasos. Y entonces, ¿por qué nos sorprendemos cuando todo se desmorona? Nuestra economía no es estática, pero actuamos como si lo fuera. Tu posición en el mundo se define en función de lo que emprendes, de cómo lo haces y de lo que aprendes de los acontecimientos que causas. ¡Hazlo! Constituye un manifiesto sobre la producción de algo que escasea y es, por lo tanto, valioso. Ha llegado el momento de que dejes de esperar a que alguien te proporcione un mapa del camino y empieces a dibujarlo tú mismo. Este libro quizá te haga sentir incómodo. Es una llamada de atención sobre las iniciativas que estás tomando, en el trabajo y en cuanto te concierne. Pero también puede ser el puntapié que necesitas para introducir un cambio en tu vida.', @Cat_Emprendimientomotivacin, N'¡Hazlo! Cuando fue la última vez que hiciste algo por primera vez.pdf', N'.pdf', 0, 1);
END;

