-- Libro 605: Chloe
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Chloe' AND Autor = N'Sarah Brianne')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Chloe', N'Sarah Brianne', N'Chloe (también estilizado como Chloë, Chloé, Cloe o Cloi)​ es un nombre femenino, cuyo significado es "floreciente" o "fertilidad". Ha sido un nombre muy popular en Reino Unido desde 1990, llegando a la cima de su popularidad en esa y la primera década del siglo XXI. El nombre viene del griego, khlóē, uno de los muchos nombres de la diosa Demeter y se refiere al follaje joven y verde. El nombre aparece en el Nuevo Testamento, en Corintios 1:11 en el contexto de "la casa de Chloe".​', @Cat_Romancemafia, N'_Y si te toco yo_ - Chloe Collins.pdf', N'.pdf', 0, 1);
END;

