-- Libro 614: Juego de ángeles
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Juego de ángeles' AND Autor = N'María Martínez')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Juego de ángeles', N'María Martínez', N'Última entrega de la trilogía «Almas Oscuras». Para todos los amantes de las novelas de vampiros y para los que creen que el amor no entiende de fronteras ni de mundos. La maldición se ha roto y la única debilidad que mantenía a los vampiros en las sombras ha desaparecido. En pocos días, cientos de renegados comenzarán a tomar las calles y a convertir humanos. Aunque ese no es el mayor problema al que deberá enfrentarse William. La tregua entre los ángeles se ha roto y no tardarán en declararse la guerra. Las lectoras dicen: «Oscuro, inquietante, impredecible. El final perfecto para una trilogía que me ha mantenido pegada a sus páginas desde la primera escena. Me era imposible dejar de leer.» Cristina Mas, Leyendo entre horas «Una lectura absorbente y muy sexy. Un giro argumental inesperado. Unos personajes complejos y pasionales que parecen saltar de la página gracias al talento de la autora.» Marta Fernández, Tejiendo críticas en la sombra «Emocionante e intensa. La trilogía que necesitaba para volver a engancharme y caer en las redes de las historias de vampiros y licántropos.» María Cabal, Soy Cazadora de Sombras y Libros', @Cat_Romanceparanormalfantasa, N'PDF/Juego de ángeles - María Martínez.pdf', N'.pdf', 0, 1);
END;

-- Libro 615: Bill Gates en sus propias palabras
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Bill Gates en sus propias palabras' AND Autor = N'Lisa Rogak')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Bill Gates en sus propias palabras', N'Lisa Rogak', N'Ruthless billionaire or benevolent philanthropist? Whatever your take on him, Bill Gates is a force to be reckoned with in the world of business and in the realm of international philanthropy. Hailed by most as an ingenious visionary and considered by some to be an unscrupulous monopolist, Gates has had an indelible impact on the growth of digital technology. As founder and former CEO of Microsoft, he helped spearhead one of the greatest revolutions in modern history, seizing on the importance of software in the rise of personal computing and becoming in 1987 - at the age of 31 - the youngest ever self-made billionaire. But Gates''s second act has been no less compelling than his first. After leaving Microsoft''s day-to-day operations in 2008 to devote himself full-time to the Bill & Melinda Gates Foundation, a kinder, gentler Gates began to emerge, one deeply concerned with Third World health issues and educational reform. Drawing on more than three decades of media coverage - print, electronic and online - this book offers real insight into the man behind the millions. Essential reading for anyone seeking wisdom from the world''s entrepreneur extraordinaire.', @Cat_Biografanegocios, N'PDF/Bill Gates en sus propias palabras - Lisa Rogak.pdf', N'.pdf', 0, 1);
END;

