-- Libro 618: Origin
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Origin' AND Autor = N'Jennifer L. Armentrout')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Origin', N'Jennifer L. Armentrout', N'Origin by Jennifer Armentrout, Book Four of the bestselling Lux series Daemon will do anything to get Katy back. After the successful but disastrous raid on Mount Weather, he''s facing the impossible. Katy is gone. Taken. Everything becomes about finding her. Taking out anyone who stands in his way? Done. Burning down the whole world to save her? Gladly. Exposing his alien race to the world? With pleasure. All Katy can do is survive. Surrounded by enemies, the only way she can come out of this is to adapt. After all, there are sides of Daedalus that don''t seem entirely crazy, but the group''s goals are frightening and the truths they speak even more disturbing. Who are the real bad guys? Daedalus? Mankind? Or the Luxen? Together, they can face anything. But the most dangerous foe has been there all along, and when the truths are exposed and the lies come crumbling down, which side will Daemon and Katy be standing on? And will they even be together?', @Cat_Romanceparanormalcienciaficcinjuvenil, N'PDF/Origin - Jennifer L. Armentrout.pdf', N'.pdf', 0, 1);
END;

-- Libro 619: Unida a los guerreros
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Unida a los guerreros' AND Autor = N'Grace Goodwin')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Unida a los guerreros', N'Grace Goodwin', N'Cuando las circunstancias la dejan sin otra opción más que ofrecerse como voluntaria en el Programa de Novias Interestelares, Hannah Johnson es asignada no solo a un compañero, sino a dos. Sus futuros esposos son guerreros del planeta Prillon, un mundo cuyos hombres son conocidos en todos lados debido a su destreza en las batallas y en la cama. Luego de ser transportada en una nave espacial hacia el otro lado de la galaxia, Hannah se despierta en presencia de Zane Deston, el enorme y ferozmente guapo comandante de la flota Prillon. Tras hacerle saber que es ahora su compañera, así como la de su segundo, Zane se encarga de supervisar la manera minuciosa e íntima en la que Hannah es examinada. Su incapacidad de cooperar adecuadamente con el doctor de la nave le vale una dolorosa y vergonzosa nalgada sobre su trasero desnudo, pero es la reacción de su cuerpo ante el examen lo que la hace sonrojarse de verdad. A pesar de su desconcierto ante la perspectiva de ser compartida entre Zane y su segundo, el atractivo guerrero Dare, Hannah no puede esconder su excitación mientras estos dos machos alfa se toman su tiempo para dominar su cuerpo. A medida que el día de la ceremonia de unión se aproxima, Hannah comienza a anhelar el momento en el que Zane y Dare la hagan totalmente suya; pero ¿se arriesgará a entregar su corazón a unos hombres que podrían morir en combate en cualquier momento?', @Cat_Romanceerticocienciaficcin, N'PDF/Unida a los guerreros - Grace Goodwin.pdf', N'.pdf', 0, 1);
END;

-- Libro 620: Strawberry Moon: La hija de la luna
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Strawberry Moon: La hija de la luna' AND Autor = N'Laia López')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Strawberry Moon: La hija de la luna', N'Laia López', N'Diana es una sirena hija de la Luna que, al cumplir la mayoría de edad, decide salir a la superficie para vivir como los humanos. En la universidad coincide con Edlyn, Mako, Isla y Lucas, otros seres como ella. Bajo las aguas de la laguna, Diana siempre había estado sola, pero ahora tiene grandes amigos con los que compartir su día a día. Además, está Eiden, ese humano tan simpático al que tiene ganas de conocer más... Sin embargo, su amistad con él podría hacer peligrar la vida de todas las sirenas y tritones del planeta. Entre tanto, en el campus están pasando cosas de lo más extrañas. Los alumnos desaparecen continuamente, e Isla sospecha que detrás de esto están las merrows, otra especie de sirenas capaces de arrebatar las almas de los humanos. Pero hacía ya muchos años que las merrows respetaban el pacto de paz establecido por el consejo de la laguna; ¿por qué lo tendrían que romper justo ahora?', @Cat_Fantasajuvenil, N'PDF/Strawberry Moon- La hija de la luna - Laia López.pdf', N'.pdf', 0, 1);
END;

