-- Libro 624: Zafiro
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Zafiro' AND Autor = N'Kerstin Gier')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Zafiro', N'Kerstin Gier', N'Cruza las fronteras del tiempo y encuentra el verdadero amor. Sigue la grandiosa aventura de Gideon y Gwen: un torbellino de sentimientos que arrastra a los protagonistas a través de los siglos. Gwen vive en una nube... ¡con Gideon!, aunque sabe bien que el amor entre dos viajeros en el tiempo puede deparar sorpresas traicioneras. Por suerte, tiene muy buenos consejeros: su mejor amiga, Leslie, su compinche, James el fantasma, y Xemerius, una gárgola que se mete en bastantes líos. Además, Gwen y Gideon tienen importantes problemas de los que ocuparse... Por ejemplo, salvar el mundo. O aprender a bailar un minué (algo nada fácil). Sin embargo, ambos deberán entender que el amor debe pasar por delante de lo demás, sobre todo cuando caigan en las redes del conde de Saint Germain... Todo había empezado con aquel beso. Gideon de Villiers me había besado a mí: Gwendolyn Sheperd. Naturalmente, debería haberme preguntado por qué se le habría ocurrido aquella idea de una forma tan repentina y en unas circunstancias tan extrañas, escondidos en un confesionario y todavía sin aliento tras una persecución de película por medio Londres. Pero el hecho era que en aquel momento yo no pensaba absolutamente en nada, aparte quizá de que no quería que el beso acabara nunca. Por eso tampoco fui del todo consciente del tirón que sentí en el vientre ni me di cuenta de que entre tanto habíamos vuelto a saltar en el tiempo... Reseña: «Kerstin debe de haber lanzado algún tipo de magia entre sus páginas. La historia es alucinante... ¡Quién fuera Gwen para pasar dos horas con Gideon en un sofá! ¡A SOLAS! Sin lugar a dudas, la trilogía ES UN IMÁN del que no te podrás separar. ¡Imprescindible en tu estantería!» Eva Rubio, administradora de JUVENIL ROMÁNTICA', @Cat_Fantasajuvenil, N'PDF/Zafiro - Kerstin Gier.pdf', N'.pdf', 0, 1);
END;

