-- Libro 627: ¿Cómo crece tu jardín?
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¿Cómo crece tu jardín?' AND Autor = N'Agatha Christie')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¿Cómo crece tu jardín?', N'Agatha Christie', N'Una anciana llamada Amelia Barrowby envía a Poirot una extraña carta explicando que necesita sus servicios. En su mensaje, insiste en que la discreción es fundamental porque su familia podría estar involucrada en el asunto. El detective acepta y propone un encuentro, pero no vuelve a tener noticias de su cliente. Cinco días más tarde, el periódico anuncia la muerte de la señora Barrowby. Hércules Poirot visitará su casa e investigará a la familia hasta descubrir toda la verdad.', @Cat_Misteriorelatopolicial, N'PDF/Como crece tu jardin - Agatha Christie.pdf', N'.pdf', 0, 1);
END;

-- Libro 628: Pareja asignada
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Pareja asignada' AND Autor = N'Grace Goodwin')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Pareja asignada', N'Grace Goodwin', N'La única manera de salvar a la testigo Eva Daily hasta el juicio es escondiéndola en prisión y sacándola del planeta a través del Programa de Novias Interestelares como Evelyn Day. Pero la unión con Tark de Trion es real. Y él exige que Eva se someta, en cuerpo y alma, porque ha estado esperándola y está decidido a quedarse con ella.', @Cat_Romancedecienciaficcin, N'PDF/Pareja asignada - Grace Goodwin.pdf', N'.pdf', 0, 1);
END;

-- Libro 629: ¡Sálvese quien pueda!
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¡Sálvese quien pueda!' AND Autor = N'Andrés Oppenheimer')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¡Sálvese quien pueda!', N'Andrés Oppenheimer', N'Manteniéndose fiel a su característico estilo periodístico, Andrés Oppenheimer lleva a sus lectores en un nuevo viaje, esta vez a través del mundo, con la intención de comprender cuál será el futuro de los trabajos de hoy en el día, mientras se aproxima lo que muchos han denominado como la era de la automatización. Tal como lo indican dos de los entrevistados de Oppenheimer -ambos expertos en tecnología y economía de la Universidad de Oxford- el cuarenta y siete por ciento de los trabajos existentes corren el riesgo de automatizarse o volverse obsoletos debido a los avances tecnológicos y el crecimiento de los productos y servicios en línea que están por venir en los próximos veinte años. Oppenheimer conversa con expertos en sus campos y examina los cambios que ya comienzan a desarrollarse en varias áreas de empleo, incluyendo en la industria de alimentos, en el mundo legal, en la banca y en la medicina. Oppenheimer contrapone también las perspectivas de los "tecno-optimistas" con las de los "tecno-negativistas" e intenta encontrar un término medio entre una visión alarmista del futuro y una que es demasiado acrítica. Autodenominado un "optimista cauteloso", Oppenheimer opina que la tecnología no necesariamente creará un desempleo masivo, sino más bien cambiará drásticamente la definición de lo que hoy conocemos como un "empleo".', @Cat_Noficcintecnologayempleo, N'PDF/¡Sálvese quien pueda! - Andrés Oppenheimer.pdf', N'.pdf', 0, 1);
END;

