-- Libro 633: El Devorador de Almas
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El Devorador de Almas' AND Autor = N'Michelle Paver')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El Devorador de Almas', N'Michelle Paver', N'Tercera entrega de «Crónicas de la prehistoria», una emocionante serie de aventuras prehistóricas que ya cuenta con un numeroso grupo de jóvenes lectores. Los protagonistas deberán recurrir en esta aventura a todo su coraje e ingenio para salvar a su amigo. Torak, Renn y Lobo viven unos días apacibles tras superar las azarosas peripecias de su última aventura. Sin embargo, cuando por fin han logrado reunirse, muy pronto se ven enfrentados a la peor pesadilla imaginable: durante una rutinaria partida de caza, los Devoradores de Almas secuestran a Lobo con malévolos designios. Así, para seguir la pista de su entrañable amigo, Torak tiene que recurrir a su recién descubierto poder de trasladar su espíritu al cuerpo de diversos animales, aunque el uso de este portentoso don tiene terribles consecuencias que pueden costarle muy caras a nuestro joven héroe. El desenlace se librará en el lejano y helado Norte, donde nuestros intrépidos protagonistas deberán recurrir a todo su ingenio y coraje en un entorno inhóspito y plagado de peligros indescriptibles. Reseñas: «Una aventura maravillosamente imaginada.» Times Educational Supplement «Soberbio.» The Times', @Cat_Fantasajuvenilaventura, N'PDF/El Devorador de Almas - Michelle Paver.pdf', N'.pdf', 0, 1);
END;

