-- Libro 640: Psicología del color
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Psicología del color' AND Autor = N'Eva Heller')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Psicología del color', N'Eva Heller', N'Este libro aborda la relación de los colores con nuestros sentimientos y demuestra cómo ambos no se combinan de manera accidental, pues sus asociaciones no son meras cuestiones de gusto, sino experiencias universales que están profundamente enraizadas en nuestro lenguaje y en nuestro pensamiento. Organizado en 13 capítulos que corresponden a 13 colores distintos, el volumen poporciona una gran cantidad y variedad de información sobre los colores: desde dichos y saberes populares, hasta su utilización en el diseño de productos, los diferentes tests que se basan en colores, la curación por medio de ellos, la manipulación de las personas, los nombres y apellidos relacionados con colores, etc. La diversidad de este enfoque convierte a la obra de Eva Heller en una herramienta fundamental para todas aquellas personas que trabajan con colores: artistas, terapeutas, diseñadores gráficos e industriales, interioristas, arquitectos, diseñadores de moda, publicistas, entre otros.', @Cat_PsicologaDiseo, N'PDF/Psicologia del color - Eva Heller.pdf', N'.pdf', 0, 1);
END;

-- Libro 641: Átame
