    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Átame', N'Anna Zaires', N'Mi nueva prisionera es una contradicción que me vuelve loca: obediente pero desafiante, frágil pero fuerte. Tengo que descubrir sus secretos, pero hacerlo podría truncarlo todo. Mi obsesión podría destruirnos a ambos.', @Cat_Romanceoscuro, N'PDF/Átame - Anna Zaires.pdf', N'.pdf', 0, 1);
END;

-- Libro 642: La princesa fiel
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La princesa fiel' AND Autor = N'Philippa Gregory')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La princesa fiel', N'Philippa Gregory', N'A los tres años de edad, Catalina de Aragón es prometida al príncipe Arthur, hijo y heredero de Henry VII de Inglaterra, y es educada para convertirse en princesa de Gales. Sin embargo, tiene que soportar duras pruebas. Finalmente, Catalina se va adaptando poco a poco a la primera corte de la dinastía Tudor y su vida como esposa de Arthur le resulta menos insoportable de lo que creía al principio. Cuando su esposo fallece, Catalina se ve obligada a construir un futuro propio. Su única salida es casarse con el hermano menor de Arthur, Harry. Henry y su madre se oponen a ese matrimonio y los poderosos padres de Catalina tampoco lo ven con buenos ojos... Pero la joven ha heredado de su madre, Isabel la Católica, su indomable espíritu de lucha.', @Cat_Novelahistrica, N'PDF/La princesa fiel - Philippa Gregory.pdf', N'.pdf', 0, 1);
END;

-- Libro 643: Prodigy
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Prodigy' AND Autor = N'Marie Lu')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Prodigy', N'Marie Lu', N'The second book in the best-selling Legend trilogy comes to life in this vibrant graphic novel adaptation. After escaping from the Republic''s stronghold, Day and June are on the run in Vegas when the country learns that their Elector Primo has died and his son has stepped in to take his place. They meet up with the rebel stronghold of the Patriots—a large organization straddling the line between the Republic and its warring neighbor, the Colonies—and learn about an assassination plot against the Elector. Using threats and blackmail to get what he wants, the Patriots'' leader, Razor, convinces June to let herself be captured by Republic soldiers so she can win over the Elector and feed him a decoy assassination plan. But when June realizes that the new Elector is nothing like his father, she must work with Day to try to stop the Patriots'' plot before Razor can fulfill his own devastating plans.', @Cat_Distopacienciaficcinjuvenil, N'PDF/Prodigy - Marie Lu.pdf', N'.pdf', 0, 1);
END;

-- Libro 644: Corona de medianoche
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Corona de medianoche' AND Autor = N'Sarah J. Maas')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Corona de medianoche', N'Sarah J. Maas', N'Una joven y famosa asesina condenada a muerte es liberada de las minas de sal en donde sirve condena a condición de competir en un torneo en el que se seleccionará al paladín oficial del rey. Se ha tenido que enfrentar a ladrones, asesinos profesionales y guerreros de todo el imperio y no solo ha salido con vida, sino que ha resultado la ganadora del certamen. Ahora Celaena deberá servir al rey durante tres años antes de ganar su libertad. Pero Caelena no puede aceptar sumisamente las macabras órdenes del monarca del Reino de Endovier y deberá poner en riesgo todo aquello que ha aprendido a querer: al atractivo capitán de la guardia y al propio príncipe. Además oscuras y poderosas fuerzas se están concentrando en el horizonte y amenazan con destruir todo su mundo. Ella es la única esperanza del reino y tendrá que elegir a quién debe lealtad y por lo que está más dispuesta a luchar.', @Cat_Fantasajuvenil, N'PDF/Corona de medianoche - Sarah J. Maas.pdf', N'.pdf', 0, 1);
END;

-- Libro 645: Ciudad de las almas perdidas
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Ciudad de las almas perdidas' AND Autor = N'Cassandra Clare')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Ciudad de las almas perdidas', N'Cassandra Clare', N'Jace es ahora un sirviente del mal, vinculado a Sebastian por toda la eternidad. Solo un pequeño grupo de Cazadores de Sombras cree posible su salvación. Para lograrla, deben desafiar al Cónclave, y deben actuar sin Clary. Porque Clary está jugando a un juego muy peligroso por su propia cuenta y riesgo. Si pierde, el precio que deberá pagar no consiste tan solo en entregar su vida, sino también el alma de Jace. Clary está dispuesta a hacer lo que sea por Jace, pero ¿puede seguir confiando en él? ¿O lo ha perdido para siempre? ¿Es el precio a pagar demasiado alto, incluso para el amor?', @Cat_Fantasaurbanajuvenil, N'PDF/Ciudad de las almas perdidas - Cassandra Clare.pdf', N'.pdf', 0, 1);
END;

