-- Libro 650: Predestined
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Predestined' AND Autor = N'Abbi Glines')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Predestined', N'Abbi Glines', N'You would think after helping save her boyfriend from an eternity in Hell that things would go back to normal. Well, as normal as life can be when you can see souls and your boyfriend is Death. But for Pagan Moore, things are just getting weirder. The high school quarterback and reigning heartthrob, Leif Montgomery, is missing. While the town is in a frenzy of worry, Pagan is a nervous wreck for other reasons. Apparently good ''ol Leif isn''t your average teenage boy. He isn''t even human. According to Death, Leif doesn''t have a soul. The quarterback may have skipped town but he''s still showing up in Pagan''s dreams... uninvited. Dank has known from the beginning Leif wasn''t human. But he hadn''t worried about a simple soulless creature. Now, he realizes he made a grave mistake. Pagan''s soul has been marked since birth as a restitution, to a spirit so dark not even Death walks near it. Dank knows saving Pagan''s soul won''t be easy but Pagan is his. And he''s already proven he''ll defy Heaven to keep her. If Hell wants a piece of him too, then bring it on.', @Cat_Romanceparanormal, N'PDF/Predestined - Abbi Glines.pdf', N'.pdf', 0, 1);
END;

-- Libro 651: Kundalini Yoga
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Kundalini Yoga' AND Autor = N'Anónimo')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Kundalini Yoga', N'Anónimo', N'El kundalini yoga (de Kuṇḍalinī más yoga) es una disciplina física, mental y espiritual basada en distintos senderos yóguicos como
raya yoga,
shakti yoga,
kriya yoga y
nada yoga (desarrollo de los nāḍī , o ‘ríos’ de energía dentro del cuerpo) —que están basados en los pilares del texto sánscrito Yoga sutra (de Patanyali, siglo III a. C.)— con agregados de bhakti (devoción a Dios) y tantra.
El Kundalini yoga es muy parecido al laya yoga (yoga que se enfoca en la fusión de la consciencia individual con la consciencia universal), en el aspecto de que ambos se basan en el desarrollo  y control de la energía (al parecer básicamente prāṇa), que según los hinduistas reside en el ser humano y debe unirse a la consciencia universal (que en el caso del kundalini yoga sería Shivá en el chakra coronario (sahasrara), situado en la parte superior de la cabeza), diferenciándose el Kundalini, por enfocar su concentración en todos los chakras a diferencia del laya yoga que suele en su práctica el tener que enfocarse directamente en el Chakra superior Ajna que está ubicado en el entrecejo del individuo. 
La difusión a nivel mundial de esta disciplina en el siglo XX se debió principalmente gracias al trabajo del maestro Yogui Bhajan. Sin embargo su uso en occidente por parte de la corriente de la nueva era ha tergiversado su verdadera esencia, pasando a ser solo otra forma de esoterismo, a diferencia de lo que sucede en la India.', @Cat_Yogaespiritualidad, N'PDF/Kundalini Yoga - Anonimo.pdf', N'.pdf', 0, 1);
END;

