-- Libro 653: ¿Quién mató a Alex? El secreto desvelado
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¿Quién mató a Alex? El secreto desvelado' AND Autor = N'Janeth G. S.')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¿Quién mató a Alex? El secreto desvelado', N'Janeth G. S.', N'El fenómeno que arrasa en Wattpad. Más de 37 millones de lecturas. Premio Wattys. Hannah es una adolescente de dieciséis años enganchada a las redes sociales. Pero un día recibe una solicitud de amistad de Facebook de un chico llamado Alex Crowell. Al aceptarla, descubre en el muro de Alex que está muerto. Y luego pasa algo todavía más escalofriante: recibe un mensaje privado del joven donde él le pide ayuda para averiguar quién lo mató. En una trepidante investigación, Hannah descubre que hay muchas personas involucradas en su muerte. Pero contará con una ayuda inesperada, la del fantasma de Alex.', @Cat_Misteriothrillerjuvenil, N'PDF/Quien mato a Alex El secreto desvelado - Janeth G. S..pdf', N'.pdf', 0, 1);
END;

-- Libro 654: Dirty Red
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Dirty Red' AND Autor = N'Tarryn Fisher')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Dirty Red', N'Tarryn Fisher', N'Manipulation. Lies. Backstabbing. Just your typical obsessively toxic love triangle. Dear Opportunist, You thought you could take him from me, but you lost. Now that he''s mine, I''ll do anything to keep him. Do you doubt me? I have everything that was supposed to be yours. In case you were wondering—he doesn''t even think about you anymore. I won''t let him go…ever. Dirty Red Leah Smith finally has everything she’s ever wanted. Except she doesn''t. Her marriage feels more like a loan than a lifelong commitment, and the image she has worked so hard to build is fraying before her eyes. With a new role and a past full of secrets, Leah must decide how far she is willing to go to keep what she has stolen. You know Olivia’s side of the story, but now it’s Leah’s turn.', @Cat_Romancecontemporneo, N'PDF/Dirty Red - Tarryn Fisher.pdf', N'.pdf', 0, 1);
END;

-- Libro 655: Inframundo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Inframundo' AND Autor = N'S. D. Perry')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Inframundo', N'S. D. Perry', N'Umbrella está creando monstruosos asesinos biológicos. A pesar de su inmenso poder, está empezando a perder el control de sus instalaciones secretas, pero una de las más avanzadas está a punto de entrar en funcionamiento. En su interior se encuentra también la clave para detener a Umbrella de una vez por todas. Pero Leon, Claire, Redfield y Rebeca deberán superar los horrores de la ingeniería genética que les esperan bajo tierra.', @Cat_Terrorcienciaficcin, N'PDF/Inframundo - S. D. Perry.pdf', N'.pdf', 0, 1);
END;

-- Libro 656: Corazón desnudo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Corazón desnudo' AND Autor = N'Elena Montagud')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Corazón desnudo', N'Elena Montagud', N'Has dudado mucho, pero ahora ya lo sabes: es el hombre de tu vida. ¿Cómo conseguirás retenerlo a tu lado? Corazón desnudo es el esperadísimo y ardiente desenlace de la trilogía «Corazón» de Elena Montagud, iniciada con Corazón elástico y Corazón indomable. ADVERTENCIA: El esperado desenlace de esta ardiente e inolvidable trilogía puede dejarte sin respiración. Blanca y Adrián deben separarse cuando él acepta la oferta de montar su obra musical en los escenarios de Broadway. Pero no se trata solo un distanciamiento físico por trabajo y Blanca lo sabe. Detrás de esa separación se esconden también otros miedos que ella no llega a entender del todo y que le hacen temer que Adrián se esté replanteando su relación. Por eso, cuando por fin él la invita al estreno de la obra en Nueva York, una Blanca más decidida y hermosa que nunca se decide a tomar la Gran Manzana al asalto y dejarle claro que ese músico que la enamoró en la adolescencia es el hombre a quien sigue amando y deseando, el único que la hace vibrar de placer y temblar de verdadera emoción. Una novela para quienes se atreven a saltar al abismo del amor sin más red que un corazón sincero. Intenso, vertiginoso, sensible, sexual... Nunca lo olvidarás.', @Cat_Romancecontemporneo, N'PDF/Corazón desnudo - Elena Montagud.pdf', N'.pdf', 0, 1);
END;

-- Libro 657: ¡Santa tía Rita, lo que se da no se quit
