-- Libro 658: Requiem
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Requiem' AND Autor = N'Lauren Oliver')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Requiem', N'Lauren Oliver', N'''The new Hunger Games... '' Cosmopolitan He never loved me. It was all a lie. ''The old Lena is dead,'' I say, and then push past him. Each step is more difficult that the last; the heaviness fills me and turns my limbs to stone. You must hurt, or be hurt. An all-out uprising has been ignited and Lena Haloway is right at its centre. But things have changed. The Wilds are no longer a safe haven for the rebels and pockets of resistance have opened throughout the country. And when a face from her past reappears, Lena is faced with a devastating choice that could tear her and the revolution apart. ''Un-put-downable, a truly fantastic finale.'' Guardian', @Cat_Distopajuvenil, N'PDF/Requiem - Lauren Oliver.pdf', N'.pdf', 0, 1);
END;

