-- Libro 660: Atrápame
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Atrápame' AND Autor = N'Anna Zaires')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Atrápame', N'Anna Zaires', N'—Yulia —susurra mirándome y sé que siente también esta atracción, esta conexión tan visceral entre nosotros. Quizás tenga todo el poder, pero, en este momento, es tan vulnerable como yo, atrapado en la misma locura. Obligada a unirse a una agencia secreta de inteligencia a una edad muy temprana, la espía e intérprete rusa Yulia Tzakova no es ajena a los hombres peligrosos. Pero nunca ha conocido a uno tan despiadado y cautivador como Lucas Kent. El mercenario de carácter impetuoso la asusta, pero se siente atraída por él, por un hombre al que no tiene más remedio que traicionar. Lucas Kent es la mano derecha de un poderoso traficante de armas y nunca ha conocido a una mujer a la que desee tanto como a Yulia. Está obsesionado con esa preciosa rubia, por lo que no se detendrá ante nada para atraparla y hacerle pagar su traición. Desde las calles gélidas de Moscú hasta la jungla húmeda de Colombia, esta oscura pasión cautivadora los destruirá o los hará libres. ***** «Una montaña rusa perfecta y oscura de acción sobrecogedora y romance abrasador» —Skye Warren, autora superventas del New York Times. «Candente, cautivadora y trepidante» —Josie Litton, autora superventas del New York Times. ***** Más de 60 reseñas de 5 estrellas entre todos los libros. Esto es lo que dicen los lectores: · «Intensa, oscura, erótica, magnética, cautivadora, enigmática, apasionante y muy intrigante». · «…página tras página de anhelo y necesidad, de peligro, de más anhelo, de más peligro. Luego, culminación erótica, más necesidad. Después, dicha romántica y, de nuevo (¡aaahhh!), ¡MÁS PELIGRO! He disfrutado cada minuto leyéndola». · «La intensidad entre Yulia y Lucas era electrizante y trágica de la mejor manera posible». · «Anna Zaires ha creado una nueva obra de arte. Nunca me canso de leer sus relatos. Lucas es otro de sus héroes oscuros, me ha atrapado el corazón desde el principio y esta trilogía siempre será una de las mejores historias románticas y tenebrosas que he leído». · «…el tipo de colecciones que siempre tendrá un hueco en mi corazón». Este práctico paquete rebajado contiene los tres libros de la serie Atrápame: Atrápame, Átame y Tómame.', @Cat_Romanceoscurosuspense, N'PDF/Atrapame - Anna Zaires.pdf', N'.pdf', 0, 1);
END;

-- Libro 661: Madam Temptress
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Madam Temptress' AND Autor = N'Meghan March')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Madam Temptress', N'Meghan March', N'From New York Times bestselling author Meghan March comes the stunning conclusion to the highly-anticipated Magnolia Duet. I didn’t choose this path. No one would. I played the cards I was dealt. This life made me. This city made me. I won’t apologize for who I’ve become. Moses wouldn''t have me any other way. He says he wants forever, and I’m starting to believe him. But I can’t outrun my past, and my sins are catching up with me. If it’s time to atone, I’ll gladly pay my penance. We might be getting our second chance, but we have to make it out alive first. Madam Temptress is the second book of the Magnolia Duet and should be read following Creole Kingpin.', @Cat_Romancesuspense, N'PDF/Madam Temptress - Meghan March.pdf', N'.pdf', 0, 1);
END;

-- Libro 662: Tras el telón
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Tras el telón' AND Autor = N'Stella Knightley')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Tras el telón', N'Stella Knightley', N'La complicada historia de amor entre Sarah Thomson y Marco Donato continúa. La pasión que los une es profunda, pero ambos han sufrido experiencias traumáticas y tienen miedo de mostrarle al otro sus puntos más vulnerables. Mientras tanto, Sarah ha empezado una nueva investigación histórica En la Alemania de la década de 1930, Katherine Hazleton se escapa de su asfixiante internado y viaja a Berlín siguiendo a un hombre que no le conviene. Cuando su novio la abandona, se encuentra sola y sin dinero en un país extranjero. Las circunstancias la llevan a trabajar como camarera en un cabaret. Allí se reinventa y se convierte en Kitty Katkin, quien no sólo llega a escribir sus propias canciones, sino que las acompaña de bailes atrevidos que se convierten en todo un éxito. Kitty se enamora de Berlín y de un guapo pianista, pero Alemania está cambiando rápidamente. ¿Encontrarán Sarah y Kitty el amor que ambas merecen?', @Cat_ErticaRomance, N'PDF/Tras el telon - Stella Knightley.pdf', N'.pdf', 0, 1);
END;

