-- Libro 665: El libro del mindfulness
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El libro del mindfulness' AND Autor = N'Bhante Henepola Gunaratana')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El libro del mindfulness', N'Bhante Henepola Gunaratana', N'El libro del mindfulness es ya el texto más leído, reconocido y recomendado en todo el mundo acerca de la práctica de la meditación. Joseph Goldstein lo ha elogiado como una obra "extraordinariamente clara y directa". Con un lenguaje muy ingenioso y asequible, Bhante G como cariñosamente se conoce a su autor extiende su mano y ofrece su amplia experiencia y conocimientos a lectores de cualquier extracción y condición. Paso a paso, nos conduce a través de los mitos, realidades y beneficios de la práctica de la meditación y de la atención plena (mindfulness). Con una claridad poco habitual nos revela que ya poseemos el fundamento necesario para vivir nuestra vida de un modo más productivo, consciente y pacífico. Bhante simplemente señala cada herramienta de meditación y nos explica en qué consiste, lo que hace y cómo emplearla con eficacia. Esta edición ampliada incluye el texto completo de la aclamada primera versión, así como un nuevo capítulo dedicado al cultivo del amor-amistad, un tema especialmente importante en el mundo convulso en el que vivimos.', @Cat_Mindfulnessmeditacin, N'PDF/El libro del mindfulness - Bhante Henepola Gunaratana.pdf', N'.pdf', 0, 1);
END;

