-- Libro 667: El ABC de la actitud
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El ABC de la actitud' AND Autor = N'John C. Maxwell')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El ABC de la actitud', N'John C. Maxwell', N'Durante una conferencia John C. Maxwell, uno de los gurúes más destacados del liderazgo, preguntó a su audiencia: “¿Qué palabra describe lo que determina nuestra felicidad, aceptación, paz y éxito?”. Como respuesta, del público surgieron palabras como trabajo, educación, dinero, tiempo. Finalmente, alguien dijo “actitud”. Un área tan importante de sus vidas constituía un pensamiento secundario para esas personas... y para casi todos nosotros. Sin embargo, es la fuerza principal que predispone a unos y destroza a otros, que determina si triunfamos o fracasamos. Maxwell desarrolla en este libro la importancia de la actitud y nos motiva a adoptar la que ayude a un líder a pasar el siguiente nivel. ¡La actitud es contagiosa! ¡Asegúrate de que tu equipo esté contagiándose de la actitud correcta! El ABC de la Actitud, junto con El ABC del Éxito, El ABC de las Relaciones y El ABC de la Capacitación integran la colección que se ha convertido en un auténtico best seller de los libros de management inspiracional.', @Cat_Desarrollopersonalliderazgo, N'PDF/El ABC de la actitud - John C. Maxwell.pdf', N'.pdf', 0, 1);
END;

-- Libro 668: Lucca
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Lucca' AND Autor = N'Sarah Brianne')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Lucca', N'Sarah Brianne', N'Lucca es una ciudad y municipio italiano ubicado en la región de Toscana, en el centro-norte del país. Situada a orillas del río Serchio, en una fértil llanura cercana al mar Tirreno, es la capital de la provincia homónima y cuenta con unos 88 000 habitantes.', @Cat_Romancemafia, N'PDF/Lucca - Sarah Brianne.pdf', N'.pdf', 0, 1);
END;

