-- Libro 670: Solo Tuya
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Solo Tuya' AND Autor = N'Anabel García')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Solo Tuya', N'Anabel García', N'Solo tuya es el primer álbum de estudio de la cantante y actriz mexicana Aracely Arámbula. Este fue lanzado por el sello Disa Records en 14 de mayo de 2002 como un disco compacto y un casete.​ Solo tuya alcanzó número 35 en la lista de Billboard de los álbumes de música latina y número 19 en México.​ Los dos sencillos — «Te quiero más que ayer», el dúo con Palomo, y «Ojalá» — fueron lanzados en 2002. «Te quiero más que ayer» logró número nueve en México y número 27 en la lista Billboard Hot Latin Tracks.', @Cat_Romanceertico, N'PDF/Solo tuya - Anabel García.pdf', N'.pdf', 0, 1);
END;

-- Libro 671: La caída
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La caída' AND Autor = N'Amanda Hocking')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La caída', N'Amanda Hocking', N'Al descubrir su verdadera identidad, Wendy cae entre dos destinos: el amor y la lealtad. Wendy parece estar más conectada a sus rivales, los Vittra, de lo que jamás imaginó, y estos intentan convencerla de que luche junto a ellos. Con una guerra a punto de estallar, la única esperanza de salvar a los suyos está en desarrollar su fuerza y casarse con un poderoso noble. Dividida entre los dictados de su corazón y la llamada del deber, Wendy tendrá que decidir, y si se equivoca, podría perder todo loque ama.', @Cat_Fantasajuvenil, N'PDF/La caída - Amanda Hocking.pdf', N'.pdf', 0, 1);
END;

-- Libro 672: ¡Buenos días, princesa!
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¡Buenos días, princesa!' AND Autor = N'Blue Jeans')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¡Buenos días, princesa!', N'Blue Jeans', N'Han pasado algo más de dos años en la vida de los chicos que forman “el club de los incomprendidos”. Las cosas han cambiado desde que uno tras otro se fueron encontrando en el camino. Nuevos problemas, secretos, amores, celos... Sin embargo, hasta el momento, su amistad ha podido con todo y con todos.Raúl, se ha convertido en un atractivo joven y en un líder nato; Valeria, derrocha simpatía por donde pisa, aunque no ha vencido del todo a su timidez; Eli, es la que más se ha transformado de todos y se los lleva de calle; María, vigila y sueña tras sus gafas de pasta de color azul; Bruno, no consigue olvidar lo que siente y en lo más profundo de su corazón espera ser correspondido; y Ester, es la nuera que toda madre querría tener aunque no es tan inocente como todos piensan.Son seis chicos que sienten, sufren, aman, creen, ríen, evolucionan... como otros chicos de su edad. Pero los seis son especiales. Al menos, para el resto del grupo.¿Conseguirán superar todas las pruebas que se le van a presentar?Sólo puedes averiguarlo leyendo, ¡Buenos días, princesa!', @Cat_Juvenilromance, N'PDF/Buenos dias, princesa - Blue Jeans (2).pdf', N'.pdf', 0, 1);
END;

-- Libro 673: Creole Kingpin
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Creole Kingpin' AND Autor = N'Meghan March')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Creole Kingpin', N'Meghan March', N'New York Times bestselling author Meghan March goes back to New Orleans and the world of Lachlan Mount with a dangerous and bold new anti-hero. The thing about ghosts is they’re supposed to stay dead. That’s exactly what I am, but I can’t stay away from Magnolia Marie Maison for one more day, let alone another year. We’ve already got fifteen of those between us. As it stands, she’ll want to kill me as soon as she lays eyes on me. And knowing her, she’s completely up to the task. But I’m a man on a mission, and I’ve got everything riding on this. So, here I come, Magnolia. This ghost is ready for whatever you got. After all, there’s only one way I want this to end—’til death do us part. Creole Kingpin is the first book in the Magnolia Duet. Magnolia’s story concludes in Madam Temptress.', @Cat_Romancemafia, N'PDF/Creole Kingpin - Meghan March.pdf', N'.pdf', 0, 1);
END;

