-- Libro 675: La pelirroja
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La pelirroja' AND Autor = N'Tarryn Fisher')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La pelirroja', N'Tarryn Fisher', N'Querida Oportunista: Pensaste que podrías quitármelo, pero perdiste. Ahora él es mío y haré lo que sea para mantenerlo a mi lado. ¿No me crees? Tengo todo lo que se suponía que iba a ser tuyo. Por si acaso te lo preguntabas: no, él ya no piensa en ti. No lo dejaré marchar... Nunca. La Pelirroja Leah Smith tiene por fin todo lo que quería. O quizá no. Su matrimonio parece cada vez más un préstamo que un compromiso para toda la vida, y la imagen que tanto ha trabajado para construir está deshilándose ante sus propios ojos. Con un nuevo rol y un pasado lleno de secretos, Leah debe decidir hasta dónde está dispuesta a llegar para mantener aquello que robó.', @Cat_Romancecontemporneodrama, N'PDF/La pelirroja - Tarryn Fisher.pdf', N'.pdf', 0, 1);
END;

-- Libro 676: Broken Juliet
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Broken Juliet' AND Autor = N'Leisa Rayven')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Broken Juliet', N'Leisa Rayven', N'Leisa Rayven has captivated millions of fans with her intoxicating romance set behind the theater’s curtains. For the first time together in an exhilarating eBook bundle, fall in love again with the Starcrossed series: Bad Romeo Cassie Taylor was the good girl actress until she met bad boy Ethan Holt in their college’s production of Romeo and Juliet. Like their characters, Cassie and Ethan’s epic romance ended in tragedy; but now, years later, they’re on Broadway together, and Ethan is determined to change their ending. Broken Juliet Reunited ex-lovers Cassie and Ethan are starring in a Broadway show together, and Ethan claims to be a changed man...but can Cassie believe him? Or has their love been broken beyond repair? Wicked Heart Elissa Holt has only ever loved Liam Quinn. But when they have to work together on his new Broadway show (alongside his fiancé), Elissa realizes that love doesn’t always follow the script...', @Cat_Romancecontemporneo, N'PDF/Broken Juliet - Leisa Rayven.pdf', N'.pdf', 0, 1);
END;

