-- Libro 678: Switched
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Switched' AND Autor = N'Amanda Hocking')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Switched', N'Amanda Hocking', N'Switched is the first novel in Amanda Hocking''s bestselling trilogy, Trylle. Wendy Everly knew she was different the day her mother tried to kill her and accused her of having been switched at birth. Although certain she''s not the monster her mother claimed she is, she does feel that she doesn''t quite fit in. She''s bored and frustrated by her small-town life - and then there''s the secret she can''t tell anyone. Her mysterious ability - she can influence people''s decisions, without knowing how, or why . . . When the intense and darkly handsome newcomer Finn suddenly turns up at her bedroom window one night, her world is turned upside down. He holds the key to her past, the answers to her strange powers and is the doorway to a place she never imagined could exist: Förening, the home of the Trylle. Finally everything makes sense. Among the Trylle she is not just different, but special. But what marks her out as chosen for greatness in this world also places her in grave danger. With everything around her changing, Finn is the only person she can trust. But dark forces are conspiring - not only to separate them, but to see the downfall of everything that Wendy cares about. The fate of Förening rests in Wendy''s hands, and the decisions she and Finn make could change all their lives forever . . .', @Cat_Fantasajuvenil, N'PDF/Switched - Amanda Hocking.pdf', N'.pdf', 0, 1);
END;

-- Libro 679: Chloe
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Chloe' AND Autor = N'Sarah Brianne')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Chloe', N'Sarah Brianne', N'Chloe (también estilizado como Chloë, Chloé, Cloe o Cloi)​ es un nombre femenino, cuyo significado es "floreciente" o "fertilidad". Ha sido un nombre muy popular en Reino Unido desde 1990, llegando a la cima de su popularidad en esa y la primera década del siglo XXI. El nombre viene del griego, khlóē, uno de los muchos nombres de la diosa Demeter y se refiere al follaje joven y verde. El nombre aparece en el Nuevo Testamento, en Corintios 1:11 en el contexto de "la casa de Chloe".​', @Cat_Romancemafia, N'PDF/Chloe - Sarah Brianne.pdf', N'.pdf', 0, 1);
END;

