-- Libro 684: ¡Defendámonos de los dioses!
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¡Defendámonos de los dioses!' AND Autor = N'Salvador Freixedo')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¡Defendámonos de los dioses!', N'Salvador Freixedo', N'Podria ser que los dioses que nos presentan las religiones fuesen unos embaucadores? Y que los tripulantes de los ovnis tampoco fueran lo que parecen ser, como por ejemplo unos seres de otros planetas que vienen al nuestro por las noches a recoger muestras? Este libro trata de averiguar como se manifiestan las inteligencias extrahumanas y que se esconde realmente detras de ellas, y lo hace buceando tanto en la historia humana -una historia a menudo complicada y plagada de injusticias- como en la no menos compleja historia de las religiones. Quienes son esos "dioses" que desde tiempos inmemoriales parecen ser los instigadores de la mayoria de religiones? Cuales son sus intereses? Por que se entrometen en la vida de las personas y juegan con nosotros? A lo largo de estas paginas el autor busca respuestas a un tema tan controvertido, abordandolo desde un punto de vista donde los limites entre la religion y el fenomeno ovni se difuminan hasta casi desaparecer y convertirse en un todo del que quiza tengamos que defendernos. "Defendamonos de los dioses" es una de las obras mas conocidas de Salvador Freixedo, y una de las mas populares de la ufologia mundial. Esta edicion, revisada y actualizada por el propio autor, no puede faltar en la biblioteca de ningun aficionado a los ovnis... ni a las religiones."', @Cat_Ensayoufologa, N'PDF/Defendamonos de los dioses - Salvador Freixedo.pdf', N'.pdf', 0, 1);
END;

