-- Libro 688: Los chamanismos a revisión
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Los chamanismos a revisión' AND Autor = N'Josep M.ª Fericgla')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Los chamanismos a revisión', N'Josep M.ª Fericgla', N'Desde hace décadas el fenómeno del chamanismo suscita un enorme interés entre la comunidad científica y el público no especializado. A partir de los años setenta también comenzó a difundirse un neochamanismo occidental popular, normalmente ligado a los movimientos de crecimiento personal. El presente libro es una revisión acutalizada de los conceptos básicos del fenómeno, notablemente de la figura del chamán y de los fenómenos mentales, culturales, terpéuticos y cognitivos que se esconden bajo este arquetipo. También es una crítica lúcida, acerada y no exente de ironía sobre algunas versiones del neochamanismo y sobre el supermercado de creencias en el que se ha convertido la moderna sociedad occidental.', @Cat_Ensayoantropologa, N'PDF/Los chamanismos a revision - Josep M.a Fericgla.pdf', N'.pdf', 0, 1);
END;

-- Libro 689: ¿Quién mató a Alex? El secreto desvelado
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¿Quién mató a Alex? El secreto desvelado' AND Autor = N'Janeth G. S.')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¿Quién mató a Alex? El secreto desvelado', N'Janeth G. S.', N'El fenómeno que arrasa en Wattpad. Más de 37 millones de lecturas. Premio Wattys. Hannah es una adolescente de dieciséis años enganchada a las redes sociales. Pero un día recibe una solicitud de amistad de Facebook de un chico llamado Alex Crowell. Al aceptarla, descubre en el muro de Alex que está muerto. Y luego pasa algo todavía más escalofriante: recibe un mensaje privado del joven donde él le pide ayuda para averiguar quién lo mató. En una trepidante investigación, Hannah descubre que hay muchas personas involucradas en su muerte. Pero contará con una ayuda inesperada, la del fantasma de Alex.', @Cat_Misteriothrillerjuvenil, N'PDF/¿Quién mató a Alex - El secreto desvelado - Janeth G. S..pdf', N'.pdf', 0, 1);
END;

-- Libro 690: Todo lo que quiero
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Todo lo que quiero' AND Autor = N'Alanna Ignacio')
