    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Todo lo que quiero', N'Alanna Ignacio', N'Todo lo que quiero (título original All I Want, también conocida como Try Seventeen) es una película comedia-dramática del año 2002, dirigida por Jeffrey Porter y escrita por Charles Kephart. Está protagonizada por Elijah Wood, Franka Potente y Mandy Moore. La película se estrenó en el Festival de Cine de Toronto el 10 de septiembre de 2002 y en el Palm Springs International Film Festival el 12 de enero de 2003.', @Cat_Romance, N'PDF/Todo lo que quiero - Alanna Ignacio.pdf', N'.pdf', 0, 1);
END;

