-- Libro 692: ¡A otra con ese cuento!
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¡A otra con ese cuento!' AND Autor = N'Raquel Antúnez')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¡A otra con ese cuento!', N'Raquel Antúnez', N'Lucía es una chica normal y corriente que vive cómo quiere y puede. Comparte piso con sus dos mejores amigas, trabaja en una importante empresa y mantiene una relación más o menos estable con Daniel, el chico que le gusta. Pero un buen día todo cambia de la noche a la mañana. Lucía es enviada a otra oficina bajo el mando de una jefa déspota que parece tener algo contra ella. Como si esto no fuese suficiente, además tiene que aguantar a Marcos, un compañero que muestra un extraño interés por ella, no sabe si espía para la jefa o si sólo es un tarado. Para colmo, algo no acaba de funcionar bien con Daniel y la sombra de la sospecha empieza a planear sobre su idílico romance. Y así, con la vida vuelta del revés, Lucía comprende que los cuentos no son más que un embuste y que lo difícil viene justo después del: “Y vivieron felices”. «¡A otra con ese cuento!» es una novela que habla sobre las relaciones y sobre cómo en muchas ocasiones se idealizan los sentimientos. Delicada e íntima, te muestra un punto de vista diferente sobre el amor y sobre los “finales felices”. ¿Vas a perdértelo?', @Cat_Romancecontemporneo, N'PDF/A otra con ese cuento - Raquel Antunez.pdf', N'.pdf', 0, 1);
END;

