-- Libro 694: Opposition
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Opposition' AND Autor = N'Jennifer L. Armentrout')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Opposition', N'Jennifer L. Armentrout', N'Don''t miss Opposition, the fifth and final book in Jennifer L. Armentrout''s bestselling Lux series, now available as a standalone in print for the first time! "An unmissable series!" –Samantha Young, New York Times bestselling author of On Dublin Street “This is the stuff swoons are made of.” —Wendy Higgins, New York Times bestselling author of Sweet Evil Katy knows the world changed the night the Luxen came. She can''t believe Daemon stood by as his kind threatened to obliterate every last human and hybrid on Earth. But the lines between good and bad have blurred. Daemon will do anything to save those he loves, even if it means betrayal. But when it quickly becomes impossible to tell friend from foe, and the world is crumbling around them, they may lose everything to ensure the survival of their friends...and mankind. Want to read the LUX series on your ereader? Each book is sold individually in e-format: #1: Obsidian #2: Onyx #3: Opal #4: Origin #5: Opposition Dawson’s story: Shadows', @Cat_Romanceparanormalcienciaficcinjuvenil, N'PDF/Opposition - Jennifer L. Armentrout.pdf', N'.pdf', 0, 1);
END;

