-- Libro 696: Atada
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Atada' AND Autor = N'Lorelei James')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Atada', N'Lorelei James', N'Amery Hardwich está tan concentrada en levantar su negocio que apenas tiene tiempo para divertirse. Pero cuando Molly, su ayudante, es víctima de un atraco y se apunta a un dojo de jiu jitsu para recibir clases de defensa personal, Amery no lo duda y la acompaña para apoyarla. Ronin Black, propietario del dojo, se siente tan atraído por Amery que se hace cargo en exclusiva de su formación, tanto en público como en privado. El atractivo y enigmático profesor pone a prueba los límites de la joven desde el principio y, con cada nuevo encuentro amoroso, ella se vuelve más adicta al placer que el sensei le proporciona. Sin embargo, cuando percibe que Ronin le oculta algo, Amery se cuestiona sus sentimientos, a pesar de la innegable excitación que le produce sentirse dominada por él.', @Cat_Romanceertico, N'PDF/Atada - Lorelei James.pdf', N'.pdf', 0, 1);
END;

