-- Libro 713: La ciudad de los muertos
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La ciudad de los muertos' AND Autor = N'S. D. Perry')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La ciudad de los muertos', N'S. D. Perry', N'Cae la noche... Leon Kennedy; un policía novato y lleno de energía, dispuesto a demostrar su valía y con ganas de comenzar una nueva vida en Racoon City... y que encuentra la ciudad extrañamente desierta. El fantasmal silencio del anochecer sólo se ve roto por el ruido esporádico de unos pasos en las sombras y por el espectral gemido de algo que acecha en las cercanías... Claire Redfield; la independiente y audaz hermana de Chris Redfield, uno de los miembros de los STARS, desaparecido en Racoon City.', @Cat_Terrorcienciaficcin, N'PDF/La ciudad de los muertos - S. D. Perry.pdf', N'.pdf', 0, 1);
