-- Libro 715: Opal
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Opal' AND Autor = N'Jennifer L. Armentrout')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Opal', N'Jennifer L. Armentrout', N'Book Three of the bestselling Lux series No one is like Daemon Black. When he set out to prove his feelings for me, he wasn''t fooling around. Doubting him isn''t something I''ll do again, and now that we''ve made it through the rough patches, well... There''s a lot of spontaneous combustion going on. But even he can''t protect his family from the danger of trying to free those they love. After everything, I''m no longer the same Katy. I''m different... And I''m not sure what that will mean in the end. When each step we take in discovering the truth puts us in the path of the secret organization responsible for torturing and testing hybrids, the more I realize there is no end to what I''m capable of. The death of someone close still lingers, help comes from the most unlikely source, and friends will become the deadliest of enemies, but we won''t turn back. Even if the outcome will shatter our worlds forever. Together we''re stronger...and they know it. Read the entire bestselling series! #1: Obsidian (from Katy''s point of view) #2: Onyx (from Katy''s point of view) #3: Opal (from Katy''s point of view) #4: Origin #5: Opposition Oblivion (Books 1-3 from Daemon''s point of view) CAN BE READ FIRST OR AFTER KATY''S POV! Prequel: Shadows (Dawson''s story)', @Cat_Romanceparanormalcienciaficcinjuvenil, N'PDF/Opal - Jennifer L. Armentrout.pdf', N'.pdf', 0, 1);
END;

-- Libro 716: La oportunista
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La oportunista' AND Autor = N'Tarryn Fisher')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La oportunista', N'Tarryn Fisher', N'Querido Caleb: ¿Qué demonios? ¿No sabes quién soy? ¿Cómo te atreves a OLVIDAR a quien te rompió el corazón? Te diré lo que PIENSO HACER: haré ver que NUNCA NOS CONOCIMOS. Entonces haré que te ENAMORES de mí otra vez. Los dos sabemos que haré LO QUE SEA para conseguir lo que quiero. NUNCA he pretendido ser una buena persona. Si hay algo REAL en mí, eres TÚ. Por favor, no me recuerdes... POR FAVOR. Con amor, OLIVIA P.D.: ¿Una pelirroja, Caleb? ¿DE VERDAD? ¿No podrías haberme sustituido por una RUBIA? Olivia Kaspen es una manipuladora y acaba de descubrir que su exnovio, Caleb Drake, ha perdido la memoria. Por supuesto, hará todo lo que sea necesario para recuperarlo a la vez que intentará mantener en secreto su pasado en común. Sin embargo, su principal obstáculo será Leah Smith, la nueva novia de Caleb. Las dos se enfrascarán en una descarnada lucha para poseer a un hombre que ya no las recuerda. Pero pronto Olivia tendrá que hacer frente a las consecuencias de sus mentiras, y durante el proceso descubrirá que a veces el amor no es suficiente para alcanzar la redención.', @Cat_Romancecontemporneodrama, N'PDF/La oportunista - Tarryn Fisher.pdf', N'.pdf', 0, 1);
END;

