-- Libro 719: Profecía
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Profecía' AND Autor = N'María Martínez')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Profecía', N'María Martínez', N'Me encontraba tomando una clase de hermenéutica cuando el maestro mencionó que la creación estaba narrada dos veces en la Biblia. Esta afirmación llamó profundamente mi atención, ya que previamente había escuchado diferentes versiones sobre la creación de la humanidad: la Biblia la presenta de una manera y la ciencia de otra. Entonces, ¿a quién debía creer? Con esa inquietud en mente, me propuse investigar tanto en las Sagradas Escrituras como en la historia y la ciencia, con el objetivo de llegar a una conclusión. Descubrí que, al escudriñar la Biblia y examinar la historia, es posible entender mejor el propósito de la profecía. Comprendí que la única manera de conocer la verdad absoluta es a través de la Palabra de Dios, tal como está plasmada en la Biblia. Fue precisamente ahí donde entendí que no se trataba de dos narraciones diferentes de la creación, sino de un enfoque complementario: el Señor primero describe lo que hizo y luego detalla cómo lo hizo. Muchas veces, nuestra confusión surge porque no prestamos atención a lo que las Escrituras realmente nos enseñan. Eso fue exactamente lo que me ocurrió a mí. Me tomó dos años y medio investigar y profundizar aquí y allá en la Biblia, en la ciencia y en la historia para finalmente comprender con mayor claridad las “dimensiones históricas del último día de la creación.”', @Cat_Fantasaparanormal, N'PDF/Profecía - María Martínez.pdf', N'.pdf', 0, 1);
END;

