END;

-- Libro 721: The Rebel King
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'The Rebel King' AND Autor = N'Kennedy Ryan')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'The Rebel King', N'Kennedy Ryan', N'From beloved, RITA-award-winning author Kennedy Ryan comes the gripping, passionate finale of the All the King''s Men duology. Though surrender is what Maxim Cade demanded of Lennix Hunter''s body and heart, she had other plans. They were fast-burning fascination and combustible chemistry, the son of an oil baron and the Apache daughter at war with his family, but she trusted him, and he turned out to be a thief who stole her love. Still, if what they had was a lie, why had it felt so real? Now, the man she swore to hate is about to have it all, and he wants Lennix at his side. But when the two of them are forced to face the unthinkable, their rocky foundation is tested, as is the invisible thread that seems to wind their fates together. As they navigate a treacherous political landscape in their quest for justice, Maxim and Lennix soon learn that power is a game, and they are merely the pawns and players. Facing insurmountable odds, will they win the world, or will they lose it all?', @Cat_Romancecontemporneo, N'PDF/The Rebel King - Kennedy Ryan.pdf', N'.pdf', 0, 1);
END;

-- Libro 722: Obsidian
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Obsidian' AND Autor = N'Jennifer L. Armentrout')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Obsidian', N'Jennifer L. Armentrout', N'Discover the New York Times bestselling series from Jennifer L. Armentrout. Starting over sucks. When we moved to West Virginia right before my senior year, I''d pretty much resigned myself to thick accents, dodgy internet access, and a whole lot of boring...until I spotted my hot neighbor, with his looming height and eerie green eyes. Things were looking up. And then he opened his mouth. Daemon is infuriating. Arrogant. Stab-worthy. We do not get along. At all. But when a stranger attacks me and Daemon literally freezes time with a wave of his hand, well, something...unexpected happens. The hot alien living next door marks me. You heard me. Alien. Turns out Daemon and his sister have a galaxy of enemies wanting to steal their abilities, and Daemon''s touch has me lit up like the Vegas Strip. The only way I''m getting out of this alive is by sticking close to Daemon until my alien mojo fades. If I don''t kill him first, that is. Read the entire bestselling series! #1: Obsidian (from Katy''s point of view) #2: Onyx (from Katy''s point of view) #3: Opal (from Katy''s point of view) #4: Origin #5: Opposition Oblivion (Books 1-3 from Daemon''s point of view) CAN BE READ FIRST OR AFTER KATY''S POV! Prequel: Shadows (Dawson''s story)', @Cat_Romanceparanormaljuvenil, N'PDF/Obsidian - Jennifer L. Armentrout.pdf', N'.pdf', 0, 1);
END;

-- Libro 723: Unida a la bestia
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Unida a la bestia' AND Autor = N'Grace Goodwin')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Unida a la bestia', N'Grace Goodwin', N'Tras la muerte de sus dos hermanos en la guerra contra la implacable amenaza alienígena que pone en peligro a toda la Coalición Interestelar, Sarah Mills se ofrece como voluntaria para sumarse al combate en un intento de llevar a casa a su único hermano vivo. Sin embargo, cuando la procesan por error como una novia en vez de un soldado, opta por rechazar a su pareja. Pero su compañero tiene otras ideas… Dax es un señor de la guerra de Atlán, y al igual que todos los hombres de su raza, una bestia primitiva vive en su interior, lista para aparecer en la furia de la batalla o en la intensidad de la fiebre de apareamiento. Al enterarse de que su novia ha elegido luchar en las líneas de fuego en vez de quedarse en su cama, parte para encontrarla y reclamar lo que la bestia necesita. Sarah no se muestra muy contenta cuando una imponente bestia, que afirma ser su compañero, llega repentinamente en medio de una batalla; y su descontento se transforma en ira cuando la presencia de Dax interrumpe su misión y da lugar a la captura de su hermano. Pero luego de que su oficial superior se niegue a autorizar una misión de rescate, la única esperanza de Sarah para salvar al único pariente que le queda es aceptar la oferta de Dax para ayudarla, incluso si eso significa entregarse a él como recompensa. A pesar de su felicidad por haber encontrado a su rebelde novia, Dax rápidamente descubre que Sarah no se parece en nada a las mujeres dóciles y sumisas de su mundo. Si la quiere, deberá dominarla; así tenga que usar su firme mano sobre su trasero. Pero Dax no solo quiere a Sarah, sino que la necesita. ¿Podrá ella satisfacer la temible bestia que se encuentra en su interior antes de que pierda el control por completo?', @Cat_Romanceerticocienciaficcin, N'PDF/Unida a la bestia - Grace Goodwin.pdf', N'.pdf', 0, 1);
END;

-- Libro 724: Ciudad del fuego celestial
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Ciudad del fuego celestial' AND Autor = N'Cassandra Clare')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Ciudad del fuego celestial', N'Cassandra Clare', N'La oscuridad ha regresado al Mundo de las Sombras. Mientras su mundo se desmorona alrededor, Clary, Jace, Simon y sus amigos deben unirse para luchar contra el mayor enemigo al que se han enfrentado nunca los nefilim: el hermano de Clary. Se perderán vidas, se sacrificarán amores y el mundo entero cambiará en el sexto volumen de la serie Cazadores de Sombras.', @Cat_Fantasaurbanajuvenil, N'PDF/Ciudad del fuego celestial - Cassandra Clare.pdf', N'.pdf', 0, 1);
END;

