-- Libro 729: Like the First Time
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Like the First Time' AND Autor = N'Jennifer L. Armentrout')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Like the First Time', N'Jennifer L. Armentrout', N'Aliens are the new vampires, and sexy Daemon Black will set your pulse racing. . . STARTING OVER SUCKS When we moved to West Virginia right before my senior year, I''d pretty much resigned myself to thick accents, dodgy internet access, and a whole lot of boring. . . until I spotted my hot neighbour, with his looming height and eerie green eyes. Things were looking up. AND THEN HE OPENED HIS MOUTH Daemon is infuriating. Arrogant. Stab-worthy. We do not get along. At all. But when a stranger attacks me and Daemon literally freezes time with a wave of his hand, well, something. . . unexpected happens. THE HOT ALIEN LIVING NEXT DOOR MARKS ME You heard me. Alien. Turns out Daemon and his sister have a galaxy of enemies wanting to steal their abilities, and Daemon''s touch has me lit up like the Vegas Strip. The only way I''m getting out of this alive is by sticking close to Daemon until my alien mojo fades. IF I DON''T KILL HIM FIRST, THAT IS ''If you haven''t already picked these books up, seriously what are you waiting for!'' ⭐⭐⭐⭐⭐ ''I don''t usually like alien stories, but this one! Oh my god! AMAZING!'' ⭐⭐⭐⭐⭐ ''Immediately upon starting Obsidian I was hit with the most beautiful feelings of nostalgia. It made me feel how I felt reading Twilight, The Hunger Games, and Divergent for the first time'' ⭐⭐⭐⭐⭐', @Cat_Fantasacienciaficcinjuvenil, N'PDF/Like the First Time - Jennifer L. Armentrout.pdf', N'.pdf', 0, 1);
END;

-- Libro 730: Las 7 leyes espirituales del éxito
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Las 7 leyes espirituales del éxito' AND Autor = N'Deepak Chopra')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Las 7 leyes espirituales del éxito', N'Deepak Chopra', N'En Las siete leyes espirituales del éxito se destila la esencia de las enseñanzas de Chopra en siete sencillos pero poderosos principios, que pueden ser fácilmente aplicados para crear el éxito en todas las áreas de su vida. Colmado de eterna sabiduría, y pasos prácticos que usted puede poner en práctica de inmediato, este es un libro que apreciará toda su vida, pues en su interior se encuentran los secretos para que todos sus sueños se hagan realidad. Basado en las leyes naturales que gobiernan la creación, este libro destruye el mito de que el éxito es el resultado del trabajo arduo, de la esmerada planificación o de la ambición. Deepak Chopra ofrece a cambio, una perspectiva sobre la consecución del éxito capaz de transformar su vida. Cuando comprendemos nuestra verdadera naturaleza y aprendemos a vivir en armonía con las leyes naturales brotan, con facilidad y sin esfuerzo, el sentido de bienestar, la buena salud, las relaciones satisfactorias y la abundancia material.', @Cat_EspiritualidadAutoayuda, N'PDF/Las 7 leyes espirituales del exito - Deepak Chopra.pdf', N'.pdf', 0, 1);
END;

-- Libro 731: 365 días
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'365 días' AND Autor = N'Blanka Lipińska')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'365 días', N'Blanka Lipińska', N'BEST SELLER INTERNACIONAL N.o 1 2.000.000 ejemplares vendidos La novela que inspiró el fenómeno mundial emitido por Netflix. Una excitante historia de sexo de alto voltaje, lujo y poder que no olvidarás. Una pasión sin medida. Un mundo donde no existen los límites ni la clemencia. Tiene 365 días para enamorarse de él. Massimo Toricelli es el capo de una familia de la mafia siciliana. Oscuro, peligroso y tremendamente atractivo, busca obsesionado desde hace años a una mujer que se le apareció en una visión cuando estuvo a punto de morir. Laura es una joven ejecutiva polaca, quemada por el trabajo y atrapada en una relación sin pasión. Durante unas vacaciones en las que Laura viaja a Sicilia, el poderoso Massimo la reconoce y, dispuesto a hacerla suya a cualquier precio, la secuestra en su lujosa mansión y le da un plazo de un año para que se enamore de él. La prensa ha dicho: «Coronada como la nueva "Cincuenta sombras".» Cosmopolitan', @Cat_Romanceertico, N'PDF/365 dias - Blanka Lipinska.pdf', N'.pdf', 0, 1);
END;

-- Libro 732: El espíritu de la laguna
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El espíritu de la laguna' AND Autor = N'Laia López')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El espíritu de la laguna', N'Laia López', N'¿Qué oscura criatura se esconde bajo las aguas de la laguna? Ahora que el curso ha terminado, Diana y sus amigos tienen por delante unas tranquilas vacaciones de verano. Sin embargo, pronto se darán cuenta de que los problemas no han hecho más que empezar... Un dragón amenaza con destruirlo todo a su paso y alguien con mucho poder en la laguna está empeñado en sellar un pacto que causará mucho dolor. Por si fuera poco, para las sirenas es más difícil que nunca ocultar su verdadera identidad, especialmente desde que un par de periodistas andan husmeando por el campus universitario... Las pesadillas de Eiden no dejan de empeorar, y su hermana Liv tampoco está pasando por un buen momento. La sospecha de que sobre la familia Kirous pesa una terrible maldición es cada vez más fuerte. La cuenta atrás para la próxima luna llena ha comenzado, pero Diana está decidida a salvar a sus amigos... sin importarle las consecuencias.', @Cat_Fantasajuvenil, N'PDF/El espíritu de la laguna - Laia López.pdf', N'.pdf', 0, 1);
END;

-- Libro 733: Princesa mecánica
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Princesa mecánica' AND Autor = N'Cassandra Clare')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Princesa mecánica', N'Cassandra Clare', N'El peligro aumenta para los Cazadores de Sombras ahora que esta trilogía, besteller del New York Times, llega a su fin. Si la única manera de salvar el mundo fuera destruyendo a quien más amás, ¿lo harías? El tiempo corre. Debes elegir. Pasión. Poder. Secretos. Magia. El peligro acecha a los Cazadores de Sombras en la entrega final de Los Orígenes.', @Cat_Fantasaurbanajuvenil, N'PDF/Princesa mecánica - Cassandra Clare.pdf', N'.pdf', 0, 1);
END;

