-- Libro 735: Reina de las sombras
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Reina de las sombras' AND Autor = N'Sarah J. Maas')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Reina de las sombras', N'Sarah J. Maas', N'La serie bestseller de The New York Times , Trono de Cristal, alcanza nuevas alturas en este cuarto volumen. Continúa el viaje épico de Celaena, cuya intensidad va en aumento hasta alcanzar una apasionada y terrible crisis que podría destrozar su mundo. Una épica travesía que ha cautivado los corazones y la imaginación de millones de personas en todo el mundo y que en su cuarta entrega mantendrá a los lectores embelesados mientras la historia de Celaena avanza in crescendo, a un ritmo de infarto que sacudirá el orbe de la nueva reina. Celaena Sardothien ha perdido a todos aquellos que ama, pero por fin está de vuelta en el imperio para vengarse, para rescatar su reino, antes glorioso, y para enfrentar las sombras de su pasado... Ha reconocido su identidad como Aelin Galathynius, reina de Terrasen. Pero antes de reclamar su trono deberá luchar. Luchará por su primo, un guerrero dispuesto a morir por volver a verla. Luchará por su amigo, un joven atrapado en una prisión inenarrable. Y luchará por su gente, que aguarda esclavizada, bajo el yugo de un inhumano rey, el retorno triunfal de su reina perdida. La crítica ha opinado: "Las motivaciones y las interacciones de los personajes aparecen siempre muy acertadas y con delicados matices, en especial conforme la creciente madurez de Aelin le ofrece nuevas perspectivas sobre viejos conocidos. Imposible dejar de leer." Kirkus Reviews "A los fans de las series de fantasía intensa les tendrá totalmente sin cuidado la prolongada historia, cargada como viene de amenazantes miradas, tensión sexual a punto de ebullición, sinuosos giros de la trama, sarcástico humor y una exuberante construcción del universo. Los capítulos finales de esta entrega" Booklist', @Cat_Fantasajuvenil, N'PDF/Reina de las sombras - Sarah J. Maas.pdf', N'.pdf', 0, 1);
END;

-- Libro 736: Rubí
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Rubí' AND Autor = N'Kerstin Gier')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Rubí', N'Kerstin Gier', N'Cruza las fronteras del tiempo y encuentra el verdadero amor. Engánchate a la saga que ha cautivado a miles de lectores. Vivir en una familia cargada de secretos no es fácil. O al menos eso es lo que piensa Gwendolyn Sheperd. Y es que en su casa nada ni nadie es del todo «normal»: empezando por su excéntrica tía abuela, pasando por la misteriosa Lucy, que se escapó de casa hace diecisiete años sin dejar rastro... y, para acabar, también está Charlotte, su encantadora y rabiosamente perfecta prima, quien, según parece, ha heredado un extraño gen familiar que le permitirá viajar en el tiempo. Pero un día Gwen se encuentra de pronto en el Londres del penúltimo cambio de siglo y comprende que el mayor secreto de su familia es ¡ella misma! Para protegerla, su madre trató de ocultarle todas las pruebas, pero en realidad ella es la última viajera en el tiempo y tiene una importante misión que cumplir. Ahora Gwen está en el ojo del huracán y parece que todo el mundo tiene un montón de advertencias que hacerle. En cambio, nadie va a decirle lo más importante: es mejor no enamorarse mientras se viaja de una época a otra, porque eso puede complicar terriblemente las cosas... Como cualquier otro día, regresé pronto a casa al salir del instituto. Mi tía se había quedado sin sus dulces favoritos y me ofrecí para ir a la tienda a comprar más. Pero de camino empecé a sentir algo muy extraño: las piernas me temblaban y tuve una sensación rara en el estómago. De repente, la calle desapareció ante mis ojos. Poco después reapareció, pero muchas cosas eran diferentes. Había vuelto al pasado. Me llamo Gwen y soy la última viajera en el tiempo. Así empieza la aventura de mi vida... Reseña: «Kerstin debe de haber lanzado algún tipo de magia entre sus páginas. La historia es alucinante... ¡Quién fuera Gwen para pasar dos horas con Gideon en un sofá! ¡A SOLAS! Sin lugar a dudas, la trilogía ES UN IMÁN del que no te podrás separar. ¡Imprescindible en tu estantería!» Eva Rubio, administradora de JUVENIL ROMÁNTICA', @Cat_Fantasajuvenil, N'PDF/Rubí - Kerstin Gier.pdf', N'.pdf', 0, 1);
END;

