-- Libro 738: Pacto de sangre
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Pacto de sangre' AND Autor = N'María Martínez')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Pacto de sangre', N'María Martínez', N'Primera entrega de la trilogía «Almas Oscuras». Para todos los amantes de las novelas de vampiros y para los que creen que el amor no entiende de fronteras ni de mundos. Desde hace siglos, vampiros y licántropos mantienen un pacto que protege a los humanos de un mundo de peligros y oscuridad. William es uno de ellos, un vampiro temible y letal. Callado y distante, su mirada esconde grandes secretos y un corazón frío como el hielo. Pero eso no es lo que le hace diferente: William es el único vampiro que puede vivir bajo el sol. Ese don le convierte en un ser especial, en la esperanza que su raza necesita, pero también en la llave que los renegados persiguen para liberarse de su maldición. Ahora, William tendrá que volver a luchar, no solo por su vida, también por la de Kate: una humana que amenaza con cambiar todo su mundo. Reseñas: «Adictiva, trepidante y sugerente.María Martínez sabe cómo cautivar al lector a través de unos diálogos y unas descripciones que dotan de vida propia a la novela. El libro que necesitaba para volver a engancharme a las historias de vampiros y licántropos.» María Cabal Gómez, administradora del blog Soy cazadora de sombras y libros. «Una estupenda novela, intensa y vibrante, con un ritmo ágil y una atmósfera muy cinematográfica. Unos personajes complejos y pasionales que parecen saltar de la página gracias al talento de la autora.» Marta Fernández, administradora del blog Tejiendo críticas en la sombra.', @Cat_Romanceparanormal, N'PDF/Pacto de sangre - Maria Martinez.pdf', N'.pdf', 0, 1);
END;

-- Libro 739: Revelada
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Revelada' AND Autor = N'P. C. Cast y Kristin Cast')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Revelada', N'P. C. Cast y Kristin Cast', N'Neferet está agora mais poderosa do que nunca, e sua busca por vingança ameaça as vidas não apenas de Zoey e seus aliados, mas de toda a humanidade. O caos impera em Tulsa, e todos passam a culpar a Morada da Noite por isso. Poderá Zoey impedir os planos terríveis de Neferet a tempo, antes que seu ódio possa desencadear uma guerra de consequências devastadoras? A série House of Night é um dos maiores fenômenos do mercado editorial, tendo alcançado a primeira posição na lista dos mais vendidos em países como Estados Unidos, Alemanha e Reino Unido, mantendo-se na lista de best-sellers do The New York Times por cerca de 150 semanas consecutivas. Agora, no penúltimo capítulo dessa aclamada série, a ação é ainda mais eletrizante, e os riscos são ainda maiores na batalha de Zoey e de seus amigos para proteger sua escola – e seu lar – da destruição. Ao mesmo tempo, os cativantes personagens criados por P. C. e Kristin Cast têm de lidar com seus sentimentos, com o jogo de amizades e traições e com o dia a dia entre as paredes da Morada da Noite.', @Cat_Fantasaparanormaljuvenil, N'PDF/Revelada - P. C. Cast y Kristin Cast.pdf', N'.pdf', 0, 1);
END;

-- Libro 740: ¿Quién mató a Alex? El misterio que nos 
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¿Quién mató a Alex? El misterio que nos une' AND Autor = N'Janeth G. S.')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¿Quién mató a Alex? El misterio que nos une', N'Janeth G. S.', N'El fenómeno que arrasa en Wattpad. Más de 37 millones de lecturas. Premio Wattys. Hannah es una adolescente de dieciséis años enganchada a las redes sociales. Pero un día recibe una solicitud de amistad de Facebook de un chico llamado Alex Crowell. Al aceptarla, descubre en el muro de Alex que está muerto. Y luego pasa algo todavía más escalofriante: recibe un mensaje privado del joven donde él le pide ayuda para averiguar quién lo mató. En una trepidante investigación, Hannah descubre que hay muchas personas involucradas en su muerte. Pero contará con una ayuda inesperada, la del fantasma de Alex.', @Cat_Misteriojuvenil, N'PDF/¿Quién mató a Alex- El misterio que nos une - Janeth G. S.pdf', N'.pdf', 0, 1);
END;

