-- Libro 743: Príncipe mecánico
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Príncipe mecánico' AND Autor = N'Cassandra Clare')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Príncipe mecánico', N'Cassandra Clare', N'Consciente del singular poder de Tessa, El Magister sigue tras sus pasos, dispuesto a acabar con los Cazadores de Sombras. Tessa, junto al bello y autodestructivo Will y el dulce y devoto Jem, iniciará un viaje que les llevará a descubrir el secreto familiar que esconde la verdadera identidad de la chica.Segundo título de la exitosa trilogía que precede la historia de Cazadores de sombras y nos desvela sus orígenes.', @Cat_Fantasajuvenil, N'PDF/Principe mecanico - Cassandra Clare.pdf', N'.pdf', 0, 1);
END;

-- Libro 744: Legend
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Legend' AND Autor = N'Marie Lu')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Legend', N'Marie Lu', N'"Legend doesn''t merely survive the hype, it deserves it." From the New York Times bestselling author of The Young Elites What was once the western United States is now home to the Republic, a nation perpetually at war with its neighbors. Born into an elite family in one of the Republic''s wealthiest districts, fifteen-year-old June is a prodigy being groomed for success in the Republic''s highest military circles. Born into the slums, fifteen-year-old Day is the country''s most wanted criminal. But his motives may not be as malicious as they seem. From very different worlds, June and Day have no reason to cross paths - until the day June''s brother, Metias, is murdered and Day becomes the prime suspect. Caught in the ultimate game of cat and mouse, Day is in a race for his family''s survival, while June seeks to avenge Metias''s death. But in a shocking turn of events, the two uncover the truth of what has really brought them together, and the sinister lengths their country will go to keep its secrets. Full of nonstop action, suspense, and romance, this novel is sure to move readers as much as it thrills.', @Cat_Cienciaficcindistopajuvenil, N'PDF/Legend - Marie Lu.pdf', N'.pdf', 0, 1);
END;

-- Libro 745: Running Mate
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Running Mate' AND Autor = N'Katie Ashley')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Running Mate', N'Katie Ashley', N'Barrett The name''s Barrett Callahan. Yeah, that Barrett Callahan-the one the press dubbed "Bare" after those naked pictures surfaced. At twenty-seven, I was armed with an MBA from Harvard, an executive position at my father''s Fortune 500 company, a penthouse, and a different piece of delectable eye candy in my bed every weekend. I had a life most men dreamed of. But then my father decided to run for president, and my playboy lifestyle became a liability to his campaign that was built on family values. My "makeover" comes in the form of a fake fiancée who I don''t even get to choose--one who is an uptight, choirgirl acting priss but also sexy-as-hell. Addison My latest relationship had gone down in flames, and I was drowning in a sea of student loans when in true Godfather status, James Callahan made me an offer I couldn''t refuse. Seven figures for seven months on the campaign trail pretending to be the adoring fiancée of his son, Barrett. As soon as he won the election, our engagement would be dissolved amicably for the press, I was free to ride off into the sunset a million dollars richer, and because of the NDA, no one would be the wiser. Sure, I''d never met the guy, but I''d been a theater nerd in high school. I could pull off any role from Lady Macbeth to Maria Von Trapp. But that was before I met my fake fiancé-the infuriating, self-absorbed, egotistical, drop-dead-sexy King of the Manwhores. The race will be a fight to the death finish, and that''s not even the actual campaign.', @Cat_Romance, N'PDF/Running Mate - Katie Ashley.pdf', N'.pdf', 0, 1);
END;

-- Libro 746: Ceaseless
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Ceaseless' AND Autor = N'Abbi Glines')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Ceaseless', N'Abbi Glines', N'Can he make her fall in love with him... again? When Pagan Moore proved worthy of Death''s devotion, he was given the gift of getting to keep her. But Dank was never promised that Pagan would keep him. When a soul is created, so is its mate. In every lifetime those souls find each other. They complete the other''s destiny. It''s time for Pagan''s soul to choose if she truly wants an eternity at Death''s side or if she wants the mate created just for her. Dank didn''t think he had to worry about her choice. He knew where her heart belonged. Until he realized that every kiss, every touch, every moment of their time together would be washed from her memories. He would have to win her heart all over again and prove to her soul that he was where she belonged. If only her soul''s mate wasn''t right there standing in his way.', @Cat_Romanceparanormal, N'PDF/Ceaseless - Abbi Glines.pdf', N'.pdf', 0, 1);
END;

-- Libro 747: El beso del traidor
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El beso del traidor' AND Autor = N'Erin Beaty')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El beso del traidor', N'Erin Beaty', N'Una chica convencida de no casarse. Un soldado desesperado por demostrar su valía. Un reino al borde de la guerra. La nueva trilogía de fantasía que está triunfando en Estados Unidos. Con una lengua afilada y un temperamento indisciplinado, Salvia no es precisamente lo que se espera de una dama, lo que no le supone ningún problema. Cuando la consideran no apta para el matrimonio, tiene que aprender de la mano de una casamentera, junto a otras jóvenes damas, cómo ser la jovencita perfecta. El único fin es que acabe contrayendo matrimonio en una alianza política. Pero Salvia sabe que tiene que estar siempre alerta, así que escucha las conversaciones de sus compañeras y de los soldados que las escoltan para enterarse de las verdades que ocultan. Cuando la escolta militar de las damas siente un levantamiento político, Salvia es reclutada por un intrépido militar para infiltrarse en las filas enemigas. Cuanto más descubre como espía, menos segura está de en quién confiar... Salvia se ve en atrapada en la representación más importante de toda su vida: de su actuación dependerá el destino del reino. ¿Podrá ser la espía que todos esperan? La crítica ha dicho... «Una historia de acción, con un argumento perfectamente trazado, repleta de traiciones y de intriga, con una heroína irresistible y un romance dulce y sexy» Publishers Weekly. Los blogs opinan... « El Beso de la Traición es un libro un poco introductorio pero que marca el principio de una trilogía que promete y que pienso seguir leyendo.» Blog Paperblog', @Cat_Fantasajuvenilromance, N'PDF/El beso del traidor - Erin Beaty.pdf', N'.pdf', 0, 1);
END;

-- Libro 748: Tras un abanico
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Tras un abanico' AND Autor = N'Stella Knightley')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Tras un abanico', N'Stella Knightley', N'Dolida y confusa por el repentino final de su extraña aventura amorosa con el millonario veneciano Marco Donato, Sarah Thomson se traslada a París, donde tratará de olvidar lo mucho que añora a Marco sumergiéndose en un nuevo proyecto: el estudio de la famosa cortesana del siglo xix Augustine Levert, cuyos encantos causaron la ruina de muchos hombres de su época. Durante su estancia en la capital francesa, Sarah se reúne con su exnovio Steven. Su relación, psicológica y sexualmente torturada, parece reavivarse. Sin embargo, cuando la vida de Sarah empieza a parecerse demasiado a la de Augustine, se da cuenta de que nunca podrá borrar a Marco de su corazón. Ambas mujeres deberán elegir entre la seguridad y la pasión arrebatadora, pero ¿serán capaces de tomar la decisión correcta?', @Cat_Ertica, N'PDF/Tras un abanico - Stella Knightley.pdf', N'.pdf', 0, 1);
END;

