-- Libro 750: Juntos
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Juntos' AND Autor = N'Ally Condie')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Juntos', N'Ally Condie', N'Nunca desafíes el juego del amor... Juntos, primera parte de la trilogía, lo tiene todo: un futuro utópico, aventura, suspense, crítica social y un amor imposible. En el mundo de Cassia, las autoridades lo deciden todo. A quién debes amar, de qué debes trabajar, incluso cuándo debes morir. Cassia nunca ha cuestionado las decisiones que han tomado por ella, ni siquiera cuando le comunican que su «pareja perfecta» -la persona con quien deberá compartir el resto de su vida- es Xander, su mejor amigo. Los problemas llegan más tarde, cuando un extraño error informático hace que en la microficha que las autoridades le han entregado aparezca la cara de otro chico: el enigmático Ky. Con una mezcla de estupefacción y curiosidad, Cassia empieza a investigar. ¿Y si este error no fuera fortuito? ¿Y si la persona de su vida no fuera quien le han asegurado que es? Al intentar buscar respuestas a todas estas preguntas, Cassia deberá afrontar una elección imposible entre la perfección y la pasión, entre Xander y Ky, entre la única vida que conoce y el camino que nadie hasta entonces se ha atrevido a seguir... Reseñas: «El mayor éxito juvenil desde Los juegos del hambre.» Entertainment Weekly «Si el mundo de Katniss te ha marcado, no puedes perderte esta saga en la que no hay libertad ni para decidir de quién te enamoras.» Seventeen Magazine «Intenso, inolvidable, adictivo.» Kirkus Review', @Cat_Distopajuvenil, N'PDF/Juntos - Ally Condie.pdf', N'.pdf', 0, 1);
END;

