-- Libro 754: #Quiérete. La receta de Vikika para ser 
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'#Quiérete. La receta de Vikika para ser feliz' AND Autor = N'Verónica Costa')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'#Quiérete. La receta de Vikika para ser feliz', N'Verónica Costa', N'En este libro, el más personal de Vikika, la autora contesta a muchas de las preguntas que recibe en sus redes sociales: cómo se cuida, de dónde saca la motivación para entrenarse y mantener una dieta saludable, cómo se marca sus metas y objetivos, lo imprescindible que es estar bien con uno mismo para poder conseguir todo lo que te propongas, el esfuerzo, el inconformismo, la importancia del amor y la amistad... También nos explicará paso a paso las recetas que le ayudan a mantener unos abdominales perfectos. #Quiérete es un grito de guerra, un tatuaje vital, un acto para hacer de la felicidad, la alegría y, sobre todo, de quererte tu prioridad. «Con este libro quiero hacer lo mismo que con mi vida: escribir algo que merezca la pena leer. O hacer algo que merezca la pena escribir.» Vikika', @Cat_Bienestarautoayuda, N'PDF/Quierete. La receta de Vikika para ser feliz - Veronica Costa.pdf', N'.pdf', 0, 1);
END;

