-- Libro 756: Detrás de un beso
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Detrás de un beso' AND Autor = N'Adriana Rubens')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Detrás de un beso', N'Adriana Rubens', N'Después de Detrás de la máscara y Detrás de tu mirada, llega la esperada tercera entrega de la serie «Whitechapel» ambientada en el Londres de finales del siglo XIX. Jacqueline Darcy fue testigo del asesinato de su hermano, y desde entonces vive escondida en Whitechapel bajo la identidad masculina de Jack Ellis. Cuando le sugieren que se convierta en el asistente del doctor Richmond para descubrir la causa del extraño comportamiento de este, ella acepta, aunque con renuencia. La relación no empieza con buen pie, pero cuanto más conoce al doctor, más se enamora de él, hasta que descubre que aquello que lo atormenta es un enemigo más temible de lo que nadie hubiese podido imaginar. Joshua Richmond tiene dos problemas. El primero es la atracción que despierta en él su nuevo asistente. El segundo, su creciente dependencia del opio, aunque al menos esto último puede controlarlo. O eso cree él. Tendrá que enfrentarse al riesgo de perder a sus seres queridos, a la vez que a sus miedos y más terribles pesadillas, para darse cuenta de que se ha metido en un infierno del que no puede escapar sin ayuda. Cualquier cosa, con tal de conseguir aquello que vislumbró detrás de un beso.', @Cat_Romancehistrico, N'PDF/Detrás de un beso - Adriana Rubens.pdf', N'.pdf', 0, 1);
END;

-- Libro 757: Oscuros. La primera maldición
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Oscuros. La primera maldición' AND Autor = N'Lauren Kate')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Oscuros. La primera maldición', N'Lauren Kate', N'Solo la luz de su amor podría iluminar la oscuridad de todo un mundo... La primera maldición es la cuarta entrega de la saga paranormal romántica «Oscuros», que narra la cruel historia de amor de Daniel y Luce. A Luce y a Daniel solo les queda una oportunidad para salvar su historia... y la del mundo. Y es que Lucifer ha desvelado por fin sus planes: quiere recrear la Caída de los Ángeles a la Tierra para alterar el tiempo y borrar, de un plumazo, todo lo acontecido en los últimos siete mil años. Luce y Daniel son los únicos que pueden detenerle, pero cuentan solo con nueve días. Así que, acompañados de sus amigos (e incluso de algún enemigo) iniciarán una carrera contrarreloj para evitar que el ángel traidor destruya el rumbo de la humanidad...', @Cat_FantasaromnticaJuvenil, N'PDF/Oscuros. La primera maldicion - Lauren Kate.pdf', N'.pdf', 0, 1);
END;

