-- Libro 760: El ladrón
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El ladrón' AND Autor = N'Tarryn Fisher')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El ladrón', N'Tarryn Fisher', N'El amor es paciente; el amor es amable; el amor no presume o alardea. No hay arrogancia en el amor; nunca es brusco, bruto ni indecente; no es egocéntrico. El amor no es fácilmente amargo. El amor no se equivoca calculando. El amor confía, cree y sobrevive a todo. El amor nunca se quedará obsoleto. Lucharé por ella.', @Cat_Romancecontemporneodrama, N'PDF/El ladron - Tarryn Fisher.pdf', N'.pdf', 0, 1);
END;

-- Libro 761: ¡Sin pretextos! Cambia el pero por el pu
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¡Sin pretextos! Cambia el pero por el puedo' AND Autor = N'Yordi Rosado')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¡Sin pretextos! Cambia el pero por el puedo', N'Yordi Rosado', N'Lo que eres es mucho más que suficiente para ser… todo lo grande que quieres ser. Sabías que: · No puedes regresar al pasado para volver a empezar, pero puedes empezar ahora y cambiar el futuro. · Cuando crees de verdad en algo, tu mente encuentra la manera de lograrlo. · Tus logros no te definen, te define lo que superas. · Las crisis son la mejor oportunidad para crecer, pues la vida te las pone en frente para que hagas algo que jamás te hubieras atrevido. · El éxito no se basa en hacer cosas extraordinarias de vez en cuando, sino en hacer cosas correctas constantemente. Así que: ¡Sin pretextos! Cambia el pero por el puedo. En este libro encontrarás un gran número de herramientas, estrategias, consejos y estudios avalados por los más grandes coach motivacionales, emprendedores, terapeutas y líderes, así como muchos de los aciertos y errores que he enfrentado para lograr mis objetivos. En este escrito te comparto situaciones muy íntimas de mi vida que jamás había contado, con el único fin de que nos ayuden a todos a mejorar. En ¡Sin Pretextos! Cambia el pero por el puedo, te invito —con una lectura fresca, documentada, sincera y al mismo tiempo muy profunda—, a que vayas por más, te empoderes, mejores tu autoestima —de forma permanente—, ubiques tus cualidades para que conozcas los alcances que realmente tienes y, especialmente, para que descubras que puedes ser muy feliz con lo que cuentas y con la persona que eres. ENGLISH DESCRIPTION You are more than enough to be... everything great that you want to be. Did you know: · You can''t go back to the past and start over again, but you can begin now and change your future. · When you really believe in something, your mind finds a way to make it happen. · Your achievements don''t define you, what you overcome defines you. · Crisis is the best opportunity for growth, so life places them in front of you so that you''ll do something you never would have dared to do before. · Success isn''t based on doing extraordinary things from time to time, rather in doing the right things consistently. So that''s why: No Excuses! Change I Can''t to I Can! In this book you will find a great number of tools, strategies, advice, and supported studies by the best motivational coaches, entrepreneurs, therapists, and leaders, as well as many wise choices and errors that I''ve made to reach my goals. In this writing, I share intimate situations of my life that I''ve never talked about before, with the only objective to help all of us improve ourselves. In, No Excuses! Change I Can''t to I Can! I invite you—with a refreshing, documented, sincere and, at the same time, very profound, read—to go for more, empower yourself, improve your self-esteem—permanently—to find your virtues so that you really understand the power you have, especially, so you will discover that you can be happy with what counts and with the person you are.', @Cat_Autoayuda, N'PDF/¡Sin pretextos! Cambia el pero por el puedo - Yordi Rosado.pdf', N'.pdf', 0, 1);
END;

