-- Libro 764: Dominada por sus compañeros
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Dominada por sus compañeros' AND Autor = N'Grace Goodwin')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Dominada por sus compañeros', N'Grace Goodwin', N'Amanda Bryant ha sido una espía durante cinco largos años, pero cuando los alienígenas aparecen repentinamente, afirmando que un enemigo mortal amenaza la supervivencia de los habitantes de la Tierra, los superiores de Amanda la envían a enfrentar la misión más peligrosa de su vida: ofrecerse para ser la novia de un alienígena, compartir la cama con el extraño guerrero y, finalmente, traicionarlo. Aceptando la tarea, Amanda es procesada como la primera novia interestelar y es transportada al otro lado de la galaxia, con dirección a la nave de guerra de su nuevo compañero. Al despertar, descubre que ha sido emparejada no solo con un gigante guerrero de Prillon, sino con dos de ellos. Estupefacta por su sed de sentir a dos machos alfas y dominantes, Amanda se da cuenta de que la amenaza para la Tierra es muy real. ¿Cómo puede proteger a los guerreros que ha terminado amando y, al mismo tiempo, impedir que las personas de la Tierra cometan un terrible error? ¿Le creerán sus contactos en la Tierra cuando, con cada uno de sus movimientos, con cada una de sus miradas, noten hasta qué punto ha sido dominada por sus compañeros?', @Cat_Romanceerticocienciaficcin, N'PDF/Dominada por sus companeros - Grace Goodwin.pdf', N'.pdf', 0, 1);
END;

