-- Libro 766: La otra Bolena
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La otra Bolena' AND Autor = N'Philippa Gregory')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La otra Bolena', N'Philippa Gregory', N'María Bolena tiene apenas catorce años cuando inicia un romance adúltero con el rey Enrique VIII, fruto del cual nacerán dos hijos. Las cosas se complican cuando su astuta y perversa hermana, Ana, se convierte en amante y consejera del rey, y trama un plan para deshacerse de la reina Catalina de Aragón.', @Cat_Novelahistrica, N'PDF/La otra Bolena - Philippa Gregory.pdf', N'.pdf', 0, 1);
END;

-- Libro 767: ¡Auxilio, somos padres! Manual para no e
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¡Auxilio, somos padres! Manual para no enloquecer (al pediatra)' AND Autor = N'Ingrid Beck y Alejandro Fainboim')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¡Auxilio, somos padres! Manual para no enloquecer (al pediatra)', N'Ingrid Beck y Alejandro Fainboim', N'Ingrid Beck vuelve con todo el humor de la «Guía (inútil) para madres primerizas». Esta vez embarca en su locura a Alejandro Fainboim, el pediatra de sus hijos. La sala de espera de un pediatra es un cuadro dantesco. Ese lugar al que llegamos luego de un arduo casting para encontrar al pediatra ideal es el caldo de cultivo de piojos, mocos y virus en todas sus variedades. Es el lugar al que llegamos con nuestras ojeras, bolsos, ropa manchada, asientos de bebé, mamaderas y a veces también con lo que queda de quien supo ser nuestra pareja. Y, por último, es el lugar donde está él o ella. Nuestra salvación: el pediatra. El hombre o la mujer que nos quitará todos los miedos, todas nuestras angustias, que nos ayudará a criar al niño o niña y que nos dirá qué hacer, cuándo y cómo. Nos dirá si está flaco o está gordo, si tiene que dejar la teta, si tiene que dejar el pañal, si ya debería decir más de diez palabras, si ya debería caminar, si ya debería dormir solo de un tirón, qué hacemos si se cae de cabeza, si se corta, si tiene fiebre, en fin, que nos confirme que somos pésimos padres y que la culpa es el motor de nuestras vidas. El pediatra es todo, por eso este libro también es para ellos, que podrán reírse de las insólitas preguntas que les hacemos los padres, en el consultorio o por teléfono a las cuatro de la madrugada porque el nene tiene tanto catarro que parece un cantor de tango.', @Cat_Crianzasaludinfantil, N'PDF/Auxilio, somos padres Manual para no enloquecer (al pediatra) - Ingrid Beck y Alejandro Fainboim.pdf', N'.pdf', 0, 1);
END;

