-- Libro 769: ¡Libre! El camino emprendedor como filos
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¡Libre! El camino emprendedor como filosofía de vida' AND Autor = N'Andy Freire')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¡Libre! El camino emprendedor como filosofía de vida', N'Andy Freire', N'Cómo utilizar herramientas del mundo emprendedor para alcanzar sus objetivos cotidianos. El carácter emprendedor es una de las cualidades más importantes en el mundo de la empresa y los negocios, a punto tal que existe un conjunto de herramientas que ayudan a desarrollarlo. Andy Freire, emprendedor por excelencia y columnista reconocido en radio y televisión, descubrió que esas herramientas pueden trascender el ámbito empresarial y ser de enorme utilidad para definir nuestros propósitos y trazar de manera dinámica y proactiva el camino para conseguirlos, que no es otro que el de una vida plena. "Emprender es mucho más que crear una empresa o una organización: es hacer que las cosas sucedan". Reducir la brecha entre lo que somos y lo que queremos ser es, en fin, la manera de alcanzar y ejercer nuestra propia libertad.', @Cat_Emprendimiento, N'PDF/Libre El camino emprendedor como filosofia de vida - Andy Freire.pdf', N'.pdf', 0, 1);
END;

