-- Libro 773: Rey de las mentiras
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Rey de las mentiras' AND Autor = N'Whitney G.')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Rey de las mentiras', N'Whitney G.', N'El hombre del que me he enamorado es un mentiroso. No tengo mucho tiempo para revelar todos los detalles, pero esos titulares de "Una mujer desaparece después de su boda" no son más que mentiras. No he desaparecido. No he huido después de mi boda. Nunca habría huido después de mi increíble luna de miel. Mi marido me ha raptado. No, me ha secuestrado. Porque, según él, "Es mejor así"; solo soy un peón en su retorcida partida de ajedrez. A pesar de que mi corazón sigue atado al suyo o de que es el hombre más arrolladoramente guapo y atractivo que he conocido en toda mi vida (aún puede hacer que me encienda solo con dirigirme la palabra), tengo que centrarme en escapar de él. Debo aceptar que ya no es el hombre del que me enamoré. Es el rey de las mentiras. La mujer de la que me he enamorado es tremendamente sexy, pero también exasperante. Está desesperadamente enamorada de mí, pero también está urdiendo un cuidadoso plan para escaparse. ¿Piensa de verdad que yo soy "el rey de las mentiras"? Ella sí que es la reina de las mentiras. Estamos en esto juntos; mentira por mentira, verdad por verdad. Los dos arrastramos un pasado doloroso, a los dos nos da miedo construir un futuro... A pesar de todo, hay un atisbo de esperanza para ambos... siempre que uno de los dos se doblegue. Somos el rey y la reina de las mentiras.', @Cat_Romancecontemporneo, N'PDF/Rey de las mentiras - Whitney G.pdf', N'.pdf', 0, 1);
END;

