END;

-- Libro 775: El café de los corazones rotos
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El café de los corazones rotos' AND Autor = N'Penelope Stokes')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El café de los corazones rotos', N'Penelope Stokes', N'Una encantadora historia de la autora que ya nos deleitó con El café de los corazones rotos. Veintitrés años atrás, la reina de belleza Peach Rondell había dejado Misisipí a sus espaldas y jurado que no regresaría nunca más. Ahora está de vuelta, divorciada y con el corazón roto, e intenta entender por qué la vida le ha ido tan mal. Para escapar de la mirada acechante de su madre, pasa el día en el pequeño Heartbreak Café, sentada a una de cuyas mesas va escribiendo en su diario, a la espera de algo que la ilumine. En lugar de eso, Peach conseguirá algo incluso mejor: la amistad inesperada de un insólito grupo de personas que le enseñarán que averiguar adónde vas suele implicar aceptar de dónde vienes. Reseñas: «Una bonita novela. Penelope stokes explora con habilidad tanto las dificultades como la satisfacción de encontrarse a sí mismo.» The Romance Readers Connection «Fantástica historia que nos devuelve a nuestros propios recuerdos y hace que revivamos las razones que nos llevaron a convertirnos en las personas que somos.» The Night Owl Reviews «Un relato divertido, conmovedor y lleno de esperanza.» De amor, libros y otras historias, sobre El café de los corazones rotos «Una escritura que destaca por su calidad. La prosa de Stokes es tersa como la mantequilla.» Publishers Weekly', @Cat_Ficcincontempornea, N'PDF/El cafe de los corazones rotos - Penelope Stokes.pdf', N'.pdf', 0, 1);
END;

-- Libro 776: Predestined
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Predestined' AND Autor = N'Abbi Glines')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Predestined', N'Abbi Glines', N'You would think after helping save her boyfriend from an eternity in Hell that things would go back to normal. Well, as normal as life can be when you can see souls and your boyfriend is Death. But for Pagan Moore, things are just getting weirder. The high school quarterback and reigning heartthrob, Leif Montgomery, is missing. While the town is in a frenzy of worry, Pagan is a nervous wreck for other reasons. Apparently good ''ol Leif isn''t your average teenage boy. He isn''t even human. According to Death, Leif doesn''t have a soul. The quarterback may have skipped town but he''s still showing up in Pagan''s dreams... uninvited. Dank has known from the beginning Leif wasn''t human. But he hadn''t worried about a simple soulless creature. Now, he realizes he made a grave mistake. Pagan''s soul has been marked since birth as a restitution, to a spirit so dark not even Death walks near it. Dank knows saving Pagan''s soul won''t be easy but Pagan is his. And he''s already proven he''ll defy Heaven to keep her. If Hell wants a piece of him too, then bring it on.', @Cat_Romanceparanormal, N'PDF/Predestined - Abbi Glines (2).pdf', N'.pdf', 0, 1);
END;

-- Libro 777: Corazón indomable
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Corazón indomable' AND Autor = N'Elena Montagud')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Corazón indomable', N'Elena Montagud', N'Le has dado una segunda oportunidad y te ha vuelto a fallar. ¿Existe alguna fórmula mágica para superar el desengaño? Tras Corazón elástico, llega Corazón indomable, la segunda novela de la trilogía «Corazón», en la que Elena Montagud vuelve a sorprendernos con una historia de relaciones aparentemente imposibles y sensualmente inevitables. A esta novela le sigue el desenlace Corazón desnudo. ADVERTENCIA: Esta historia tierna y pasional puede provocarte los sueños más eróticos. Después de la ruptura con Adrián, Blanca regresa a su vida anterior. Mucho trabajo, algún ligue sin importancia, fiesta y descontrol. Ella sabe que eso no es lo que le conviene ni lo que desea de verdad, aunque cualquier cosa es mejor que quedarse en casa echando de menos a un hombre al que no es capaz de perdonar. Pero Adrián no se da por vencido. Quizá las circunstancias no los hayan ayudado, ni en la adolescencia ni tampoco ahora. Quizá ambos hayan dejado que el sexo devore las palabras... Pero lo que está claro es que la atracción sigue viva como una llama, encendiendo sus cuerpos para luego hacerlos pelear de nuevo, con la misma voracidad con la que antes hicieron el amor. ¿Hay solución para esta pareja imposible? Él despierta en ti las emociones más desatadas: pasión, odio, temor, deseo... Ese chico se está convirtiendo en el dueño de tu placer. Frágil, sexy, sincero, atrevido... Nunca lo olvidarás.', @Cat_Romancecontemporneo, N'PDF/Corazón indomable - Elena Montagud.pdf', N'.pdf', 0, 1);
END;

