-- Libro 779: La ensenada Calibán
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La ensenada Calibán' AND Autor = N'S. D. Perry')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La ensenada Calibán', N'S. D. Perry', N'La ensenada de la bioquímica y médico militar Rebecca Chambers, única superviviente del equipo Bravo de Racoon City, se une a una nueva fuerza de ataque de los STARS cuando les llega el rumor de la existencia de otro centro experimental de Umbrella. Se encuentra oculto bajo los acantilados rocosos de la Ensenada de Calibán, un pueblo de Maine, donde alguien está reuniendo un ejército de zombies. Los STARS deben llegar al interior del siniestro faro tras atravesar un laberinto de cuevas submarinas y, finalmente, enfrentarse dentro de los restos de un naufragio a horrores inenarrables.', @Cat_Terrorcienciaficcin, N'PDF/La ensenada Calibán - S. D. Perry.pdf', N'.pdf', 0, 1);
END;

-- Libro 780: ¡Despierta!... que la vida sigue
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¡Despierta!... que la vida sigue' AND Autor = N'César Lozano')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¡Despierta!... que la vida sigue', N'César Lozano', N'En este libro el Dr. César Lozano nos invita a tratar de ser felices y disfrutar de la vida, incluso de los más pequeños detalles Del autor bestseller de Por el placer de vivir, Destellos, El lado fácil de la gente difícil. César Lozano ha motivado a más de 20 millones de personas en el mundo. Reflexiones para disfrutar plenamente la vida. Esta es una obra en la que el Dr. César Lozano nos exhorta a valorar lo que tenemos; es un reconocimiento de que nuestra vida es breve y pasajera pero que, para aquellos que tenemos esperanza, siempre nos lleva al verdadero despertar. ¡Despierta!... que la vida sigue ofrece valiosas fórmulas y técnicas que te sacudirán para que no te quedes enredado en tus problemas y disfrutes de los mejores momentos de tu vida: una sonrisa de tus hijos, la caricia de un ser querido, la alegría de hacer algo por alguien desconocido. Después de leer este libro, tus relaciones tendrán un nuevo sentido y habrás encontrado la verdadera motivación para fijar sentirte feliz.', @Cat_Autoayudareflexin, N'PDF/Despierta... que la vida sigue - Cesar Lozano.pdf', N'.pdf', 0, 1);
END;

-- Libro 781: Oscuros
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Oscuros' AND Autor = N'Lauren Kate')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Oscuros', N'Lauren Kate', N'Oscuros (en inglés: Fallen) es una novela romántica de ángeles caídos dirigida al público adolescente, escrita por Lauren Kate y publicada en 2009.
De esta gran historia de fantasía se desprenden 5 libros más y un anexo, en total 6, el primero es Oscuros (2009), el segundo El poder de las sombras (2010), el tercero La trampa del amor  (2011), el cuarto La primera maldición (2012), y el quinto El retorno de los caídos (2015). Después de que se publicara el primer libro de "Oscuros" en 2009, los derechos de los cinco libros fueron comprados en su totalidad para ser llevados a la gran pantalla. El 9 de septiembre del 2022 Variety informo sobre la preparación de una serie de televisión de Fallen (Oscuros), la producción esta acargo de Silve Reel y Night Train Media, con la coproducción del servicio de streaming brasileño Globoplay.​ La saga ha sido traducida a más de 30 idiomas.
Lauren Kate publicó en noviembre de 2015 el quinto libro de la saga llamado en inglés "Unforgiven", que se centra solo en el personaje de Cam, el personaje antagonista de "Oscuros". Según Kate la historia narra qué fue lo que pasó con Cam una vez que termina el libro "La primera maldición", esto fue como respuesta a los fanes que querían saber más de este personaje y qué es lo que le depara después de su misteriosa despedida en el último libro.
El anexo se llama La eternidad y un día (2012), donde se relata la historia de amor de 4 de las parejas principales de la historia.​', @Cat_Fantasaparanormalromancejuvenil, N'PDF/Oscuros - Lauren Kate.pdf', N'.pdf', 0, 1);
END;

-- Libro 782: ¡Buenos días, princesa!
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¡Buenos días, princesa!' AND Autor = N'Blue Jeans')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¡Buenos días, princesa!', N'Blue Jeans', N'Han pasado algo más de dos años en la vida de los chicos que forman “el club de los incomprendidos”. Las cosas han cambiado desde que uno tras otro se fueron encontrando en el camino. Nuevos problemas, secretos, amores, celos... Sin embargo, hasta el momento, su amistad ha podido con todo y con todos.Raúl, se ha convertido en un atractivo joven y en un líder nato; Valeria, derrocha simpatía por donde pisa, aunque no ha vencido del todo a su timidez; Eli, es la que más se ha transformado de todos y se los lleva de calle; María, vigila y sueña tras sus gafas de pasta de color azul; Bruno, no consigue olvidar lo que siente y en lo más profundo de su corazón espera ser correspondido; y Ester, es la nuera que toda madre querría tener aunque no es tan inocente como todos piensan.Son seis chicos que sienten, sufren, aman, creen, ríen, evolucionan... como otros chicos de su edad. Pero los seis son especiales. Al menos, para el resto del grupo.¿Conseguirán superar todas las pruebas que se le van a presentar?Sólo puedes averiguarlo leyendo, ¡Buenos días, princesa!', @Cat_Juvenilromance, N'PDF/Buenos dias, princesa - Blue Jeans.pdf', N'.pdf', 0, 1);
END;

-- Libro 783: Hermano Lobo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Hermano Lobo' AND Autor = N'Michelle Paver')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Hermano Lobo', N'Michelle Paver', N'Hermano lobo es la primera entrega de la serie «Crónicas de la prehistoria». Una historia de amistad y aventuras en la prehistoria que encantará a los niños de todas las edades. Hace miles de años, un niño llamado Torak vive feliz en el bosque, hasta el día en que un oso gigante ataca y hiere a su padre. Moribundo, éste le ordena que se dirija al Norte para encontrar la Montaña del Espíritu del Mundo, antes de que aparezca en el cielo la Luna del Sauce Rojo. Pero Torak sólo tiene doce años, desconoce qué camino tomar y no puede acudir a nadie en busca de ayuda. Sin embargo, perseguido por el enorme oso, el niño emprende el viaje acompañado de un lobezno que ha encontrado a la orilla de un río. Pronto se unirá a ellos Renn, una niña perteneciente al Clan del Cuervo, y juntos vivirán emocionantes y peligrosas aventuras que pondrán a prueba su valor, su habilidad como cazadores, su inteligencia y su naciente amistad. La crítica ha dicho... « Hermano Lobo es el tipo de novela que sueñas con leer y que es tan difícil encontrar.» The Times «Impresionante.» The Guardian', @Cat_Fantasajuvenilaventura, N'PDF/Hermano Lobo - Michelle Paver.pdf', N'.pdf', 0, 1);
END;

-- Libro 784: ¡Hazlo!
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¡Hazlo!' AND Autor = N'Seth Godin')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¡Hazlo!', N'Seth Godin', N'Este libro es una llamada de atención sobre las iniciativas que estás tomando, en el trabajo y en cuanto te concierne. Ha llegado el momento de que dejes de esperar a que alguien te proporcione un mapa del camino y empieces a dibujarlo tú mismo. Llevamos a nuestros hijos al colegio y nos obsesionamos con sus notas, su comportamiento y su capacidad de integración. Colgamos una oferta de trabajo y buscamos experiencia, universidades de prestigio y una carrera sin fracasos. Y entonces, ¿por qué nos sorprendemos cuando todo se desmorona? Nuestra economía no es estática, pero actuamos como si lo fuera. Tu posición en el mundo se define en función de lo que emprendes, de cómo lo haces y de lo que aprendes de los acontecimientos que causas. ¡Hazlo! Constituye un manifiesto sobre la producción de algo que escasea y es, por lo tanto, valioso. Ha llegado el momento de que dejes de esperar a que alguien te proporcione un mapa del camino y empieces a dibujarlo tú mismo. Este libro quizá te haga sentir incómodo. Es una llamada de atención sobre las iniciativas que estás tomando, en el trabajo y en cuanto te concierne. Pero también puede ser el puntapié que necesitas para introducir un cambio en tu vida.', @Cat_Emprendimientomotivacin, N'PDF/Hazlo - Seth Godin.pdf', N'.pdf', 0, 1);
END;

-- Libro 785: Las 7 leyes espirituales del éxito
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Las 7 leyes espirituales del éxito' AND Autor = N'Deepak Chopra')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Las 7 leyes espirituales del éxito', N'Deepak Chopra', N'En Las siete leyes espirituales del éxito se destila la esencia de las enseñanzas de Chopra en siete sencillos pero poderosos principios, que pueden ser fácilmente aplicados para crear el éxito en todas las áreas de su vida. Colmado de eterna sabiduría, y pasos prácticos que usted puede poner en práctica de inmediato, este es un libro que apreciará toda su vida, pues en su interior se encuentran los secretos para que todos sus sueños se hagan realidad. Basado en las leyes naturales que gobiernan la creación, este libro destruye el mito de que el éxito es el resultado del trabajo arduo, de la esmerada planificación o de la ambición. Deepak Chopra ofrece a cambio, una perspectiva sobre la consecución del éxito capaz de transformar su vida. Cuando comprendemos nuestra verdadera naturaleza y aprendemos a vivir en armonía con las leyes naturales brotan, con facilidad y sin esfuerzo, el sentido de bienestar, la buena salud, las relaciones satisfactorias y la abundancia material.', @Cat_EspiritualidadAutoayuda, N'PDF/Las 7 leyes espirituales del exito - Deepak Chopra (2).pdf', N'.pdf', 0, 1);
END;

-- Libro 786: Tomada por sus compañeros
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Tomada por sus compañeros' AND Autor = N'Grace Goodwin')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Tomada por sus compañeros', N'Grace Goodwin', N'El príncipe Nial es desterrado y se le niega su derecho a reclamar una pareja. Acompañado por su segundo, se dirige a la Tierra. Rechazada una vez, Jessica está lejos de perdonar y olvidar. Cuando el príncipe Nial regrese y defienda su derecho de nacimiento, ¿Jessica se someterá a feroces y dominantes guerreros para salvar a todos?', @Cat_Romanceerticocienciaficcin, N'PDF/Tomada por sus compañeros - Grace Goodwin.pdf', N'.pdf', 0, 1);
END;

