-- Libro 788: Blue Moon: El espíritu de la laguna
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Blue Moon: El espíritu de la laguna' AND Autor = N'Laia López')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Blue Moon: El espíritu de la laguna', N'Laia López', N'¿Qué oscura criatura se esconde bajo las aguas de la laguna? Ahora que el curso ha terminado, Diana y sus amigos tienen por delante unas tranquilas vacaciones de verano. Sin embargo, pronto se darán cuenta de que los problemas no han hecho más que empezar... Un dragón amenaza con destruirlo todo a su paso y alguien con mucho poder en la laguna está empeñado en sellar un pacto que causará mucho dolor. Por si fuera poco, para las sirenas es más difícil que nunca ocultar su verdadera identidad, especialmente desde que un par de periodistas andan husmeando por el campus universitario... Las pesadillas de Eiden no dejan de empeorar, y su hermana Liv tampoco está pasando por un buen momento. La sospecha de que sobre la familia Kirous pesa una terrible maldición es cada vez más fuerte. La cuenta atrás para la próxima luna llena ha comenzado, pero Diana está decidida a salvar a sus amigos... sin importarle las consecuencias.', @Cat_Fantasajuvenil, N'PDF/Blue Moon El espiritu de la laguna - Laia Lopez.pdf', N'.pdf', 0, 1);
END;

-- Libro 789: Mafia Queen
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Mafia Queen' AND Autor = N'Bella J.')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Mafia Queen', N'Bella J.', N'Rules. I''m starting to think I have the natural talent for breaking them. I hate rules. Always have. Especially since I had them shoved in my face my entire life. I didn''t ask to be a Valenti. And I sure as hell didn''t agree to follow all their goddamn rules. Yet it''s been years since I broke one of my family''s most cardinal laws. It was a mistake-I know that now. But that''s the thing about mistakes. You never know you''re about to make one until it''s too late. Unfortunately, every transgression, every wrong decision has a way to demand atonement. No matter if it''s hours, days, or years after. I''m still waiting for my past mistakes to exact payment. It''ll come. I know it will. But now, while I''m sitting in the interrogation room staring at the sinfully gorgeous Detective Lorik Stone, I can''t help but think about all my family''s rules... ...and how I''m about to break another one.', @Cat_Romancemafia, N'PDF/Mafia Queen - Bella J..pdf', N'.pdf', 0, 1);
END;

-- Libro 790: Inteligencia práctica: el arte y la cien
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Inteligencia práctica: el arte y la ciencia del sentido común' AND Autor = N'Karl Albrecht')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Inteligencia práctica: el arte y la ciencia del sentido común', N'Karl Albrecht', N'El autor de Inteligencia social, Karl Albrecht, da un paso más y nos explica que la inteligencia práctica puede considerarse una de las aptitudes vitales clave. Karl Albrecht, autor de Inteligencia social, aborda ahora el tema de la inteligencia práctica, y nos muestra que quienes la poseen toman mejores decisiones, son capaces de pensar en términos de opciones y posibilidades, convivir con la ambigüedad y la complejidad, articular problemas con claridad y trabajar hasta dar con soluciones, además de tener ideas originales y creativas. Inteligencia práctica es el perfecto compañero de cualquiera que desee aprender a pensar con mayor claridad y eficacia. Opinión: «Tal u como hizo en su brillante libro Inteligencia social, Karl Albercht nos regala una obra lúcida y amena sobre algo tan necesario como la inteligencia práctica. Su lectura no les dejará indiferentes: les abrirá nuevas puertas de pensamiento y creatividad y, probablemente, les dará claves sumamente útiles para gestionar la gran oportunidad que es la vida» Álex Rovira', @Cat_PsicologaDesarrollopersonal, N'PDF/Inteligencia practica - el arte y la ciencia del sentido comun - Karl Albrecht (2).pdf', N'.pdf', 0, 1);
END;

