-- Libro 797: ¡No te prives! Defensa de la ciudadanía
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¡No te prives! Defensa de la ciudadanía' AND Autor = N'Fernando Savater')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¡No te prives! Defensa de la ciudadanía', N'Fernando Savater', N'Er político en el sentido auténtico del término, no en el insultante y pueril, es preferir enmendar errores a linchar culpables. Actualmente, en España, los debates políticos giran en torno al rechazo abrupto a los gobernantes por ineficaces o corruptos, la desconfianza en las instituciones a causa de la crisis económica y las pulsiones separatistas en Cataluña o el País Vasco. Pero no siempre queda claro en todas estas cuestiones en qué consiste el papel de la ciudadanía democrática, que es lo que realmente está en juego. Con la fuerza y la valentía que le caracteriza, Savater trata de dilucidar ese punto y plantear la irrenunciable defensa de los derechos y garantías del ciudadano, recordando también sus deberes: porque sin apoyarse en ellos cualquier intento de solución política está condenado de antemano a la frustración o la involución democrática hacia populismo retrógrados. Una obra combativa pero que no renuncia juntamente a ser pedagógica.', @Cat_Ensayopoltico, N'PDF/¡No te prives! Defensa de la ciudadanía - Fernando Savater.pdf', N'.pdf', 0, 1);
END;

