-- Libro 801: El libro de la vida
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El libro de la vida' AND Autor = N'Deborah Harkness')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El libro de la vida', N'Deborah Harkness', N'El desenlace de «El descubrimiento de las brujas». Un magistral cierre del suspense y la magia de una trilogía que ha cautivado a millones de lectores en todo el mundo. Tras viajar en el tiempo con La sombra de la noche, la historiadora y bruja Diana Bishop y el genetista Matthew Clairmont vuelven al presente para hacer frente a nuevos problemas y a viejos enemigos. Pero la amenaza real para su futuro todavía está por llegar y, cuando lo hace, la búsqueda del Ashmole 782 y sus páginas perdidas cobra aún mayor urgencia. En casas ancestrales y laboratorios universitarios, haciendo uso de conocimientos antiguos y de la ciencia moderna, desde las colinas de la campiña francesa hasta los palacios de Venecia, la pareja al fin desvelará lo que las brujas descubrieron hace siglos. ¿En qué consistía el secreto encerrado en el misterioso Ashmole 782 y después perseguido incansablemente por daimones, vampiros y brujos? ¿Cómo podrán la bruja Diana y el vampiro Matthew vivir su amor y cumplir con su misión bajo el peso de todas las diferencias que los separan? La gran aventura culmina aquí. ENGLISH DESCRIPTION The #1 New York Times bestselling series finale and sequel to A Discovery of Witches and Shadow of Night. Look for the hit TV series “A Discovery of Witches” airing Sundays on AMC and BBC America, and streaming on Sundance Now and Shudder. Bringing the magic and suspense of the All Souls Trilogy to a deeply satisfying conclusion, this highly anticipated finale went straight to #1 on the New York Times bestseller list. In The Book of Life, Diana and Matthew time-travel back from Elizabethan London to make a dramatic return to the present—facing new crises and old enemies. At Matthew’s ancestral home, Sept-Tours, they reunite with the beloved cast of characters from A Discovery of Witches—with one significant exception. But the real threat to their future has yet to be revealed, and when it is, the search for Ashmole 782 and its missing pages takes on even more urgency.', @Cat_Fantasaromanceparanormal, N'PDF/El libro de la vida - Deborah Harkness.pdf', N'.pdf', 0, 1);
END;

-- Libro 802: Solo Tuya
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Solo Tuya' AND Autor = N'Anabel García')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Solo Tuya', N'Anabel García', N'Solo tuya es el primer álbum de estudio de la cantante y actriz mexicana Aracely Arámbula. Este fue lanzado por el sello Disa Records en 14 de mayo de 2002 como un disco compacto y un casete.​ Solo tuya alcanzó número 35 en la lista de Billboard de los álbumes de música latina y número 19 en México.​ Los dos sencillos — «Te quiero más que ayer», el dúo con Palomo, y «Ojalá» — fueron lanzados en 2002. «Te quiero más que ayer» logró número nueve en México y número 27 en la lista Billboard Hot Latin Tracks.', @Cat_Romanceertico, N'PDF/Solo Tuya - Anabel Garcia.pdf', N'.pdf', 0, 1);
END;

-- Libro 803: Allegiant
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Allegiant' AND Autor = N'Veronica Roth')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Allegiant', N'Veronica Roth', N'The explosive conclusion to Veronica Roth''s #1 New York Times bestselling Divergent trilogy reveals the secrets of the dystopian world that captivated millions of readers and film fans in Divergent and Insurgent. One choice will define you. What if your whole world was a lie? What if a single revelation—like a single choice—changed everything? What if love and loyalty made you do things you never expected? Told from a riveting dual perspective, this third installment in the series follows Tris and Tobias as they battle to comprehend the complexities of human nature—and their selves—while facing impossible choices of courage, allegiance, sacrifice, and love. And don''t miss The Fates Divide, Veronica Roth''s powerful sequel to the bestselling Carve the Mark!', @Cat_Distopacienciaficcinjuvenil, N'PDF/Allegiant - Veronica Roth.pdf', N'.pdf', 0, 1);
END;

-- Libro 804: La ladrona de libros
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La ladrona de libros' AND Autor = N'Markus Zusak')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La ladrona de libros', N'Markus Zusak', N'Trying to make sense of the horrors of World War II, Death relates the story of Liesel--a young German girl whose book-stealing and story-telling talents help sustain her family and the Jewish man they are hiding, as well as their neighbors.', @Cat_Novelahistrica, N'PDF/La ladrona de libros - Markus Zusak.pdf', N'.pdf', 0, 1);
END;

-- Libro 805: Mafia Princess
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Mafia Princess' AND Autor = N'Bella J.')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Mafia Princess', N'Bella J.', N'La princesa de la mafia (título original: Mafia Princess) es un telefilme estadounidense de drama y crimen de 1986, dirigido por Robert L. Collins,​ escrito por Robert W. Lenski, está basado en un libro de Antoinette Giancana y Thomas C. Renner; musicalizado por Lee Holdridge, en la fotografía estuvo Alexander Gruszynski y los protagonistas son Susan Lucci, Kathleen Widdoes y Tony Curtis, entre otros.​ Este largometraje fue producido por Group W y se estrenó el 19 de enero de 1986.', @Cat_Romancemafia, N'PDF/Mafia Princess - Bella J..pdf', N'.pdf', 0, 1);
END;

-- Libro 806: La sombra de la noche
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La sombra de la noche' AND Autor = N'Deborah Harkness')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La sombra de la noche', N'Deborah Harkness', N'Picking up from A Discovery of Witches’ cliffhanger ending, Shadow of Night takes Diana and Matthew on a trip through time to Elizabethan London, where they are plunged into a world of spies, magic, and a coterie of Matthew’s old friends, the School of Night. As the search for Ashmole 782 deepens and Diana seeks out a witch to tutor her in magic, the net of Matthew’s past tightens around them, and they embark on a very different—and vastly more dangerous—journey.', @Cat_Fantasaromanceparanormal, N'PDF/La sombra de la noche - Deborah Harkness.pdf', N'.pdf', 0, 1);
END;

-- Libro 807: La conspiración Umbrella
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La conspiración Umbrella' AND Autor = N'S. D. Perry')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La conspiración Umbrella', N'S. D. Perry', N'La Unidad de Rescate y Tácticas Especiales (STARS) se ha desplegado en Racoon City para investigar el caos. Se trata de un ecléctico grupo de especialistas: el rebelde Chris Redfield, la antigua ladrona de guante blanco Jill Valentine, el combativo Barry Burton y el enigmático jefe de la unidad, Albert Wesker. Pero lo que los STARS descubren cuando entran en la mansión es un terror que supera sus peores pesadillas: criaturas que desafían las leyes de la vida y de la muerte. S. D. Perry es la autora de casi todos los libros de la serie Resident Evil. También ha escrito novelas sobre Alien y novelizaciones de películas.', @Cat_Terrorcienciaficcin, N'PDF/La conspiracion Umbrella - S. D. Perry.pdf', N'.pdf', 0, 1);
END;

-- Libro 808: La redención de Gabriel
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La redención de Gabriel' AND Autor = N'Sylvain Reynard')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La redención de Gabriel', N'Sylvain Reynard', N'El profesor Gabriel Emerson ha dejado su plaza en la Universidad de Toronto para iniciar una nueva vida junto a su amada Julianne. Está seguro de que juntos podrán enfrentarse a cualquier desafío, in cluso a su deseo de ser padre. Pero el programa de doctorado de la joven pondrá a prueba los planes de Gabriel, ya que la dura vida de estudiante le roba demasiado tiempo. Cuando Julianne recibe el honor de dar una conferencia en Oxford, éste se muestra reacio, pues ambos tienen opiniones encontradas sobre la materia. Para complicar un poco más la relación, aparecen varios personajes del pasado empeñados en humillar a Julia y en sacar a la luz uno de los secretos más oscuros de Gabriel', @Cat_Romancecontemporneo, N'PDF/La redencion de Gabriel - Sylvain Reynard.pdf', N'.pdf', 0, 1);
END;

-- Libro 809: Oscuros. La eternidad y un día
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Oscuros. La eternidad y un día' AND Autor = N'Lauren Kate')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Oscuros. La eternidad y un día', N'Lauren Kate', N'La eternidad y un día es la quinta novela de la saga «Oscuros», y funciona como una secuela en la que la autora aborda, además de la historia de amor principal entre Luce y Daniel, los romances entre otros personajes de la saga, en el marco de la celebración de San Valentín. Inesperado Prohibido No correspondido Eterno El amor tiene muchas caras, pero un solo corazón... «El amor eterno de Luce y Daniel es emblemático, pero no es el único tipo de amor posible... Este es un libro inspirado por vosotros, mis lectores, que habéis compartido conmigo vuestras historias de amor desde el principio y me habéis mostrado las distintas formas que puede adoptar el más elevado de los sentimientos. » La eternidad y un día es un grand tour de romanticismo que atraviesa el tiempo y los corazones. Acercaos un poco más a la eternidad de Luce y Daniel y descubrid los derroteros amorosos de Miles, Shelby, Roland, Arriane...» Lauren Kate, la autora Reseña: «Sexy, fascinante y estremecedora. ¡Me encantó!» P.C. Cast, autora de La Casa de la Noche', @Cat_FantasaromnticaJuvenil, N'PDF/Oscuros. La eternidad y un dia - Lauren Kate.pdf', N'.pdf', 0, 1);
END;

-- Libro 810: This Girl
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'This Girl' AND Autor = N'Colleen Hoover')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'This Girl', N'Colleen Hoover', N'From the New York Times bestselling author of It Ends With Us, Colleen Hoover’s bestselling Slammed series comes to its gripping conclusion. There are two sides to every love story. Now hear Will’s. Layken and Will’s love has managed to withstand the toughest of circumstances, and the young lovers, now married, are beginning to feel safe and secure in their union. As much as Layken relishes their new life together, she finds herself wanting to know everything there is to know about her husband, even though Will makes it clear he prefers to keep the painful memories of the past where they belong. Still, he can’t resist his wife’s pleas, and so he begins to untangle his side of the story, revealing for the first time his most intimate feelings and thoughts, retelling both the good and bad moments, and sharing a few shocking confessions of his own from the time when they first met. In This Girl, Will tells the story of their complicated relationship from his point of view. Their future rests on how well they deal with the past in this final instalment of the beloved Slammed series.', @Cat_Romancecontemporneo, N'PDF/This Girl - Colleen Hoover.pdf', N'.pdf', 0, 1);
END;

-- Libro 811: Tras una máscara
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Tras una máscara' AND Autor = N'Stella Knightley')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Tras una máscara', N'Stella Knightley', N'Sarah Thompson viaja a Venecia con un doble objetivo: profundizar en su trabajo de doctorado e intentar, además, superar la ruptura con su novio Steven. Sin embargo, el seductor Marco Donato le roba enseguida la capacidad de concentrarse. A pesar de que su relación es cada vez más profunda, el misterioso millonario la reta a participar en un juego repleto de sombras tras las que él se esconde. ¿De qué está huyendo Marco? La tesis de Sarah se centra en la joven veneciana Luciana Giordano. En una época en la que el desenfreno sexual era el pasatiempo favorito de la ciudad, la virginal Luciana permanece oculta y custodiada por una estricta carabina... hasta que conoce a Giacomo Casanova. El legendario amante le descubrirá no solo los secretos del erotismo y el placer, sino que también le dará las claves para obtener la libertad.', @Cat_Romanceertico, N'PDF/Tras una mascara - Stella Knightley.pdf', N'.pdf', 0, 1);
END;

-- Libro 812: Una noche mágica
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Una noche mágica' AND Autor = N'Lisa Kleypas')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Una noche mágica', N'Lisa Kleypas', N'Una encantadora novela de la inimitable Lisa Kleypas, que te hará llorar y reír, a veces al mismo tiempo. Una niña que necesita una familia. Una noche lluviosa, la pequeña Holly perdió a la única familia que conocía: su madre, Victoria. Y desde esa noche no ha vuelto a pronunciar una sola palabra. Un soltero que necesita una esposa. Lo último que necesita Mark Nolan en su vida es una niña de seis años. Pero pronto se da cuenta de que hará todo lo que esté en su mano para que a Holly no le falte de nada. El testamento de su hermana le señala el camino correcto: «Eres la única alternativa. Solo tienes que quererla. El resto vendrá solo.» A veces solo hace falta un poco de magia... Maggie Conroy no se atreve a enamorarse de nuevo, pero cree en la magia de la imaginación. Cuando conoce a Holly Nolan, ve a una niña desesperada por un poco de magia en su vida... Tres personas solitarias. Tres vidas que se encuentran en una encrucijada. Tres seres que están a punto de descubrir que a veces los deseos encuentran el modo de llegar a casa... ENGLISH DESCRIPTION Now a Hallmark Hall of Fame television movie, CHRISTMAS WITH HOLLY (previously published as CHRISTMAS EVE AT FRIDAY HARBOR) is the first book in New York Times bestselling author Lisa Kleypas''s new series, which begins during the most magical time of year... ONE LITTLE GIRL NEEDS A FAMILY One rain-slicked night, six-year-old Holly lost the only parent she knew, her beloved mother Victoria. And since that night, she has never again spoken a word. ONE SINGLE MAN NEEDS A WIFE The last thing Mark Nolan needs is a six-year-old girl in his life. But he soon realizes that he will do everything he can to make her life whole again. His sister''s will gives him the instructions: There''s no other choice but you. Just start by loving her. The rest will follow. SOMETIMES, IT TAKES A LITTLE MAGIC… Maggie Collins doesn''t dare believe in love again, after losing her husband of one year. But she does believe in the magic of imagination. As the owner of a toy shop, she lives what she loves. And when she meets Holly Nolan, she sees a little girl in desperate need of a little magic. …TO MAKE DREAMS COME TRUE Three lonely people. Three lives at the crossroads. Three people who are about to discover that Christmas is the time of year when anything is possible, and when wishes have a way of finding the path home…', @Cat_Romancecontemporneo, N'PDF/Una noche magica - Lisa Kleypas.pdf', N'.pdf', 0, 1);
END;

