-- Libro 818: Tower of Dawn
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Tower of Dawn' AND Autor = N'Sarah J. Maas')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Tower of Dawn', N'Sarah J. Maas', N'Poder, alianzas, guerra, venganza... La travesía a un imperio distante de sanadores mágicos. Chaol Westfall siempre se ha definido a sí mismo como un hombre de lealtad inquebrantable, de gran fortaleza y a partir de su posición como capitán de la Guardia. Pero todo eso ha cambiado desde que el castillo de cristal se hizo añicos: sus hombres fueron diezmados y el rey de Adarlan lo libró de un golpe mortal pero dejó su cuerpo destrozado. Su única oportunidad de recuperarse reside en los legendarios curanderos de la Torre Cesme en Antica -el bastión del poderoso imperio en el Continente Meridional. Y ahora que la guerra se cierne sobre Dorian y Aelin de vuelta en casa, su supervivencia quizá dependa de que Chaol y Nesryn convenzan a sus regidores de formar una alianza con ellos. Pero lo que descubren en Antica los cambiará por completo y será más vital salvar a Erilea de lo que podrían haber imaginado. ENGLISH DESCRIPTION In the next installment of the New York Times bestselling Throne of Glass series, follow Chaol on his sweeping journey to a distant empire. Chaol Westfall has always defined himself by his unwavering loyalty, his strength, and his position as the Captain of the Guard. But all of that has changed since the glass castle shattered, since his men were slaughtered, since the King of Adarlan spared him from a killing blow, but left his body broken. His only shot at recovery lies with the legendary healers of the Torre Cesme in Antica--the stronghold of the southern continent''s mighty empire. And with war looming over Dorian and Aelin back home, their survival might lie with Chaol and Nesryn convincing its rulers to ally with them. But what they discover in Antica will change them both--and be more vital to saving Erilea than they could have imagined.', @Cat_Fantasajuvenil, N'PDF/Tower of Dawn - Sarah J. Maas.pdf', N'.pdf', 0, 1);
END;

-- Libro 819: Corazón elástico
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Corazón elástico' AND Autor = N'Elena Montagud')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Corazón elástico', N'Elena Montagud', N'Si tu primer amor te destrozó el corazón, ¿crees que merece una segunda oportunidad? Corazón elástico es la primera novela de la trilogía «Corazón», en la que Elena Montagud vuelve a sorprendernos con una historia de rabiosa actualidad, una relación tan tormentosa como sensual y unos protagonistas inolvidables. A esta novela le siguen: Corazón indomable y Corazón desnudo. ADVERTENCIA: Esta historia romántica e increíblemente sexy puede alterar el ritmo de tu corazón. Blanca es una abogada capaz y decidida, una amante experta que disfruta de una activa y variada vida sexual, una mujer moderna que no quiere compromisos ni ataduras. Pero hay alguien a quien no ha conseguido olvidar: Adrián, su mejor y único amigo en la adolescencia, el joven a quien entregó su virginidad y con quien vivió un primer amor sensual e inesperado, el chico que le falló y al que ha intentado desterrar de su mente con innumerables ligues de una noche. Ahora ha llegado la hora de enfrentarse al pasado, al pueblo agobiante del que huyó años atrás y, tal vez también, al hombre que a pesar de todo sigue convirtiendo sus sueños en fantasías eróticas de alto voltaje. Una novela sobre el hechizo del primer amor: ese chico tan especial que sigue haciéndote vibrar de placer muchos años después. Arrollador, ingenuo, inocente, sensual... Nunca lo olvidarás.', @Cat_Romance, N'PDF/Corazon elastico - Elena Montagud.pdf', N'.pdf', 0, 1);
END;

-- Libro 820: Bad Boy's Girl: Te odiaré hasta que te q
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Bad Boy''s Girl: Te odiaré hasta que te quiera' AND Autor = N'Blair Holden')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Bad Boy''s Girl: Te odiaré hasta que te quiera', N'Blair Holden', N'#BadBoysGirl, el nuevo fenómeno de la plataforma de lectura Wattpad, con más de 130 millones de lecturas, llega a las librerías. Tessa es una chica del montón. Su plan para el último curso del instituto es pasar desapercibida y seguir admirando a su fichaje, Jay Stone, desde la distancia. Pero todo cambia cuando el hermano de Jay, Cole, vuelve al instituto. Desde que Tessa puede recordar, Cole se ha dedicado a hacerle la vida imposible. Aunque también es verdad que si vas a tener un enemigo número uno, mejor que sea como Cole: alto, buenorro como hay pocos y con unos ojos azules que tiran para atrás. Sí, es verdad, ha sido el tormento de Tessa desde que eran pequeños: le ha puesto motes, se ha metido con su manera de hablar, de andar y hasta de respirar. Pero el chico que ha vuelto no se parece en nada al bully de antes. Este chico nuevo la desafía, prueba sus límites, la fuerza a sacar a la chica guay que ella se empeña en esconder bajo una capa de mediocridad y cutrerío... ¡Un momento! ¿Podría ser que quien ella cree que es su peor pesadilla sea en realidad su ángel de la guarda? Ya lo dice el refrán: quien bien te quiere, te hará rabiar. ADVERTENCIA: Incluido en esta historia viene un chico malo, cuyas contraindicaciones son suspiros pronunciados y risa histérica. Los efectos secundarios incluyen alucinaciones y plantearte si podrías encontrar uno igualito en eBay y pagar por él lo que sea necesario. La opinión de los lectores: «Gracias a Dios [que me hice con este libro] porque esta reseña se queda corta para decir lo mucho que he amado a Cole. Te odiaré hasta que te quiera es una lectura juvenil que te engancha y que te hace suspirar cada página por Cole dejándote con un final altamente inesperado.» Blog La chica del mundo perdido «Lo devoré. Lo saboreé lenta y orgullosamente y lo disfruté con ganas. Fui feliz mientras leía. [...] Es una de esas novelas que conseguirá hacerse un huequecito en vuestros corazones a la mínima, capaz de despertaros muchos sentimientos y desenterrar recuerdos enterrados. Altamente recomendable.» Blog El blog de Wendy', @Cat_Romancejuvenil, N'PDF/Bad Boy''s Girl Te odiare hasta que te quiera - Blair Holden.pdf', N'.pdf', 0, 1);
END;

