-- Libro 824: Champion
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Champion' AND Autor = N'Marie Lu')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Champion', N'Marie Lu', N'The explosive finale to Marie Lu''s New York Times bestselling LEGEND trilogy - perfect for fans of THE HUNGER GAMES and DIVERGENT! He is a Legend. She is a Prodigy. Who will be Champion? June and Day have sacrificed so much for the people of the Republic - and each other - and now their country is on the brink of a new peaceful existence. June is back in the good graces of the Republic, working within the government''s elite circles while Day has been assigned a high level military position. But when a plague outbreak, deadlier than any other, causes panic in the Colonies, and war threatens the Republic''s border cities, the two are thrown back together. June is the only one who knows the key to her country''s defence. But saving the lives of thousands will mean asking the one she loves to give up everything he has. With heart-pounding action and suspense, Marie Lu''s bestselling trilogy, a brilliant re-imaginging of Les Miserables, draws to a stunning conclusion. Praise for the Legend trilogy: If you liked The Hunger Games, you''ll LOVE this! - Sarah-Rees Brennan, author of The Demon''s Lexicon Legend is impossible to put down and even harder to forget - Kami Garcia, NYT bestselling author of Beautiful Creatures Razor-sharp plotting, depth of character and emotional arc, Legend doesn''t merely survive the hype, it deserves it - USA Today ''To me it blows the socks off of Hunger Games." - Wyck Godfrey, producer of The Twilight Saga @Marie_Lu marielu.org legendtheseries.com facebook.com/legendtheseries', @Cat_Distopacienciaficcinjuvenil, N'PDF/Champion - Marie Lu.pdf', N'.pdf', 0, 1);
END;

-- Libro 825: Heredera de fuego
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Heredera de fuego' AND Autor = N'Sarah J. Maas')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Heredera de fuego', N'Sarah J. Maas', N'Ella es la heredera de ceniza y fuego, y no se doblegará ante nadie. Descubre la tercera parte de la trilogía Trono de Cristal, serie bestseller de The New York Times. La asesina del rey enfrenta el desafío de un destino aún más importante y arde con un resplandor más impresionante que nunca antes en Heredera de fuego, continuación del bestseller Corona de sangre. Celaena Sardothien ha sobrevivido a mortíferos combates y a la demoledora experiencia del desamor, pero a un costo indescriptible. Ahora debe viajar a una nueva tierra para enfrentar su más oscuro pasado, una verdad sobre su historia que podría darle un vuelco a su vida, y a su futuro, para siempre. Mientras tanto, brutales y monstruosas fuerzas se van reuniendo en el horizonte e intentan esclavizar su mundo. Para derrotarlos, Celaena debe hallar la fortaleza no solo para combatir a sus propios demonios internos, sino para vencer al mal que está a punto de desencadenarse. La crítica ha opinado: "Los lectores van a devorar esta última entrega de Sarah J. Maas... Una adquisición obligada." - School Library Journal- "Una avalancha de tensión con giros devastadores y un desenlace absolutamente fascinante. Dejará a los lectores ávidos de más." - Kirkus Reviews- "¡Temía soltar este libro!" -Tamora Pierce, autora bestseller de The New York Times-', @Cat_Fantasajuvenil, N'PDF/Heredera de fuego - Sarah J. Maas.pdf', N'.pdf', 0, 1);
END;

-- Libro 826: La novia se va a Irlanda
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La novia se va a Irlanda' AND Autor = N'Carlota Manzano')
