    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La novia se va a Irlanda', N'Carlota Manzano', N'<div>
<p style="font-family: ''Amazon Ember'',''Arial'',''sans-serif''; font-size: 14px"><span style="color: #333333; background-color: #ffffff">Andrea entra en la iglesia del brazo de su padre para casarse cuando no puede creer lo que ven sus ojos… El pasado a menudo nos persigue y a veces lo hace en los lugares más insospechados y en las situaciones más variopintas. De lo que decida en ese momento van a depender su futuro y el de su bebé, Lorcan. La mirada de su déspota progenitor no la ayuda, pero ¿será capaz de tomar una decisión que suponga una vuelta de tuerca brutal para sus vidas?</span></p></div>', @Cat_Romancecontemporneo, N'PDF/La novia se va a Irlanda - Carlota Manzano.pdf', N'.pdf', 0, 1);
END;

