-- Libro 829: #Mírate
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'#Mírate' AND Autor = N'Andrea Vilallonga')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'#Mírate', N'Andrea Vilallonga', N'Andrea Vilallonga, profesora de OT 2017 y experta en imagen y comunicación, nos presenta el método #MÍRATE: Mejora tu imagen, renueva tu actitud, trabaja tu expresión. EL MÉTODO MÍRATE TE PERMITE, SENCILLAMENTE, AMARTE: - Aceptar cómo te ves. - Mejorar la comunicación con los demás. - Aclarar lo que realmente quieres transmitir con tu imagen. - Revelar qué te hace único y decidir sacar lo mejor de ti mismo. - Transformar la perspectiva que tienes sobre tu imagen. - Elevar tu autoestima. El método #MÍRATE se basa en la idea de aceptación de la imagen propia como punto de mejora, usándola como elemento de presencia y no de belleza. Este libro desarrolla un trabajo que explica cómo descubrir cuál es la imagen transmitida y, a través de la propia imagen externa, la expresión y la actitud, entender cómo mejorarla, basándose siempre en las características y necesidades de cada persona para transmitir su verdadero yo, sin disfrazarse o querer ser lo que no se es.', @Cat_Autoayudaimagenpersonal, N'PDF/Mirate - Andrea Vilallonga.pdf', N'.pdf', 0, 1);
END;

-- Libro 830: Técnicas terapéuticas de la oración
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Técnicas terapéuticas de la oración' AND Autor = N'Joseph Murphy')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Técnicas terapéuticas de la oración', N'Joseph Murphy', N'En este libro, el doctor Murphy nos enseña unas técnicas de oración cuya eficacia está comprobada, pues han ayudado a miles de personas en todo el mundo a resolver sus problemas. A través de ejemplos sacados de la vida real, podemos ver cómo a menudo la o', @Cat_Autoayudaespiritualidad, N'PDF/Tecnicas terapeuticas de la oracion - Joseph Murphy.pdf', N'.pdf', 0, 1);
END;

-- Libro 831: Angel
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Angel' AND Autor = N'Sarah Brianne')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Angel', N'Sarah Brianne', N'Un ángel es un ser sobrenatural presente en varias religiones y mitologías, cuya función principal es servir a una deidad suprema. Sus funciones y especificaciones varían según cada cultura. La rama de la teología que se especializa en  los ángeles se denomina angelología.
Las religiones monoteístas muchas veces representan a los ángeles como seres celestiales benevolentes que actúan como intermediarios entre Dios y la humanidad.
En el catolicismo se habla del ángel de la guarda o del custodio, que sería aquel que Dios tiene señalado a cada persona para protegerla. Por contraposición, también se tiene la figura del ángel caído, aquel que ha sido expulsado del cielo por desobedecer o rebelarse contra Dios. Los ángeles más conocidos en las tradiciones judeocristianas son: San Miguel, San Gabriel y San Rafael.', @Cat_Romancemafia, N'PDF/Angel - Sarah Brianne.pdf', N'.pdf', 0, 1);
END;

