-- Libro 834: Redimida
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Redimida' AND Autor = N'P. C. Cast y Kristin Cast')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Redimida', N'P. C. Cast y Kristin Cast', N'Zoey Redbird está em apuros. Tendo dado a pedra da vidência para Aphrodite e rendendo‐se à Polícia de Tulsa, ela se isola de seus amigos e mentores, determinada a enfrentar a punição que merece – mesmo que isso lhe custe a vida. Só o amor das pessoas mais próximas poderá salvá‐la da escuridão em seu espírito. Um mal terrível emerge das sombras, mais poderoso do que nunca... Neferet finalmente se revela aos mortais. Coroando‐seDeusa das Trevas, ela está desencadeando o mal e escravizando os cidadãos de Tulsa. Os vampiros da Morada da Noite aliam‐se à polícia, juntando suas últimas forças, mas sabem que nenhum deles é forte o suficiente para vencê‐la. Apenas Zoey é herdeira de tal poder... contudo, está incapacitada de ajudar por causa das consequências do uso da magia antiga. No derradeiro livro da série House of Night, uma batalha épica da Luz contra as Trevas irá decidir quem será redimida... ... e quem se perderá para sempre.', @Cat_Fantasaparanormaljuvenil, N'PDF/Redimida - P. C. Cast y Kristin Cast.pdf', N'.pdf', 0, 1);
END;

-- Libro 835: El precio de la inteligencia
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El precio de la inteligencia' AND Autor = N'Jordi Agustí, Enric Bufill y Marina Mosquera')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El precio de la inteligencia', N'Jordi Agustí, Enric Bufill y Marina Mosquera', N'En la investigación sobre el origen de nuestra mente están hoy involucradas un gran número de disciplinas, que incluyen la paleoantropología, la paleoecología humana, la arqueología prehistórica, la primatología, la etología, la neurociencia cognitiva y la genómica. La cuestión del origen de la mente humana, por tanto, sólo puede ser abordada desde un enfoque pluridisciplinar. Pero a pesar de los importantísimos logros de los últimos años, la tarea sigue siendo mucho más ardua de lo que podíamos imaginar: cada nuevo avance supone un nuevo frente abierto que muchas veces plantea muchas más nuevas cuestiones de las que pretendía responder. Y ello es así porque la complejidad de la tarea es directamente proporcional a la complejidad del problema que se pretende abordar, la mente humana y su origen. Esta obra pretende hacer un recorrido por las cuestiones más candentes en torno al origen de la mente humana y el órgano que la rige, el cerebro, así como trazar algunas de las líneas maestras que pueden marcar la investigación en este campo. Los autores pretenden ofrecer un esbozo de algunas de las líneas de investigación más activas que se desarrollan en este centro, como son la paleoantropología, la paleoecología humana, la arqueología prehistórica, la neurociencia evolutiva o los estudios sobre cognición en primates.', @Cat_CienciaEvolucinhumana, N'PDF/El precio de la inteligencia - Jordi Agusti, Enric Bufill y Marina Mosquera.pdf', N'.pdf', 0, 1);
END;

