-- Libro 839: Divergente
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Divergente' AND Autor = N'Veronica Roth')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Divergente', N'Veronica Roth', N'Una sola elección puede transformarte. Una sola elección puede destruirte. Una elección te define. Divergente, una de las sagas más exitosas de todos los tiempos, reunida en un atractivo estuche. Una apasionante historia distópica de elecciones electrizantes, consecuencias poderosas, un romance inesperado y una sociedad perfecta que es en realidad profundamente defectuosa. En una sociedad dividida donde todos deben conformarse, Tris no encaja. Así que se aventura, sola, decidida a descubrir a dónde pertenece realmente. Una tetralogía apasionante para todos los que intentan identificar su lugar en el mundo.', @Cat_Distopajuvenil, N'PDF/Divergente - Veronica Roth.pdf', N'.pdf', 0, 1);
END;

-- Libro 840: Panteras
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Panteras' AND Autor = N'Lena Valenti')
