    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Panteras', N'Lena Valenti', N'Imoco Volley es un club de voleibol femenino italiano fundado en Conegliano, perteneciente a la Serie A1 de la Liga Italiana de Voleibol. Es uno de los clubes de voleibol femenino italianos más exitosos, habiendo conseguido ocho títulos de liga, tres campeonatos europeos y tres mundiales, entre otras competencias.', @Cat_Novelahistrica, N'PDF/Panteras - Lena Valenti.pdf', N'.pdf', 0, 1);
