-- Libro 841: Detrás de tu mirada
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Detrás de tu mirada' AND Autor = N'Adriana Rubens')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Detrás de tu mirada', N'Adriana Rubens', N'Segunda entrega de la serie «Whitechapel» de Adriana Rubens. Una novela romántica histórica ambientada en el Londres de finales del siglo XIX, de la mano de una autora clásica del sello y ganadora del Premio Vergara. Lady Samantha Richmond es una dama poco común. No solo por su singular belleza sino por el interés que tiene en ejercer una profesión: ser periodista. Un empleo poco usual para una mujer a finales del siglo XIX y completamente descabellado para la hija de un duque. Sabedor de que la joven no va a dejar que nadie la detenga en sus aspiraciones, su padre, Nathaniel Richmond, duque de Bellrose, decide contratar los servicios de la mejor empresa de seguridad de Londres para protegerla mientras trabaja. En los blogs... «La historia de amor entre los personajes prometía un libro que estaba deseando leer, pero Adriana Rubens ha ido más allá de mis expectativas y me ha dejado con una sensación tan maravillosa y aturdida al terminar la novela, que lo único quería hacer era volver a principio para releer la historia de nuevo con todos su matices. Porque así es Detrás de tu mirada, una de esas joyas que necesito guardar en mi estantería para poder volver a disfrutar de sus inolvidables escenas siempre que quiera.» Blog A merced de las musas', @Cat_Romancehistrico, N'PDF/Detrás de tu mirada - Adriana Rubens.pdf', N'.pdf', 0, 1);
END;

