-- Libro 845: ¿De quien te escondes?
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'¿De quien te escondes?' AND Autor = N'Charlotte Link')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¿De quien te escondes?', N'Charlotte Link', N'«¿De quién te escondes?». Al final Simon tiene que preguntárselo a Nathalie. Dos días atrás se tropezó con esta joven en la playa. Estaba demacrada y asustada, y él se ofreció a ayudarla. Una decisión impulsiva que se ha vuelto en su contra, pues desde entonces se han visto envueltos en una espiral creciente de violencia y muerte que les ha convertido en blancos… ¿de quién? Nathalie no está simplemente perdida o desamparada, como él creyó. ¿Es una víctima? ¿Es culpable? ¿Qué está pasando? «¿De quién te escondes?», un suspense psicológico impecable, nos lleva a una decisión cuyas consecuencias, como sucede tantas veces, era imposible prever, al tiempo que va atrapándonos en una historia de secretos, mentiras, asesinatos y una sórdida red que trafica con los sueños y la vida de quienes tienen poco que perder. La novela que desbancó a J. K. Rowling, Elena Ferrante, Henning Mankell, Stephen King y Jojo Moyes en las listas de libros más vendidos en Alemania.', @Cat_Thrillerpsicolgicosuspense, N'EPUB/De quien te escondes - Charlotte Link.epub', N'.epub', 0, 1);
END;

-- Libro 846: Destino: tu Corazón
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Destino: tu Corazón' AND Autor = N'Katy Colins')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Destino: tu Corazón', N'Katy Colins', N'Déjate llevar… Se suponía que poner en marcha el Club de Viaje de los Corazones Solitarios iba a ser una segunda oportunidad, la oportunidad que le devolvería a Georgia Green su vida. Ella pensaba que tan solo sería cuestión de viajar, pero la realidad no era tan idílica, ¡poner en marcha un nuevo negocio no era precisamente un camino de rosas! Así que, cuando Georgia se vio de repente rumbo a la India por una cuestión de trabajo, supo que algo tenía que cambiar. ¿Dónde estaba la chica que había luchado con tanto ahínco por reconstruir su vida? Tal vez, en la tierra de Bollywood, de las playas maravillosas y del Taj Mahal, pudiera encontrar la clave para recuperar el ritmo… Pero lo que estaba a punto de comprobar era que, en La India, el país tenía las riendas de la situación, y no el viajero. ¡Sin embargo, Georgia no iba a desanimarse tan fácilmente! Puro entretenimiento.', @Cat_RomnticoNovela, N'EPUB/Destino tu Corazón - Katy Colins.epub', N'.epub', 0, 1);
END;

-- Libro 847: Tu nombre es escándalo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Tu nombre es escándalo' AND Autor = N'Stephanie Laurens')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Tu nombre es escándalo', N'Stephanie Laurens', N'«SERÁ EL PADRE DE TUS HIJOS...». Catriona Hennessy, la señora del valle un viejo título de la pequeña aristocracia escocesa, queda desconcertada al recibir esta predicción. ¿Cómo puede ella casarse con Richard Cynster, un autoritario caballero con una reputación escandalosa? Más asombroso todavía resulta el testamento de su tutor, que decreta que ella y Richard han de casarse en el plazo de una semana. Aunque no puede negar que a pesar de todo se siente muy atraída por él, no quiere renunciar a su independencia, por lo que urde un plan para conseguir lo que necesita sin tener que pronunciar los votos nupciales. Richard se queda igual de atónito ante la disposición testamentaria. El matrimonio nunca ha entrado en sus planes, aunque quizás domesticar a la señora del valle sea justo el desafío que necesita...', @Cat_NovelaRomntico, N'EPUB/Tu nombre es escándalo - Stephanie Laurens.epub', N'.epub', 0, 1);
END;

-- Libro 848: Cómo seducir a un guerrero
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Cómo seducir a un guerrero' AND Autor = N'Karen Marie Moning')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Cómo seducir a un guerrero', N'Karen Marie Moning', N'Gavrael Mclllioch había nacido en un clan de guerreros de fuerza sobrenatural, pero abandonó su nombre y su castillo de las Highlands decidido a escapar del sombrío destino de sus antepasados. Ocultando su identidad al implacable clan rival que lo perseguía, pasó a llamarse Grimm para proteger a la gente que le importaba y juró no admitir jamás su amor por la encantadora Jillian St. Clair. Y entonces el padre de Jillian lo convocó con urgencia…¿Por qué había huido él de ella durante tantos años? Y ¿por qué regresa ahora para verla ofrecida como premio en una competición orquestada por su padre? Furiosa, Jillian había jurado no casarse jamás. Pero Grimm era el hombre al que amaba, y ella la única mujer que podía domeñar a la bestia que bramaba dentro de él… Todo ello, mientras sus enemigos mortales se conjuraban para acabar con ambos.', @Cat_Romntico, N'EPUB/Cómo seducir a un guerrero - Karen Marie Moning.epub', N'.epub', 0, 1);
END;

-- Libro 849: Padres Toxicos
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Padres Toxicos' AND Autor = N'Jose Luis Canales')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Padres Toxicos', N'Jose Luis Canales', N'<font class="Apple-style-span" face="''MS Shell Dlg 2'', sans-serif"><span class="Apple-style-span" style="font-size: 12px;">El legado de una infancia tóxica es fácil de reconocer pero difícil de interiorizar y superar. Nuestros padres dejan semillas emocionales en nosotros. En algunas familias, éstas son de respeto, amor e independencia, pero en otras, son de miedo, culpa y autocastigo. Si te identificas con el segundo grupo, necesitas entender el legado nocivo de tus padres y comprometerte a cambiar los pensamientos dañinos que te marcaron, dejar ir las emociones negativas que rigen tu vida y reconocer que, mientras no te liberes de las enredaderas de tu infancia, vivirás un ciclo autodestructivo. Todos los padres emocionalmente sanos se equivocan; el problema es cuando lo hacen intencionalmente y de manera repetitiva. Es normal que pierdan el control por momentos o que tengan ciertas conductas abusivas con los hijos; sin embargo, lo que los convierte en tóxicos es el patrón de daño constante. Los hijos de padres tóxicos tienden a relacionar el amor con sufrimiento, a caer en relaciones de dependencia, a vivir con culpa y, más importante aún, a repetir los patrones destructivos que sufrieron en su niñez. Recuerda que no eres culpable de lo que viviste en la infancia pero sí eres responsable de tu adultez. Este libro es el primer paso para tener una vida plena, romper los patrones perjudiciales que viviste y criar una familia sana. </span></font>', @Cat_PsicologiaSociologia, N'EPUB/Padres Toxicos - Jose Luis Canales.epub', N'.epub', 0, 1);
END;

-- Libro 850: La violinista de la rosa blanca
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La violinista de la rosa blanca' AND Autor = N'Amelia Noguera')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La violinista de la rosa blanca', N'Amelia Noguera', N'<div>
<p style="font-family: ''Arial''; font-size: 14px"><span style="background-color: #ffffff; color: #333333">Una desgraciadísima noche de luna llena, el barrendero Hipólito mata por accidente con el camión de la basura a la anciana vagabunda Isabella y al socorrerla, su amigo Bruno cae en coma. Sintiéndose culpable por la desventura de los dos, nuestro protagonista iniciará entonces un viaje que comienza por el encuentro con una loca heredera que busca al asesino de su padre y jura y perjura que él y otros fueron asesinados hace décadas, allá por los años cincuenta más o menos, por un hombre lobo, a quien ella necesita encontrar para vengarse. Y este viaje sabe dios dónde acaba, pero llevará a Hipólito —un buen chico que cuida de su abuelo enfermo, aunque también un poco desmemoriado, maniático y puede que algo gafe— tras la pista de los dos, en una sucesión de episodios a veces grotescos y disparatados, pero siempre emocionantes.</span></p></div>', @Cat_HistricaSuspense, N'EPUB/La violinista de la rosa blanca - Amelia Noguera.epub', N'.epub', 0, 1);
END;

-- Libro 851: Hugo: Un corazón para conquistar
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Hugo: Un corazón para conquistar' AND Autor = N'Jenny Del')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Hugo: Un corazón para conquistar', N'Jenny Del', N'<div>
<p style="font-size: 14px; font-family: ''Amazon Ember'',''Arial'',''sans-serif''"><span style="color: #333333; background-color: #ffffff">Cuando Mara conoce a Hugo no puede imaginar que perderá la cabeza por él. Y es que ese misterioso hombre, que le da una de cal y otra de arena, parece jugar con ella a su antojo. La espiral sexual en la que ambos se ven envueltos no es más que la punta del iceberg. Lo complicado llega cuando los sentimientos entran en juego.</span></p></div>', @Cat_Romanceertico, N'EPUB/Hugo - Un corazón para conquistar - Jenny Del.epub', N'.epub', 0, 1);
END;

-- Libro 852: Nieblas de las Highlands
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Nieblas de las Highlands' AND Autor = N'Karen Marie Moning')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Nieblas de las Highlands', N'Karen Marie Moning', N'En el reino todo el mundo lo conoce como Halcón, legendario predador de los campos de batalla y los tocadores de las damas. Ninguna mujer puede resistirse a sus encantos, pero ninguna ha conquistado jamás su corazón. Hasta que un hada vengativa hace caer a Adrienne de Simone, del moderno Seattle a la Escocia medieval... Cautiva en un siglo que no es el suyo, absolutamente temeraria, franca y sincera, constituye un desafío irresistible para un bribón [también podría ser donjuán, por el contexto] del siglo XVI. Obligada a casarse con Halcón, Adrienne jura mantenerlo a distancia..., pero los encantos de él hacen estragos en sus planes. Para ese bribón ella siempre tiene un rotundo ''no'' en los hermosos labios, pero Halcón se ha propuesto que susurre su nombre presa del deseo, de la pasión arrebatadora que ha conseguido encender en su interior. Las barreras del tiempo y el espacio no impedirán que Halcón conquiste el amor de Adrienne. A pesar de su indecisión acerca de si seguir o no los deseos de su apasionado corazón, las reticencias de Adrienne aumentan la determinación de Halcón de conservarla a su lado.', @Cat_Romancehistricoparanormal, N'EPUB/Nieblas de las Highlands - Karen Marie Moning.epub', N'.epub', 0, 1);
END;

-- Libro 853: Las Guerreras 03 - Siempre te encontraré
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Las Guerreras 03 - Siempre te encontraré' AND Autor = N'Megan Maxwell')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Las Guerreras 03 - Siempre te encontraré', N'Megan Maxwell', N'Tercer volumen de la saga que consagró a Megan como la autora más querida del género El laird Kieran O''Hara y sus guerreros son atacados por unos villanos mientras pernoctan en el bosque cercano al castillo de Caerlaveroch, pero una misteriosa banda de encapuchados, liderados por una mujer a la que los aldeanos llaman «Hada», consigue salvarlos. Angela es la menor de las hijas del laird Kubrat Ferguson. Todo el mundo cree que es una muchacha débil, temerosa de los caballos y que tiembla ante el acero. Cuando Kieran la conoce, la actitud tímida de la joven, su torpeza y su sentido del pudor ante su caballerosidad y galantería llaman su atención, sin saber que aquélla es la encapuchada a la que anda buscando. Juntos conseguirán desenmascarar al codicioso cuñado de Angela, Cedric Steward, quien ha tramado un plan terrible que cambiará para siempre el futuro de los habitantes del castillo de Caerlaveroch. Una historia vibrante, con unos personajes que te enamorarán y te harán sonreír mientras disfrutas de sus andanzas por las Highlands escocesas.', @Cat_Noespecificado, N'EPUB/Las Guerreras 03 - Siempre te encontraré - Megan Maxwell.epub', N'.epub', 0, 0);
END;

-- Libro 854: Diagnóstico del placer
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Diagnóstico del placer' AND Autor = N'Mimmi Kass')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Diagnóstico del placer', N'Mimmi Kass', N'Después de todo lo ocurrido entre ellos, las dudas atormentan a Erik y a Inés. Caer en una relación sin futuro podría destrozarlos a los dos, pero sus límites comienzan a difuminarse, y todo aquello en lo que creen, lo que sienten y anhelan, se derrumba y se rompe en mil pedazos. Santiago de Chile muestra su doble faz, desde el lujo más obsceno hasta la pobreza más amarga. Erik ya no sabe cuál es su hogar, y su vocación se tambalea. Inés experimenta el placer más sublime y el dolor más absoluto. El sexo adquiere dimensiones hasta ahora nunca exploradas. Cuando la persona que camina a tu lado sacude todos tus cimientos, solo cabe una pregunta. ¿Se atreverán a explorar fuera de su zona de confort? Por fin llega la esperada segunda entrega de En cuerpo y alma. En Diagnóstico del placer, el erotismo y las emociones se profundizan. Tras el éxito conseguido con Radiografía del deseo, best seller en ficción erótica de Amazon, la autora nos entrega una historia donde los límites se hacen difusos y los personajes se ven enfrentados continuamente con el desafío de abandonar sus zonas de confort. Y tú, ¿sabes bien cuáles son tus límites?', @Cat_ErticoNovela, N'EPUB/Diagnóstico del placer - Mimmi Kass.epub', N'.epub', 0, 1);
END;

-- Libro 855: Caer
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Caer' AND Autor = N'Javier de Frutos')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Caer', N'Javier de Frutos', N'<div><p class="description"></p><div style="font-family: ''MS Shell Dlg 2'', sans-serif; font-size: 12px; text-align: justify;"><b style="color: rgb(51, 51, 51); font-family: verdana, arial, helvetica, sans-serif; font-size: small; orphans: 2; widows: 2; background-color: rgb(255, 255, 255);">La historia oculta que el Vaticano no quiere que sepas, ni Dan Brown que leas.</b></div><div style="text-align: justify;"><font color="#333333" face="verdana, arial, helvetica, sans-serif" size="2"><br></font></div><strong style="font-family: verdana, arial, helvetica, sans-serif; font-size: small; color: rgb(51, 51, 51); orphans: 2; widows: 2; background-color: rgb(255, 255, 255);"><div style="text-align: justify;"><strong>Septiembre de 2014 (España).</strong> Daniel Steelman, un joven profesor de idiomas canadiense, recibe la desesperada llamada de una exalumna: su hermana gemela ha desaparecido y necesita su ayuda.</div></strong><div style="text-align: justify;"><font color="#333333" face="verdana, arial, helvetica, sans-serif" size="2"><br></font></div><span style="font-family: verdana, arial, helvetica, sans-serif; font-size: small; color: rgb(51, 51, 51); orphans: 2; widows: 2; background-color: rgb(255, 255, 255);"><div style="text-align: justify;">Las circunstancias que rodean la desaparición y los descubrimientos que se irán realizando conforme se desarrolla la búsqueda pondrán de manifiesto que no se trata una simple desaparición más.</div></span><div style="text-align: justify;"><font color="#333333" face="verdana, arial, helvetica, sans-serif" size="2"><br></font></div><span style="font-family: verdana, arial, helvetica, sans-serif; font-size: small; color: rgb(51, 51, 51); orphans: 2; widows: 2; background-color: rgb(255, 255, 255);"><div style="text-align: justify;">El inesperado hallazgo de unas cartas de finales del s. XIX y otras de mediados del s. XX junto con un extraño moleskine revelará la verdad que en ellos se oculta.</div></span><div style="text-align: justify;"><font color="#333333" face="verdana, arial, helvetica, sans-serif" size="2"><br></font></div><span style="font-family: verdana, arial, helvetica, sans-serif; font-size: small; color: rgb(51, 51, 51); orphans: 2; widows: 2; background-color: rgb(255, 255, 255);"><div style="text-align: justify;">Una verdad difícil de asumir que algunos preferirían que nunca fuera descubierta.</div></span><div style="text-align: justify;"><font color="#333333" face="verdana, arial, helvetica, sans-serif" size="2"><br></font></div><span style="font-family: verdana, arial, helvetica, sans-serif; font-size: small; color: rgb(51, 51, 51); orphans: 2; widows: 2; background-color: rgb(255, 255, 255);"><div style="text-align: justify;">CAER <i>es una novela de misterio y acción en la que conviven personajes ficticios con otros reales no menos sorprendentes.</i></div></span><i style="orphans: 2; widows: 2; background-color: rgb(255, 255, 255);"><div style="text-align: justify;"><font color="#333333" face="verdana, arial, helvetica, sans-serif" size="2"><br></font></div><font color="#333333" face="verdana, arial, helvetica, sans-serif" size="2"><div style="text-align: justify;"><i><font color="#333333" face="verdana, arial, helvetica, sans-serif" size="2">Es el fruto de una minuciosa labor de investigación y documentación que ha permitido, basándose en ella, crear una trama intrigante que abre la mente del lector a hacerse preguntas que, tal vez, antes de leer este libro nunca se hubiera preguntado.</font></i></div></font></i><div style="text-align: justify;"><font color="#333333" face="verdana, arial, helvetica, sans-serif" size="2"><br></font></div><strong style="font-family: verdana, arial, helvetica, sans-serif; font-size: small; color: rgb(51, 51, 51); orphans: 2; widows: 2; background-color: rgb(255, 255, 255);"><div style="text-align: justify;"><strong>Solo quería acallar su conciencia,</strong></div><div style="text-align: justify;"><strong>acabar con aquellas pesadillas,</strong></div><div style="text-align: justify;"><strong>reconciliarse con su pasado.</strong></div></strong><b style="font-family: verdana, arial, helvetica, sans-serif; font-size: small; color: rgb(51, 51, 51); orphans: 2; widows: 2; background-color: rgb(255, 255, 255);"><div style="text-align: justify;"><b>Pero uno no elige su destino.</b></div></b></div>', @Cat_AccinAventurasSuspense, N'EPUB/Caer - Javier de Frutos.epub', N'.epub', 0, 1);
END;

-- Libro 856: El beso del highlander
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El beso del highlander' AND Autor = N'Karen Marie Moning')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El beso del highlander', N'Karen Marie Moning', N'Drustan MacKeltar, un vigoroso jefe de un clan escocés, había sido confinado por una maldición gitana a permanecer dormido en una cueva hasta el fin de los tiempos. Pero, quinientos años después, Gwen, una joven turista norteamericana, es capaz de cambiar tan triste sino y despertarle de un sueño eterno. Confuso y desorientado, Drustan sólo sabe que debe encontrar el modo de regresar a su época para salvar a su pueblo. Aunque ahora debe enfrentarse a un nuevo problema: ¿cómo abandonar a aquella atractiva joven que le ha devuelto la vida?', @Cat_Romntico, N'EPUB/El beso del highlander - Karen Marie Moning.epub', N'.epub', 0, 1);
END;

-- Libro 857: Deseo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Deseo' AND Autor = N'Adrian Blake')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Deseo', N'Adrian Blake', N'Deseo es el undécimo álbum de estudio de la cantante mexicana Paulina Rubio. Fue lanzado el 14 de septiembre de 2018​ por Universal Spain, marcando su última producción con el sello discográfico Universal Music Group y el primero a siete años de editar Brava! (2011). Colaboró con una multitud de productores y músicos para el disco, entre ellos Mauricio Rengifo, Andrés Torres, los Julca Brothers, Antonio "Toy Selectah" Hernández, Joey Montana, Morat, Nacho, Juan Magán, Xabier San Martin y Alexis & Fido. Deseo es un álbum pop latino con una fuerte vibra del género urbano, aunque mantiene el característico estilo pop rock de la cantante en algunas canciones.
Paulina Rubio empezó a trabajar en un disco inédito a finales de 2014, pero por varias situaciones desconocidas Universal retrasó sus proyectos al grado de publicar sencillos independientes a lo largo de los siguientes dos años. Además, se involucró en su faceta como jueza en diferentes shows de televisión incluyendo la versión mexicana de La Voz, La Voz Kids, la versión estadounidense de The X Factor y La Apuesta.
Inicialmente se lanzaron dos sencillos del álbum: «Desire (Me Tienes Loquita)», una colaboración con Nacho, estrenada el 28 de mayo de 2018, y «Suave y Sutil», lanzada cuatro meses más tarde. El 15 de abril de 2019 se lanzó una edición especial de Deseo que incluía cuatro canciones inéditas, incluyendo el sencillo «Ya No Me Engañas», estrenado solo unos días antes del lanzamiento de la reedición.​ El disco también contiene los sencillos independientes  —lanzados entre 2015 y 2016— «Mi Nuevo Vicio», «Si Te Vas» y «Me Quema».
Tras su lanzamiento, Deseo recibió críticas mixtas por parte de los críticos de música, quienes elogiaron la «energía» de la cantante y su capacidad de adaptarse a los nuevos géneros musicales, pero sintieron que el flujo de las canciones en el disco no tenía ningún sentido ya que la mitad de los temas ya habían sido publicados, por lo que sostuvieron que se trataba más de una «compilación» poco sorprendente. Comercialmente, Deseo tuvo poco impacto en las listas musicales, alcanzando la posición número trece de la lista de Billboard Latin Pop Albums. Pese a ello, obtuvo una certificación de disco de oro en Chile,​ y se embarcó en una gira de conciertos en los Estados Unidos.', @Cat_Romanceertico, N'EPUB/S.E.C.R.E.T. 3 - Deseos revelados - L. Marie Adeline.mobi', N'.mobi', 0, 1);
END;

-- Libro 858: Zapatos de cristal
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Zapatos de cristal' AND Autor = N'Ruy Alexander')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Zapatos de cristal', N'Ruy Alexander', N'<div>
<p style="font-size: 14px; font-family: ''Amazon Ember'',''Arial'',''sans-serif''"><span style="color: #333333; background-color: #ffffff">''¿Qué niña no ha deseado ser una Cenicienta de cuento con su zapatito de cristal?'' Un traumático suceso llevará a Ana a desaparecer de su antigua vida, a cambiar de instituto, de compañeros, a desconfiar y saber que, tarde o temprano, le volverán a hacer daño. Con el telón de fondo de las redes sociales y cómo éstas afectarán a la vida de los protagonistas.</span></p></div>', @Cat_RelatosRomntica, N'EPUB/Zapatos de cristal - Ruy Alexander.epub', N'.epub', 0, 1);
END;

-- Libro 859: (Fjallbacka 04) Crimen en directo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'(Fjallbacka 04) Crimen en directo' AND Autor = N'Camilla Lackberg')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'(Fjallbacka 04) Crimen en directo', N'Camilla Lackberg', N'Patrik y Erica siguen disfrutando de su idilio en el pueblo de Fjällbacka, ahora acompañados por su bebé, la pequeña Maja, que ya tiene ocho meses. Mientras la joven pareja está plenamente volcada en los preparativos de su próxima boda, los asuntos en la comisaría, donde Patrik trabaja, siguen su curso rutinario. Pero el alcalde reúne al pleno del Ayuntamiento para anunciar la llegada a Tanum de un equipo de televisión para filmar un «reality-show» bastante escandaloso llamado «Fucking Tanum» que, supuestamente, debería reportar unos jugosos beneficios a la población y que va a suponer en realidad una auténtica pesadilla. Poco después, Patrik debe investigar la muerte de una mujer, víctima de un accidente de tráfico. Aparentemente la mujer bebió más de la cuenta, pero a Patrik le llaman la atención unas extrañas marcas en el cuello de la víctima y descubre muy pronto que existe una misteriosa relación entre ese crimen y otros asesinatos que tuvieron lugar en el pasado en distintos lugares de Suecia. Al lado de todos los cuerpos había una página del cuento infantil «Hansel y Gretel». Mientras tanto, el productor del programa, consciente de que a mayor escándalo, mayor índice de audiencia, alimenta los conflictos entre el grupo de participantes.', @Cat_Novelanegrathrillernrdico, N'EPUB/(Fjallbacka 04) Crimen en directo - Camilla Lackberg.epub', N'.epub', 0, 1);
END;

-- Libro 860: Witch Fury
