-- Libro 861: Petirrojo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Petirrojo' AND Autor = N'Jo Nesbø')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Petirrojo', N'Jo Nesbø', N'Año 1944: Daniel, combatiente del frente oriental, muere asesinado en las trincheras de Leningrado. En un hospital de Viena, un soldado herido dice ser Daniel. Entre él y la enfermera Helena surge un romance. Año 1999: El investigador Harry Hole dispara por accidente a un agente de los servicios secretos durante la visita a Noruega del presidente norteamericano Clinton. Harry Hole es trasladado a la policía de seguridad ciudadana, donde se le asigna la misión de comprobar la información sobre una red de tráfico de armas relacionada con círculos de viejos y nuevos nazis. Año 2000: Mientras la nieve se funde en las calles de Oslo, entra en escena un asesino con un objetivo muy especial.', @Cat_NovelaPolicial, N'EPUB/Petirrojo - Jo Nesbø.epub', N'.epub', 0, 1);
END;

-- Libro 862: Lusitania. El hundimiento que cambió el 
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Lusitania. El hundimiento que cambió el rumbo de la historia' AND Autor = N'Erik Larson')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Lusitania. El hundimiento que cambió el rumbo de la historia', N'Erik Larson', N'Hacia las dos de la tarde del 7 de mayo de 1915, el Lusitania, el mayor y más lujoso transatlántico del momento, recibía el impacto de un torpedo disparado por un submarino alemán, hundiéndose en apenas veinte minutos con el doloroso balance de 1.200 muertos, la mayoría ciudadanos estadounidenses.Esta muerte fue utilizada por los periódicos para crear un clima de opinión propicio a la participación en la guerra. Incluso se dijo que a los niños alemanes se les había dado un día de fiesta para celebrar el hundimiento del Lusitania.Pero ¿cuál es la verdad sobre este hundimiento? ¿Fue un hecho orquestado para justificar la entrada de Estados Unidos en la Gran Guerra? ¿Iba cargado con armamento para la Gran Bretaña? La realidad como suele suceder es completamente diferente a lo divulgado por la prensa de la época.Este libro se acerca como nunca hasta ahora a todas las claves del suceso que llevo a Estados Unidos a intervenir en la primera guerra mundial, y que a la postre inclinaría la victoria hacia el lado aliado.', @Cat_Histrico, N'EPUB/Lusitania. El hundimiento que cambió el rumbo de la historia - Erik Larson.epub', N'.epub', 0, 1);
END;

-- Libro 863: Mi hermosa apostadora
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Mi hermosa apostadora' AND Autor = N'A. S. Lefebre')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Mi hermosa apostadora', N'A. S. Lefebre', N'Una promesa y dos corazones dispuestos a apostar por un amor. Katherine Rushmore debe cumplir una promesa y casarse con el nieto del mejor amigo de su abuelo... pero ella en realidad solo desea una cosa: casarse por amor. Su carácter rebelde le obliga a no aceptar el compromiso, y decide hacer lo imposible para que su prometido, a quien aún no conoce, rompa con ella para encontrar así a quien robó su corazón unas noches atrás. Sebastian Beckham regresa a Londres con un único objetivo: cumplir la promesa de casarse. Sin embargo, una noche conoce a una misteriosa enmascara de ojos esmeralda vestida como un hombre, quien se adueña de sus sueños y su corazón... hasta que conoce a su prometida y queda atraído por su belleza y carácter. Tiene un serio problema: ella no quiere casarse y él se siente atraído por dos mujeres con el mismo color de ojos. Sebastian decide jugar su última carta y conquistar a su prometida, mientras que Katherine se encuentra cara a cara con quien le robó el corazón... y decide ponerlo a prueba. ¿Será él merecedor de su amor? ¿Cumplirán ambos la promesa de matrimonio?', @Cat_Romntico, N'EPUB/Mi hermosa apostadora - A. S. Lefebre.epub', N'.epub', 0, 1);
END;

