-- Libro 865: Cruzada contra el Grial
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Cruzada contra el Grial' AND Autor = N'Otto Rahn')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Cruzada contra el Grial', N'Otto Rahn', N'<p class="description" style="text-align: justify;">La primera edición de «Cruzada contra el Grial» apareció en Alemania en 1933; era el resultado de varios años de investigación rigurosa. Su autor, Otto Rahn, tenía entonces veintiocho años. Su obra es la síntesis de sus visitas a la región de los cátaros y a los castillos de los templarios en el sur de Francia, de los impresionantes testimonios que recogió, de sus excursiones por el teatro de los hechos y de sus exploraciones en las cuevas pirenaicas acompañado por guías expertos, de su estudio de las fuentes en archivos y bibliotecas de universidades francesas y alemanas, y de su concienzudo trabajo bibliográfico. Su libro es un compendio de nociones y conocimientos de historia, de germanística, de religión, de arte y de vivas descripciones paisajísticas. En su campo, es un libro atrevido, que marcó caminos nuevos en la interpretación y en la recuperación del pasado. El autor parte en su obra de lo literario, del Parsifal de Wolfram von Eschenbach, y de la poesía de los trovadores y «minnesänger», para llevarnos al campo histórico de la creación de la Inquisición y de la Cruzada contra los Albigenses en que Roma y París, aliadas, acabaron con la civilización occitana y con unas formas de vida y espiritualidad que Rahn ejemplificó y simbolizó en el mítico Grial, el cáliz de los más altos ideales.</p>', @Cat_EnsayoEspiritualidadHistoria, N'EPUB/Cruzada contra el Grial - Otto Rahn.epub', N'.epub', 0, 1);
END;

-- Libro 866: Un hombre sueña despierto
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Un hombre sueña despierto' AND Autor = N'Lavie Tidhar')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Un hombre sueña despierto', N'Lavie Tidhar', N'En el campo de concentración más infame de la historia, un hombre sueña despierto. Se llama Shomer, y antes de la guerra era escritor de novelas pulp. Ahora, para escapar de la brutal realidad de su vida en Auschwitz, pasa sus noches imaginando otro mundo, uno en el que un exdictador llamado Wolf lleva una vida miserable como detective en Londres.Como toda buena novela negra, la trama comienza en la oficina cutre del detective con la visita de una mujer fatal que requiere de sus servicios. Aquí empieza la caída libre del personaje en un proceso de humillación, destrucción y transformación. Tras todo tipo de vejaciones, Wolf, Adolf Hitler, acabará transformado en judío, en humano.El modo en que al final se entrelazan ficción y realidad es sobrecogedor. Una novela fantástica, de ritmo trepidante y muy divertida. Un homenaje inolvidable al poder de la imaginación.', @Cat_IntrigaOtros, N'EPUB/Un hombre sueña despierto - Lavie Tidhar.epub', N'.epub', 0, 1);
END;

-- Libro 867: Esposa de mi jefe
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Esposa de mi jefe' AND Autor = N'Rox Aguirre')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Esposa de mi jefe', N'Rox Aguirre', N'<div><div style="font-family: ''Segoe UI'', sans-serif; font-size: 13px; text-align: justify;"><span style="color: rgb(51, 51, 51); font-family: verdana, arial, helvetica, sans-serif; font-size: small; orphans: 2; widows: 2; background-color: rgb(255, 255, 255);">Alexandra Carlin, es una chica recién graduada de la universidad, sin éxito en el campo laboral, es contratada por fin como secretaria del presidente de una revista de prestigio a nivel internacional, Oliver Anderson, un joven apuesto de 25 años, Oliver está a punto de perder la presidencia de la empresa por no tener una vida formal, sus vidas dan un giro cuando hace un contrato con Alex de ser su esposa por seis meses.</span></div><div style="text-align: justify;"><font color="#333333" face="verdana, arial, helvetica, sans-serif" size="2"><br></font></div><span style="font-family: verdana, arial, helvetica, sans-serif; font-size: small; color: rgb(51, 51, 51); orphans: 2; widows: 2; background-color: rgb(255, 255, 255);"><div style="text-align: justify;">Conoce el divertido matrimonio odio-amor entre Alex Carlin y su jefe, una vez que nada sale como ellos esperaban.</div></span></div>', @Cat_Romancecontemporneoertico, N'EPUB/Esposa de mi jefe - Rox Aguirre.epub', N'.epub', 0, 1);
END;

-- Libro 868: (Las aventuras de Alfred y Agatha 1) Los
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'(Las aventuras de Alfred y Agatha 1) Los 10 pajaros Elster' AND Autor = N' Ana Campoy')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'(Las aventuras de Alfred y Agatha 1) Los 10 pajaros Elster', N' Ana Campoy', N'¿Qué hubiera ocurrido si Alfred Hitchcock y Agatha Christie se hubieran conocido de niños? ¿Qué aventuras habrían vivido? ¿Qué sorprendentes casos habrían resuelto juntos? Las aventuras de Alfred&Agatha nos muestra cómo podría haber sido la amistad de infancia de los dos maestros del suspense más importantes de nuestro tiempo. En esta primera entrega, Alfred vivirá la aventura más increíble que jamás hubiera imaginado. Junto a Agatha y Morritos Jones, investigará la desaparición de las diez joyas Elster, unas lujosas figuras con forma de pájaro. Y los tres se verán implicados en un caso de auténticos detectives cuando la dueña de las joyas, la vieja señora Elster, también desaparece. Alfred nunca hubiera pensado que saltaría en tirolina, que se colaría en una mansión a escondidas ni que sobreviviría a un ataque de pájaros hambrientos. Pero lo que jamás habría creído es que gracias a esta aventura, lograría encontrar amigos de verdad.', @Cat_Infantilmisterio, N'EPUB/(Las aventuras de Alfred y Agatha 1) Los 10 pajaros Elster - Ana Campoy.epub', N'.epub', 0, 1);
END;

-- Libro 869: La princesa de hielo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La princesa de hielo' AND Autor = N'Camilla Läckberg')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La princesa de hielo', N'Camilla Läckberg', N'En un pueblo que esconde muchos secretos es peligroso saber la verdad. Se llamaba Alexandra, era joven, rica y guapa, y nadie en el pueblo se puede explicar su muerte. Por pura casualidad, Erica, amiga de la infancia y autora de biografías, se ve involucrada en el caso. Había regresado a su pueblo natal para hacerse cargo de la casa que acababa de heredar de sus padres, recientemente fallecidos en un accidente, y para trabajar en su próximo libro. Cuando la familia de Alex le pide que escriba un recordatorio para el funeral, Erica, todavía conmocionada por la repentina muerte de su amiga, comienza a investigar la vida de la víctima.Con la ayuda del comisario Patrik, otro viejo conocido que pronto se convertirá en algo más que un amigo, descubre un oscuro secreto, largamente guardado. Alguien conoció a Alex desde su infancia y le preparó un helado lecho mortuorio.Camilla Läckberg dibuja finamente el retrato de la sociedad cerrada de una pequeña ciudad, en la que todos lo saben todo de todo el mundo, pero en la cual las apariencias son fundamentales.', @Cat_Policialmisterio, N'EPUB/La princesa de hielo - Camilla Läckberg.epub', N'.epub', 0, 1);
END;

-- Libro 870: Frío invierno en París
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Frío invierno en París' AND Autor = N'Dylan Martins, Janis Sandgrouse')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Frío invierno en París', N'Dylan Martins, Janis Sandgrouse', N'Cuando el vaso se llena, no hay más opción que poner remedio y distancia de por medio.

Eso es lo que hace Carmen cuando se da cuenta de que tiene que cambiar su vida.

Con una maleta y decidida a dejar todo atrás, viaja a París donde empezará a reconstruir su vida.

Una niña perdida, un hombre que dará la vuelta a su mundo, un secreto y un objetivo: ser feliz.

Acompaña a Carmen en esta huida sin retorno donde risas, emoción y amor serán parte de su rutina.', @Cat_Noespecificado, N'EPUB/Frío invierno en París - Dylan Martins, Janis Sandgrouse.epub', N'.epub', 0, 0);
END;

-- Libro 871: Némesis
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Némesis' AND Autor = N'Jo Nesbø')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Némesis', N'Jo Nesbø', N'Una cámara de seguridad muestra a un atracador en un banco de Oslo apuntando a un empleado. Le ha dado veinticinco segundos al director para que vacíe el cajero. Dispara. Ha tardado treinta y uno. A Harry Hole, el impredecible detective que ha dado fama mundial a Jo Nesbø, la imagen granulada del homicidio no se le va de la cabeza. Junto a la inexperta Beate Lønn deberá encontrar al asesino. Siguen la pista hasta un famoso atracador. Sólo que está en la cárcel. Además, Harry Hole tiene un gran defecto: nadie como él sabe crearse problemas y casi siempre huelen a alcohol. Cuando parecía que su vida privada había alcanzado la paz con Rakel y sus problemas en la comisaria estaban resueltos, amanece con una resaca que despierta sus peores pesadillas. Sólo recuerda la insensatez que cometió la noche anterior: atender la llamada y la invitación de Anna, una antigua novia, nada más. Lo peor es que Anna ha aparecido muerta esa misma mañana. Y él es el sospechoso, a menos que pueda aclarar y demostrar lo que ha hecho durante las últimas doce horas.', @Cat_Noespecificado, N'EPUB/Némesis - Jo Nesbø.epub', N'.epub', 0, 0);
END;

-- Libro 872: (Fjallbacka 02) Los gritos del pasado
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'(Fjallbacka 02) Los gritos del pasado' AND Autor = N'Camilla Lackberg')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'(Fjallbacka 02) Los gritos del pasado', N'Camilla Lackberg', N'La escritora Erika Falk y su compañero, el detective Patrik Hedströn, disfrutan de unas merecidas vacaciones en su casa en la pequeña población costera de Fjällbacka que, en verano, es visitada por muchos turistas. Erika está embarazada de ocho meses y la ola de calor hace especialmente difícil este último mes de gestación. En esta situación, lo que menos falta le hace a la joven pareja es un nuevo caso de asesinato. Pero las vacaciones de Patrik se terminan de golpe, cuanto un niño descubre casualmente el cadáver de una joven turista. Lo más extraño es que junto al cadáver aparecen los restos de dos mujeres desaparecidas años atrás. Las autopsias demuestran que las tres víctimas murieron estranguladas y que además fueron torturadas. Basando el suspense en la acertada caracterización de los personajes, el realismo de sus comportamientos y una excelente ambientación, Camilla Läckberg vuelve a mantener al lector sin aliento hasta la última página y consigue meternos de lleno en la piel de los protagonistas.', @Cat_Novelanegrathrillernrdico, N'EPUB/(Fjallbacka 02) Los gritos del pasado - Camilla Lackberg.epub', N'.epub', 0, 1);
END;

-- Libro 873: Artemis Fowl
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Artemis Fowl' AND Autor = N'Eoin Colfer')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Artemis Fowl', N'Eoin Colfer', N'Nom : Fowl. Prénom : Artemis. Age : 12 ans. Signes particuliers : une intelligence hors du commun. Profession : voleur. Recherché pour : enlèvement de fée et demande de rançon. Appel à tous les FARfadets, membres des Forces Armées de Régulation du Peuple des fées : cet humain est dangereux et doit être neutralisé par tous les moyens possibles. Un anti-héros pétillant de malice, une galerie de personnages décapants, des dialogues vifs et intelligents, une histoire au rythme débridé... Laissez-vous entraîner dans l''univers sophistiqué d''Eoin Colfer, unique et enchanteur.', @Cat_Fantsticojuvenil, N'EPUB/Artemis Fowl - La cuenta atrás - Eoin Colfer.epub', N'.epub', 0, 1);
END;

-- Libro 874: 3 pasos contra el sedentarismo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'3 pasos contra el sedentarismo' AND Autor = N'Juanje Ojeda')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'3 pasos contra el sedentarismo', N'Juanje Ojeda', N'<span style="font-family: Tahoma, sans-serif, Arial, Helvetica; orphans: 2; white-space: pre-wrap; widows: 2; background-color: rgb(255, 255, 255);">Caminar más, colgarte de las manos y sentarte a menudo en el suelo son los tres sencillos pasos que te ayudarán a moverte más y mejor y a contrarrestar los graves efectos del sedentarismo en tu bienestar. Si tienes problemas de movilidad, dolores o estrés, muy probablemente sean a causa de nuestro estilo de vida sedentario. Juanje Ojeda, entrenador personal, te da las claves para recuperar la funcionalidad de tu cuerpo sin invertir mucho tiempo ni aplicar técnicas complejas. Tienes en las manos la mejor guía para personas sedentarias de todas las edades, pero también para atletas avanzados, con ejercicios muy sencillos pero de gran impacto en nuestra salud.</span>', @Cat_Saludybienestar, N'EPUB/3 pasos contra el sedentarismo - Juanje Ojeda.epub', N'.epub', 0, 1);
END;

-- Libro 875: Las hijas del frío
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Las hijas del frío' AND Autor = N'Camilla Läckberg')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Las hijas del frío', N'Camilla Läckberg', N'La alegría de Erica y Patrik por el nacimiento de su hija es inmensa, pero deben enfrentarse a unos problemas nuevos para ellos; la pequeña llora mucho, Erica sufre una depresión posparto y Patrik está constantemente cansado. Erica encuentra entonces apoyo en Charlotte, madre de Sara, una niña de siete años que sufre el síndrome de deficiencia de atención cuando, de repente, se produce un drama totalmente inesperado. Un pescador encuentra el cadáver de la pequeña Sara, ahogada en el mar. Las autoridades piensan que se trata de un accidente, pero la autopsia revela que la pequeña fue ahogada en una bañera antes de ser arrojada al mar, y que alguien le hizo tragar cenizas.', @Cat_Policial, N'EPUB/Las hijas del frío - Camilla Läckberg.epub', N'.epub', 0, 1);
END;

-- Libro 876: Destino de cazadora
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Destino de cazadora' AND Autor = N'Mari Mancusi')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Destino de cazadora', N'Mari Mancusi', N'Rayne McDonald lo tenía todo calculado: convertirse en vampiro, ser la compañera del líder del Círculo de Sangre y vivir la buena vida para toda la eternidad... pero el destino tenía otros planes para ella. De hecho, Rayne no solo sigue siendo humana, sino que se ha enterado de que es una cazavampiros. Tras ser reclutada por una organización secreta, a Rayne le asignan su primera misión: infiltrarse en un bar de mala reputación y desenmascarar a su propietario vampiro, un tal Maverick, por propagar a propósito un virus en la sangre. Por suerte, el Círculo de Sangre envía ayuda, personificada en un sensual vampiro llamado Jareth. ¿Serán capaces el vampiro y la cazadora de resolver sus diferencias y trabajar juntos para detener a Maverick?', @Cat_Fantstica, N'EPUB/Destino de cazadora - Mari Mancusi.epub', N'.epub', 0, 1);
END;

-- Libro 877: (Star Wars) Asi que quieres ser un jedi
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'(Star Wars) Asi que quieres ser un jedi' AND Autor = N'Adam Gidwitz')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'(Star Wars) Asi que quieres ser un jedi', N'Adam Gidwitz', N'3 años después de la batalla de Yavin. ¿ASÍ QUE QUIERES SER UN JEDI? Parece emocionante. Puedes mover objetos con la mente. Controlar a la gente con tus pensamientos. Ah, y los sables de luz. Sí, son impresionantes. Pero no todo es poder mental y linternas armadas. Ser un jedi requiere de mucho trabajo. Además, hay tipos malos, muchísimos. Y quieren matarte. ¿AÚN QUIERES SER UN JEDI? Aquí encontrarás la historia de uno de los más grandes jedi de todos los tiempos y un recuento del clásico filme Star Wars El Imperio contraataca. Pero no sólo eso. Sabrás cómo ser un jedi. Tal vez no necesites aprender a levitar o percibir tu alrededor con los ojos vendados. Tal vez no te interese escuchar una historia sobre sables de luz, criaturas de nieve asesinas y naves espaciales, pero quizá sí. Y tal vez, sólo tal vez, quieras aprender a ser un jedi. Bueno, en ese caso, este es el libro para ti. La decisión, mi joven amigo, está en tus manos. Literalmente.', @Cat_Fantasacienciaficcinjuvenil, N'EPUB/(Star Wars) Asi que quieres ser un jedi - Adam Gidwitz.epub', N'.epub', 0, 1);
END;

