-- Libro 879: La villa de las telas
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La villa de las telas' AND Autor = N'Anne Jacobs')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La villa de las telas', N'Anne Jacobs', N'La villa de las telas abre de nuevo sus puertas. Llega la esperada cuarta parte de la saga superventas de Anne Jacobs. Una magnífica mansion Una época turbulenta Un amor que puede vencerlo todo... Augsburgo, 1930. Marie y Paul Melzer son felices y su amor es más fuerte que nunca. Su hijo menor, el pequeño Kurti, que ahora tiene cuatro años, es un rayo de sol que se gana el afecto de todo el mundo y los gemelos Dodo y Leo han crecido espléndidamente. Dodo ha descubierto su amor por la técnica y sueña con convertirse en aviadora, mientras que Leo demuestra un gran talento para el piano, que se ha convertido en su gran pasión. Pero la villa no es ajena a la agitada situación política en Alemania y la crisis económica golpea con fuerza el negocio familiar. Los Melzer tienen importantes deudas y Marie deberá enfrentarse a dolorosas decisiones para evitar la ruina. El destino de la familia está en juego. Y su amada villa de las telas solo podrá salvarse si todos permanecen unidos. Sobre los libros de la saga han dicho: «Amor imposible y las rígidas normas sociales de la Europa central a principios del siglo XX serán el escenario en el que se desenvuelva esta entretenida historia llena de secretos». Jorge Pato García, El Imparcial «Es una gran historia de amor, con tintes dramáticos y secretos familiares, que nos ha gustado tanto por su calidad literaria como por su preciosismo histórico». Revista Kritica «Downton Abbey en Augsburgo». Histo-couch «Este libro lo tiene todo, todo que podríamos desear para un día de lluvia: una gran historia de amor, intriga [...] y un gran secreto familiar». Delmenhorster Kreisblatt «Con su escritura fluida, Anne Jacobs sabe cómo seducir a sus lectoras y transportarlas a la vida de la alta sociedad de hace cien años con todo su glamour pero también con sus sombras». Weilheimer Tagblatt Los lectores opinan: «A todos los que os gustan las sagas familiares estos libros os van a encantar. De esos libros que tiene un ritmo muy bueno en todo momento, no decae para nada y hace su lectura muy agradable». Blog Leyendo entre páginas «Una historia de familias, de amor, de superación personal y de valentía. Pero de una valentía que no sabes que tienes hasta que la necesitas». Blog Viajando gracias a los libros «Si echáis de menos Downton Abbey (yo la echo de menos casi a diario) esta saga llenará ese hueco por completo». labibliotecadelaabuela en Instagram « Regreso a la Villa de las telas ha sido la vuelta a uno de mis lugares favoritos de la literatura». Patricia Llamas para Sigue en serie', @Cat_Sagafamiliarficcinhistrica, N'EPUB/La villa de las telas - Anne Jacobs.epub', N'.epub', 0, 1);
END;

-- Libro 880: Los gritos del pasado
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Los gritos del pasado' AND Autor = N'Camilla Läckberg')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Los gritos del pasado', N'Camilla Läckberg', N'La escritora Erika Falk y su compañero, el detective Patrik Hedström, disfrutan de unas merecidas vacaciones en su casa en la pequeña población costera de Fjällbacka que, en verano, es visitada por muchos turistas. Erika está embarazada de ocho meses y la ola de calor hace especialmente difícil este último mes de gestación. En esta situación, lo que menos falta le hace a la joven pareja es un nuevo caso de asesinato. Pero las vacaciones de Patrik se terminan de golpe, cuanto un niño descubre casualmente el cadáver de una joven turista. Lo más extraño es que junto al cadáver aparecen los restos de dos mujeres desaparecidas años atrás. Las autopsias demuestran que las tres víctimas murieron estranguladas y que además fueron torturadas.Basando el suspense en la acertada caracterización de los personajes, el realismo de sus comportamientos y una excelente ambientación, Camilla Läckberg vuelve a mantener al lector sin aliento hasta la última página y consigue meternos de lleno en la piel de los protagonistas.', @Cat_Policial, N'EPUB/Los gritos del pasado - Camilla Läckberg.epub', N'.epub', 0, 1);
END;

-- Libro 881: El juramento de un libertino
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El juramento de un libertino' AND Autor = N'Stephanie Laurens')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El juramento de un libertino', N'Stephanie Laurens', N'Vane Cynster siempre había sabido hacia dónde soplaba el viento: en dirección al matrimonio. Tal vez a los demás varones de la familia Cynster no les importase llegar al altar, pero Vane nunca quiso verse atado a ninguna mujer, por muy encantadora que fuera. Bellamy May le parecía el lugar perfecto para ocultarse durante un tiempo de las cazamaridos de Londres; pero cuando conoció a Patience Debbington comprendió que había encontrado la pareja ideal para él, y pronto nació en su mente algo más que el deseo de seducción.', @Cat_NovelaRomntico, N'EPUB/El juramento de un libertino - Stephanie Laurens.epub', N'.epub', 0, 1);
END;

-- Libro 882: La ira y el amanecer
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La ira y el amanecer' AND Autor = N'Renée Ahdieh')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La ira y el amanecer', N'Renée Ahdieh', N'«Cien vidas por la que tomasteis. Una vida por cada amanecer». En una tierra regida por un monstruoso califa, cada nuevo amanecer rompe el corazón de una familia. Día tras día, el rey contrae matrimonio con una joven que al alba es ejecutada. «Si falláis una sola vez, os arrebataré vuestros sueños, os arrebataré vuestra ciudad. Y os arrebataré estas vidas multiplicadas por mil». Por eso es un misterio cuando una desconocida se presenta voluntaria para casarse con él. Esa misma noche, ella le cuenta una historia. «Yo no estoy aquí para luchar. Estoy aquí para ganar». Y por primera vez, la aurora no llega teñida de rojo. «Os juro que viviré para ver todos los atardeceres posibles. Y que os mataré. Con mis propias manos».', @Cat_JuvenilOtros, N'EPUB/La ira y el amanecer - Renée Ahdieh.epub', N'.epub', 0, 1);
END;

-- Libro 883: (Fjallbacka 08) La mirada de los ángeles
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'(Fjallbacka 08) La mirada de los ángeles' AND Autor = N'Camilla Lackberg')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'(Fjallbacka 08) La mirada de los ángeles', N'Camilla Lackberg', N'Cuando ya lo has perdido todo, puede que alguien quiera destruirte también a ti.Tras la muerte accidental de su hijo pequeño, Ebba y Mårten se trasladan a la isla de Valö para rehacer su vida. Ahí, se instalan en una granja en la que vivió la familia de Ebba hace muchos años. Pero la tragedia los sigue acechando, y un incendio, a todas luces provocado, saca a relucir la historia siniestra que pesa sobre la granja. Hace treinta años toda la familia de Ebba desapareció sin dejar rastro. Solo se salvó ella, entonces un bebé de un año, a quien encontraron sola en la casa. Desde ese momento, recibe una misteriosa felicitación el día de su cumpleaños, firmada con una simple G…Patrik abre una investigación, y Erica, siempre en busca de material narrativo, empieza a tirar del hilo de la historia de la granja por su cuenta. Un acto impulsivo de Anna, la hermana de Erica, aún afectada por la pérdida del bebé que esperaba, revelará la verdad de golpe.', @Cat_Novelanegrathrillernrdico, N'EPUB/(Fjallbacka 08) La mirada de los ángeles - Camilla Lackberg.epub', N'.epub', 0, 1);
END;

-- Libro 884: Mi suerte eres tú
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Mi suerte eres tú' AND Autor = N'Kate Danon')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Mi suerte eres tú', N'Kate Danon', N'<div>
<p style="font-size: 14px; font-family: ''Amazon Ember'',''Arial'',''sans-serif''"><span style="color: #333333; background-color: #ffffff">Los sueños a veces se hacen realidad. Sin embargo, en ocasiones, se vuelven pesadillas. Jennifer Morrison lo descubrió cuando emigró a California en busca de un marido y se encontró con un demonio que transformó su vida en un infierno. Ahora, tras enviudar, su existencia en Loan''s Valley se ha convertido en una rutina solitaria que carece de cualquier aliciente. Pero está a salvo y ya nadie la maltrata. No volverán a hacerle daño, porque ha blindado su corazón y no piensa volver a enamorarse nunca más... Hasta que Nat Hardei, un itinerante jugador de póker, llega a Loan''s Valley desplegando su encanto canalla y sus modales elegantes, tan distintos al del resto de los vaqueros del lugar. El recién llegado despierta en ella sentimientos olvidados y tendrá que luchar con todas sus fuerzas para no dejarse engatusar por ese conquistador nato. Un hombre que disfruta de su libertad y que vive cada momento dejándose llevar, sin pensar en las consecuencias. Un hombre que no le conviene en absoluto, que lleva la fiebre del juego en las venas y que nunca se queda mucho tiempo en un mismo lugar. Sin embargo, el destino es caprichoso y logra que Nat y Jenny se embarquen juntos en una aventura inesperada que pondrá a prueba sus mutuas convicciones. </span><strong style="color: #333333; background-color: #ffffff">Ella descubrirá que estar a salvo no es lo mismo que estar viva, y él se dará cuenta de que, a veces, la mejor manera de ganar la partida más importante, es guardar bajo la manga un as de corazones.</strong></p></div>', @Cat_Romntica, N'EPUB/Mi suerte eres tú - Kate Danon.epub', N'.epub', 0, 1);
END;

-- Libro 885: Las luces de septiembre
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Las luces de septiembre' AND Autor = N'Carlos Ruiz Zafón')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Las luces de septiembre', N'Carlos Ruiz Zafón', N'Un misterioso fabricante de juguetes vive recluido en una mansión gigantesca poblada de seres mecánicos y sombras del pasado. Un enigma en torno a las extrañas luces que brillan entre la niebla que rodea el islote del faro. Una criatura de pesadilla que se oculta en la profundidad del bosque. Estos y otros elementos tejen la trama del misterio que unirá a Irene e Ismael para siempre durante un mágico verano en Bahía Azul.', @Cat_NovelaIntrigaJuvenil, N'EPUB/Las luces de septiembre - Carlos Ruiz Zafón.epub', N'.epub', 0, 1);
END;

-- Libro 886: (Fjallbacka 05) Las huellas imborrables
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'(Fjallbacka 05) Las huellas imborrables' AND Autor = N'Camilla Lackberg')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'(Fjallbacka 05) Las huellas imborrables', N'Camilla Lackberg', N'El secreto de una joven en los años cuarenta. Un nuevo caso trepidante de Erica Falck y Patrik Hedström. El verano llega a su fin y la escritora Erica Falck vuelve al trabajo tras la baja de maternidad. Ahora le toca a su compañero, el comisario Patrik Hedström, tomarse un tiempo libre para ocuparse de la pequeña Maja. Pero el crimen no descansa nunca, ni siquiera en la tranquila ciudad de Fjällbacka, y cuando dos adolescentes descubren el cadáver de Erik Frankel, Patrik compaginará el cuidado de su hija con su interés por el asesinato de este historiador especializado en la Segunda Guerra Mundial. Mientras tanto, Erica hace un sorprendente hallazgo: diarios de su madre Elsy, con quien tuvo una relación difícil, junto con una antigua medalla nazi. Pero lo más inquietante es que, poco antes de la muerte del historiador, Erica había ido a su casa para obtener más información sobre la medalla. ¿Es posible que su visita desencadenara los acontecimientos que condujeron a su muerte? En «Las huellas imborrables» Camilla Läckberg entreteje con maestría una historia contemporánea con la vida de una joven en la Suecia de 1940. Escrita con numerosos «flashbacks», en esta novela Erica Falck debe adentrarse en el oscuro pasado de su propia familia.', @Cat_Novelanegrathrillernrdico, N'EPUB/(Fjallbacka 05) Las huellas imborrables - Camilla Lackberg.epub', N'.epub', 0, 1);
END;

-- Libro 887: Batir de alas
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Batir de alas' AND Autor = N'Paul Hoffman')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Batir de alas', N'Paul Hoffman', N'Thomas Cale ha estado huyendo de la verdad. Desde que descubrió que su brutal formación militar obedecía a un solo propósito —la destrucción del mayor error divino, la humanidad. Cale vive bajo la amenaza fantasmal del hombre que le convirtió en Ángel de la Muerte: el papa redentor Bosco. Pero Cale no ha dicho todavía su última palabra: la suerte de la humanidad está en sus manos.', @Cat_NovelaAventurasFantstico, N'EPUB/Batir de alas - Paul Hoffman.epub', N'.epub', 0, 1);
END;

-- Libro 888: Te veré bajo el hielo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Te veré bajo el hielo' AND Autor = N'Robert Bryndza')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Te veré bajo el hielo', N'Robert Bryndza', N'Su cuerpo está congelado. Sus ojos cerrados han visto la muerte. Sus labios parecen estar a punto de decirnos algo. El thriller que ha sorprendido a más de 1.000.000 de lectores. Un joven descubre el cadáver de una chica debajo de una gruesa capa de hielo en un parque del sur de Londres. La detective Erika Foster será la encargada de dirigir la investigación del caso, mientras lucha contra sus propios demonios personales. Cuando Erika comienza a indagar en el pasado de la víctima, todo parece apuntar que su asesinato está conectado con el homicidio de otras tres mujeres que han sido encontradas con signos de estrangulación, las manos atadas y, sospechosamente, también bajo las aguas congeladas de otros lagos en Londres. Poco a poco, Erika se aproxima a la verdad, sin sospechar que el asesino quizá también la observa y se acerca cada vez más a ella. Reseñas: «Ha nacido una nueva detective estrella.» La Razón «Un excelente modelo o ejemplo de novela negra, negrísima y muy actual.» Juan Bolea, El Periódico de Aragón «Todo un fenómeno mundial en lo que al thriller británico se refiere.» Laura Fernández, El Mundo «Leí de un tirón Te veré bajo el hielo. Y lo hice con esa gratificación que dejan los libros muy bien construidos.» J. Ernesto Ayala-DIP, El Correo «Un thriller sorprendente, ameno, que se "devora" sin respiro.» Quelibroleo «Una historia de bajos fondos y alta sociedad con pulso de gran thriller.» Cultura|s de La Vanguardia «El amplio abanico de posibles sospechosos, los constantes giros y, sobre todo, el buen ritmo que mantiene Robert Bryndza, hacen que la lectura sea amena, intrigante y altamente recomendable.» Revista Krítica «Las aventuras de una detective de origen eslovaco y con un carácter de hierro.» El Periodico / EFE «Todo lo que se le pide a una novela de este género: Trama trepidante, intriga hasta el desenlace, ritmo frenético, grandes personajes y un final impactante.» Carmen en su tinta «Una gran trama que apela a lo más profundo de la naturaleza humana.» Book Lover «Lleno de pistas inteligentes y de giros. Mantiene al lector cautivado hasta la última página.» The Book Review Café «Un thriller que te mantendrá en vilo toda la noche.» Booked: The Crime Fiction Club «Una novela adictiva y compulsiva.» For the Love of Books «Una lectura que atrapa, con un final totalmente sorprendente. Absolutamente necesaria para todos los fans de la novela criminal.» The Letter Book Reviews', @Cat_Thrillerpolicial, N'EPUB/Te veré bajo el hielo - Robert Bryndza.epub', N'.epub', 0, 1);
END;

-- Libro 889: Un amor secreto
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Un amor secreto' AND Autor = N'Stephanie Laurens')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Un amor secreto', N'Stephanie Laurens', N'En el Londres de la Regencia, todos saben que ninguno de los Cynster abandonaría a una dama en problemas& Pero su protección puede tener un alto y muy seductor precio para la dama en cuestión. Cuando una mujer misteriosa, con el rostro oculto por un velo negro, le ruega a Gabriel Cynster que la ayude, él no puede resistirse. A cambio, sin embargo, le exige algo que sólo un Cynster podría pedir: por cada dato que él le aporte ella debe pagarle con un beso. Lady Alathea Morwellan sabe que Gabriel está intrigado. A pesar de la inocultable atracción que los une, nunca lograron estar juntos sin reñir. Por otra parte, cuantas más cosas están en juego, más crece el deseo de Gabriel por obtener su pago, y cada beso embriagador, cada brazo apasionado, aleja para Alathea la posibilidad de resistir la seducción final... Pero ¿qué pasará cuando ella le revele la verdad que tan celosamente le oculta?', @Cat_NovelaRomntico, N'EPUB/Un amor secreto - Stephanie Laurens.epub', N'.epub', 0, 1);
END;

-- Libro 890: La guerra de los cielos: Volumen IV
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La guerra de los cielos: Volumen IV' AND Autor = N'Fernando Trujillo Sanz')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La guerra de los cielos: Volumen IV', N'Fernando Trujillo Sanz', N'La guerra más antigua y devastadora de la existencia ha encontrado el modo de continuar, de extenderse por toda la creación. El Cielo y el Infierno ya no son los únicos escenarios para este terrible conflicto.Comenzó cuando el planeta se estremeció. Todos los habitantes perdieron la facultad de moverse, quedando resignados a contemplar impotentes cómo todo su mundo se desmoronaba. Al fenómeno lo llamaron la Onda y produjo cambios más allá de la comprensión humana. Después de aquello nada volvió a ser lo mismo para ninguno de nosotros.Ahora tenemos que sobrevivir a las consecuencias. Los ángeles y los demonios están entre nosotros, son reales, y nos han impuesto su guerra. Una guerra en la que somos insignificantes, una guerra que no creímos posible y que cambiará nuestras vidas para siempre.', @Cat_Fantstico, N'EPUB/La guerra de los cielos - Volumen IV - Fernando Trujillo Sanz.epub', N'.epub', 0, 1);
END;

-- Libro 891: S.E.C.R.E.T. 2 - Secretos compartidos
