-- Libro 892: Witch Heart
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Witch Heart' AND Autor = N'Anya Bast')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Witch Heart', N'Anya Bast', N'Third in the Elemental Witch series from the national bestselling author View our feature on Anya Bast’s Witch Heart. Claire, a demon’s handmaiden, is rescued from enslavement by a handsome playboy. Now they’re both in danger of being captured by warlocks who are determined to harness Claire’s powers for evil.', @Cat_Noespecificado, N'EPUB/Witch Heart - Anya Bast.epub', N'.epub', 0, 0);
END;

-- Libro 893: La hermana perla
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La hermana perla' AND Autor = N'Lucinda Riley')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La hermana perla', N'Lucinda Riley', N'<span itemprop="description"><b>Subtitulado: La historia de Cece.</b><br>
<br>
CeCe D’Aplièse nunca ha encajado en ningún lugar. Tras la muerte de su 
padre, el misterioso multimillonario Pa Salt, que adoptó a las seis 
hermanas desde distintas partes del mundo, se encuentra en una 
encrucijada: ha dejado la escuela de arte y su hermana Star se distancia
 de ella para perseguir su sueño.<br>
A la desesperada decide huir de Londres y descubrir su pasado. Las 
únicas pistas que tiene son una fotografía y el nombre de una mujer 
pionera que vivió en Australia hace un siglo.<br>
De camino hacia Sidney hace parada en el único lugar donde se ha sentido
 ella misma: las playas de Krabi en Tailandia, donde conoce al 
misterioso Ace.<br>
Cien años antes Kitty McBride, hija de un reverendo de Edimburgo, viaja a
 Australia como dama de compañía de la acaudalada señora McCrombie. En 
Adelaida su destino se ve unido a la rica familia, incluidos los 
idénticos aunque muy diferentes gemelos, el impetuoso Drummond y el 
ambicioso Andrew, heredero de una fortuna en la industria de la perla.</span>', @Cat_Narrativa, N'EPUB/La hermana perla - Lucinda Riley.epub', N'.epub', 0, 1);
END;

-- Libro 894: La llamada de las sombras
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La llamada de las sombras' AND Autor = N'Karen Chance')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La llamada de las sombras', N'Karen Chance', N'Un legado reciente convirtió a Cassandra Palmer en heredera del título de pitia, la vidente más poderosa del mundo. Normalmente, el puesto se consigue después de años de entrenamiento, pero las circunstancias que rodean a Cassie son un tanto anormales. Ahora, Cassie se ve atrapada en una situación en la que dispone de una cantidad ingente de poder que los vampiros, duendes y magos de la ciudad quieren monopolizar o erradicar a toda costa… y que ella misma no se atreve a usar. Es más, Cassandra acaba de descubrir que cierto maestro vampiro un tanto arrogante le ha lanzado un hechizo mágico que advierte a cualquier posible pretendiente para que no se acerque a ella... y que podría explicar la incomprensible atracción que existe entre ellos.', @Cat_NovelaAventurasFantsticoTerrorRomntico, N'EPUB/La llamada de las sombras - Karen Chance.epub', N'.epub', 0, 1);
END;

-- Libro 895: Cucarachas
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Cucarachas' AND Autor = N'Jo Nesbø')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Cucarachas', N'Jo Nesbø', N'El embajador noruego aparece asesinado en un burdel de Bangkok. El embajador mantenía relaciones muy cercanas con el primer ministro noruego. En Oslo, para evitar el escándalo, tratan de desviar la atención hacia el ministro de Asuntos Exteriores… Harry Hole, alcoholizado y adicto a la vitamina B12, llega a Bangkok con instrucciones claras: silenciar el caso. ¿Será necesario ocultar pruebas? Harry descubre que el caso esconde otras tramas siniestras: se trata de un asesinato mucho más complejo de lo que a priori parecía. Inmerso en el ruido y el tráfico de una ciudad multitudinaria, Harry recorre las calles de un Bangkok lleno de bares de alterne, templos, fumadores de opio, trampas para turistas… Harry trata de encontrar la clave del asesinato del embajador, aunque nadie se lo ha pedido. Y nadie le quiere cerca, ni siquiera él mismo…', @Cat_NovelaPolicial, N'EPUB/Cucarachas - Jo Nesbø.epub', N'.epub', 0, 1);
END;

-- Libro 896: (Fjallbacka 01) La princesa de hielo 
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'(Fjallbacka 01) La princesa de hielo ' AND Autor = N'Camilla Lackberg')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'(Fjallbacka 01) La princesa de hielo ', N'Camilla Lackberg', N'En un pueblo que esconde muchos secretos es peligroso saber la verdad. Se llamaba Alexandra, era joven, rica y guapa, y nadie en el pueblo se puede explicar su muerte. Por pura casualidad, Erica, amiga de la infancia y autora de biografías, se ve involucrada en el caso. Había regresado a su pueblo natal para hacerse cargo de la casa que acababa de heredar de sus padres, recientemente fallecidos en un accidente, y para trabajar en su próximo libro. Cuando la familia de Alex le pide que escriba un recordatorio para el funeral, Erica, todavía conmocionada por la repentina muerte de su amiga, comienza a investigar la vida de la víctima. Con la ayuda del comisario Patrik, otro viejo conocido que pronto se convertirá en algo más que un amigo, descubre un oscuro secreto, largamente guardado. Alguien conoció a Alex desde su infancia y le preparó un helado lecho mortuorio. Camilla Läckberg dibuja finamente el retrato de la sociedad cerrada de una pequeña ciudad, en la que todos lo saben todo de todo el mundo, pero en la cual las apariencias son fundamentales.', @Cat_Novelanegrathrillernrdico, N'EPUB/(Fjallbacka 01) La princesa de hielo - Camilla Lackberg.epub', N'.epub', 0, 1);
END;

-- Libro 897: Innovación docente en didáctica de la le
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Innovación docente en didáctica de la lengua y la literatura: teoría e investigación' AND Autor = N'Pilar Núñez Delgado, Irene Alonso Aparicio')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Innovación docente en didáctica de la lengua y la literatura: teoría e investigación', N'Pilar Núñez Delgado, Irene Alonso Aparicio', N'El libro recoge varias aportaciones surgidas de un proyecto de innovación de la docencia universitaria desarrollado en la Universidad de Granada. El principal propósito de este ha sido dar a conocer —en el plano teórico y principalmente en la práctica— a los estudiantes de los grados de Maestro de Educación Infantil y de Maestro de Educación Primaria estrategias metodológicas adecuadas para el desarrollo de la competencia comunicativa y literaria de los escolares, dado que el ámbito de innovación que parece más rentable para lograr tales metas es, sin duda, el de la metodología. Esta metodología, entendida como el conjunto de criterios y decisiones que organiza la acción didáctica y que define el estilo educativo del docente, lejos de ser un elemento menor, es la clave para la implementación del necesario cambio que contribuya a desterrar el gramaticalismo y el historicismo que aún imperan en nuestras aulas. Los trabajos aquí compilados pueden ser útiles, por una parte, tanto para los docentes en ejercicio como para los que se preparan para serlo, especialmente para los de lengua y literatura. Además, también pueden guiar a profesores universitarios que forman a futuros docentes.', @Cat_EducacinDidcticaInvestigacin, N'EPUB/Innovación docente en didáctica de la lengua y la literatura - teoría e investigación - Pilar Núñez Delgado, Irene Alonso Aparicio.epub', N'.epub', 0, 1);
END;

-- Libro 898: El tiempo suficiente
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El tiempo suficiente' AND Autor = N'Amara Castro Cid')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El tiempo suficiente', N'Amara Castro Cid', N'<div>
<p style="font-family: ''Amazon Ember'',''Arial'',''sans-serif''; font-size: 14px"><span style="color: #000000">Las hermanas Telma y Celia viven en Vigo. Telma es una enfermera que se preocupa por sus pacientes y que presta especial atención a un anciano llamado Pío. Celia, dos años más joven, acaba de ascender a jefa de departamento en su empresa, pero no se siente a gusto en la compañía. Las comidas de los miércoles en casa de su abuela Gala, un importante referente para las hermanas, son lo más sagrado para las tres. Cuando la abuela fallece, las hermanas leen juntas las memorias que les ha dejado y descubren muchos detalles que desconocían de Gala, una mujer fuerte que perdió a su primer marido y su gran amor cuando su hija, Amparo, tenía tan solo dos años. Afortunadamente, volvió a encontrar la felicidad al lado de su segundo marido, Rodrigo, el abuelo que conocieron las dos hermanas.</span></p></div>', @Cat_Noespecificado, N'EPUB/El tiempo suficiente - Amara Castro Cid.epub', N'.epub', 0, 0);
END;

-- Libro 899: Hambre
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Hambre' AND Autor = N'Roxane Gay')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Hambre', N'Roxane Gay', N'<div>
<p>En sus tremendamente populares ensayos y en su blog de Tumblr, Roxane Gay ha escrito con intimidad y sensibilidad sobre la comida y el cuerpo, usando sus propias luchas emocionales y psicológicas como una forma de explorar nuestras ansiedades compartidas sobre el placer, el consumo, la apariencia y la salud.<br>Como mujer que describe su propio cuerpo como "salvajemente indisciplinado", Roxane comprende la tensión entre el deseo y la negación, entre el confort con uno misma y cuidarse.<br>En <em>Hambre</em> explora su pasado, incluido el devastador acto de violencia que supuso un punto de inflexión en su joven vida, y acerca a los lectores en su viaje para comprender y finalmente salvarse a sí misma.</p></div>', @Cat_Noespecificado, N'EPUB/Hambre - Roxane Gay.epub', N'.epub', 0, 0);
END;

-- Libro 900: Promesas en la oscuridad
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Promesas en la oscuridad' AND Autor = N'Sadie Matthews')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Promesas en la oscuridad', N'Sadie Matthews', N'Déjate llevar por el corazón... ¿Se puede salvar un amor que ha sufrido una profunda fractura? Separarme de Dominic me había dejado mucho más hundida de lo que nunca me pude imaginar. Me tenía en sus manos en cuerpo y alma, pero un malentendido hizo que todo saltara en pedazos. El dolor y la tristeza me persiguen como un a sombra y me resulta imposible darle sentido a mi vida. Un momento con él y la sangre me hierve de nuevo, su contacto enciende un fuego que mi cuerpo se ha negado a olvidar. Estoy perdida, indefensa ante Dominic. Encontrar la forma de recuperar lo que fuimos va a exigirnos mucha confianza y tener fe el uno en el otro. Sólo así sabremos si existe la posibilidad de que lo que hay entre nosotros dure para siempre. Intensidad, sensualidad y seducción? Todas estas sensaciones esperan en esta parte final de la excitante trilogía romántica que ha cautivado a miles de lectores en todo el mundo.', @Cat_loveerotica, N'EPUB/Promesas en la oscuridad - Sadie Matthews.epub', N'.epub', 0, 1);
END;

-- Libro 901: Vengo a matarle
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Vengo a matarle' AND Autor = N'W. Martyn')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Vengo a matarle', N'W. Martyn', N'Un jinete a todo galope entró en la polvorienta calzada que formaba la mejor calle de Fontenelle, en Wyoming, casi en las márgenes del Green River y detuvo el caballo frente a una de las tabernas de la calle. Se apeó casi antes de que el animal detuviese su loca carrera y penetró en el establecimiento preguntando: — ¿Está mi patrón? —Está ahí dentro, en el reservado. El peón cruzó el pasillo y empujó una puerta penetrando en el reservado, donde ante una botella con dos vasos, uno de ellos vacío, se encontraba el patrón por quien el jinete preguntaba. Se trataba de un hombre que aún no habría cumplido los cuarenta años. Era alto, bien proporcionado, guapo y de facciones enérgicas. Tenía un cigarrillo entre los morenos dedos y un vaso a medio llenar en el borde de la mesa. Vestía con bastante elegancia, acusando el traje su posición acomodada. Era un ranchero de la localidad llamado Babe Lucien. El peón, un poco agitado, exclamó: —Patrón, Tiger viene hacia aquí… ¿Manda usted algo? —Nada, puedes marcharte. — ¿No… me… necesitará…?', @Cat_Westernthriller, N'EPUB/Vengo a matarle - W. Martyn.epub', N'.epub', 0, 1);
END;

-- Libro 902: Huye
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Huye' AND Autor = N'Lisa McMann')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Huye', N'Lisa McMann', N'Por primera vez en años, Janie se va de vacaciones. Está pasando unos días en la cabaña del lago que tiene el hermano de Cabe, lejos de su madre alcohólica y del revuelo que ha causado en el pueblo la revelación de que ella trabaja para la policía. Por suerte, ya puede dejar de esconder su relación con Cabe y el año que viene comienza la universidad, lejos del pueblo. Por desgracia sus poderes le evitan llevar una vida normal, y tras un par de incidentes con sueños en los que Cabe no reacciona como ella espera, Janie comienza a tener dudas. Pero todo deja de tener importancia cuando Janie recibe una llamada de Carrie en la que su amiga le informa que ha tenido que llevar a su madre al hospital. Janie y Cabe vuelven corriendo para descubrir que no es la madre de Janie la que está ingresada, si no su padre, al que Janie jamás conoció ya que abandonó a su madre antes de que ella naciera. El padre está en coma, y la única persona que aparece en los papeles médicos que hay en su casa es su madre, que no quiere saber nada del tema. Sospecha que su padre podría ser como ella y tener la habilidad de entrar en los sueños de los demás, así que comienza a investigar su vida y su pasado para intentar descifrar su propio futuro.', @Cat_NovelaJuvenilFantstico, N'EPUB/Huye - Lisa McMann.epub', N'.epub', 0, 1);
END;

-- Libro 903: Un conde sin corazón
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Un conde sin corazón' AND Autor = N'Nuria Rivera')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Un conde sin corazón', N'Nuria Rivera', N'<p>Para encontrar el amor… ¿será necesario convertirse en una dama?</p> <p>Algunas reglas están para romperlas.</p> <p>&nbsp;</p> <p>Para retrasar la decisión paterna de un matrimonio concertado, <i xml:lang="en">lady</i> Rose Mary Lowell ingresa en la Escuela de Señoritas de lady Acton, en Minstrel Valley, para convertirse en una Dama Selecta y enfrentarse a su destino: un matrimonio sin amor. Allí, su solitaria y triste existencia, se llena de amistad y camaradería; aunque la melancolía que a veces la consume, y una noticia que temía, la lleva a un acto desesperado.</p> <p>El nuevo conde de McEwan, Richard Bellamy, se formó como médico porque no iba a heredar un título, pero la muerte de su hermano trastoca sus planes. Si algo tiene claro es que jamás entregará su corazón, sencillamente porque no tiene. La invitación de su tía a visitarla le sirve de excusa para alejarse de esa vida que lo aburre y busca refugiarse en el pueblo donde encontró sosiego tras la muerte de su padre.</p> <p>La casualidad hace que sea testigo de la acción desolada de una joven y se lance a ayudarla. Conocer a la ninfa a la que salvó acrecentará su deseo y es que desde el momento en que la tuvo entre sus brazos se propuso seducirla y poseerla, sin pensar en el riesgo que eso supondría.</p> <p>Rose está resignada a su destino, aunque la intensa seducción que le ofrece el nuevo conde de McEwan le hará olvidar algunas reglas para ser una dama. ¿Será capaz de no entregar su corazón a alguien que no tiene y casarse con otro?</p>', @Cat_NovelaRomnticoHistrico, N'EPUB/Un conde sin corazón - Nuria Rivera.epub', N'.epub', 0, 1);
END;

-- Libro 904: Una sombra en la oscuridad (Serie Erika 
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Una sombra en la oscuridad (Serie Erika Foster) (Spanish Edition)' AND Autor = N'Robert Bryndza')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Una sombra en la oscuridad (Serie Erika Foster) (Spanish Edition)', N'Robert Bryndza', N'En el ocaso de una sofocante noche de calor, la detective Erika Foster recibe una llamada para asistir a la escena de un crimen. La víctima es hallada asfixiada en su cama. Sus muñecas están atadas y se perciben sus abultados ojos a través de una bolsa de plástico atada por encima de su cabeza. Pocos días después, otra víctima es encontrada muerta; la escena del crimen es exactamente igual. Mientras Erika Foster y su equipo comienzan a profundizar en la investigación, pronto descubren que se enfrentan a un calculador asesino en serie que acecha a sus víctimas antes de elegir el momento más oportuno para atacarlas. Todas las víctimas son hombres solteros, con vidas privadas muy alejadas del foco público. ¿Por qué sus pasados están envueltos en tantos secretos? Y sobre todo, ¿qué es lo que les unía a cada uno de ellos con el asesino?', @Cat_Ficcinmoderna, N'EPUB/Una sombra en la oscuridad (Serie Erika Foster) (Spanish Edition) - Robert Bryndza.epub', N'.epub', 0, 1);
END;

-- Libro 905: Artemis Fowl: Encuentro en el ártico
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Artemis Fowl: Encuentro en el ártico' AND Autor = N'Eoin Colfer')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Artemis Fowl: Encuentro en el ártico', N'Eoin Colfer', N'¿Todavía sigues ahí? A estas alturas, ya sabes que no soy una persona —por favor, lo de niño dejémoslo para los adultos ignorantes— normal. Después de conseguir el oro que necesitaba, tenía otra prioridad: rescatar a mi padre, secuestrado en algún lugar del frío Antártico. No fue fácil, pero pude chantajear al mundo subterráneo para que me ayudaran porque, como decimos los humanos, ''En todas partes cuecen habas'' y ellos no lo están pasando demasiado bien: así que hicimos un pacto de caballeros…', @Cat_FantsticoJuvenil, N'EPUB/Artemis Fowl Encuentro en el ártico - Eoin Colfer.epub', N'.epub', 0, 1);
END;

-- Libro 906: La sombra del minotauro
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La sombra del minotauro' AND Autor = N'Antonio Lozano')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La sombra del minotauro', N'Antonio Lozano', N'Las Palmas de Gran Canaria. En su despacho, el detective José García Gago recibe la visita de María Elena y José Miguel Bravo, hijos de un acaudalado empresario de edad avanzada, que ven peligrar su herencia próxima y sustanciosa por la relación que su padre mantiene con una joven dominicana. El asesinato de ésta convertirá sin embargo lo que parecía una investigación anodina en una rocambolesca historia que obligará al detective a asociarse al inspector Márquez, y que conducirá a ambos a través de los laberintos de la actividad mafiosa de la isla, con el análisis satírico de la doble moral de una burguesía rancia y trasnochada como telón de fondo. Una trama en la mejor tradición del género negro sobre la que, permanentemente, planea la sombra del Minotauro. Y, tal vez, la mejor novela de Antonio Lozano, que fuera ganador de la primera edición del Premio Internacional de Novela Negra Ciudad de Carmona por su celebrada y memorable “El caso Sankara”. ''Antonio Lozano es uno de los mejores narradores del género negro en español. No en vano fue apadrinado en sus comienzos por el mismísimo Vázquez Montalbán''. Rogelio Dueñas', @Cat_Policial, N'EPUB/La sombra del minotauro - Antonio Lozano.epub', N'.epub', 0, 1);
END;

-- Libro 907: Secretos En La Oscuridad
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Secretos En La Oscuridad' AND Autor = N'Sadie Matthews')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Secretos En La Oscuridad', N'Sadie Matthews', N'<p class="description">Enamorarme de Dominic me cambió como persona. Renuncié totalmente a lo que era antes y le entregué mi corazón y mi confianza, pero en un momento exquisito y a la vez terrible, él perdió el control. Angustiado por lo que había hecho, decidió encerrar sus deseos oscuros en lo más profundo de su ser.Ahora Dominic no es el único que necesita desesperadamente ese juego de seducción que implica caminar por el filo de la pasión, entre el dolor y el placer, el desenfreno y la liberación. Persuadir a Dominic para que deje salir esa parte tan íntima de sí mismo va a suponer el mayor riesgo que he corrido en mi vida, pero no puedo evitarlo. Aunque eso signifique que no volvamos a estar juntos nunca más.Provocativa y sofisticada, emocionante y seductora,''Secretos en la oscuridad''te llevará de la mano de Beth y Dominic por caminos que nunca imaginaste, por placeres cautivadores que siempre soñaste. Te acercará un paso más al filo agridulce de la pasión.</p>', @Cat_Erticoromance, N'EPUB/Secretos En La Oscuridad - Sadie Matthews.epub', N'.epub', 0, 1);
END;

-- Libro 908: (Fjallbacka 09) El domador de leones
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'(Fjallbacka 09) El domador de leones' AND Autor = N'Camilla Lackberg')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'(Fjallbacka 09) El domador de leones', N'Camilla Lackberg', N'En ocasiones, el mal puede ser aún más poderoso que el amor. Una tragedia familiar no resuelta reabre varios casos en el presente. Estamos en pleno mes de enero y en Fjällbacka hace un frío polar. Una joven medio desnuda deambula por el bosque nevado y llega a la carretera. Un coche aparece de la nada y no tiene tiempo de esquivarla. Cuando el comisario Patrik Hedström y su equipo reciben la alarma sobre el accidente, la chica ya ha sido identificada. Desapareció cuatro meses atrás y desde entonces no se ha sabido nada de ella. Su cuerpo tiene marcas de atrocidades inimaginables, y es posible que no sea la única, ni la última víctima de su agresor. Al mismo tiempo, Erica Falck investiga una vieja tragedia familiar que acabó con la muerte de un hombre. Erica sospecha que su esposa oculta algo terrible y teme que el pasado proyecte su alargada sombra sobre el presente.', @Cat_Novelanegrathrillernrdico, N'EPUB/(Fjallbacka 09) El domador de leones - Camilla Lackberg.epub', N'.epub', 0, 1);
END;

-- Libro 909: La estrella del diablo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La estrella del diablo' AND Autor = N'Jo Nesbø')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La estrella del diablo', N'Jo Nesbø', N'Es un verano excepcionalmente caluroso en Oslo. El cuerpo de una joven aparece en el suelo de su apartamento, en medio de un charco de sangre. Tiene amputado un dedo de la mano izquierda, y bajo un párpado le han colocado un pequeño diamante rojo con la forma de una estrella de cinco puntas: el emblema del diablo. Cinco días después, un hombre denuncia la desaparición de su esposa. Otro dedo cercenado aparece en escena: lleva un anillo con un diamante rojo engarzado, tallado como una estrella de cinco puntas. A los cinco días aparece el tercer cadáver… y se repite el ritual.Harry Hole es un policía poco convencional. El alcohol y una situación personal muy complicada le han hecho tocar fondo. Los demonios reales y los imaginarios se mezclan en la mente Hole, que se tiene que enfrentar a un criminal sanguinario y a un enemigo implacable dentro del departamento.', @Cat_IntrigaPolicial, N'EPUB/La estrella del diablo - Jo Nesbø.epub', N'.epub', 0, 1);
END;

-- Libro 910: Teme
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Teme' AND Autor = N'Lisa McMann')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Teme', N'Lisa McMann', N'Para Janie y Cabel la vida real se está poniendo mucho más difícil que los sueños. Ambos están tratando conseguir un poco de tiempo para poder estar juntos (en secreto) pero no están teniendo suerte. Y, por si fuera poco, algo extraño está pasando en el instituto Fieldridge, aunque nadie se atreve a hablar sobre ello. Cuando Janie entra en las violentas pesadillas de una compañera de clase, todo empieza a tener sentido, pero nada sale como lo habían planeado. Ni mucho menos. Janie siente que las cosas no van bien en su cabeza y el escandaloso comportamiento de Cabe tiene grave consecuencias para ambos. Y lo que es peor aún, Janie ha descubierto toda la verdad sobre sí misma y su especial habilidad. Y es una verdad desoladora y brutal, que no solo sella su destino como Cazadora de Sueños sino que hace que lo que está por venir sea más oscuro de lo que jamás se hubiera podido imaginar. ¿Crees que estás solo en tus sueños? No es cierto, no si yo estoy cerca. No es tu voluntad ni la mía sino una especie de maldición de la que no puedo escapar. Nadie puede ayudarme. Al menos eso pensaba hasta que Cabel llegó a mi vida. No estoy segura de quién es, no sé si puedo confiar en él, pero para mi corazón es demasiado tarde.Para Janie y Cabel la vida real se está poniendo mucho más difícil que los sueños. Ambos están tratando conseguir un poco de tiempo para poder estar juntos (en secreto) pero no están teniendo suerte. Y, por si fuera poco, algo extraño está pasando en el instituto Fieldridge, aunque nadie se atreve a hablar sobre ello. Cuando Janie entra en las violentas pesadillas de una compañera de clase, todo empieza a tener sentido, pero nada sale como lo habían planeado. Ni mucho menos. Janie siente que las cosas no van bien en su cabeza y el escandaloso comportamiento de Cabe tiene grave consecuencias para ambos. Y lo que es peor aún, Janie ha descubierto toda la verdad sobre sí misma y su especial habilidad. Y es una verdad desoladora y brutal, que no solo sella su destino como Cazadora de Sueños sino que hace que lo que está por venir sea más oscuro de lo que jamás se hubiera podido imaginar. ¿Crees que estás solo en tus sueños? No es cierto, no si yo estoy cerca. No es tu voluntad ni la mía sino una especie de maldición de la que no puedo escapar. Nadie puede ayudarme. Al menos eso pensaba hasta que Cabel llegó a mi vida. No estoy segura de quién es, no sé si puedo confiar en él, pero para mi corazón es demasiado tarde.', @Cat_NovelaJuvenilFantstico, N'EPUB/Teme - Lisa McMann.epub', N'.epub', 0, 1);
END;

-- Libro 911: Calle Dublín
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Calle Dublín' AND Autor = N'Samantha Young')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Calle Dublín', N'Samantha Young', N'Cuatro años atrás, Jocelyn Butler dijo adiós a su trágico pasado en Estados Unidos para empezar una nueva vida en Edimburgo. Pero cuando se muda a un apartamento en Dublin Street y conoce al hermano mayor de su compañera de piso, todo cuanto ha intentado proteger se ve sacudido hasta lo más profundo. Braden Carmichael es un hombre que siempre consigue lo que quiere, y ahora la quiere a ella. Sabedor de que Jocelyn ha renunciado a establecer cualquier clase de relación, le propone dar rienda suelta a la intensa atracción que siente el uno por el otro, sin dejar que la relación vaya más allá del sexo. Jocelyn acepta, sin imaginar que el atractivo escocés se enamorará de ella sin remedio.', @Cat_Romntico, N'EPUB/Calle Dublín - Samantha Young.epub', N'.epub', 0, 1);
END;

-- Libro 912: 3.096 días
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'3.096 días' AND Autor = N'Natascha Kampusch')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'3.096 días', N'Natascha Kampusch', N'Natascha Kampusch no era una niña feliz: su infancia había estado marcada por unos padres inmaduros y por un omnipresente sentimiento de inseguridad. El 2 de marzo de 1998, Natascha, que tenía por aquel entonces diez años, se dirigía a la escuela, sola por primera vez. Era un auténtico desafío para ella, una manera de demostrarse, a ella y a su madre, con la que se había enfadado la noche antes y de la que no se había despedido, que ya era una niña mayor. Apenas llevaba andados unos pocos metros cuando vio a un hombre junto a una furgoneta. No recordaba haberlo visto antes. Era Wolfgang Priklopil, y con él iba a pasar en cautiverio los siguientes ocho años de su vida.
A partir de aquel día todo cambiaría en la vida de Natascha. Su mundo se vería reducido primero a un zulo de cinco metros cuadrados y posteriormente a toda una serie de maltratos físicos y psicológicos que acabarían por anular su personalidad. Sin embargo, algo permaneció inmutable en su interior: la fortaleza y la madurez que se había visto obligada a desarrollar en su niñez la habían preparado, de algún modo, para sobrevivir a aquella tortura diaria. Y así es como, siendo aún una niña, se hizo una valiente promesa a sí misma: cuando cumpliera la mayoría de edad, escaparía...
El presente libro es el relato de aquel largo cautiverio, el más largo que haya vivido una menor en Europa. 3.096 días marcados por el miedo, el desconcierto, el dolor y la humillación, pero también, y no en menor medida, por la lucha, la esperanza y la superación, las mismas que permitirían a su joven protagonista obtener la libertad y contar al mundo su historia.', @Cat_Noespecificado, N'EPUB/3.096 días - Natascha Kampusch.epub', N'.epub', 0, 0);
END;

-- Libro 913: Reina
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Reina' AND Autor = N'Fernández, Bebi')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Reina', N'Fernández, Bebi', N'Reina, el esperado desenlace de Memorias de una salvaje, es más que un thriller. Es un desafío a toda la sociedad. España, año 2020. La vida de Kassandra Fernández transcurre entre libros e intentos por superar su pasado, pero todo se tambalea cuando su mayor enemigo hace acto de presencia de la peor forma posible, dando lugar a una cruenta guerra fría donde la estrategia, los negocios criminales y los límites entre el bien y el mal se difuminan, y en la cual la protagonista se debatirá internamente entre la venganza y la justicia, librando también una batalla interna donde tendrá que averiguar quién es en realidad. Mientras todo ocurre, el amor y la amistad parecen ser más difíciles de comprender que nunca. Abrir el cajón donde guardaba las piezas de ajedrez no será fácil, pero Kassandra Fernández ya no es solo una joven valiente y necesitada de conocer su destino, sino una salvaje mujer dispuesta a ganar la partida —o quizás no. Reina, el esperado desenlace de Memorias de una salvaje, es más que un thriller. Es un desafío a toda la sociedad. Bebi Fernández, el despertar de una generación SALVAJE. Más de 200.000 lectores.', @Cat_Noespecificado, N'EPUB/Reina - Fernández, Bebi.epub', N'.epub', 0, 0);
END;

-- Libro 914: Neïra - Siete citas para Valentina
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Neïra - Siete citas para Valentina' AND Autor = N'Neïra')
