-- Libro 915: El límite del deseo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El límite del deseo' AND Autor = N'Eve Berlin')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El límite del deseo', N'Eve Berlin', N'Sexual dominant Dante knew Kara back in high school. He never imagined her darkest fantasies would align so perfectly with his. When Dante lands a job at Kara''s law firm, intense desire draws them closer while deep-rooted fears threaten to pull them apart- unless they can embrace both the pain and pleasure of love. **Winner of the 2011 Holt Medallion Award!**', @Cat_RomnticoErtico, N'EPUB/El límite del deseo - Eve Berlin.mobi', N'.mobi', 0, 1);
END;

-- Libro 916: Autoridad
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Autoridad' AND Autor = N'Jeff VanderMeer')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Autoridad', N'Jeff VanderMeer', N'Segunda entrega de la trilogía Southern Reach. Después del fracaso de la expedición número 12, la agencia se encuentra sumida en el caos. John Rodríguez ha sido nombrado nuevo director de la agencia. Con la única ayuda de un equipo en el que no puede confi ar, debe desentrañar qué sucedió en la última expedición. Pero a medida que resuelve los enigmas que rodean el Área X, se ve enfrentado también a su propia verdad y a la de la agencia que dirige.', @Cat_NovelaCienciaficcin, N'EPUB/Autoridad - Jeff VanderMeer.epub', N'.epub', 0, 1);
END;

-- Libro 917: Muerte en Hamburgo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Muerte en Hamburgo' AND Autor = N'Craig Russell')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Muerte en Hamburgo', N'Craig Russell', N'Un macabro asesino tiene a la ciudad de Hamburgo ente sus manos. «Podra detenerme, pero nunca me atrapará». Así finaliza el nuevo mensaje que el comisario Jan Fabel acaba de recibir de parte de alguien que firma como «Hijo de Sven». Es el segundo comunicado de este misterioso personaje, y otra vez anuncia un crimen macabro: dos mujeres han muerto asesinadas de la misma manera, con los pulmones arrancados, como si se tratara de un terrible ritual donde lo sagrado y lo monstruoso se dan la mano. El comisario Fabel debe resolver las numerosas incógnitas que el caso propone antes de que el asesino vuelva a actuar. Pero éste no ha dejado rastro alguno, ni parece haber relación entre una víctima y otra, ni un móvil claro. Tan sólo una pista que conduce a la extraña pervivencia de un culto vikingo, a la comunión de supersticiones antiguas y modernas ideologías sanguinarias, en las que el mal es la ley. En su primera novela, Craig Russell nos sumerge en una trama de misterio que no da descanso, y nos conduce por una Hamburgo convertida en un escenario fantasmagórico y violento de la mano de Jan Fabel, mitad policía, mitad historiador.', @Cat_NovelaPolicial, N'EPUB/Muerte en Hamburgo - Craig Russell.epub', N'.epub', 0, 1);
END;

