BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Neurociencia para educadores', N'Bueno i Torrens, David', N'Un libro riguroso, claro y de agradable lectura, lleno de ideas para meditar sobre el oficio de ser aprendices. Neurociencia para educadores es un libro espléndido que lleva un subtítulo suficientemente explícito. Los lectores encontraran en su interior " todo aquello que los educadores siempre han querido saber sobre el cerebro de sus alumnos y nunca nadie se ha atrevido a explicárselo de manera comprensible y útil". Para sorpresa de muchos, el resultado no echa por tierra la totalidad de la pedagogía moderna, sino que da una explicación científica complementaria a por qué, si se trabaja con conocimiento y dedicación, todo funciona razonablemente bien. Y un argumento sólido para no dar marcha atrás, como parecen querer algunas voces desmemoriadas.', @Cat_Noespecificado, N'EPUB/Neurociencia para educadores - Bueno i Torrens, David.epub', N'.epub', 0, 0);
END;

-- Libro 920: Un mes para seducir a una dama
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Un mes para seducir a una dama' AND Autor = N'Diane Howards')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Un mes para seducir a una dama', N'Diane Howards', N'<p class="centrado">¿A quién seguir cuando el corazón te grita que te enamores del joven apuesto que hace que la pasión despierte en cada poro de tu piel, pero la razón te dice que es otro el adecuado?</p> <p>&nbsp;</p> <p>Becca Grant ha decidido enamorarse del nuevo profesor de arte. Ese hombre debe ser el adecuado, pues es apuesto, culto y le hace sentir un ligera expectativa, así que se lanza a una serie de encuentros no tan casuales para llamar su atención. Pero en su camino se interpone el señor Miller, que se va a quedar en Minstrel Valley unas semanas y ha decidido hacer de ella su conquista, con él todo se convierten en deseo de aventura.</p> <p>Desde el momento en que Patrick ve a Becca el resto de mujeres dejan de existir. Tiene poco tiempo para hacerla suya así que se ve obligado a utilizar métodos… poco sofisticados para llamar su atención. Pero cuando la traición cae sobre su amada se da cuenta de que no todo vale en el amor y que si tiene que esperar toda una vida por ella, lo hará.</p> <p>Porque cuando los sentimientos son verdaderos, el amor espera para siempre.</p>', @Cat_NovelaRomnticoHistrico, N'EPUB/Un mes para seducir a una dama - Diane Howards.epub', N'.epub', 0, 1);
END;

-- Libro 921: Fuera de juego
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Fuera de juego' AND Autor = N'Anna Casanovas')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Fuera de juego', N'Anna Casanovas', N'Con apenas dieciocho años, Pam sobrevivió a un infierno y empezó de cero lejos de casa. Entonces se prometió que sería fuerte y los tatuajes que lleva le recuerdan que es una luchadora y que no necesita a nadie. Su trabajo como fotógrafa y cámara le permite viajar por el mundo y se especializa en rodar documentales, cuanto más peligrosos mejor. Pero el último casi acaba con su vida y ahora, para evitar que la despidan, tiene que rodar un maldito documental en Cerdeña con el National Geographic. Pam se lo toma con resignación, como unas vacaciones forzosas, hasta que se tropieza con Ben y siente que nada de lo que ha hecho o sentido hasta ahora la ha preparado para un hombre como él. Ben estudió la carrera perfecta, se enamoró y se casó con la mujer perfecta y tenía el trabajo perfecto. Hasta que estuvo a punto de ser acusado de traición. Ahora Ben acaba de divorciarse y ha dimitido. No tiene nada ni a nadie, y necesita desaparecer para poder pensar y recordar quién es de verdad. Cuando tenía veinte años pasó un verano en Cerdeña y, en un impulso, compra un billete para la isla. Una vez allí, Ben se da cuenta de que lleva años viviendo sin respirar, sin sentir, sin emocionarse y decide hacer todo lo que sea necesario para remediarlo. Pero en sus planes no entra para nada sentirse atraído por una mujer completamente opuesta a él, una mujer cuya mirada contiene demasiados secretos y a la que él, sin saberlo, lleva toda la vida esperando. Hay personajes secundarios que se merecen su propia y gran historia de amor. Si conociste a Pam y a Ben en Las reglas del juego y Donde empieza todo, ahora te enamorarás de ellos en Fuera de juego.', @Cat_Romntico, N'EPUB/Fuera de juego - Anna Casanovas.epub', N'.epub', 0, 1);
END;

-- Libro 922: Artemis Fowl y su peor enemigo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Artemis Fowl y su peor enemigo' AND Autor = N'Eoin Colfer')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Artemis Fowl y su peor enemigo', N'Eoin Colfer', N'Han pasado tres años desde las últimas aventuras de Artemis y, ahora, es un chico normal. Hechas las paces con el mundo mágico y convertido en una persona respetable, solo hay algo que le preocupa: la salud de su madre que se deteriora por momentos. Según el médico, padece una rarísima enfermedad incurable y le quedan pocos días de vida. Pero Artemis guarda un as en la manga: conserva magia del mundo elemental y está convencido de que puede curar a su madre. Al no ser así, no le quedará otro remedio que pedir ayuda al mundo mágico que le asegura que el antídoto de la enfermedad de su madre está en el cerebro de un animal que el propio Artemis mató ocho años atrás. A Artemis sólo le queda una posibilidad: volver ocho años atrás y recuperar el cerebro de ese animal…', @Cat_FantsticoJuvenil, N'EPUB/Artemis Fowl y su peor enemigo - Eoin Colfer.epub', N'.epub', 0, 1);
END;

-- Libro 923: Cercano y peligroso
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Cercano y peligroso' AND Autor = N'Linda Howard')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Cercano y peligroso', N'Linda Howard', N'Un misterioso accidente de avión... un peligroso viaje a través de la salvaje tierra de Idaho... una intensa atracción y un letal juego del gato y el ratón. Los intrigantes hijastros de Bailey Wingate se quedan sorprendidos cuando descubren que la última voluntad de su padre, casado con Bailey, deja el control de toda su fortuna a su esposa... y entonces da comienzo una guerra sin tregua. Un año más tarde, volando desde Seattle hasta Denver en un pequeño avión, Bailey casi muerecuando el motor deja de funcionar.
Sin embargo, gracias a las habilidades de Cam Justice, su piloto privado, consiguen realizar un aterrizaje forzoso sin perder la vida. Perdidos en una tierra árida, y luchando por ocultar los sentimientos que ese apuesto texano le inspiran, Bailey comienza a preguntarse si el fallo del motor ha sido un mero accidente o hay algo más detrás. Y una vez de vuelta a la civilización las sospechas de Bailey comienzan a confirmarse: ¿Quién ha podido manipular el avión? ¿Quién está tratando de reunir a Bailey y a su difunto esposo en el Más Allá?
Confiando su vida –y su corazón– a Cam, Bailey tendrá que ser más lista que un asesino que es capaz de todo para terminar el trabajo que se le ha encomendado.
Cercano y peligroso es una novela llena de sensualidad y de intriga, con un ritmo vertiginoso. Linda Howard nos obsequia con una narración en la que las aventuras extremas y el aislamiento llevan a nuestros protagonistas al límite de sus sentimientos.', @Cat_Romntico, N'EPUB/Cercano y peligroso - Linda Howard.epub', N'.epub', 0, 1);
END;

-- Libro 924: Tres abuelas y un plan de sabotaje
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Tres abuelas y un plan de sabotaje' AND Autor = N'Minna Lindgren')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Tres abuelas y un plan de sabotaje', N'Minna Lindgren', N'Las obras de mejora en la residencia El Bosque del Crepúsculo llegan a su fin y los ancianos pueden regresar a sus apartamentos. Ahora todo es diferente porque la dirección está en manos de una organización religiosa de dudosa legalidad; es poco probable que convertir ancianos y pedirles su dinero esté permitido. Pero hay otro tema que preocupa más a los residentes: las innovaciones tecnológicas hacen que ya no se necesite la presencia de personas que cuiden de los ancianos. La supervisión médica se hace online, se ha sustituido a los enfermeros por inventos automatizados y el servicio de apoyo se presta por Internet desde la India. Las tres abuelas están hartas de una vida programada por ordenador, así que deciden tramar un plan para destruir el sistema informático. A su edad se pueden romper unas cuantas leyes y reglas si no hay justicia. Su intento de hackeo les hace acabar en prisión, pero después de una noche en la celda empiezan a vislumbrar un futuro un poco más libre. La aventura más emocionante está todavía por llegar', @Cat_NovelaIntriga, N'EPUB/Tres abuelas y un plan de sabotaje - Minna Lindgren.epub', N'.epub', 0, 1);
END;

-- Libro 925: La sombra de la sirena
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La sombra de la sirena' AND Autor = N'Camilla Läckberg')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La sombra de la sirena', N'Camilla Läckberg', N'Un hombre desaparece en Fjällbacka sin dejar rastro. Pese a que Patrik Hedström y sus colegas de la policía han hecho cuanto han podido para encontrarlo, nadie sabe si está vivo o muerto. Al cabo de tres meses, lo encuentran finalmente congelado en el hielo. Cuando averiguan que el escritor Christian Thydell, uno de los amigos de la víctima, lleva más de un año recibiendo cartas anónimas plagadas de amenazas, todo se complica.Christian trata de restarle importancia, pero su amiga Erica Falck, quien lo ayudó en la escritura de su primera y exitosa novela, La sombra de la sirena, es consciente del peligro. La policía no tarda en comprender que el asesinato y las cartas están relacionados.Alguien odia a Christian profundamente, y ese alguien parece que no dudará en cumplir sus amenazas…', @Cat_NovelaPolicial, N'EPUB/La sombra de la sirena - Camilla Läckberg (2).epub', N'.epub', 0, 1);
END;

-- Libro 926: El Palacio de la Medianoche
