-- Libro 927: Fuego en la oscuridad
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Fuego en la oscuridad' AND Autor = N'Sadie Matthews')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Fuego en la oscuridad', N'Sadie Matthews', N'<p class="description">''Adam acababa de destrozarme el corazón. Me lo había roto en tantos pedazos que apenas podía unirlos para volver a ser una persona medianamente feliz. Pero todo iba a cambiar cuando conocí a Dominic. Dominic me enseñó una manera de dejarme llevar, de abandonarme, que nunca había conocido. Me mostró un sendero de puro placer, pero también de dolor... Su amor me iluminaba, aunque tenía un lado oscuro. Y, me llevara donde me llevara, yo no tenía más opción que seguirle.''<br>La historia de Beth te cautivará y te seducirá como nunca habías soñado. Intensa y romántica, sensual y embriagadora, Fuego en la oscuridad te conducirá por unas sendas en las que el amor y el sexo juegan libremente ajenos a cualquier límite.</p>', @Cat_Romanceertico, N'EPUB/Fuego en la oscuridad - Sadie Matthews.epub', N'.epub', 0, 1);
END;

