-- Libro 929: Memento Mori
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Memento Mori' AND Autor = N'Cesar Perez Gellida')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Memento Mori', N'Cesar Perez Gellida', N'Septiembre de 2010. Aquella mañana de domingo nada le hacía presagiar al inspector de homicidios de Valladolid Ramiro San­cho que acababa de dar comienzo una pesadilla que lo dejaría marcado para el resto de sus días.
La investigación del asesinato de una joven ecuatoria­na a la que le han mutilado los párpados y cuyo cuer­po han encontrado unos versos amenazantes, ocupa las primeras páginas de esta novela negra narrada con un dinámico y atrevido lenguaje cinematográfico. Sin embargo, el autor nos arrastra por un camino inespe­rado al describir los hechos desde la perspectiva del propio asesino: un sociópata narcisista influenciado por la música más actual y por las grandes obras de la literatura universal.
La evolución frenética de los acontecimientos desem­boca en la intervención de uno de los especialistas más reconocidos en el comportamiento de los ase­sinos en serie. Este complejo triángulo emocional, unido a la intriga que envuelve al siniestro cómplice del asesino, hace que Memento mori se convierta en un profundo thriller de acción con banda sonora que atrapará al lector de principio a fin.', @Cat_Policialdetective, N'EPUB/Memento Mori - Cesar Perez Gellida.epub', N'.epub', 0, 1);
END;

-- Libro 930: Minstrel Valley 4. La tentación de un be
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Minstrel Valley 4. La tentación de un beso' AND Autor = N'Christine Cross')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Minstrel Valley 4. La tentación de un beso', N'Christine Cross', N'<div><p style="margin: -4px 0px 14px; padding: 0px; color: rgb(51, 51, 51); font-family: Arial, sans-serif; font-size: 14px; orphans: 2; widows: 2; background-color: rgb(255, 255, 255);">Eleanor ha cumplido 25 años y se siente algo abrumada por la monotonía de su vida. Una mañana se presenta en la escuela un abogado para hablar con ella. Alguien ha hecho un testamento en su favor dejándole una herencia sustanciosa con la que podría cumplir su sueño de viajar, conocer el mundo y a otras personas, o volver a la alta sociedad a la que pertenecía. Junto con el dinero, recibe también un extraño y antiguo medallón. Asaltada por las dudas sobre la cuestión del dinero, decide hablar con Lady Acton.</p><p style="margin: -4px 0px 14px; padding: 0px; color: rgb(51, 51, 51); font-family: Arial, sans-serif; font-size: 14px; orphans: 2; widows: 2; background-color: rgb(255, 255, 255);">Cuando acude a su saloncito privado conoce a Ashton Melham, conde de Clifford, un hombre que desestabiliza su mundo, aunque lo considera un aventurero. Él se interesa enseguida por el medallón. Recuerda haber visto algo parecido, cuando era un niño, en algún lugar de la vieja mansión de su familia. Lady Acton anima a Eleanor a tomarse unas pequeñas vacaciones para que pueda serenarse y tomar una adecuada decisión con respecto a su futuro; de paso, podrá visitar la mansión Clifford y averiguar algo sobre el medallón...</p><p style="margin: -4px 0px 14px; padding: 0px; color: rgb(51, 51, 51); font-family: Arial, sans-serif; font-size: 14px; orphans: 2; widows: 2; background-color: rgb(255, 255, 255);"><b>Las tardes pasadas en Clifford Manor, se transformarán en un refugio cálido para Eleanor mientras la relación con Ash se va transformando en algo distinto.</b></p></div>', @Cat_RomanceHistrica, N'EPUB/Minstrel Valley 4. La tentación de un beso - Christine Cross.epub', N'.epub', 0, 1);
END;

-- Libro 931: Radiografía del deseo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Radiografía del deseo' AND Autor = N'Mimmi Kass')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Radiografía del deseo', N'Mimmi Kass', N'Primera parte de la serie «En cuerpo y alma», donde la pasión y el erotismo, junto a los grandes temas sobre la vida y el amor, se mezclan en un cóctel explosivo. Elegante, arriesgada, y divertida, «Radiografía del Deseo» no te dejará indiferente.Erik es un cardiocirujano noruego volcado en su trabajo; vive dedicado al hospital y no tiene tiempo, ni le interesan, las relaciones serias. Es duro y exigente consigo mismo, y espera lo mismo del resto de sus colegas.Inés es residente. Un espíritu libre que intenta equilibrar todas las facetas de su vida, segura de que cumplirá su proyecto de futuro al lado de un hombre que la ame. A pesar de las diferencias culturales, de temperamento y de los continuos enfrentamientos en un hospital competitivo de primer nivel, nace entre ellos una espiral de deseo irresistible contra la que no podrán luchar. El sexo lo inundará todo, pero ¿surgirá algo más?', @Cat_Ertico, N'EPUB/Radiografía del deseo - Mimmi Kass.epub', N'.epub', 0, 1);
END;

