-- Libro 933: La caja mágica
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La caja mágica' AND Autor = N'Ana Campoy')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La caja mágica', N'Ana Campoy', N'¿Qué hubiera ocurrido si Alfred Hitchcock y Agatha Christie se hubieran conocido de niños? ¿Qué aventuras habrían vivido? ¿Qué sorprendentes casos habrían resuelto juntos? Las aventuras de Alfred&Agatha nos muestra cómo podría haber sido la amistad de infancia de los dos maestros del suspense más importantes de nuestro tiempo.  En esta tercera aventura, la madre de Agatha regala a los niños un par de entradas para el cinematógrafo. Alfred está emocionado ante el acontecimiento y disfruta mucho del espectáculo. A la salida de la película, los niños conocen a un imponente caballero, Thomas Alva Edison, inventor y empresario que no duda en ofrecerles visitar su próspera compañía.', @Cat_Noespecificado, N'EPUB/La caja mágica - Ana Campoy.epub', N'.epub', 0, 0);
END;

-- Libro 934: Una flor para otra flor (Las guerreras M
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Una flor para otra flor (Las guerreras Maxwell 4)' AND Autor = N'Megan Maxwell')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Una flor para otra flor (Las guerreras Maxwell 4)', N'Megan Maxwell', N'<div>Estar enamorado de la mujer que se desea olvidar no es algo que el joven e impetuoso highlander Zac Philips lleve bien.<br><br>Tiempo atrás, Zac posó sus ojos en Sandra, una joven de mirada y pelo castaños que cautivó con su sonrisa. Pero cuando el padre de Sandra falleció, sus abuelos maternos las obligaron, tanto a ella como a su madre, a dejar las Highlands, su lugar de residencia, y regresar a Carlisle, un lugar en el que ninguna de las dos conseguía ser feliz, sobre todo cuando sus abuelos se empeñaron en concertarle un matrimonio. <br><br>Dispuesto a salvar a su amada, Zac partió hacia Carlisle, pero al llegar allí se encontró con Sandra riendo divertida con uno de aquellos ingleses. Ofuscado y con el corazón destrozado, regresó a las Highlands con la intención de olvidarla. <br><br>Sin remilgos ni medias tintas, Sandra iba ahuyentando a sus supuestos pretendientes, ganándose así la enemistad de sus abuelos y, con el tiempo, cargando con la culpa por la muerte de su abuela.

</div>', @Cat_Romntica, N'EPUB/Una flor para otra flor (Las guerreras Maxwell 4) - Megan Maxwell.epub', N'.epub', 0, 1);
END;

-- Libro 935: Bruja Americana
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Bruja Americana' AND Autor = N'Thea Harrison')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Bruja Americana', N'Thea Harrison', N'<div>
<p>Llega la primera novela de una nueva fascinante trilogía de Thea Harrison… </p>
<p>El poder puede cambiar a una persona... </p>
<p>Durante meses Molly Sullivan soporta lo inexplicable: sobrecargas eléctricas, averías en los coches, visiones. Incluso se pregunta si ella podría ser la causa... y se pregunta si podría estar loca. Luego descubre que su marido la ha engañado. Otra vez. Ahora Molly se da cuenta de que es una bruja recién despertada y una mujer al límite. </p>
<p>La venganza puede formar a una persona... </p>
<p>Josiah Mason es un poderoso brujo y el líder de un aquelarre secreto con un objetivo compartido: destruir a un antiguo enemigo que ha arruinado muchas vidas. Josiah perdió años con este hombre, y su único objetivo es la venganza. Está preparado para cualquier contingencia, excepto para encontrarse con una nueva y hermosa bruja que no entiende nada del inmenso Poder que acumula en su interior ni de la atracción que ejerce sobre él. </p>
<p>El peligro puede unirlos... </p>
<p>Al divorciarse de su marido, Molly descubre un peligroso secreto cuya protección él está dispuesto a matar. Acude a Josiah en busca de ayuda, y descubren una conexión entre el marido de Molly y el enemigo de Josiah. </p>
<p>Mientras trabajan juntos, se enciende una chispa entre ellos que amenaza con convertirse en un incendio. Pero Molly ya no se compromete con ningún hombre, y la misión de Josiah es su principal prioridad. Y el enemigo es astuto, cruel y cada vez más cercano. </p>
<p>A medida que el peligro aumenta, también lo hace la tensión entre ellos. ¿Es posible una relación duradera? ¿Vivirá alguno de ellos lo suficiente para intentarlo? </p></div>', @Cat_Romanceparanormal, N'EPUB/Bruja Americana - Thea Harrison.epub', N'.epub', 0, 1);
END;

-- Libro 936: (Fjallbacka 03) Las hijas del frío
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'(Fjallbacka 03) Las hijas del frío' AND Autor = N'Camilla Lackberg')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'(Fjallbacka 03) Las hijas del frío', N'Camilla Lackberg', N'La alegría de Erica y Patrik por el nacimiento de su hija es inmensa, pero deben enfrentarse a unos problemas nuevos para ellos; la pequeña llora mucho, Erica sufre una depresión posparto y Patrik está constantemente cansado. Erica encuentra entonces apoyo en Charlotte, madre de Sara, una niña de siete años que sufre el síndrome de deficiencia de atención cuando, de repente, se produce un drama totalmente inesperado. Un pescador encuentra el cadáver de la pequeña Sara, ahogada en el mar. Las autoridades piensan que se trata de un accidente, pero la autopsia revela que la pequeña fue ahogada en una bañera antes de ser arrojada al mar, y que alguien le hizo tragar cenizas.', @Cat_Novelanegrathrillernrdico, N'EPUB/(Fjallbacka 03) Las hijas del frío - Camilla Lackberg.epub', N'.epub', 0, 1);
END;

-- Libro 937: El límite de la tentación
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El límite de la tentación' AND Autor = N'Eve Berlin')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El límite de la tentación', N'Eve Berlin', N'Mischa Kennon es una luchadora nata y pocas cosas la harán sucumbir, esto es hasta que conoce al muy sexy Connor Galloway, un irlandés de ojos verdes con un aire autoritario que es irresistible. Mientras que ejerce sus labores como dama de honor de su mejor amiga, Mischa se mete en una relación poco seria con Connor. Y se verá sorprendida por el dominio que él ejerce sobre ella y que le hace desear más y más batallas desenfrenadas antes de la rendición total. Todo es un juego en el Club de BDSM La cúpula del placer, hasta que Mischa empieza a darse cuenta de que Connor también podría acabar por dominar su corazón. Si cede a su deseo, ¿será imposible de dominar o le abrirá los ojos a un tipo de amor que jamás pensó posible?', @Cat_Ertico, N'EPUB/El límite de la tentación - Eve Berlin.epub', N'.epub', 0, 1);
END;

