-- Libro 939: Las siete Hermanas 5 - La hermana luna
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Las siete Hermanas 5 - La hermana luna' AND Autor = N'Lucinda Riley')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Las siete Hermanas 5 - La hermana luna', N'Lucinda Riley', N'La hermana luna es el quinto volumen de la emocionante saga de Lucinda Riley Las Siete Hermanas, una serie de novelas basada en la mitología griega y en la astrología que enamorará a sus lectoras y que en este caso nos transporta a Granada, Barcelona y Madrid. Siete hermanas, siete destinos, un padre con un pasado misterioso... Cuando Tiggy D''Aplièse acepta trabajar en una de las zonas más recónditas de Escocia, en concreto en la enorme finca Kinnaird, nada le hace sospechar que el misterioso terrateniente, Charlie Kinnaird, está a punto de alterar su futuro e, irónicamente, revelarle su pasado. En su nuevo hogar Tiggy descubrirá que tiene un don, el sexto sentido, una herencia de sus antepasados gitanos. Lucía Amaya-Albaycín nació en 1912 en el barrio del Sacromonte, frente a la Alhambra, y la apodaron La Candela. En su destino está escrito convertirse en una de las grandes bailarinas de la historia, y por eso su padre se la lleva a los bares de flamenco de Barcelona con solo diez años. Al estallar la Guerra Civil, Lucía y su grupo de bailaores se ven obligados a buscar refugio en Nueva York. Pero para ver cumplido su sueño Lucía tendrá que elegir entre la pasión por el baile o el hombre al que ama... Conforme conoce sus raíces españolas y desentraña el pasado de su familia, Tiggy comienza a aceptar y a controlar su don sin saber que ella también deberá tomar una difícil decisión, no muy distinta a la que en su día afrontó Lucía. Si quieres saber más, incluso sobre mitología griega, las Pléyades, las esferas armilares..., visita la web de Lucinda Riley en español: esp.lucindariley.co.uk. También encontrarás documentación sobre las Highlands, Carmen Amaya, las cuevas del Sacromonte, el flamenco, los gitanos en España y los ciervos blancos. La crítica ha dicho sobre la saga Las Siete Hermanas... «La serie Las Siete Hermanas es romántica, arrolladora, lujosa y glamurosa». The Daily Mail «Un libro brillante que no puedes dejar, lleno de glamour y romance». The Daily Mail «Riley es una experta contadora de relatos románticos que entreteje con habilidad la historia con la ficción. Un libro absorbente y fascinante». Booklist «Una pizca de misterio, un poco de romance, algo de ficción histórica y mucho drama familiar en una historia maravillosa. Una apuesta segura para fans de Kate Morton, Kristin Hannah o Maeve Binchy». Library Journal Los lectores opinan: «Las Siete Hermanas siguen siendo una maravillosa conjunción de astrología, feminismo, mitología, romance... junto a unos personajes capaces de amar y sufrir a partes iguales». Blog El cuervo de alas rotas «Si os gusta la novela contemporánea, los libros de misterios familiares, los saltos en el tiempo, viajar a través de la lectura... esta es vuestra autora». Blog Historias de algodón «He vuelto a disfrutar de la habilidad de la autora para mezclar grandes protagonistas con amor, historia y buena ambientación.» Blog Bajo la piel de un lector «Un logro por parte de la autora conseguir que todas las entregas de esta larga serie sean igualmente interesantes». Blog Libros que hay que leer', @Cat_Noespecificado, N'EPUB/Las siete Hermanas 5 - La hermana luna - Lucinda Riley.epub', N'.epub', 0, 0);
END;

-- Libro 940: Deseo concedido
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Deseo concedido' AND Autor = N'Megan Maxwell')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Deseo concedido', N'Megan Maxwell', N'Lady Megan Phillips es una joven y bella luchadora que tiene a su cargo a dos hermanos pequeños. La vida no le ha resultado nada fácil, por lo que ha forjado el carácter de una auténtica guerrera que no se doblega ante nada ni nadie. El highlander Duncan McRae, más conocido como el Halcón, es un hombre acostumbrado a liderar ejércitos, librar batallas y salir victorioso de todas ellas junto con su clan. Pero al llegar al castillo de Dunstaffnage para celebrar el enlace de su buen amigo Alex McDougall, se encuentra con el mayor desafío de su vida, alguien con quien no está acostumbrado a lidiar: lady Megan Phillips, una morena que no le tiene miedo a nada. Asombrado por el descaro y el ímpetu de la joven, el Halcón no puede apartar sus ojos verdes de ella y, tras hacerle una promesa al abuelo de la muchacha, se ve unido a lady Megan en una boda que durará un año y un día. ¿Qué les deparará el destino a los señores McRae? ¿Conseguirán entenderse o acabarán odiándose para el resto de sus días?', @Cat_Romancehistrico, N'EPUB/Deseo concedido - Megan Maxwell.epub', N'.epub', 0, 1);
END;

-- Libro 941: La propuesta de un canalla
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La propuesta de un canalla' AND Autor = N'Stephanie Laurens')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La propuesta de un canalla', N'Stephanie Laurens', N'Felicity sabía que Demonio Cynster era uno de los solteros más codiciados de la alta sociedad londinense y un canalla de la peor ralea, pero era el único capaz de hacer que su amigo saliese del lío en que se había metido. Pese a la fuerza que asoma bajo su fachada de despreocupación, Felicity no puede evitar sentirse fascinada por él, ni aplacar el deseo que se apodera de su cuerpo cada vez que la toma entre sus brazos. Sabe que Demonio nunca le entregará su amor, y que la pasión sería el único sostén posible de un matrimonio con un hombre como él…', @Cat_NovelaRomntico, N'EPUB/La propuesta de un canalla - Stephanie Laurens.epub', N'.epub', 0, 1);
END;

-- Libro 942: Not My Romeo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Not My Romeo' AND Autor = N'Ilsa Madden-Mills')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Not My Romeo', N'Ilsa Madden-Mills', N'<div> <p align="justify">Comenzamos con una mentira el día de San Valentín. </p> <p align="justify">Mi cita a ciegas no es el tipo estudioso que esperaba. No, es un sexy jugador magnífico con ojos ambarinos pecaminosos y un cuerpo asesino. De alguna manera terminamos en su ático. Culpo al gin tonic. </p> <p align="justify">Al día siguiente, descubro que es Jack Hawke: todo un chico malo y mariscal de campo profesional con un pasado turbio. </p> <p align="justify">El acuerdo de confidencialidad que me hizo firmar debería haber sido una advertencia de que no es una persona normal. Por favor. Lo firmé como Julieta Capuleto, así que adiós, jugador de fútbol famoso con abdominales de acero, y buena suerte rastreando a esta bibliotecaria de un pueblo pequeño. </p> <p align="justify">Pero Jack sigue apareciendo en los lugares donde menos lo espero. Justo cuando estoy segura que se ha ido, entra al teatro de mi comunidad y gana el papel del Romeo para mi Julieta. </p> <p align="justify">¿Cómo se supone que una chica sencilla, mayormente inocente como yo, debe resistirse a un hombre como él? </p> <p align="justify">¿Acaso Jack es mi verdadero Romeo... o este magnífico jugador de fútbol solo me romperá el corazón? </p></div>', @Cat_Romancecontemporneo, N'EPUB/Not My Romeo - Ilsa Madden-Mills.epub', N'.epub', 0, 1);
END;

-- Libro 943: Aceptación
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Aceptación' AND Autor = N'Jeff VanderMeer')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Aceptación', N'Jeff VanderMeer', N'Tercera entrega de la trilogía Southern Reach. Control, el director de la agencia estatal Southern Reach, se dirige al Área X. Está convencido de que si descubre cuál es el misterio que se esconde más allá de sus fronteras podrá evitar que su naturaleza amenazante se propague. Pero una vez allí todas sus convicciones se d esmontan. En pleno invierno y sin ninguna certeza a la que aferrarse, deberá remontarse hasta los orígenes del Área X y aquellos que la han habitado para resolver el enigma. Aceptación es la última entrega de la trilogía Southern Reach, una serie que ha sido calificada de ''''inquietante'''' (The New York Times), ''''apasionante'''' (Los Angeles Times) y ''''adictiva'''' (BookPage).', @Cat_NovelaCienciaficcin, N'EPUB/Aceptación - Jeff VanderMeer.epub', N'.epub', 0, 1);
END;

-- Libro 944: El asesino del Camino Norte
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El asesino del Camino Norte' AND Autor = N'Rober H. L. Cagiao')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El asesino del Camino Norte', N'Rober H. L. Cagiao', N'<div>
<p style="font-family: ''Arial'',''sans-serif''; font-size: 14px"><span style="background-color: #ffffff; color: #333333">Primera parte de uno de los nuevos capítulos de la Saga de El Guardián de las Flores, thriller ambientado en Galicia. En este caso, en el Camino Norte de peregrinación a Compostela. Colindres, Gernika, Zarautz, Luarca, Arzúa y la capital de Galicia serán los nuevos escenarios en esta nueva entrega.</span></p></div>', @Cat_Noespecificado, N'EPUB/El asesino del Camino Norte - Rober H. L. Cagiao.epub', N'.epub', 0, 0);
END;

-- Libro 945: Amores Cruzados
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Amores Cruzados' AND Autor = N'Erina Alcala')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Amores Cruzados', N'Erina Alcala', N'<div><span style="color: rgb(51, 51, 51); font-family: ''Amazon Ember'', Arial, sans-serif; font-size: 14px; orphans: 2; widows: 2; background-color: rgb(255, 255, 255);">Amores que se cruzan, amores que no son felices. Amores infieles. Eso le pasó a Candela Díaz, una chica malagueña, cuya vida no había sido fácil desde la infancia.</span><br style="color: rgb(51, 51, 51); font-family: ''Amazon Ember'', Arial, sans-serif; font-size: 14px; orphans: 2; widows: 2; background-color: rgb(255, 255, 255);"><span style="color: rgb(51, 51, 51); font-family: ''Amazon Ember'', Arial, sans-serif; font-size: 14px; orphans: 2; widows: 2; background-color: rgb(255, 255, 255);">En el amor, no tuvo mejor suerte y su divorcio la llevó a enamorarse del marido de la amante de su marido. Y él, Jesús, de ella. Pero cada vez que podían unirse algo, los separaba.</span><br style="color: rgb(51, 51, 51); font-family: ''Amazon Ember'', Arial, sans-serif; font-size: 14px; orphans: 2; widows: 2; background-color: rgb(255, 255, 255);"><span style="color: rgb(51, 51, 51); font-family: ''Amazon Ember'', Arial, sans-serif; font-size: 14px; orphans: 2; widows: 2; background-color: rgb(255, 255, 255);">Jesús, era bombero y nunca creyó, que su mujer Bea le fuese infiel, hasta que Candela llegó a su puerta con un sobre amarillo de un detective privado con unas fotos que no daban lugar a ninguna duda de que su mujer estaba con el marido de Candela.</span><br style="color: rgb(51, 51, 51); font-family: ''Amazon Ember'', Arial, sans-serif; font-size: 14px; orphans: 2; widows: 2; background-color: rgb(255, 255, 255);"><span style="color: rgb(51, 51, 51); font-family: ''Amazon Ember'', Arial, sans-serif; font-size: 14px; orphans: 2; widows: 2; background-color: rgb(255, 255, 255);">Se volvieron a encontrar y se enamoraron.</span><br style="color: rgb(51, 51, 51); font-family: ''Amazon Ember'', Arial, sans-serif; font-size: 14px; orphans: 2; widows: 2; background-color: rgb(255, 255, 255);"><span style="color: rgb(51, 51, 51); font-family: ''Amazon Ember'', Arial, sans-serif; font-size: 14px; orphans: 2; widows: 2; background-color: rgb(255, 255, 255);">Pero la vida para ellos no fue tan fácil a pesar de que él nunca dejó de amarla y de los errores que ambos cometieron.</span><br style="color: rgb(51, 51, 51); font-family: ''Amazon Ember'', Arial, sans-serif; font-size: 14px; orphans: 2; widows: 2; background-color: rgb(255, 255, 255);"><span style="color: rgb(51, 51, 51); font-family: ''Amazon Ember'', Arial, sans-serif; font-size: 14px; orphans: 2; widows: 2; background-color: rgb(255, 255, 255);">¿Volverían a reunirse y a amarse con el tiempo? Si te gustan las novelas donde la vida real supera la ficción, no te la pierdas.</span></div>', @Cat_Noespecificado, N'EPUB/Amores Cruzados - Erina Alcala.epub', N'.epub', 0, 0);
END;

-- Libro 946: Lo que encontré bajo el sofá
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Lo que encontré bajo el sofá' AND Autor = N'Eloy Moreno')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Lo que encontré bajo el sofá', N'Eloy Moreno', N'¿Qué ocurre al mover un sofá? ¿Y al mover una vida? Es posible que en ambos casos encuentres algo parecido: recuerdos que ya esperabas, otros de los que ni te acordabas y alguno que no hubieras deseado encontrar nunca… de esos que se convierten al instante en secretos.¿Y si movemos una sociedad? Entonces uno se da cuenta de que vive en un lugar con demasiados gusanos para tan poca manzana. Pero también un lugar donde, al observarnos, descubrimos que somos los primeros en hacer aquello que tanto criticamos.', @Cat_Otros, N'EPUB/Lo que encontré bajo el sofá - Eloy Moreno.epub', N'.epub', 0, 1);
END;

-- Libro 947: Tres abuelas y un joyero de ida y vuelta
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Tres abuelas y un joyero de ida y vuelta' AND Autor = N'Minna Lindgren')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Tres abuelas y un joyero de ida y vuelta', N'Minna Lindgren', N'La esperada segunda entrega de la «Trilogía de Helsinki», una original mezcla entre comedia y thriller escandinavo protagonizado por un grupo de nonagenarias. Siiri, Irma y Anna-Liisa son tres viudas de noventa años residentes en El Bosque del Crepúsculo, un centro privado de apartamentos para la tercera edad de Helsinki que, bajo su apariencia de nidito acogedor para personas mayores, resulta un lugar un tanto siniestro. En esta ocasión las abuelas ven su vida convertida en un infierno por unas obras interminables. El ruido es ensordecedor, en las paredes surgen agujeros, las cosas desaparecen y los residentes tienen que usar inodoros portátiles. A las protagonistas no les queda más remedio que mudarse a un apartamento compartido, donde sus costumbres y manías no harán la convivencia nada fácil. Las ancianas comienzan además a darse cuenta de que las obras de su residencia son bastante sospechosas y podrían estar encubriendo actividades criminales. Cuando los misterios comiencen a resolverse, las amigas descubrirán que en esta vida poca gente está tan libre de culpa como parece.', @Cat_NovelaIntrigaPolicial, N'EPUB/Tres abuelas y un joyero de ida y vuelta - Minna Lindgren.epub', N'.epub', 0, 1);
END;

-- Libro 948: (Fjallbacka 10) La bruja
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'(Fjallbacka 10) La bruja' AND Autor = N'Camilla Lackberg')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'(Fjallbacka 10) La bruja', N'Camilla Lackberg', N'La desaparición de Linnea, una niña de cuatro años, de una granja en las afueras de Fjällbacka, despierta trágicos recuerdos. Treinta años antes se perdió en la misma granja el rastro de otra niña, Stella, que al poco fue hallada sin vida.Entonces dos adolescentes fueron acusadas y declaradas culpables de su secuestro y asesinato, pero evitaron ir a prisión por ser menores de edad. Una de ellas, Helen, ha llevado una vida apacible en Fjällbacka; la otra, Marie, una actriz de éxito, regresa por primera vez después del suceso para rodar una película.</b></p><p><b>Los habitantes de Fjällbacka se organizan para buscar a Linnea y no pueden evitar preguntarse si otras niñas pueden estar en peligro. Aunque Patrik cree que la verdad siempre encuentra su camino a pesar de los rumores, tanto él como sus compañeros de la comisaría investigan la conexión entre ambos casos.</b></p><p><b>Tan solo su mujer Erika parece conservar la calma; lleva algún tiempo trabajando en un libro sobre el asesinato de aquella niña, aparentemente resuelto hace años. Pero la investigación abrirá antiguas heridas y aumentará el miedo a que lo desconocido traiga terribles consecuencias para todos los habitantes de Fjällbacka.', @Cat_Novelanegrathrillernrdico, N'EPUB/(Fjallbacka 10) La bruja - Camilla Lackberg.epub', N'.epub', 0, 1);
END;

-- Libro 949: La muerte de Erika Knapp
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La muerte de Erika Knapp' AND Autor = N'Luca D''Andrea')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La muerte de Erika Knapp', N'Luca D''Andrea', N'<div>
<p style="font-family: ''Amazon Ember'',''Arial'',''sans-serif''; font-size: 14px"><strong style="color: #000000">Regresa el autor de</strong><span style="font-style: italic; font-weight: 600; color: #000000"> La sustancia del mal</span><strong style="color: #000000">, con más de 300.000 lectores en 42 países, con un nuevo</strong><span style="font-style: italic; font-weight: 600; color: #000000"> thriller</span><strong style="color: #000000"> que lo confirma como estrella de la novela negra europea, junto a</strong><span style="color: #000000"> </span><strong style="color: #000000">Dazieri,</strong><span style="color: #000000"> </span><strong style="color: #000000">Lemaitre y</strong><span style="color: #000000"> </span><strong style="color: #000000">Dicker.</strong></p>
<p style="font-family: ''Amazon Ember'',''Arial'',''sans-serif''; font-size: 14px"><strong style="color: #000000">«De lectura obligada. Léela con el cinturón de seguridad abrochado.»</strong><span style="color: #000000"><br></span><span style="font-style: italic; font-weight: 600; color: #000000">La Stampa</span></p>
<p style="font-family: ''Amazon Ember'',''Arial'',''sans-serif''; font-size: 14px"><strong style="color: #000000">«Un experimento narrativo consumado.»</strong><span style="color: #000000"><br></span><span style="font-style: italic; font-weight: 600; color: #000000">Il Corriere</span><span style="color: #000000"> </span><span style="font-style: italic; font-weight: 600; color: #000000">della Sera</span></p>
<p style="font-family: ''Amazon Ember'',''Arial'',''sans-serif''; font-size: 14px"><span style="color: #000000">Tony Carcano lleva una vida aislada y monótona, en la que las únicas emociones que experimenta son las que describe en sus propios libros, unas novelas de amor que desde hace tiempo le proporcionan éxito y bienestar. Sin embargo, Sibylle, una veinteañera imprudente y encantadora, irrumpe en su vida con una antigua foto que lo retrata joven y sonriente junto al cadáver de una mujer: Erika Knapp.</span></p>
<p style="font-family: ''Amazon Ember'',''Arial'',''sans-serif''; font-size: 14px"><span style="color: #000000">Tony se ve obligado a retomar los hilos de una historia que durante mucho tiempo quiso dejar atrás. Junto a Sibylle, tendrá que volver a adentrarse en las sombras del pequeño pueblo tirolés de Kreuzwirt, donde se esconde un misterio hecho de mentiras, violencia, locura y codicia. Este</span><em style="color: #000000"> thriller,</em><span style="color: #000000"> de una potencia avasalladora y un ritmo diabólico, hará resurgir un secreto oculto durante más de veinte años abriendo de par en par las compuertas del infierno.</span></p></div>', @Cat_Noespecificado, N'EPUB/La muerte de Erika Knapp - Luca D''Andrea.epub', N'.epub', 0, 0);
END;

-- Libro 950: Hacia las estrellas
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Hacia las estrellas' AND Autor = N'Mary Robinette Kowal')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Hacia las estrellas', N'Mary Robinette Kowal', N'<div>
<p>El futuro de la humanidad está en manos de un grupo de mujeres.</p>
<p>En un frío día primaveral de 1952, un meteorito impacta contra la Tierra y arrasa la Costa Este de Estados Unidos. Pronto, las consecuencias de tal cataclismo harán del planeta un lugar inhóspito, como ocurrió antes de la extinción de los dinosaurios. Esta terrible amenaza obliga a la humanidad a acelerar radicalmente sus esfuerzos para colonizar el espacio.</p>
<p>Elma York, piloto del Servicio Aéreo Femenino y matemática, será una de las mujeres que trabajarán en la Coalición Espacial Internacional como calculadoras para llevar al hombre a la Luna. Su ambición por convertirse en astronauta hará que se enfrente a una sociedad que no está preparada para ver a una mujer rumbo hacia las estrellas.</p>
<p>La mejor novela de ciencia ficción del año, ganadora de los premios Hugo, Nébula y Locus.</p>
<p>''Elma York es lo que le falta a la NASA: una heroína con garra.''</p>
<p>The Wall Street Journal</p></div>', @Cat_Cienciaficcinhistoriaalternativa, N'EPUB/Hacia las estrellas - Mary Robinette Kowal.epub', N'.epub', 0, 1);
END;

-- Libro 951: La sombra de la sirena
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La sombra de la sirena' AND Autor = N'Camilla Läckberg')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La sombra de la sirena', N'Camilla Läckberg', N'Un hombre desaparece en Fjällbacka sin dejar rastro. Pese a que Patrik Hedström y sus colegas de la policía han hecho cuanto han podido para encontrarlo, nadie sabe si está vivo o muerto. Al cabo de tres meses, lo encuentran finalmente congelado en el hielo. Cuando averiguan que el escritor Christian Thydell, uno de los amigos de la víctima, lleva más de un año recibiendo cartas anónimas plagadas de amenazas, todo se complica.Christian trata de restarle importancia, pero su amiga Erica Falck, quien lo ayudó en la escritura de su primera y exitosa novela, La sombra de la sirena, es consciente del peligro. La policía no tarda en comprender que el asesinato y las cartas están relacionados.Alguien odia a Christian profundamente, y ese alguien parece que no dudará en cumplir sus amenazas…', @Cat_NovelaPolicial, N'EPUB/La sombra de la sirena - Camilla Läckberg.epub', N'.epub', 0, 1);
END;

-- Libro 952: Señuelo mortal
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Señuelo mortal' AND Autor = N'P. J. Tracy')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Señuelo mortal', N'P. J. Tracy', N'Tras resolver el caso de la compañía de «software». Monkeewrench, los detectives Leo Magozzi y Gino Rolseth llevan un tiempo sin ningún caso de homicidio que investigar, hasta que les llega la noticia del asesinato de Morey Gilbert, a quien su esposa, Lily, acaba de encontrar tumbado, con una bala en el cráneo, en el invernadero de su casa. ¿Quién ha podido acabar con la vida de este respetable anciano al que todo el mundo parecía adorar? Entre los sospechosos figuran no sólo la mujer del muerto, que se muestra extrañamente irritable con la policía, sino también su yerno, Marty Pullman, y su hijo, la única persona con la que Morey no se hablaba. Como si de un juego de dominó se tratara, a este homicidio siguen otros, que comparten unas características similares: además de presentar un mismo método, las víctimas siempre son ancianos. Algún tipo de secreta conexión entre éstas se les escapa a los dos detectives, que trabajan contrarreloj para tratar de adelantarse al asesino Grace McBride, la guapa fundadora de Monkeewrench, volverá a colaborar con ellos. ¿Podrán los tres, con la ayuda de los más sofisticados sistemas de búsqueda informática, descubrir la pieza que resuelve el rompecabezas?', @Cat_NovelaIntriga, N'EPUB/Señuelo mortal - P. J. Tracy.epub', N'.epub', 0, 1);
END;

-- Libro 953: Cómo salvar una mala racha
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Cómo salvar una mala racha' AND Autor = N'Marie Robert')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Cómo salvar una mala racha', N'Marie Robert', N'<div>
<p style="font-family: ''Amazon Ember'',''Arial'',''sans-serif''; font-size: 14px"><span style="color: #000000">Una visita catastrófica a Ikea en donde nada ocurre como estaba previsto, una cita a ciegas fracasa por varias incompatibilidades, una madre entra en pánico al descubrir que su hijo está en plena adolescencia y no sabe qué hacer con él… Distintas situaciones cotidianas que nos pueden confundir y hacernos pensar que estamos pasando una mala racha. ¿Qué tenemos que hacer para evitar que nos entre el pánico o para no acabar llorando? ¿Y si invitamos a Platón, Spinoza, Nietzsche o Wittgenstein para hablar de estos temas? ¿Qué habría contestado Kant a un mensaje de ruptura? ¿Aristóteles habría tomado otro vodka más? ¿Qué nos diría Epicuro sobre nuestras angustias? ¿Qué haría Spinoza en Ikea? Los filósofos salen por fin de las bibliotecas para ayudarnos a reaccionar con humor a todas las sorpresas de la vida. </span></p>
<p style="font-family: ''Amazon Ember'',''Arial'',''sans-serif''; font-size: 14px"><span style="color: #000000">Este libro original y curioso recrea doce situaciones de crisis y doce filósofos capaces de tranquilizarnos y ayudarnos a desdramatizar. Se trata de momentos que se nos escapan, de esos minutos de caos en los que todo se tambalea; esos instantes que nos llevan al enfado, el llanto, el sentimiento de culpa, la incomprensión, la vergüenza… ¿Cómo no buscar una respuesta en palabras o ideas que han sobrevivido a lo largo de los siglos?</span></p></div>', @Cat_Noespecificado, N'EPUB/Cómo salvar una mala racha - Marie Robert.epub', N'.epub', 0, 0);
END;

-- Libro 954: Consummatum est
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Consummatum est' AND Autor = N'César Pérez Gellida')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Consummatum est', N'César Pérez Gellida', N'La pequeña localidad islandesa de Grindavik amanece con todos los miembros de una familia bru­talmente asesinados. En uno de los países del mundo con menor tasa de homicidios por habitante, el comi­sario de la Brigada de Homicidios de Reykjavik, Ólafur Olafsson, se enfrenta al caso más escabroso que ha visto justo en el ocaso de su carrera profesional. Pero muy pronto todas las pistas empiezan a apuntar hacia un sofisticado asesino en serie, Augusto Ledesma, que durante varios años ha ido componiendo una siniestra poética de versos regados de sangre a lo largo y ancho de Europa.
Ante tales evidencias, la INTERPOL decide poner al frente del caso al jefe de la Unidad de Búsqueda In­ternacional de Prófugos, Robert. J. Michelson, que se rodeará de un grupo especial integrado por algunos «viejos conocidos» del asesino.
En Consummatum est el lector asistirá al ansiado desenlace de una trilogía —Versos, Canciones y troci­tos de carne— que ha robado el sueño a quienes leye­ron Memento mori y continuaron recorriendo los la­berintos de la mente criminal con Dies irae. El singular y novedoso estilo narrativo de Pérez Gellida promete no dejar a nadie indiferente en este magistral e im­previsible acto final.', @Cat_DetectivePolicial, N'EPUB/Consummatum est - César Pérez Gellida.epub', N'.epub', 0, 1);
END;

-- Libro 955: El aliento de las Tinieblas
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El aliento de las Tinieblas' AND Autor = N'Karen Chance')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El aliento de las Tinieblas', N'Karen Chance', N'Cassandra Palmer puede ver el futuro y comunicarse con los espíritus. Los fantasmas de los muertos no son peligrosos normalmente; sólo les gusta hablar… y mucho. Como cualquier chica sensata, Cassie trata de evitar a los vampiros. Pero cuando el mafioso chupasangre del que escapó hace tres años encuentra a Cassie de nuevo, a ella no le queda más remedio que dirigirse al Senado de los vampiros en busca de protección. Cassie se encontrará trabajando con uno de los integrantes más poderosos y atractivos del Senado, un maestro vampiro peligrosamente seductor; y el tributo que él desea puede ser más grande que lo que Cassie está dispuesta a pagar…', @Cat_NovelaAventurasFantsticoTerrorRomntico, N'EPUB/El aliento de las Tinieblas - Karen Chance.epub', N'.epub', 0, 1);
END;

-- Libro 956: El legado de la villa de las telas
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El legado de la villa de las telas' AND Autor = N'Anne Jacobs')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El legado de la villa de las telas', N'Anne Jacobs', N'Una poderosa familia. Una situación dramática. Una mansión que esconde más de un secreto... La brillante tercera parte de la saga superventas que comenzó con La villa de las telas . Augsburgo, 1920. El estado de ánimo en la villa es optimista respecto al futuro. Paul Melzer ha regresado del frente y toma las riendas de la fábrica decidido a que el negocio familiar recupere su antiguo esplendor. Las cosas van bien incluso para su hermana Elizabeth, que regresa a casa ilusionada con un nuevo amor. Pero «felices para siempre» puede estar aún lejos para los Melzer. Marie, la joven esposa de Paul, quiere cumplir un viejo sueño: tener su propio taller de moda. A pesar de que sus modelos y sus diseños gozan de éxito, su alegría se ve empañada por las constantes discusiones con su marido. Incapaz de soportarlo más, Marie, la mujer que mantuvo a flote la fábrica, la villa y a toda la familia cuando más la necesitaron, toma una dura decisión y abandona la mansión junto a sus hijos. Esta apasionante saga familiar continúa en la cuarta parte Regreso a la villa de las telas. Reseñas de La villa de las telas: «Es una gran historia de amor, con tintes dramáticos y secretos familiares, que nos ha gustado tanto por su calidad literaria como por su preciosismo histórico». Revista Kritica «Una novela histórica muy entretenida que capta el ambiente de comienzos del siglo XX». Fränkische Nachrichten «Amor imposible y las rígidas normas sociales de la Europa central a principios del siglo XX serán el escenario en el que se desenvuelva esta entretenida historia llena de secretos». Jorge Pato García, El Imparcial «Downtown Abbey en Augsburgo». Histo-couch «Este libro lo tiene todo, todo que podríamos desear para un día de lluvia: una gran historia de amor, intriga [...] y un gran secreto familiar». Delmenhorster Kreisblatt «Con su escritura fluida, Anne Jacobs sabe cómo seducir a sus lectoras y transportarlas a la vida de la alta sociedad de hace cien años con todo su glamour pero también con sus sombras». Weilheimer Tagblatt En los blogs... «El estilo ameno y sencillo de la autora, la intensidad de las emociones, la pasión que mueve a sus personajes y el esmerado contexto histórico componen una atractiva lectura, de las que conmueven y cautivan a lo largo de todas sus páginas». Blog Me gustan los libros «Las geniales descripciones de los espacios y la evolución psicológica que nos regala la aclamada autora Anne Jacobs hacen de esta novela toda una delicia que nos lleva a reflexionar sobre la diferencia de clases sociales». Blog La Petita Librería «Una novela de lectura muy viva que despierta rápidamente el interés del lector y en la que este queda atrapado intentando desvelar los múltiples enredos que plantea». Blog Bookeando con Ma Ángeles «La villa de las telas es una saga familiar que atrapa, emocionante y muy entretenida, que me ha hecho disfrutar muchísimo». Blog Adivina quién lee «Las intrigas y los secretos se suceden, como piezas de un puzle, que poco a poco nos permiten vislumbrar una verdad demasiado abrumadora para los habitantes de esa casa». Blog Forjada entre sueños «Ideal para perderse entre sus páginas en una de estas tardes de frío, con todos los ingredientes necesarios para enganchar al más escéptico». Blog Entérate de lo último', @Cat_Noespecificado, N'EPUB/El legado de la villa de las telas - Anne Jacobs.epub', N'.epub', 0, 0);
END;

-- Libro 957: Mutatis mutandis
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Mutatis mutandis' AND Autor = N'César Pérez Gellida')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Mutatis mutandis', N'César Pérez Gellida', N'«El problema no es el presente, es la pesarosa herencia del pasado y la paupérrima proyección del futuro»
Con esta sentencia contenida en el primer spin off de la trilogía Versos, canciones y trocitos de carne, Armando Lopategui «Carapocha» ofrece su visión de un porvenir que vislumbra ya sombrío.
César Pérez Gellida regala a sus lectores este flashback, una pequeña ventana abierta al pasado de uno de los personajes más relevantes de la trilogía desde la que podremos vislumbrar la génesis del hombre en el que se convertirá, así como su difícil relación con su hija Erika y con su mujer en el preámbulo de la guerra de los Balcanes y al filo de un vuelco radical de su destino.', @Cat_Policialdetective, N'EPUB/Mutatis mutandis - César Pérez Gellida.epub', N'.epub', 0, 1);
END;

-- Libro 958: Deseo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Deseo' AND Autor = N'Adrian Blake')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Deseo', N'Adrian Blake', N'Deseo es el undécimo álbum de estudio de la cantante mexicana Paulina Rubio. Fue lanzado el 14 de septiembre de 2018​ por Universal Spain, marcando su última producción con el sello discográfico Universal Music Group y el primero a siete años de editar Brava! (2011). Colaboró con una multitud de productores y músicos para el disco, entre ellos Mauricio Rengifo, Andrés Torres, los Julca Brothers, Antonio "Toy Selectah" Hernández, Joey Montana, Morat, Nacho, Juan Magán, Xabier San Martin y Alexis & Fido. Deseo es un álbum pop latino con una fuerte vibra del género urbano, aunque mantiene el característico estilo pop rock de la cantante en algunas canciones.
Paulina Rubio empezó a trabajar en un disco inédito a finales de 2014, pero por varias situaciones desconocidas Universal retrasó sus proyectos al grado de publicar sencillos independientes a lo largo de los siguientes dos años. Además, se involucró en su faceta como jueza en diferentes shows de televisión incluyendo la versión mexicana de La Voz, La Voz Kids, la versión estadounidense de The X Factor y La Apuesta.
Inicialmente se lanzaron dos sencillos del álbum: «Desire (Me Tienes Loquita)», una colaboración con Nacho, estrenada el 28 de mayo de 2018, y «Suave y Sutil», lanzada cuatro meses más tarde. El 15 de abril de 2019 se lanzó una edición especial de Deseo que incluía cuatro canciones inéditas, incluyendo el sencillo «Ya No Me Engañas», estrenado solo unos días antes del lanzamiento de la reedición.​ El disco también contiene los sencillos independientes  —lanzados entre 2015 y 2016— «Mi Nuevo Vicio», «Si Te Vas» y «Me Quema».
Tras su lanzamiento, Deseo recibió críticas mixtas por parte de los críticos de música, quienes elogiaron la «energía» de la cantante y su capacidad de adaptarse a los nuevos géneros musicales, pero sintieron que el flujo de las canciones en el disco no tenía ningún sentido ya que la mitad de los temas ya habían sido publicados, por lo que sostuvieron que se trataba más de una «compilación» poco sorprendente. Comercialmente, Deseo tuvo poco impacto en las listas musicales, alcanzando la posición número trece de la lista de Billboard Latin Pop Albums. Pese a ello, obtuvo una certificación de disco de oro en Chile,​ y se embarcó en una gira de conciertos en los Estados Unidos.', @Cat_Romanceertico, N'EPUB/Deseo - Adrian Blake.pdf', N'.pdf', 0, 1);
END;

-- Libro 959: Mi jugada perfecta
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Mi jugada perfecta' AND Autor = N'A.S. Lefebre')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Mi jugada perfecta', N'A.S. Lefebre', N'<div> <p style="font-family: ''Amazon Ember'',''Arial'',''sans-serif''; font-weight: 600; font-size: 14px; background-color: #ffffff"><span style="color: #333333">Segunda entrega de la serie «Apostando al amor».</span></p> <p style="font-family: ''Amazon Ember'',''Arial'',''sans-serif''; font-weight: 600; font-size: 14px; background-color: #ffffff"><span style="color: #333333">Dos corazones dispuestos a luchar por su amor contra el estatus social.</span></p> <p style="font-family: ''Amazon Ember'',''Arial'',''sans-serif''; font-weight: 600; font-size: 14px; background-color: #ffffff"><span style="color: #333333">¿Podrá el amor ir más allá de los límites que marca la aristocracia?</span></p> <p style="font-family: ''Amazon Ember'',''Arial'',''sans-serif''; font-size: 14px; background-color: #ffffff"><strong style="color: #333333">Andrew Miller</strong><span style="color: #333333"> había jurado no enamorarse nunca, ya que en el pasado una mujer lo había traicionado con su hermano y su mejor amigo. Pero su juramento se viene abajo cuando conoce a una humilde joven de ojos grises de la cual queda perdidamente enamorado, sin saber sus orígenes ni su estatus social.</span></p> <p style="font-family: ''Amazon Ember'',''Arial'',''sans-serif''; font-size: 14px; background-color: #ffffff"><strong style="color: #333333">Clara Williams</strong><span style="color: #333333"> era la doncella, pero también la mejor amiga, de Katherine Rushmore, hija de condes, quien insiste en hacerle un pequeño lugar en sociedad. Tras una salida, Clara conoce al hombre que le robará su corazón..., pero este será un amor imposible.</span></p> <p style="font-family: ''Amazon Ember'',''Arial'',''sans-serif''; font-size: 14px; background-color: #ffffff"><span style="color: #333333; background-color: #ffffff">Después de varios encuentros casuales Andrew decide confesar sus sentimientos a Clara sin tener en cuenta sus orígenes, por lo que ella huye y empieza a evitarlo por temor a ser rechazada, ya que él es un noble y ella una simple sirvienta.</span></p> <p style="font-family: ''Amazon Ember'',''Arial'',''sans-serif''; font-size: 14px; background-color: #ffffff"><span style="color: #333333; background-color: #ffffff">Dos años después, Andrew regresa en busca de Clara y esta decide confesarle su verdad, lo cual los lleva a luchar contra todas las reglas sociales y a enfrentar a sus familias para así realizar una jugada perfecta en la que el amor será el vencedor.</span></p></div>', @Cat_Noespecificado, N'EPUB/Mi jugada perfecta - A.S. Lefebre.epub', N'.epub', 0, 0);
END;

-- Libro 960: (Fjallbacka 06) La sombra de la sirena
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'(Fjallbacka 06) La sombra de la sirena' AND Autor = N'Camilla Lackberg')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'(Fjallbacka 06) La sombra de la sirena', N'Camilla Lackberg', N'Un hombre desaparece en Fjällbacka sin dejar rastro. Pese a que Patrik Hedström y sus colegas de la policía han hecho cuanto han podido para encontrarlo, nadie sabe si está vivo o muerto. Al cabo de tres meses, lo encuentran finalmente congelado en el hielo. Cuando averiguan que el escritor Christian Thydell, uno de los amigos de la víctima, lleva más de un año recibiendo cartas anónimas plagadas de amenazas, todo se complica. Christian trata de restarle importancia, pero su amiga Erica Falck, quien lo ayudó en la escritura de su primera novela “La sombra de la Sirena”, es consciente del peligro. La policia no tarda en comprender que el asesinato y las cartas, están relacionados.', @Cat_Novelanegrathrillernrdico, N'EPUB/(Fjallbacka 06) La sombra de la sirena - Camilla Lackberg.epub', N'.epub', 0, 1);
END;

-- Libro 961: El silencio de tu nombre
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El silencio de tu nombre' AND Autor = N'Andrés Pérez Domínguez')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El silencio de tu nombre', N'Andrés Pérez Domínguez', N'CuandoErika Walter, viuda de un agente secreto alemán, huye a Madrid con unimportante legajo de documentos que implican a altos cargos nazis en el exilio,su amante Martín Navarro, ex miembro del PCE, se ve obligado a abandonar Parísy perseguirla. Aunque sabe que en España le espera la cárcel si es capturadopor la policía franquista o la muerte por traición si sus camaradas del partidole descubren, Martín lo arriesgará todo, incluso sus convicciones ideológicas,por volver a reunirse con Erika. Con la policía, los nazis, los comunistas y laCIA pisándoles los talones, ambos amantes se verán envueltos en una trama deespionaje e intereses ocultos más compleja y peligrosa de lo que nunca hubieranimaginado. Plagadade espías desencantados, idealistas convencidos y héroes a su pesar, Elsilencio de tu nombre aúna historia, aventura, intriga y romance.Una novela que refleja con maestría cómo en una Europa arrasada por laintolerancia y el fanatismo político y hay lugar para el amor, la amistad, elhonor y la esperanza.', @Cat_IntrigaPolicial, N'EPUB/El silencio de tu nombre - Andrés Pérez Domínguez.epub', N'.epub', 0, 1);
END;

-- Libro 962: Días de perros
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Días de perros' AND Autor = N'Gilles Legardinier')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Días de perros', N'Gilles Legardinier', N'Cansado de vivir en un mundo en el que no encuentra su lugar, el millonario Andrew Blake decide dar un giro radical a su vida: deja su Londres natal y se marcha al campo en Francia… ¡A trabajar como mayordomo! Pero cuando llega a Beauvillier, nada sale como tenía previsto. Las relaciones entre los particulares habitantes de la mansión están llenas de malentendidos y situaciones absurdas, así que Andrew no tiene otra opción que intentar poner orden en esta caótica casa y hacerse amigo de Méphisto.', @Cat_Humor, N'EPUB/Días de perros - Gilles Legardinier.epub', N'.epub', 0, 1);
END;

-- Libro 963: El retorno del mundo de Marco Polo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El retorno del mundo de Marco Polo' AND Autor = N'Robert D. Kaplan')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El retorno del mundo de Marco Polo', N'Robert D. Kaplan', N'<div><span style="color: rgb(51, 51, 51); font-family: Arial, sans-serif; font-size: 14px; orphans: 2; widows: 2; background-color: rgb(255, 255, 255);">A finales del siglo XIII, Marco Polo emprendió un largo viaje hacia Oriente, siguiendo una Ruta de la Seda por la que Europa extendería su influencia. En las primeras décadas del siglo XXI, el sentido de esta ruta está cambiando y el poder en el escenario internacional se está moviendo. Nuevas potencias emergentes luchan por imponerse, mientras que los países que antiguamente dominaban el mundo se enfrentan a nuevos desafíos.</span><br style="color: rgb(51, 51, 51); font-family: Arial, sans-serif; font-size: 14px; orphans: 2; widows: 2; background-color: rgb(255, 255, 255);"><span style="color: rgb(51, 51, 51); font-family: Arial, sans-serif; font-size: 14px; orphans: 2; widows: 2; background-color: rgb(255, 255, 255);">Con su habitual clarividencia, Robert D. Kaplan analiza en esta recopilación de artículos el mundo que nos espera: desde las difíciles decisiones que deberá tomar Estados Unidos en un futuro próximo hasta los dilemas de la Unión Europea, pasando por los movimientos estratégicos de países como Irán o India, o por el puente que está construyendo China hacia Europa.</span></div>', @Cat_Noespecificado, N'EPUB/El retorno del mundo de Marco Polo - Robert D. Kaplan.epub', N'.epub', 0, 0);
END;

-- Libro 964: Las huellas imborrables
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Las huellas imborrables' AND Autor = N'Camilla Läckberg')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Las huellas imborrables', N'Camilla Läckberg', N'El secreto de una joven en los años cuarenta.Un nuevo caso trepidante de Erica Falck y Patrik Hedström.El verano llega a su fin y la escritora Erica Falck vuelve al trabajo tras la baja de maternidad. Ahora le toca a su compañero, el comisario Patrik Hedström, tomarse un tiempo libre para ocuparse de la pequeña Maja. Pero el crimen no descansa nunca, ni siquiera en la tranquila ciudad de Fjällbacka, y cuando dos adolescentes descubren el cadáver de Erik Frankel, Patrik compaginará el cuidado de su hija con su interés por el asesinato de este historiador especializado en la Segunda Guerra Mundial. Mientras tanto, Erica hace un sorprendente hallazgo: diarios de su madre Elsy, con quien tuvo una relación difícil, junto con una antigua medalla nazi. Pero lo más inquietante es que, poco antes de la muerte del historiador, Erica había ido a su casa para obtener más información sobre la medalla. ¿Es posible que su visita desencadenara los acontecimientos que condujeron a su muerte?En Las huellas imborrables Camilla Läckberg entreteje con maestría una historia contemporánea con la vida de una joven en la Suecia de 1940. Escrita con numerosos flashbacks, en esta novela Erica Falck debe adentrarse en el oscuro pasado de su propia familia.', @Cat_Policial, N'EPUB/Las huellas imborrables - Camilla Läckberg.epub', N'.epub', 0, 1);
END;

-- Libro 965: El highlander oscuro
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El highlander oscuro' AND Autor = N'Karen Marie Moning')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El highlander oscuro', N'Karen Marie Moning', N'Dageus McKeltar había viajado a través del tiempo desde su Escocia natal del siglo XV para salvar la vida de su hermano. Sin embargo, un maleficio había caído sobre él, y sólo en los antiguos manuscritos de los druidas escoceses podía encontrar la forma de deshacerlo. Pero en la Nueva York del siglo XXI, entre museos y colecciones privadas, conocerá a la bella experta en antigüedades Chloe Zanders, y en ese momento empezará a intuir que su salvación quizá no esté donde siempre había pensado.', @Cat_Romntico, N'EPUB/El highlander oscuro - Karen Marie Moning.epub', N'.epub', 0, 1);
END;

-- Libro 966: Más allá del espejo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Más allá del espejo' AND Autor = N'John Connolly')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Más allá del espejo', N'John Connolly', N'Algo malsano flota todavía en el interior de la Casa Grady. En esa tenebrosa casa, perdida en las lindes de un denso bosque y de cuyas paredes cuelgan tal vez demasiados espejos, ocurrieron hechos atroces. Allí su dueño, John Grady, asesinó a varios niños tras secuestrarlos. Años después, el padre de una de las víctimas, que compró la casa para que nadie olvidara los crímenes cometidos en ella, tiene indicios de que una niña desconocida podría estar en peligro. Y acude a Charlie Parker para que evite una tragedia. El detective, que no duda en aceptar el caso, va en busca de todos los que conocieron a John Grady. Quizá logre así descubrir qué secretos oculta todavía la casa, aunque eso suponga atraerse la ira de esos seres espectrales que acuden siempre a la llamada del Mal.', @Cat_Noespecificado, N'EPUB/Más allá del espejo - John Connolly.epub', N'.epub', 0, 0);
END;

-- Libro 967: El último fado (Novela)
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El último fado (Novela)' AND Autor = N'Concepción Valverde')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El último fado (Novela)', N'Concepción Valverde', N'Desde niña, Amalia vive obsesionada por la muerte de una de sus tías, a la que no llegó a conocer pero de la que lleva su nombre. El entorno en el que vive se presta a la especulación, ya que sus tres tías acostumbran a convertir la realidad en algo confuso y plagado de contradicciones. En una elegante casa de familia bien venida a menos, todo es controlado con mano férrea por la tía Celia, que esconde un secreto que la protagonista descubrirá, y que no dudará en relacionar con esa misteriosa y no aclarada muerte.
Aunque lo que más angustia a la joven es no saber apenas nada de sus padres, a los que perdió a los pocos meses de nacer. Desde entonces, la tía Celia ha urdido una sucesión de falsedades en torno a su origen que han hecho que Amalia se vea obligada a buscar la verdad por sí misma. Cuando con dieciséis años creía haber superado sus antiguos temores, la protagonista encontrará un diario que la hará regresar a ese mórbido universo familiar, en el que cada nuevo dato está a su vez envuelto en el misterio. Las diversas incógnitas se irán despejando paulatinamente hasta llegar al último recodo de esta novela, en el que una revelación inesperada imprimirá un definitivo giro al relato.

"El último fado" mantiene en vilo al lector a lo largo de sus páginas, sin darle tregua para recuperarse. En esta asombrosa obra conviven rasgos del género policíaco con los de la narrativa psicológica, en una hábil mezcolanza que provoca el aplauso a su conclusión.​', @Cat_PsicolgicoNovelaNarrativaMisterioorgenesPolicacofamiliar, N'EPUB/El último fado (Novela) - Concepción Valverde.epub', N'.epub', 0, 1);
END;

-- Libro 968: La novia se va a Irlanda
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La novia se va a Irlanda' AND Autor = N'Carlota Manzano')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La novia se va a Irlanda', N'Carlota Manzano', N'<div>
<p style="font-family: ''Amazon Ember'',''Arial'',''sans-serif''; font-size: 14px"><span style="color: #333333; background-color: #ffffff">Andrea entra en la iglesia del brazo de su padre para casarse cuando no puede creer lo que ven sus ojos… El pasado a menudo nos persigue y a veces lo hace en los lugares más insospechados y en las situaciones más variopintas. De lo que decida en ese momento van a depender su futuro y el de su bebé, Lorcan. La mirada de su déspota progenitor no la ayuda, pero ¿será capaz de tomar una decisión que suponga una vuelta de tuerca brutal para sus vidas?</span></p></div>', @Cat_Romancecontemporneo, N'EPUB/La novia se va a Irlanda - Carlota Manzano.epub', N'.epub', 0, 1);
END;

-- Libro 969: Apostando al destino
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Apostando al destino' AND Autor = N'A. S. Lefebre')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Apostando al destino', N'A. S. Lefebre', N'<div>
<p>Llega la tercera entrega de la serie «Apostando al amor». Un amor verdadero, un pasado triste y una apuesta al destino. Elizabeth Jones, después de la desaparición de su esposo y tras encontrar una carta en donde se entera de que su familia materna la buscó por años y está en Inglaterra, decide embarcarse para buscar su destino, a su familia y a su desaparecido esposo. No solo encuentra amigos que la ayudan, sino unos ojos color esmeralda que se convierten en el amor de su vida. Eduardo Rushmore, quien había decidido no casarse nunca al menos por amor, pues quien creía que había sido el amor de su vida era feliz con su familia, una noche, en un baile de máscaras, conoce a una misteriosa dama de acento extranjero. Jura que es un ángel, y queda perdido en su mirada azul claro. Cuando Eduardo llega a creer que su nuevo título es una maldición porque todos insisten en que debe casarse y por otras situaciones más, se encuentra cara a cara con su ángel, ambos se dan cuenta de que su amor es correspondido. Pero ella guarda un secreto: está casada. ¿Podrán ganar su apuesta al destino para al fin poder estar juntos y llevar a cabo su amor?</p></div>', @Cat_FictionRomanceHistoricalGeneralRegency, N'EPUB/Apostando al destino - A. S. Lefebre.epub', N'.epub', 0, 1);
END;

-- Libro 970: Más gente tóxica
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Más gente tóxica' AND Autor = N'Bernardo Stamateas')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Más gente tóxica', N'Bernardo Stamateas', N'Tras el esperado éxito del libro que ha revolucionado el mundo de la autoayuda, Bernardo Stamateas nos brinda una nueva oportunidad para reconocer los prototipos tóxicos que nos rodean al tiempo que nos desvela las claves de su personalidad, a fin de reconocerlos y librarnos de ellos. Después de explicarnos cómo distinguir y neutralizar al envidioso, al descalificador, al neurótico y al manipulador, entre otros, Stamateas descubre, en Más gente tóxica, cómo comportarse ante, por ejemplo, el triangulador, el miedoso, el obsesivo, el masoquista, el prepotente, el negativo, entre otros.
«Muchas veces permitimos entrar en nuestro círculo más íntimo a “gente tóxica”, personas equivocadas que permanentemente evalúan lo que decimos y lo que hacemos, o lo que no hacemos».
Se trata de «personas tóxicas» que potencian nuestras debilidades y nos llenan de cargas y frustraciones.
«Ser tóxico es una forma de vivir, de pensar y de actuar; es una manera de funcionar. Mientras todos tratamos de corregir los rasgos tóxicos que percibimos en nosotros mismos, la “persona tóxica” no los reconoce y vive echando la culpa a los demás, robando su energía. Son adictos emocionales que necesitan hacer sentir mal al otro para sentirse bien ellos». Bernardo Stamateas.', @Cat_EnsayoAutoayuda, N'EPUB/Más gente tóxica - Bernardo Stamateas.epub', N'.epub', 0, 1);
END;

-- Libro 971: Las aventuras de Alfred y Agatha 2: El c
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Las aventuras de Alfred y Agatha 2: El chelín de plata.' AND Autor = N'Ana Campoy')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Las aventuras de Alfred y Agatha 2: El chelín de plata.', N'Ana Campoy', N'¿Qué hubiera ocurrido si Alfred Hitchcock y Agatha Christie se hubieran conocido de niños? ¿Qué aventuras habrían vivido? ¿Qué sorprendentes casos habrían resuelto juntos? Las aventuras de Alfred&Agatha nos muestra cómo podría haber sido la amistad de infancia de los dos maestros del suspense más importantes de nuestro tiempo. Como recompensa por sus buenas notas, Alfred recibe un auténtico chelín de plata de parte de su padre. Orgulloso de su regalo, el niño acude a casa de Agatha para enseñárselo, pero su amiga tiene reservada para él otra sorpresa: va a presentarle a su honorable vecino, el escritor Sir Arthur Conan Doyle, creador de las novelas de Sherlock Holmes. Alfred queda encantado tras la visita, en cambio Morritos Jones está muy enfadada. Tras un duro enfrentamiento con la perrita, el chico se marcha a casa muy disgustado, pero a la mañana siguiente, cuando todo parece haber vuelto a la normalidad, ya es demasiado tarde. Morritos ha desaparecido sin dejar rastro.', @Cat_Noespecificado, N'EPUB/Las aventuras de Alfred y Agatha 2 El chelín de plata. - Ana Campoy.epub', N'.epub', 0, 0);
END;

-- Libro 972: Aniquilación
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Aniquilación' AND Autor = N'Jeff VanderMeer')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Aniquilación', N'Jeff VanderMeer', N'En un futuro no determinado, el Área X es un lugar remoto y escondido declarado zona de desastre ambiental desde hace décadas. La naturaleza salvaje ha conquistado el lugar y su acceso está prohibido. La agencia estatal Southern Reach ha enviado diversas expediciones pero casi siempre han fracasado: todos los miembros de una expedición se suicidaron; otros enloquecieron y acabaron matándose entre sí, y los integrantes de la última expedición regresaron convertidos en sombras de lo que un día fueron. Ésta es la expedición número doce. El grupo está compuesto por cuatro mujeres: una antropóloga, una topógrafa, una psicóloga y la narradora, una bióloga. Su misión es cartografiar el terreno y recolectar muestras, anotar todas sus observaciones tanto de su entorno como de sus compañeras. Pronto descubren una gran anomalía geográfica y formas de vida más allá de todo entendimiento. Mientras se enfrentan a una naturaleza tan bella como claustrofóbica, el pasado y los secretos con los que cruzaron la frontera se vuelven cada vez más amenazantes. Aniquilación es el primer volumen de la Trilogía Southern Reach, una serie que crea un mundo como nunca has imaginado y que nos enfrenta al extraño que se esconde dentro de nosotros mismos.', @Cat_Cienciaficcin, N'EPUB/Aniquilación - Jeff VanderMeer.epub', N'.epub', 0, 1);
END;

-- Libro 973: Chicos que muerden
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Chicos que muerden' AND Autor = N'Mari Mancusi')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Chicos que muerden', N'Mari Mancusi', N'Cuando Sunny McDonnald se ve arrastrada al Club Colmillo por su hermana gemela, Rayne, no espera encontrar nada más aparte de un puñado de niños góticos que juegan a ser vampiros. Pero cuando un tío confunde a Sunny con su hermana, amante del lado oscuro, y la muerde en el cuello, averigua que sus colmillos son reales… y mortales. Ahora Sunny tiene menos de una semana para descubrir cómo invertir los efectos del mordisco, o de lo contrario acabará igual que los no muertos. Y no solo se convertirá en vampiro, sino que también estará atada a Magnus, el chupasangre que la mordió, para siempre. Y para siempre es mucho tiempo...', @Cat_Romanceparanormaljuvenil, N'EPUB/Chicos que muerden - Mari Mancusi.epub', N'.epub', 0, 1);
END;

