-- Libro 975: La hermana sombra
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La hermana sombra' AND Autor = N'Lucinda Riley')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La hermana sombra', N'Lucinda Riley', N'La hermana sombra es el tercer libro de la serie basada en la mitología griega y en la astrología, Las Siete Hermanas, de la autora superventas mundial Lucinda Riley. Siete hermanas, siete destinos, un padre con un pasado misterioso... Star D''Aplièse se encuentra en una encrucijada tras la repentina muerte de su padre, el misterioso millonario Pa Salt. Ha dejado a cada una de sus seis hijas una pista sobre sus orígenes, pero Star, la más enigmáticade todas, tiene serias dudas sobre la necesidad de aventurarse y perder la seguridad que la estrecha relación con su hermana CeCe le brinda. A la desesperada decide seguir la pista, que la conduce a una librería de antiguo en Londres y al comienzo de un nuevo mundo para ella. Hace cien años Flora MacNichol jura que nunca se casará. Se siente feliz y segura en su casa en el Lake District cerca de Beatrix Potter, a quien idolatra. Pero se ve arrastrada contra su voluntad hasta Londres, a la casa de una de las personas más influyentes de la sociedad eduardiana: Alice Keppel, la amante más famosa de Eduardo VII, el hijo mayor de la reina Victoria. Flora se debate entre el amor apasionado y la obligación hacia su familia al mismo tiempo que se siente como un peón en juego ajeno, cuyas reglas solo conocen otros, hasta que el encuentro fortuito con un misterioso caballero le proporciona las respuestas que Flora ha estado esperando toda su vida. Si quieres saber más, incluso sobre mitología griega, las Pléyades, las esferas armilares..., visita la web de Lucinda Riley en español: esp.lucindariley.co.uk. También encontrarás documentación sobre Beatrix Potter, Kent, el distrito de los lagos, Violet y Sonia Keppel y Alice Keppel. Reseñas: «La serie "Las Siete Hermanas" es romántica, arrolladora, lujosa y glamurosa.» The Daily Mail «Un libro brillante que no puedes dejar, lleno de glamour y romance.» The Daily Mail «Riley es una experta contadora de historias románticas, que trama con habilidad la historia con la ficción. Un relato absorbente y fascinante.» Booklist En los blogs... «Me ha parecido un libro fantástico y la verdad es que creo que Lucinda es una buena escritora, ya que los tres libros que he leído de ella me han fascinado.» Blog Tesorera de libros «La mezcla perfecta de mitología griega, astrología, romance y novela contemporánea.» Blog El cuervo de las alas rotas «La tercera entrega está a la altura y promete que la siguiente va a ser interesante al acompañar a la cuarta hermana en la búsqueda de su pasado y su identidad.» Blog Viaja gracias a los libros', @Cat_Noespecificado, N'EPUB/La hermana sombra - Lucinda Riley.epub', N'.epub', 0, 0);
END;

-- Libro 976: Wanted
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Wanted' AND Autor = N'Lou Carrigan')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Wanted', N'Lou Carrigan', N'Antonio Vera Ramírez (n. 2 de julio de 1934 en Barcelona, Cataluña) es un prolífico escritor español conocido por su seudónimo Lou Carrigan que utilizó para escribir tanto novelas de aventuras, del oeste como de ciencia-ficción. Ha utilizad,o entre otros, los seudónimos de Angelo Antonioni, Crowley Farber, Mortimer Cody, Lou Flanagan, Anthony Hamilton, Sol Harrison, Anthony Michaels, Anthony W. Rawer, Angela Windsor y Giselle (muchos de ellos con variaciones de su propio nombre). En 1959 apareció su primer western:: Un hombre busca a otro hombre, y creó su seudónimo más afamado Lou Carrigan. Su producción supera las 1.000 novelas, de las cuales 500 pertenecen a la serie de la periodista y espía Brigitte Baby Montfort. León Klimovsky llevó al cine una novela suya con el título de No importa morir. Al menos otras cuatro películas están basadas en sus novelas. Su hermano Francisco Vera Ramírez, también escribió novelas como Ducan M. Cody y Mortimer Cody..', @Cat_Oestenovelapulp, N'EPUB/Wanted - Lou Carrigan.epub', N'.epub', 0, 1);
END;

-- Libro 977: Asesinato
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Asesinato' AND Autor = N'P.H. Ubeda')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Asesinato', N'P.H. Ubeda', N'Samuel Benton achicó los ojos cuando los dirigió hacia el cielo. No le estaba gustando nada aquel repentino cambio de color, pues del azul claro había, pasado casi en un cuarto de hora a ser gris. Las nubes se estaban adueñando de él y el sol había desaparecido por completo. No tuvo otro remedio que liarse a latigazos con aquellas muías perezosas que parecían ir de paseo a no ser que prefiriera llegar al rancho empapado y con el género que llevaba en la carreta echado a perder.', @Cat_Policialmisterio, N'EPUB/Asesinato - P.H. Ubeda.epub', N'.epub', 0, 1);
END;

-- Libro 978: El toque del highlander
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El toque del highlander' AND Autor = N'Karen Marie Moning')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El toque del highlander', N'Karen Marie Moning', N'El señor del castillo de Brodie era un poderoso guerrero escocés, un habitante de un mundo regido por leyes ancestrales y una antigua magia. Sin embargo, ninguno de sus poderes inmortales podía prepararle para el encuentro con aquella encantadora y maldita muchacha llamada Lisa, que se hallaba de pie ante él en su habitación, procedente de un lejano e imposible siglo XXI. Un terrible truco mágico del destino la había transportado en el tiempo a través de siete siglos, sólo para tentarlo con su fascinante y arrebatadora belleza, un arma frente a la que él, con todo su poder, no logrará resistirse. Y aunque Lisa no tenía intención alguna de permanecer en esa tierra salvaje desgarrada por la traición y la guerra, pronto descubrió que su captor tenía otros planes para ella... unos planes que la iban a salvar de un trágico destino.', @Cat_Romntico, N'EPUB/El toque del highlander - Karen Marie Moning.epub', N'.epub', 0, 1);
END;

-- Libro 979: Un océano para llegar a ti
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Un océano para llegar a ti' AND Autor = N'Sandra Barneda')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Un océano para llegar a ti', N'Sandra Barneda', N'<div>
<p style="font-size: 14px; font-weight: 600; font-family: ''Amazon Ember'',''Arial'',''sans-serif''"><span style="color: #000000">Una novela tierna y atrevida sobre los secretos familiares y las emociones silenciadas.</span></p>
<p style="font-size: 14px; font-family: ''Amazon Ember'',''Arial'',''sans-serif''"><span style="color: #000000">Tras la muerte de su madre, Gabriele vuelve al pueblo de los veranos de su infancia. Allí le espera su padre, con el que no habla desde hace años. Juntos se disponen a cumplir el último deseo de Greta: que las tres personas más importantes de su vida ―su marido, su única hija y su cuñada― esparzan sus cenizas en un lugar donde fueron felices. Los secretos que Greta desvela en las cartas que deja a su familia terminarán con el silencio entre padre e hija y, como en un dominó, alterarán la vida de todos y propiciarán un encuentro inesperado que hará que Gabriele descubra que en la vulnerabilidad se halla la magia de la vida.</span></p>
<p style="font-size: 14px; font-weight: 600; font-family: ''Amazon Ember'',''Arial'',''sans-serif''"><span style="color: #000000">¿Y si el destino de las personas tendiera un hilo invisible que las conecta con aquellos que deben encontrar? ¿Y si la vida solo fuera un viaje para encontrarlos?</span></p></div>', @Cat_Noespecificado, N'EPUB/Un océano para llegar a ti - Sandra Barneda (2).epub', N'.epub', 0, 0);
END;

-- Libro 980: El límite del placer
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El límite del placer' AND Autor = N'Eve Berlin')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El límite del placer', N'Eve Berlin', N'Erotica author Dylan Ivory meets the man who is everything she ever wanted. Alec Walker writes dark thrillers and extends them into the bedroom. The only thing he fears is true love. Slowly, Alec shows her that by letting go and submitting to his every desire she can experience the ultimate pleasure. But to keep her, can Alec take the risk and surrender his heart?', @Cat_RomnticoErtico, N'EPUB/El límite del placer - Eve Berlin.mobi', N'.mobi', 0, 1);
END;

-- Libro 981: Muuu
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Muuu' AND Autor = N'David Safier')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Muuu', N'David Safier', N'¡Muuu!, de David Safier, autor de otras obras de la narrativa de humor como Jesús me quiere o Una familia feliz, es una divertidísima fábula protagonizada, al igual que Maldito karma, por animales; y con los mismos ingredientes que hicieron de esta novela un éxito: optimismo y mucho sentido del humor. ¡Muuu! es una divertidísima novela protagonizada por una heroína conmovedora que lucha por hacer realidad sus sueños: la felicidad y el amor. David Safier es todo un fenómeno literario.Lolle, una vaca del norte de Alemania, pasa por una etapa bastante mala: no sólo ha descubierto que su queridísimo toro Champion la engaña con esa vaca idiota de Susi. No, además se ha enterado de que el agricultor quiere vender la finca y que todas las vacas del rebaño acabarán entre dos rebanadas de pan. Pero aún hay esperanza. Un gato italiano de mundo le dice que existe un paraíso para las vacas: ¡la India! De manera que Lolle decide poner pies en polvorosa esa misma noche con sus dos mejores amigas y emprender el peligroso viaje hacia la tierra prometida. Situaciones delirantes y una particular filosofía de vida.', @Cat_Humorficcincontempornea, N'EPUB/Muuu - David Safier.epub', N'.epub', 0, 1);
END;

-- Libro 982: (Trilogía Versos, Canciones Y Trocitos D
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'(Trilogía Versos, Canciones Y Trocitos De Carne 02) Dies Irae(c.1)' AND Autor = N'Cesar Perez Gellida')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'(Trilogía Versos, Canciones Y Trocitos De Carne 02) Dies Irae(c.1)', N'Cesar Perez Gellida', N'La acción de este thriller implacable arranca en la peculiar ciudad italiana de Trieste, frontera entre dos mundos. Augusto Ledesma elige el que fuera hogar de James Joyce como primer escenario para continuar su siniestra obra, que alimenta del aliento de sus víctimas y de la humillación de sus perseguidores. Hasta allí se trasladará el inspector Ramiro Sancho en su frenética y obsesiva persecución de un asesino en serie que parece haber acentuado su voracidad. Entretanto, al otro lado de la frontera, el psicólogo criminalista y exagente del KGB Armando Lopategui, «Carapocha», recorrerá las calles de Belgrado junto a su hija y ahora discípula con el propósito de zanjar cuentas con un pasado despiadado del que no logra despojarse. En otra vuelta de tuerca, a través de fugaces viajes en el tiempo, descubriremos cómo se fraguó la relación entre Pílades y Orestes y asistiremos a su sorprendente desenlace. Tras el rotundo éxito de Memento mori, primera parte de la trilogía Versos, canciones y trocitos de carne, César Pérez Gellida nos conduce de nuevo por los complejos laberintos que conforman la mente criminal desde los ojos de sus protagonistas, ya sean víctimas, asesinos en serie, genocidas o quienes les persiguen. El inesperado desarrollo de los acontecimientos obligará al lector a pasar páginas en una ineludible búsqueda de respuestas. Haciendo gala de un particular estilo cinematográfico aclamado por la crítica literaria, el autor nos envuelve en una trama adictiva, tejida a partir de un argumento sólido y pespunteado de poemas y canciones que componen una singular banda sonora del crimen.', @Cat_Policial, N'EPUB/(Trilogía Versos, Canciones Y Trocitos De Carne 02) Dies Irae(c.1) - Cesar Perez Gellida.epub', N'.epub', 0, 1);
END;

-- Libro 983: Huida mortal
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Huida mortal' AND Autor = N'P. J. Tracy')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Huida mortal', N'P. J. Tracy', N'Grace MacBride y Annie Belinsky, fundadoras de Monkeewrench, una exitosa empresa informática que presta sus servicios a la policía para resolver diversos casos, acompañadas de Sharon Mueller, una agente del FBI, viajan a Green Bay, Wisconsin, con el fin de seguir la pista de un nuevo asesino en serie. A medio camino, sufren una avería en su coche, en mitad de una zona boscosa, aparentemente alejada de cualquier tipo de civilización, incomunicada. Después de andar un buen rato por caminos intransitados, llegan a la población de Four Corners, donde esperan poder hallar a alguien que les ayude a reemprender la marcha; sin embargo, lo que encontrarán es… absolutamente nada. Four Corners parece una ciudad fantasma, un lugar que carece completamente de vida: ningún sonido, ningún medio de comunicación en funcionamiento, nada, sólo restos de una vida que ya no está. En esa ausencia de vida, de repente, serán testigos, como salido de ningún lugar, de un brutal doble asesinato. A partir de ese momento, y sin comprender muy bien qué es lo que realmente ha sucedido, emprenden una huida incierta para salvar sus vidas. Mientras tanto, en el resto del grupo Monkeewrench crece la inquietud por la desaparición de las mujeres, y con la compañía de dos policías de Mineápolis, Leo Magozzi y Gino Rolseth, inicial una búsqueda a ciegas, sin pistas ni señales.', @Cat_NovelaIntriga, N'EPUB/Huida mortal - P. J. Tracy.epub', N'.epub', 0, 1);
END;

-- Libro 984: La curandera de Atenas
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La curandera de Atenas' AND Autor = N'Isabel Martín')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La curandera de Atenas', N'Isabel Martín', N'«Una mujer vendida como esclava se convierte en discípula de Hipócrates, el médico más aclamado de la Historia».Siglo V a.C. Helena, hija del filósofo Empédocles, es secuestrada en Sicilia y, tras un largo viaje, vendida en Atenas a Aspasia de Mileto, amante de Pericles. Allí conocerá a Hipócrates, uno de los más afamados médicos de la antigua Grecia, cuya sabiduría ha llegado hasta nuestros días. Junto a él se introducirá en el mundo de la sanación y del verdadero amor. De esclava a hetaira, de hereje a curandera, el personaje de Helena nos muestra en esta novela el momento cumbre de la Atenas clásica, una ciudad por la que en este periodo desfilan los más ilustres filósofos y donde la democracia siembra sus primeras semillas. La curandera de Atenas narra los inicios de la medicina a través de un personaje sensual y fascinante.', @Cat_Histrico, N'EPUB/La curandera de Atenas - Isabel Martín.epub', N'.epub', 0, 1);
END;

-- Libro 985: El redentor
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El redentor' AND Autor = N'Jo Nesbø')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El redentor', N'Jo Nesbø', N'En pleno centro de Oslo, durante la celebración de un concierto navideño, un inocente cae abatido a manos de un pistolero que parece haber errado el tiro. Sin móvil aparente, sin sospechoso y sin arma homicida, el inspector Harry Hole deberá enfrentarse a uno de los casos más desconcertantes de su carrera. Pero pronto la situación dará un temible vuelco: el asesino parece empeñado en saldar su error dando con su auténtica víctima. La ciudad se convertirá entonces en un inmenso tablero en que asesino y policía jugarán una partida a contrarreloj. ¿A quién persigue realmente el criminal? ¿Qué relaciona su san-grienta misión con el rapto de una niña doce años atrás? A medida que el cerco sobre el volátil homicida se vaya estrechando, Hole irá tomando conciencia de que cada segundo puede llegar a contar más que toda una vida.', @Cat_Policaco, N'EPUB/El redentor - Jo Nesbø.epub', N'.epub', 0, 1);
END;

-- Libro 986: Aguas oscuras
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Aguas oscuras' AND Autor = N'Robert Bryndza')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Aguas oscuras', N'Robert Bryndza', N'<div><p>Tercer libro de la serie de la detective Erika Foster. Por el autor del best seller internacional Te vere bajo el hielo. La detective Erika Foster recibe un aviso de que la clave para resolver un importante caso de narcoticos esta escondida en una cantera abandonada en las afueras de Londres, por lo que ordena que sea registrada. Alli, entre el lodo espeso, encuentran un alijo de droga, pero tambien lo que parece ser el esqueleto de un nino pequeno. Los restos se identifican como los de Jessica Collins, de siete anos, la chica desaparecida que copo los titulares hace veintiseis anos. Mientras Erika trata de juntar las nuevas pruebas con las antiguas, tambien indaga mas sobre el pasado de la familia Collins y se pone en contacto con la principal detective del caso en aquella epoca, Amanda Baker, una mujer atormentada por el fracaso de no haber encontrado a Jessica Collins en su momento. Pero alguien guarda terribles secretos. Alguien que no quiere que este caso sea resuelto y que hara todo lo que este en sus manos para evitar que Erika descubra la verdad. / Detective Erika Foster learns that key evidence for a major narcotics case was stashed in a disused quarry on the outskirts of London and has it searched. The thick sludge contains the drugs, and also the skeleton of a young child, quickly identified as that of Jessica Collins, vanished twenty-six years ago.</p>
<p>**</p></div>', @Cat_Ficcinmoderna, N'EPUB/Aguas oscuras - Robert Bryndza.epub', N'.epub', 0, 1);
END;

-- Libro 987: La piedra del destino
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La piedra del destino' AND Autor = N'Rober H. L. Cagiao')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La piedra del destino', N'Rober H. L. Cagiao', N'<div>
<p style="font-family: ''Arial'',''sans-serif''; font-size: 14px"><span style="color: #333333; background-color: #ffffff">II Volumen de la Saga de El Guardián de las Flores: La muerte, recreada en pueblos malditos que han sido arrasados por la gran epidemia de Peste del siglo XVIII, conducirá al lector a un reencuentro inesperado: Rianxo, el Castelo Lúa, la Torre de Hércules, Castelao… La comisaria Paola Gómez y su equipo, se enfrentan al más difícil de los casos. Todo enmascarado entre enigmas, acertijos, poemas, leyendas y un enemigo implacable. Una novela policíaca de acción, misterio, suspense, magia y corrupción que se mezclan y dan lugar a esta segunda aventura de la saga El Guardián de las Flores, en la que el lector irá descubriendo, junto a sus personajes, quién está detrás de toda la trama.</span></p></div>', @Cat_Noespecificado, N'EPUB/La piedra del destino - Rober H. L. Cagiao.epub', N'.epub', 0, 0);
END;

-- Libro 988: Los cien errores de ortografía más frecu
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Los cien errores de ortografía más frecuentes en el idioma español: Manual de Consulta Interactivo' AND Autor = N'Mónica Castro Plaza')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Los cien errores de ortografía más frecuentes en el idioma español: Manual de Consulta Interactivo', N'Mónica Castro Plaza', N'<p class="description">Los cien errores mas frecuentes en ortografia y las reglas que aplican para corregirlos definitivamente.</p>', @Cat_Manual, N'EPUB/Los cien errores de ortografía más frecuentes en el idioma español - Manual de Consulta Interactivo - Mónica Castro Plaza.epub', N'.epub', 0, 1);
END;

-- Libro 989: S.E.C.R.E.T. 1
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'S.E.C.R.E.T. 1' AND Autor = N'L. Marie Adeline')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'S.E.C.R.E.T. 1', N'L. Marie Adeline', N'As young widow, Cassie’s life is filled with sadness and regret. She waits tables at the rundown Café Rose in New Orleans, heading home alone each night, yearning for more from her life and wishing she could make it happen. But when Cassie discovers a notebook left behind by a mysterious woman at the café, her world is changed forever. The notebook’s stunningly explicit confessions shock and fascinate Cassie, and eventually lead her to S·E·C·R·E·T, an underground society dedicated to helping women realize their wildest, most intimate sexual fantasies. At the heart of the society is three rules: NO JUDGEMENTS. NO LIMITS. NO SHAME. As Cassie is set free from her inhibitions, she is transformed by the confidence and passion she’s kept buried deep inside. But can she find the courage to reveal this new side of herself to the one man she never thought she could have? An irresistible, erotically charged story, perfect for fans of E. L. James’ Fifty Shades of Grey trilogy and Sylvia Day’s Bared to You.', @Cat_RomnticoErtico, N'EPUB/S.E.C.R.E.T. 1 - L. Marie Adeline.mobi', N'.mobi', 0, 1);
END;

-- Libro 990: (Helsinki 1) Tres abuelas y un cocinero 
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'(Helsinki 1) Tres abuelas y un cocinero muerto' AND Autor = N'Minna Lindgren')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'(Helsinki 1) Tres abuelas y un cocinero muerto', N'Minna Lindgren', N'Tienen 90 años. Pero no piensan morirse hasta descubrir al asesino. Siiri, Irma y Anna-Liisa son tres viudas de noventa años residentes en El Bosque del Crepúsculo, un centro privado de apartamentos para la tercera edad de Helsinki. Más que un nidito acogedor para las personas mayores, la residencia resulta un lugar siniestro en el que los ancianos se ven privados de su identidad, rodeados todos los días por enfermeros vagos e inexpertos, y obligados a hacer gimnasia, a asistir a conferencias y a tomar un gran cantidad de medicamentos prescritos por médicos a los que apenas han visto. Parece que para las tres amigas los días ya solo traerán partidas de cartas, viajes en tranvía y asistencia a funerales. Pero en la residencia se empiezan a producir unos misteriosos asesinatos… y quizá nadie había contado con la curiosidad y el tiempo libre de unas inocentes ancianitas.', @Cat_Misteriohumornegro, N'EPUB/(Helsinki 1) Tres abuelas y un cocinero muerto - Minna Lindgren.epub', N'.epub', 0, 1);
END;

-- Libro 991: Ardiente verano
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Ardiente verano' AND Autor = N'Noelia Amarillo')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Ardiente verano', N'Noelia Amarillo', N'María, una mujer de poco más de treinta años, con un hijo adolescente y una vida cómoda en Madrid, se ve «obligada» a pasar las vacaciones de verano en el pueblo de su exmarido. Y no es que le haga mucha gracia… Un día, perdida en la sierra, encuentra una rústica cabaña de madera en un claro del bosque. Junto a ella hay un pequeño cercado con dos caballos; incapaz de resistir la curiosidad, se acerca para recrearse en sus movimientos sin saber que ella misma está siendo observada. A partir de ese momento todo su mundo dará un giro radical. Todo en lo que cree cambiará a manos de un desconocido que no permite que le vea la cara mientras le ordena, susurrante, que haga lo que jamás se atrevió a hacer. ¿Lo hará? ¿Se dejará llevar por las palabras encendidas, las caricias ocultas y la pasión prohibida de un hombre al que ni siquiera puede ver el rostro?', @Cat_Romanceertico, N'EPUB/Ardiente verano - Noelia Amarillo.epub', N'.epub', 0, 1);
END;

-- Libro 992: Primeros casos de Rosendo Noriega
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Primeros casos de Rosendo Noriega' AND Autor = N'Miguel Velando Cabañas')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Primeros casos de Rosendo Noriega', N'Miguel Velando Cabañas', N'<div>
<p>Una despedida de soltero en una aislada casa rural en las montañas de Guadalajara durante una tormenta de nieve. Un asesinato trastocará los planes de los invitados. Un joven Inspector, Rosendo Noriega, se fiará de su intuición para poder desentrañar unos extraordinarios hechos y descubrir al asesino entre los nueve asistentes.</p></div>', @Cat_Policialmisterio, N'EPUB/Primeros casos de Rosendo Noriega - Miguel Velando Cabañas.epub', N'.epub', 0, 1);
END;

-- Libro 993: El highlander inmortal
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El highlander inmortal' AND Autor = N'Karen Marie Moning')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El highlander inmortal', N'Karen Marie Moning', N'Con su larga melena y sus fascinantes ojos, Adam Black es sinónimo de problemas. Inmortal y arrogante, es un maestro de la seducción que puede recorrer el tiempo y los continentes... hasta que una maldición lo despoja de su inmortalidad y lo vuelve invisible. Sólo le queda una esperanza: que la única mujer en el mundo capaz de verlo acceda a ayudarlo.Gabrielle O’Callaghan, una estudiante de Derecho, ha sido maldecida con la capacidad de ver ambos mundos, el de los mortales y el de las criaturas mágicas. En cuanto ve a Adam Black, está segura de que ese hombre podría ser su perdición. Adam la arrastrará a un mundo de hadas que hierve de mortíferas intrigas... Si consiguen alzarse con la victoria, ganarán una recompensa que pocos mortales llegan a conocer jamás: un amor que no terminará nunca.', @Cat_Romntico, N'EPUB/El highlander inmortal - Karen Marie Moning.epub', N'.epub', 0, 1);
END;

-- Libro 994: Todo sobre el amor
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Todo sobre el amor' AND Autor = N'Stephanie Laurens')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Todo sobre el amor', N'Stephanie Laurens', N'Alasdair Cynster -conocido por sus íntimos como Lucifer- ha decidido refugiarse en el campo antes de que las habilidades como casamenteras de las madres de Londres se concentren en él, el último Cynster que permanece soltero. Pero su huida hacia Devon lo lleva derecho a encontrarse con su destino, en la forma de la irresistible Phyllida Tallent, una joven tan bella como testaruda e independiente, que despierta de forma imperiosa los instintos de Cynster. Lucifer trata de negar el deseo que Phyllida suscita en él, pues no quiere caer en una trampa en la que juró que nunca caería... Phyllida ha tenido muchos pretendientes -su belleza e inteligencia son famosas en el condado-, pero ninguno la ha atraído del modo en que lo ha hecho Lucifer. La oferta de éste de enseñarle todo lo relativo a las formas del amor resulta demasiado tentadora para resistirse. Y aun cuando Phyllida no ha capitulado por completo, sabe que sólo una tonta se resistiría a Cynster..., y ella no es ninguna tonta.', @Cat_NovelaRomntico, N'EPUB/Todo sobre el amor - Stephanie Laurens.epub', N'.epub', 0, 1);
END;

-- Libro 995: Michael Jordan: La biografía definitiva
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Michael Jordan: La biografía definitiva' AND Autor = N'Roland Lazenby')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Michael Jordan: La biografía definitiva', N'Roland Lazenby', N'<div>
<p style="font-size: 14px; font-family: ''Amazon Ember'',''Arial'',''sans-serif''"><span style="color: #000000">«A veces me pregunto cómo será mirar hacia atrás y ver todo esto, incluso si me parecerá real.»<br></span><strong style="color: #000000">Michael Jordan</strong></p>
<p style="font-size: 14px; font-family: ''Amazon Ember'',''Arial'',''sans-serif''"><span style="color: #000000">El talento más excepcional de la historia del baloncesto fue como un cometa que cruza el cielo a toda velocidad, del que solo atisbamos el rastro de su brillo. La fascinante carrera de Michael Jordan dejó a seguidores, medios, entrenadores, compañeros y al propio Jordan intentando comprender qué es lo que había sucedido, incluso años después de su retirada.</span></p>
<p style="font-size: 14px; font-family: ''Amazon Ember'',''Arial'',''sans-serif''"><span style="color: #000000">Roland Lazenby dedicó casi treinta años a cubrir la carrera de Michael Jordan, desde la universidad hasta su consolidación como embajador mundial del baloncesto. Sin embargo, también fue testigo de la transformación de Jordan en un competidor insaciable y, a menudo, despiadado, muy lejos del modelo de perfección que se quiso proyectar durante años. </span></p>
<p style="font-size: 14px; font-family: ''Amazon Ember'',''Arial'',''sans-serif''"><span style="color: #000000">Este libro arroja luz sobre la compleja personalidad que se esconde detrás del mito, gracias a innumerables entrevistas con amigos y familiares, con entrenadores y compañeros, además de con el propio Michael Jordan. El resultado es una biografía monumental que muestra a Jordan desde todas sus facetas: el jugador, el icono y el hombre.</span></p></div>', @Cat_Noespecificado, N'EPUB/Michael Jordan - La biografía definitiva - Roland Lazenby.epub', N'.epub', 0, 0);
END;

-- Libro 996: Artemis Fowl
