    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Artemis Fowl', N'Eoin Colfer', N'Nom : Fowl. Prénom : Artemis. Age : 12 ans. Signes particuliers : une intelligence hors du commun. Profession : voleur. Recherché pour : enlèvement de fée et demande de rançon. Appel à tous les FARfadets, membres des Forces Armées de Régulation du Peuple des fées : cet humain est dangereux et doit être neutralisé par tous les moyens possibles. Un anti-héros pétillant de malice, une galerie de personnages décapants, des dialogues vifs et intelligents, une histoire au rythme débridé... Laissez-vous entraîner dans l''univers sophistiqué d''Eoin Colfer, unique et enchanteur.', @Cat_Fantsticojuvenil, N'EPUB/Artemis Fowl - Eoin Colfer.epub', N'.epub', 0, 1);
