-- Libro 997: Como te atreves a volver
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Como te atreves a volver' AND Autor = N'Sophie Saint Rose')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Como te atreves a volver', N'Sophie Saint Rose', N'<div>
<p style="font-family: ''Arial'',''sans-serif''; font-size: 14px"><span style="color: #333333; background-color: #ffffff">Lorrie cometió un error en el pasado que ha pagado muy caro. Perdió a la que creía su familia y ahora era el momento de enfrentarse a ellos por mucho que le doliera. Pero lo que más temía era enfrentarse a Craig, porque su rechazo seguía doliendo incluso después de tantos años. Debería odiarle, debería odiarles a todos. Solo esperaba perderles de vista cuanto antes para empezar a olvidar. Sophie Saint Rose es una prolífica escritora que tiene entre sus éxitos “Huir del amor” o “La elegida”. En los últimos años ha publicado en Amazon más de ciento cuarenta historias que han sido Best Sellers en su categoría, desde contemporáneas como la serie oficina o Australia, hasta de época victoriana o de vikingos.</span></p></div>', @Cat_Romancecontemporneo, N'EPUB/Como te atreves a volver - Sophie Saint Rose.epub', N'.epub', 0, 1);
END;

-- Libro 998: Las hijas de la villa de las telas
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Las hijas de la villa de las telas' AND Autor = N'Anne Jacobs')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Las hijas de la villa de las telas', N'Anne Jacobs', N'<p class="description">Después de La villa de las telas llega la segunda parte de esta saga romántica histórica para fans de Downton Abbey, María Dueñas, Kate Morton o Lucinda Riley, que ha cautivado a más de un millón y medio de lectoras. Una poderosa familia.Una guerra terrible.Una mansión que esconde más de un secreto... El destino de una familia en tiempos convulsos y un amor que todo lo vence.  Augsburgo, 1916. La mansión de la familia Melzer pasa a ser, por necesidad, un hospital militar. Las hijas de la casa, ayudadas por el servicio, se convierten en enfermeras que curan, cuidan y escuchan a los heridos en combate.  Entretanto, Marie, la joven esposa de Paul Melzer, se hace cargo de la fábrica de telas en ausencia de su marido. Sin embargo, recibe una terrible noticia: su cuñado ha caído en el frente y Paul es ahora un prisionero de guerra.  Marie se niega a que las circunstancias la venzan y lucha con todas sus fuerzas por preservar el patrimonio familiar. Pero, mientras no pierde la esperanza de volver a ver a Paul con vida y se deja la piel en la fábrica, el elegante Ernst von Klippstein aparece en la puerta de la mansión, empeñado en no perder de vista a la joven y bella mujer que tiene entre sus capaces manos el destino de la familia Melzer.  Esta apasionante saga familiar terminará en la tercera parte El legado de la villa de las telas. La crítica ha dicho...«Es una gran historia de amor, con tintes dramáticos y secretos familiares, que nos ha gustado tanto por su calidad literaria como por su preciosismo histórico.»Revista Kritica «Una novela histórica muy entretenida que capta el ambiente decomienzos del siglo XX.»Fränkische Nachrichten «Downtown Abbey en Augsburgo.»Histo-couch «Este libro lo tiene todo, todo que podríamos desear para un día de lluvia: una gran historia de amor, intriga [...] y un gran secreto familiar.»Delmenhorster Kreisblatt «Con su escritura fluida, Anne Jacobs sabe cómo seducir a sus lectoras y transportarlas a la vida de la alta sociedad de hace cien años con todo su glamour pero también con sus sombras.»Weilheimer Tagblatt</p>', @Cat_FiccinHistricaGeneralNarrativafemeninaRomanceContempornea, N'EPUB/Las hijas de la villa de las telas - Anne Jacobs.epub', N'.epub', 0, 1);
END;

