-- Libro 1000: Calígula
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Calígula' AND Autor = N'Albert Camus')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Calígula', N'Albert Camus', N'Reflexión sobre los problemas y obsesiones que nutrieron su creación literaria y teórica, Calígula —obra gestada entre 1938 y 1942 y representada por vez primera en 1945— es una de las grandes piezas dramáticas de Albert Camus (1913-1960). En ella, los temas recurrentes del absurdo existencial, la enajenación metafísica, el sufrimiento del hombre y la lógica del poder reciben un despliegue dramático que discurre en paralelo a las novelas y ensayos de un autor cuyo talento y sensibilidad ética se centraron siempre en una indagación sobre la complejidad, la ambigüedad y la riqueza de la condición humana.', @Cat_DramaHistrico, N'EPUB/Calígula - Albert Camus.epub', N'.epub', 0, 1);
END;

-- Libro 1001: Si me lo pide el corazón
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Si me lo pide el corazón' AND Autor = N'Bethany Bells')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Si me lo pide el corazón', N'Bethany Bells', N'<p class="centrado">Había nacido en un lugar surgido del amor eterno. No podía conformarse con menos.</p> <p> </p> <p>Olivia había nacido en un lugar surgido del amor eterno… y no podía conformarse con menos.</p> <p>Olivia y Marcus se conocen en una situación muy difícil, en la que descubren que los actos de sus padres provocaron un cambio en la línea legítima de la herencia del marquesado de Northcott. Tras ese comienzo tan conflictivo, inician una relación en la que él se siente impulsado a una boda por el deber de limpiar el honor de su apellido.</p <p>Pero Olivia, nacida en un pueblo que se mueve en entre la realidad y la leyenda de un amor eterno, no desea algo así. Ella solo se casará por amor.</p>', @Cat_Romnticohistrico, N'EPUB/Si me lo pide el corazón - Bethany Bells.epub', N'.epub', 0, 1);
END;

-- Libro 1002: Juego de asesinos
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Juego de asesinos' AND Autor = N'P. J. Tracy')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Juego de asesinos', N'P. J. Tracy', N'Los directivos de la compañía de software Monkeewrench descubren que alguien está reproduciendo los asesinatos de uno de sus juegos. De momento ya hay dos víctimas, una mujer joven y un hombre que había salido a hacer «footing», pero el número puede elevarse de forma espeluznante. Grace McBride, la fundadora de la compañía, y su equipo estudian atentamente su juego para evitar más muertes, pero inevitablemente están en el punto de mira del detective Leo Magozzi, que, tirando del hilo, ha descubierto que McBride y sus colegas ya habían estado involucrados en otra serie de asesinatos ocurridos en Atlanta una década atrás.', @Cat_Intrigapolicial, N'EPUB/Juego de asesinos - P. J. Tracy.epub', N'.epub', 0, 1);
END;

-- Libro 1003: Un océano para llegar a ti
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Un océano para llegar a ti' AND Autor = N'Sandra Barneda')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Un océano para llegar a ti', N'Sandra Barneda', N'<div>
<p style="font-size: 14px; font-weight: 600; font-family: ''Amazon Ember'',''Arial'',''sans-serif''"><span style="color: #000000">Una novela tierna y atrevida sobre los secretos familiares y las emociones silenciadas.</span></p>
<p style="font-size: 14px; font-family: ''Amazon Ember'',''Arial'',''sans-serif''"><span style="color: #000000">Tras la muerte de su madre, Gabriele vuelve al pueblo de los veranos de su infancia. Allí le espera su padre, con el que no habla desde hace años. Juntos se disponen a cumplir el último deseo de Greta: que las tres personas más importantes de su vida ―su marido, su única hija y su cuñada― esparzan sus cenizas en un lugar donde fueron felices. Los secretos que Greta desvela en las cartas que deja a su familia terminarán con el silencio entre padre e hija y, como en un dominó, alterarán la vida de todos y propiciarán un encuentro inesperado que hará que Gabriele descubra que en la vulnerabilidad se halla la magia de la vida.</span></p>
<p style="font-size: 14px; font-weight: 600; font-family: ''Amazon Ember'',''Arial'',''sans-serif''"><span style="color: #000000">¿Y si el destino de las personas tendiera un hilo invisible que las conecta con aquellos que deben encontrar? ¿Y si la vida solo fuera un viaje para encontrarlos?</span></p></div>', @Cat_Noespecificado, N'EPUB/Un océano para llegar a ti - Sandra Barneda.epub', N'.epub', 0, 0);
END;

-- Libro 1004: La muerte en mi Colt
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'La muerte en mi Colt' AND Autor = N'Spencer Curtis')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'La muerte en mi Colt', N'Spencer Curtis', N'EL hombre alto, desgarbado, de ojos grises y fríos como la muerte, dijo: —Dos ataúdes de tercera. No pienso gastar más dinero con vosotros, ratas. Lo que sucedió a continuación quizá no se había visto nunca en Hot Springs. Los dos pistoleros tenían empuñados ya los «Colts» y comenzaban ya a apretar los gatillos, cuando el hombre de los ojos grises fue en busca de sus armas con una velocidad diabólica. Pero no desenfundó. Hizo dos extraños giros con ambas muñecas y disparó a través de las pistoleras.', @Cat_Westernnovelanegra, N'EPUB/La muerte en mi Colt - Spencer Curtis.epub', N'.epub', 0, 1);
END;

-- Libro 1005: #Topadentro con Slow cooker 
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'#Topadentro con Slow cooker ' AND Autor = N'Marta Miranda')
