    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'#Topadentro con Slow cooker ', N'Marta Miranda', N'#topadentro se refiere a recetas en las que solo hay una elaboración: se ponen directamente los ingredientes en el Slow Cooker y se cocinan, sin pochar, dorar, reducir... Más fácil, imposible. ¿Y qué tipo de platos se pueden preparar de un modo tan sencillo?', @Cat_Cocinagastronoma, N'EPUB/#Topadentro con Slow cooker - Marta Miranda.epub', N'.epub', 0, 1);
END;

-- Libro 1006: El Recetario De La Abuela
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El Recetario De La Abuela' AND Autor = N'Alejandro Ruiz Reyes')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El Recetario De La Abuela', N'Alejandro Ruiz Reyes', N'<div>
<p>¿Te gustaria aprender  a comer postres siendo diabetico? </p>
<p>¿Que tal un mousse de chocolate? </p>
<p>¿Te gustan las peras envinadas? </p>
<p>¿O prefieres una gelatina de durazno?</p>
<p> </p>
<p>Tras casì 20 años de vivir en una familia de doctores y especialistas de la salud el autor nos cuenta que si es posible ser diabetico y comer rico o simplemente comer antojitos cuidando de nuestra salud</p>
<p>En este libro aprenderas: </p>
<p>✅A cocinar postres Ricos y sabrosos </p>
<p>✅A cuidar de tu salud siendo diabetico </p>
<p>✅A cocinar de forma Fit </p>
<p>✅Aprenderas a cuidar de ti y de tu familia</p>
<p>Deja De SUFRIR Y Comienza A VIVIR...</p>
<p> </p>
<p> </p></div>', @Cat_Cocinarecetario, N'EPUB/El Recetario De La Abuela - Alejandro Ruiz Reyes.epub', N'.epub', 0, 1);
END;

-- Libro 1007: El Asesino del Camino Norte Parte II
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El Asesino del Camino Norte Parte II' AND Autor = N'Rober H. L. Cagiao')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El Asesino del Camino Norte Parte II', N'Rober H. L. Cagiao', N'<div>
<p style="font-family: ''arial''; font-size: 12px"><span style="background-color: #ffffff; color: #333333">Segunda y última parte de El Asesino del Camino Norte, cuarto volumen de la saga de El Guardián de las Flores. Se puede leer independiente aunque se recomienda haber leído previamente El Guardián. Este libro desaparecerá con la crisis y la cuarentena que estamos sufriendo. Gracias.</span></p></div>', @Cat_Noespecificado, N'EPUB/El Asesino del Camino Norte Parte II - Rober H. L. Cagiao.epub', N'.epub', 0, 0);
END;

-- Libro 1008: El desfile de los malditos
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El desfile de los malditos' AND Autor = N'Antonio Lozano')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El desfile de los malditos', N'Antonio Lozano', N'<div>
<p>Nadie está a salvo de perderlo todo. Ildefonso Artiles puede dar fe de ello. De buena familia, felizmente casado, padre de dos hijos, ejemplar profesor de historia en un colegio privado, el paro lo arrastra al alcohol; el alcohol, a la calle, y la calle, a la desaparición. Metafórica, primero; real, después: su rastro parece haberse borrado de las aceras de Las Palmas, que se habían convertido en su hogar. ¿Dónde está Ildefonso? El detective José García Gago recibe el encargo de encontrarlo. Sus hermanos, tras años de ignorarlo, lo buscan. Por una herencia, dicen. Pero García Gago sospecha que hay algo más, algo mucho más turbio que lo lleva a viajar de la ciudad canaria a Madrid y a Barcelona tras el rastro de Ildefonso. Un viaje que no acaba ahí, y que le obligará a adentrarse en territorios en los que la vida de algunos seres humanos vale tan poco que se vende a piezas a quienes puedan pagarla.</p>
<p>En El desfile de los malditos, Antonio Lozano González recupera a su personaje icónico, el detective melómano José García Gago, para embarcarlo en una novela comprometida y valiente, que atrapa y revuelve, que sacude y que, a menudo, indigna. Una novela no apta para cínicos, porque la denuncia del tráfico de órganos —en Colombia, en Pakistán, en el cuerno de África y en China, pero también a la vuelta de la esquina— no permite paños calientes ni medias tintas.</p>
<p>La productora Meridional Producciones ha comprado los derechos audiovisuales de Preludio para una muerte, La sombra del Minotauro y El desfile de los malditos para la creación de una serie televisiva, Calima, protagonizada por su personaje, el inspector García Gago.</p></div>', @Cat_S2, N'EPUB/El desfile de los malditos - Antonio Lozano.epub', N'.epub', 0, 1);
END;

-- Libro 1009: El murciélago
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'El murciélago' AND Autor = N'Jo Nesbø')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'El murciélago', N'Jo Nesbø', N'Harry Hole es enviado a Sidney desde Oslo para que investigue el asesinato de una mujer noruega, Inger Holter, cuyo cadáver ha sido encontrado entre oscuras rocas, al pie de un acantilado. La policía sospecha que fue violada antes de morir, pero no se ha hallado rastro alguno de ADN. Harry Hole tendrá como compañero de investigación a Andrew Kensington, detective aborigen australiano. Ambos sospechan del novio de Inger, Evans White, atractivo camello conocido por la policía. Sin embargo, Harry comienza a vislumbrar que el caso es más complejo de lo que a priori pudiera parecer, y poco después el equipo de investigación relaciona una serie de desapariciones y asesinatos sin resolver que sugieren que un asesino en serie anda suelto. Harry Hole es un joven y brillante detective, pero esconde un oscuro secreto. Durante su estancia en Sidney se enamorará perdidamente de Birgitta Enquist, a quien le confesará lo que oculta su pasado y qué le aleja de su país…', @Cat_Policial, N'EPUB/El murciélago - Jo Nesbø.epub', N'.epub', 0, 1);
END;

-- Libro 1010: Artemis Fowl
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Artemis Fowl' AND Autor = N'Eoin Colfer')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Artemis Fowl', N'Eoin Colfer', N'Nom : Fowl. Prénom : Artemis. Age : 12 ans. Signes particuliers : une intelligence hors du commun. Profession : voleur. Recherché pour : enlèvement de fée et demande de rançon. Appel à tous les FARfadets, membres des Forces Armées de Régulation du Peuple des fées : cet humain est dangereux et doit être neutralisé par tous les moyens possibles. Un anti-héros pétillant de malice, une galerie de personnages décapants, des dialogues vifs et intelligents, une histoire au rythme débridé... Laissez-vous entraîner dans l''univers sophistiqué d''Eoin Colfer, unique et enchanteur.', @Cat_Fantsticojuvenil, N'EPUB/Artemis Fowl - La venganza de Opal - Eoin Colfer.epub', N'.epub', 0, 1);
END;

-- Libro 1011: Pecado original
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Pecado original' AND Autor = N'Karin Slaughter')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Pecado original', N'Karin Slaughter', N'La agente Faith Mitchell llega tarde a todos los sitios. Se suponía que tenía que recoger a su bebé a mediodía, pero no para de llamar a su madre a casa y no le responde. Evelyn Mitchell, capitán de la policía de Atlanta ya retirada, nunca sale de casa sin decirle a alguien adónde va, especialmente si está cuidando de su nieta. La preocupación de Faith se intensifica después de horas de llamadas sin respuesta… Cuando se presenta en casa de Evelyn, encuentra la huella sangrienta de una mano en la puerta de la entrada, y la casa hecha un caos. Todo indica que su madre ha sido secuestrada. Encontrarla se convertirá en tarea prioritaria de Amanda Wagner, la subdirectora del departamento de policía y amiga íntima de Evelyn. El compañero de Faith, Will Trent la ayudará con una investigación paralela. Las sospechas apuntan a los antiguos compañeros de Evelyn en la brigada de narcóticos, todos ellos condenados por corrupción por quedarse con parte del dinero decomisado al que tenían acceso; sin embargo, una nueva pista proporcionada por una vecina chismosa desvía la investigación hacia un caballero que visitaba a Evelyn varias veces a la semana. Mientras la investigación avanza, el romance entre la doctora Linton y Will Trent se afianza; Faith intenta mantener la compostura en la terrible situación que le ha tocado vivir; Amanda y Will persiguen todos los indicios, incluso aquellos que les lleven a los bajos fondos del estado de Georgia. La prioridad es encontrar a Evelyn y detener a sus secuestradores antes de que sea demasiado tarde…', @Cat_NovelaPolicial, N'EPUB/Pecado original - Karin Slaughter.epub', N'.epub', 0, 1);
END;

-- Libro 1012: Artemis Fowl: El Cubo B
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Artemis Fowl: El Cubo B' AND Autor = N'Eoin Colfer')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Artemis Fowl: El Cubo B', N'Eoin Colfer', N'Espero, humano, que con sólo oír mi nombre un escalofrío recorra tu cuerpo.Si no, pregúntales a las Criaturas mágicas o a las que viven en el Ártico quién soy; seguramente formo parte de sus pesadillas más temidas, y eso a mí me gusta. Sepas que yo pienso, y Mayordomo actúa. Fui el primer humano que se enfrentó a los seres subterráneos y conseguí lo que quería: oro y algún secreto más. Ahora todo parece volver a la normalidad: he rescatado a mi padre y mi madre está empeñada en que seamos una familia normal. Me queda poco tiempo para mi última maniobra... No sé si ni siquiera te mereces saber cuál es: pero, bueno, hoy me siento especialmente generoso, así que te adelanto que voy a chantajear a un magnate de la tecnología de la comunicación con un invento -mío, evidentemente-: el cubo B. Y, ahora, ¿a qué esperas para empezar a leer?', @Cat_FantsticoJuvenil, N'EPUB/Artemis Fowl El Cubo B - Eoin Colfer.epub', N'.epub', 0, 1);
END;

