-- Libro 1014: Matar un ruiseñor
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Matar un ruiseñor' AND Autor = N'Nelle Harper Lee')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Matar un ruiseñor', N'Nelle Harper Lee', N'<div>
<p>Matar a un ruiseñor</p>
<p>Harper Lee</p>
<p>narrativa</p>
<p>La explosión de odio y violencia racial en un pequeño pueblo de Alabama, es percibida por una niña cuyo padre defiende a un hombre negro acusado de violación. Matar un ruiseñor, está ambientada en el sur mítico, degradado y humillado tras la derrota contra los yankees en la Guerra de Secesión. La acción transcurre en los años treinta, los años de la terrible depresión post Crac del 29. Narrativamente acaba donde empieza Faulkner y comienza donde acaba Carson McCullers, pero es una historia de personajes. Los principales: los niños Scout y Jem y su padre Atticus, el pueblo y sus habitantes blancos y negros. El drama de la segregación racial y las raíces del funesto racismo enquistado en una sociedad tradicional y conservadora. La novela habla por si sola, se trata de una historia de niños en los que va influyendo la brutalidad y la cordura de los adultos, ese mundo fracturado cuyos fragmentos se complementan en una educación moral llena de contradicciones. La reedición ahora en castellano es una buena oportunidad para adentrarse en esa sociedad desaparecida pero con preocupantes espasmos contemporáneos.</p></div>', @Cat_narrativa, N'EPUB/Matar un ruiseñor - Nelle Harper Lee.epub', N'.epub', 0, 1);
END;

-- Libro 1015: Una impostora en Minstrel Valley
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Una impostora en Minstrel Valley' AND Autor = N'Mariam Orazal')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Una impostora en Minstrel Valley', N'Mariam Orazal', N'<p class="centrado">Valery Sherman ha conseguido ocultarse de todo y de todos, menos del amor.</p> <p> </p> <p>Cuando llegó a Minstrel Valley, la ficticia señorita Sherman creyó haber encontrado el refugio perfecto donde ocultarse de los peligros que la acechaban, pero halló mucho más que eso pues la Escuela de Señoritas de lady Acton le proporcionó un hogar y una familia. Como profesora de etiqueta su vida es pacífica y algo monótona hasta que aparece en el valle un nuevo profesor que no se dejará engañar por su disfraz de maestra severa.</p> <p>El negocio familiar lo es todo para Dunhcan Bissop. Lo que menos había pensado era que la apertura de sus nuevas caballerizas lo lanzaría de cabeza a terminar como instructor de equitación ¡en una escuela de señoritas! Por suerte, encontrará en la muy estirada señorita Sherman un aliciente para acudir todos los días a la gran mansión y descubrir quién es la mujer que se oculta bajo capas y capas de decoro y secretos.</p>', @Cat_NovelaRomnticoHistrico, N'EPUB/Una impostora en Minstrel Valley - Mariam Orazal.epub', N'.epub', 0, 1);
END;

-- Libro 1016: Los jardines de los muertos
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Los jardines de los muertos' AND Autor = N'William Brodrick')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Los jardines de los muertos', N'William Brodrick', N'Una muerte en extrañas circunstancias, una abogada de la Corona de Su Graciosa Majestad, un caso judicial que
vuelve a abrirse, removiendo conciencias sepultadas por el olvido…
Los juzgados y los muelles de Londres dibujarán el paisaje en el que deben dilucidarse cuestiones tan complejas
como la justicia, la inocencia o la línea que separa el bien del mal. Tal vez las respuestas se encuentren en el monasterio en el que se refugia un antiguo colaborador de la abogada muerta. Este monje será el encargado de desenterrar la verdad sobre un oscuro pasado, desvelando también el motivo de su tardía vocación religiosa.', @Cat_NovelaIntriga, N'EPUB/Los jardines de los muertos - William Brodrick.epub', N'.epub', 0, 1);
END;

-- Libro 1017: Enseñar a investigar. Una didáctica nuev
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Enseñar a investigar. Una didáctica nueva de la investigación en ciencias sociales y humanas' AND Autor = N'Ricardo Sánchez Puentes')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Enseñar a investigar. Una didáctica nueva de la investigación en ciencias sociales y humanas', N'Ricardo Sánchez Puentes', N'En este libro, interesa analizar y evaluar distintas estrategias didácticas que han sido diseñadas y aplicadas para generar conocimiento en ciencias sociales y humanidades. Para Ricardo Sánchez Puentes, no hay duda de que enseñar a investigar es un proceso complejo y una actividad ampliamente diversificada; así, sostiene que es más fecunda y da mejores resultados la didáctica de la investigación que tiene como referentes las prácticas concretas y los procesos efectivos de la generación de conocimiento. Si se quiere enseñar el oficio de investigador, no basta con fundar la propuesta programática en la mera descripción, análisis y crítica de ese quehacer, es necesario que quien desea aprender se involucre en todas las tareas de esta práctica, aliado de otra persona con mayor experiencia y en un ejercicio institucional en el que se promueva la investigación social y humanística.', @Cat_ensearainvestigardidcticadelainvestigacincienciassocialesyhumanidadesgeneracindeconocimientoinvestigacinsocialyhumanstica, N'EPUB/Enseñar a investigar. Una didáctica nueva de la investigación en ciencias sociales y humanas - Ricardo Sánchez Puentes.epub', N'.epub', 0, 1);
END;

