-- Libro 1019: Mi vida por la tuya
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Mi vida por la tuya' AND Autor = N'Amy Plum')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Mi vida por la tuya', N'Amy Plum', N'Cuando los padres de Kate Mercier mueren en un trágico accidente de automóvil, ella deja atrás su vida —y sus recuerdos— para irse a vivir con sus abuelos en París. Para Kate, la única manera de sobrevivir al dolor que encuentra es sumergirse en el mundo de los libros y del arte parisino. Y así es hasta que conoce a Vincent Delacroix. Misterioso, encantador y devastadoramente guapo, Vincent amenaza con derretir el hielo con el que ella protege su corazón con solo una sonrisa. A medida que se va enamorando de él, la joven descubre que es un revenant, un no muerto marcado por un destino: debe sacrificarse a sí mismo una y otra vez para salvar las vidas de los demás. Vincent y otros como él se encuentran metidos desde hace siglos en una guerra contra un grupo de revenants malvados, los numa, que solo se mantienen en este mundo para asesinar y traicionar. Si sigue a su corazón, Kate sabe que quizá nunca más pueda mantenerse a salvo.', @Cat_Romancejuvenilfantasaparanormal, N'EPUB/Mi vida por la tuya - Amy Plum.epub', N'.epub', 0, 1);
END;

-- Libro 1020: Preludio para una muerte
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Preludio para una muerte' AND Autor = N'Antonio Lozano')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Preludio para una muerte', N'Antonio Lozano', N'En Preludio para una muerte, el detective privado José García Gago se enfrenta por primera vez a un caso importante: el asesinato de un personaje destacado ocurrido veinte años atrás en una pequeña localidad cuya irresolución creó dos bandos, que aunque enfrentados desde entonces, no facilitarán la labor a nuestro investigador porque hasta las pequeñas comunidades guardan secretos que pesan sobre la conciencia de todos y de los que a nadie le interesa hablar. No obstante, la presencia de un “forastero” pone en alerta a la comunidad, y nuevas muertes y revelaciones nos descubren una historia sórdida y triste de abandono, desamor y conflicto de clases.', @Cat_Novelanegrapolicial, N'EPUB/Preludio para una muerte - Antonio Lozano.epub', N'.epub', 0, 1);
END;

