-- Libro 1022: (Fjallbacka 07) Los vigilantes del faro 
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'(Fjallbacka 07) Los vigilantes del faro ' AND Autor = N'Camilla Lackberg')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'(Fjallbacka 07) Los vigilantes del faro ', N'Camilla Lackberg', N'Desde que Patrik se ha reincorporado al trabajo, Erica se dedica de lleno a sus gemelos, que nacieron prematuros. Apenas tiene tiempo para ir a visitar a Annie Wester, una compañera de instituto que acaba de regresar a Fjällbacka después de muchos años. Junto con su hijo Sam, Annie se ha instalado en el faro abandonado de la isla de Gråskär, propiedad de su familia. A pesar de los rumores que circulan por el pueblo sobre la leyenda de la «isla de los espíritus», en la que los muertos vagan libremente, no parecen importarle las voces extrañas que oye por la noche. Además, su antiguo novio Matte Sverin, quien también ha pasado unos años en Estocolmo y acaba de empezar a trabajar en el Ayuntamiento de Fjällbacka, aparece asesinado. Annie es la última persona que lo ve con vida. Estos sucesos le depararán a Patrik y a su eficaz colaboradora Paula muchos quebraderos de cabeza. Por su parte, Erica, que realiza su propia investigación en paralelo, conseguirá atar algunos cabos sueltos que serán de gran ayuda para la resolución del caso.', @Cat_Novelanegrathrillernrdico, N'EPUB/(Fjallbacka 07) Los vigilantes del faro - Camilla Lackberg.epub', N'.epub', 0, 1);
END;

-- Libro 1023: No cambies por mí, amor
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'No cambies por mí, amor' AND Autor = N'Sophie Saint Rose')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'No cambies por mí, amor', N'Sophie Saint Rose', N'Natalya tiene una vida perfectamente ordenada. Ha conseguido el trabajo que siempre había soñado y tiene unas amigas estupendas. La única pega es que no tiene novio y por mucho que lo intentaba no conseguía al hombre de sus sueños. ¿Era demasiado exigente? Puede, pero estaba en su derecho. Aunque sus amigas consideraban que la conocían lo suficiente para encontrar al hombre que encajara en su vida, ¿debía arriesgarse? Mira que tenían gustos muy distintos y podía llegar a salir con hombres que ella ni miraría dos veces. Pero el premio era demasiado tentador…', @Cat_NovelaRomntico, N'EPUB/No cambies por mí, amor - Sophie Saint Rose.epub', N'.epub', 0, 1);
END;

-- Libro 1024: ¡Y tenía que ser mi jefe! 4: El desenlac
