BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'¡Y tenía que ser mi jefe! 4: El desenlace', N'Norah Carter & Monika Hoff', N'Cuando Davinia cree que Óscar es el amor de su vida, descubre el engaño de este. Mientras decide terminar con su matrimonio, es su antiguo jefe quien decide apoyarla en todo y no separarse de ella en ningún momento.Peter ha sufrido un cambio radical y eso puede que le haga ganarse el corazón de la única mujer que amó. ¿Lograrán estar por fin juntos? El desenlace de esta saga lo conoceremos aquí.', @Cat_NovelaRomntico, N'EPUB/¡Y tenía que ser mi jefe! 4 El desenlace - Norah Carter & Monika Hoff.epub', N'.epub', 0, 1);
