    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'No soy un asesino', N'Kent Wilson', N'Ángel Cazorla Olmo, nacido en Santa Cruz de Marchena (provincia de Almería) en 1930, en una familia de humildes labradores. A los 15 años emigra a Cataluña, donde realiza diversos trabajos. A los 22 años se inicia en la literatura popular con el seudónimo Kent Wilson, publicando casi un centenar de relatos del genero westerns, policíacos, de guerra y ciencia ficción.', @Cat_Thrillersuspense, N'EPUB/No soy un asesino - Kent Wilson.epub', N'.epub', 0, 1);
END;

-- Libro 1027: Territorio de caza
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Territorio de caza' AND Autor = N'Miguel Velando Cabañas')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Territorio de caza', N'Miguel Velando Cabañas', N'<div>
<p style="font-size: 14px; font-family: ''Amazon Ember'',''Arial'',''sans-serif''"><span style="background-color: #ffffff; color: #333333">Una mujer es encontrada muerta de un tiro de escopeta en un camino cerca de Madrid. Casi a la vez, otra mujer es asesinada de la misma manera en un pueblo de Ciudad Real. La investigación llevará al inspector Noriega y a la oficial Salinas a colaborar con el capitán Torres de la UCO en medio de la atmósfera opresiva de Vegas de Calatraba, un pueblo imaginario perfectamente real.</span></p></div>', @Cat_Policiaca, N'EPUB/Territorio de caza - Miguel Velando Cabañas.epub', N'.epub', 0, 1);
END;

-- Libro 1028: Diablo
IF NOT EXISTS (SELECT 1 FROM dbo.BibliotecaLibros WHERE Titulo = N'Diablo' AND Autor = N'Stephanie Laurens')
BEGIN
    INSERT INTO dbo.BibliotecaLibros (Titulo, Autor, Sinopsis, IdCategoria, RutaArchivo, Formato, PrecioDracoins, Activo) 
    VALUES (N'Diablo', N'Stephanie Laurens', N'Las fans de la serie Cynster disfrutarán de esta apasionate novela, que como las demás se puede leer de forma independiente. Primera entrega de la saga romántica «Cynster». ¿Era el marido que siempre había soñado, o un verdadero demonio? Honoria Wetherby es institutriz, pero tiene otros proyectos: vivir aventuras, conocer mundo... aunque lo inesperado puede cambiar drásticamente hasta los mejores planes. Su intento de ayudar a un moribundo la lleva a pasar la noche en una cabaña solitaria en compañía del miembro más denostado de los Cynster, a quien llaman Diablo. Cuando esto sale a la luz, él no tiene otro remedio que pedir su mano. La familia Cynster está encantada de que el famoso libertino finalmente decida casarse, pero lo que menos desea la rebelde joven es un marido que la controle, y enamorarse no está en sus planes.', @Cat_Romntico, N'EPUB/Diablo - Stephanie Laurens.epub', N'.epub', 0, 1);
END;

